{
  "name": "DataHarmonizer Pro",
  "description": "Professional data processing engine that automatically splits mixed-type columns, provides AI-driven summaries, pivot tables, and advanced filtering for large datasets.",
  "requestFramePermissions": []
}

export type DataRow = Record<string, any>;

export interface ProcessedData {
  headers: string[];
  rows: DataRow[];
  originalHeaders: string[];
}

export enum DataType {
  NUMBER = 'Number',
  TEXT_ENGLISH = 'Text (English)',
  DATE = 'Date',
  UNKNOWN = 'Unknown'
}

export interface PivotConfig {
  rowField: string;
  columnField: string;
  valueField: string;
  aggType: 'sum' | 'count' | 'avg';
}

export interface FilterConfig {
  column: string;
  value: string;
  operator: 'equals' | 'contains' | 'greaterThan' | 'lessThan';
}

import { DataRow, DataType, ProcessedData } from '../types';

const DATE_REGEX = /^(?:\d{1,2}[\/\-]\d{1,2}[\/\-]\d{2,4})|(?:\d{4}[\/\-]\d{1,2}[\/\-]\d{1,2})$/;
const ENGLISH_TEXT_REGEX = /^[A-Za-z\s\.,!\?\(\)\-]+$/;

function inferType(value: any): DataType {
  if (value === null || value === undefined || value === '') return DataType.UNKNOWN;

  const str = String(value).trim();

  // Try Number
  if (!isNaN(Number(str)) && str !== '') return DataType.NUMBER;

  // Try Date
  if (DATE_REGEX.test(str)) return DataType.DATE;

  // Try English Text
  if (ENGLISH_TEXT_REGEX.test(str)) return DataType.TEXT_ENGLISH;

  return DataType.UNKNOWN;
}

export function harmonizeData(rawRows: DataRow[]): ProcessedData {
  if (rawRows.length === 0) return { headers: [], rows: [], originalHeaders: [] };

  const originalHeaders = Object.keys(rawRows[0]);
  const splitMap: Record<string, Set<DataType>> = {};

  // 1. Identify mixed columns
  originalHeaders.forEach(header => {
    const types = new Set<DataType>();
    rawRows.forEach(row => {
      const val = row[header];
      if (val !== undefined && val !== null) {
        // Handle newline-separated values as separate entries for typing check
        const parts = String(val).split(/\r?\n/).map(p => p.trim()).filter(p => p !== '');
        parts.forEach(p => {
            const t = inferType(p);
            if (t !== DataType.UNKNOWN) types.add(t);
        });
      }
    });
    splitMap[header] = types;
  });

  // 2. Transform Rows
  const finalHeaders = new Set<string>();
  const harmonizedRows = rawRows.map(row => {
    const newRow: DataRow = {};

    originalHeaders.forEach(header => {
      const typesInCol = splitMap[header];

      // If it's a simple column, keep it as is (or keep original header)
      if (typesInCol.size <= 1) {
          finalHeaders.add(header);
          newRow[header] = row[header];
      } else {
          // It's a mixed column! Split into sub-columns
          const val = row[header];
          const parts = String(val).split(/\r?\n/).map(p => p.trim()).filter(p => p !== '');

          // Initialize empty values for all potential types to maintain horizontal spread
          typesInCol.forEach(t => {
              const subHeader = `${header} (${t})`;
              finalHeaders.add(subHeader);
              newRow[subHeader] = "";
          });

          parts.forEach(p => {
              const type = inferType(p);
              if (type !== DataType.UNKNOWN) {
                  const subHeader = `${header} (${type})`;
                  // Append if multiple of same type exist in one cell
                  newRow[subHeader] = newRow[subHeader] ? `${newRow[subHeader]}; ${p}` : p;
              }
          });
      }
    });
    return newRow;
  });

  return {
    headers: Array.from(finalHeaders),
    rows: harmonizedRows,
    originalHeaders
  };
}

export function generatePivotData(rows: DataRow[], rowField: string, colField: string, valField: string, aggType: string) {
  const pivot: Record<string, Record<string, number>> = {};
  const allCols = new Set<string>();

  rows.forEach(row => {
    const rVal = String(row[rowField] || '(Blank)');
    const cVal = String(row[colField] || '(Blank)');
    const vVal = parseFloat(row[valField]) || 0;

    allCols.add(cVal);
    if (!pivot[rVal]) pivot[rVal] = {};

    if (aggType === 'sum') {
      pivot[rVal][cVal] = (pivot[rVal][cVal] || 0) + vVal;
    } else if (aggType === 'count') {
      pivot[rVal][cVal] = (pivot[rVal][cVal] || 0) + 1;
    }
  });

  return {
    rows: Object.keys(pivot).map(key => ({ row: key, ...pivot[key] })),
    columns: Array.from(allCols)
  };
}

import { GoogleGenAI } from "@google/genai";
import { DataRow } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export async function generateDataSummary(data: DataRow[]): Promise<string> {
  if (!process.env.API_KEY) return "AI Summary requires an API Key.";

  // Take a representative sample to avoid token limits
  const sample = data.slice(0, 20);
  const prompt = `Analyze this dataset and provide a high-level executive summary. Identify trends, anomalies, and key takeaways.

  Data Sample (JSON):
  ${JSON.stringify(sample, null, 2)}

  Total records in full dataset: ${data.length}.
  Please write a professional summary in 3-4 paragraphs.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Unable to generate summary.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Error generating AI summary. Please check your connection and API key.";
  }
}

import React from 'react';
import { DataRow } from '../types';

interface DataTableProps {
  headers: string[];
  rows: DataRow[];
}

export const DataTable: React.FC<DataTableProps> = ({ headers, rows }) => {
  return (
    <div className="overflow-auto max-h-[600px] border border-slate-200 rounded-lg shadow-sm bg-white custom-scrollbar">
      <table className="w-full text-sm text-left border-collapse">
        <thead className="bg-slate-50 sticky top-0 z-10 shadow-sm">
          <tr>
            {headers.map((h, i) => (
              <th key={i} className="px-4 py-3 font-semibold text-slate-700 border-b border-slate-200 min-w-[150px] whitespace-nowrap uppercase tracking-wider text-xs">
                {h}
              </th>
            ))}
          </tr>
        </thead>
        <tbody className="divide-y divide-slate-100">
          {rows.map((row, rowIndex) => (
            <tr key={rowIndex} className="hover:bg-slate-50 transition-colors">
              {headers.map((h, colIndex) => (
                <td key={colIndex} className="px-4 py-3 text-slate-600 border-b border-slate-100">
                  {row[h] !== undefined ? String(row[h]) : ""}
                </td>
              ))}
            </tr>
          ))}
          {rows.length === 0 && (
            <tr>
              <td colSpan={headers.length} className="px-4 py-10 text-center text-slate-400">
                No matching records found.
              </td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { DataRow, PivotConfig } from '../types';
import { generatePivotData } from '../utils/dataProcessor';

interface PivotViewProps {
  rows: DataRow[];
  headers: string[];
}

export const PivotView: React.FC<PivotViewProps> = ({ rows, headers }) => {
  const [config, setConfig] = useState<PivotConfig>({
    rowField: headers[0],
    columnField: headers[1] || headers[0],
    valueField: headers.find(h => h.includes('Number')) || headers[0],
    aggType: 'count'
  });

  const pivotData = useMemo(() => {
    return generatePivotData(rows, config.rowField, config.columnField, config.valueField, config.aggType);
  }, [rows, config]);

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4 bg-slate-50 p-4 rounded-xl border border-slate-200">
        <div>
          <label className="block text-xs font-bold text-slate-500 mb-1 uppercase">Rows</label>
          <select 
            className="w-full p-2 rounded border border-slate-300 bg-white"
            value={config.rowField}
            onChange={(e) => setConfig({ ...config, rowField: e.target.value })}
          >
            {headers.map(h => <option key={h} value={h}>{h}</option>)}
          </select>
        </div>
        <div>
          <label className="block text-xs font-bold text-slate-500 mb-1 uppercase">Columns</label>
          <select 
            className="w-full p-2 rounded border border-slate-300 bg-white"
            value={config.columnField}
            onChange={(e) => setConfig({ ...config, columnField: e.target.value })}
          >
            {headers.map(h => <option key={h} value={h}>{h}</option>)}
          </select>
        </div>
        <div>
          <label className="block text-xs font-bold text-slate-500 mb-1 uppercase">Values</label>
          <select 
            className="w-full p-2 rounded border border-slate-300 bg-white"
            value={config.valueField}
            onChange={(e) => setConfig({ ...config, valueField: e.target.value })}
          >
            {headers.map(h => <option key={h} value={h}>{h}</option>)}
          </select>
        </div>
        <div>
          <label className="block text-xs font-bold text-slate-500 mb-1 uppercase">Method</label>
          <select 
            className="w-full p-2 rounded border border-slate-300 bg-white"
            value={config.aggType}
            onChange={(e) => setConfig({ ...config, aggType: e.target.value as any })}
          >
            <option value="count">Count</option>
            <option value="sum">Sum</option>
          </select>
        </div>
      </div>

      <div className="overflow-auto border border-slate-200 rounded-lg shadow-sm bg-white">
        <table className="w-full text-sm text-left">
          <thead className="bg-slate-50">
            <tr>
              <th className="px-4 py-3 font-bold border-b bg-slate-100">{config.rowField} \ {config.columnField}</th>
              {pivotData.columns.map(c => (
                <th key={c} className="px-4 py-3 font-bold border-b text-center">{c}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {pivotData.rows.map((r, i) => (
              <tr key={i} className="hover:bg-slate-50">
                <td className="px-4 py-2 font-medium border-b bg-slate-50">{r.row}</td>
                {pivotData.columns.map(c => (
                  <td key={c} className="px-4 py-2 border-b text-center">
                    {r[c] !== undefined ? r[c].toLocaleString() : '-'}
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import * as XLSX from 'xlsx';
import { 
  FileUp, 
  Table, 
  LayoutGrid, 
  Sparkles, 
  Download, 
  Filter, 
  RefreshCw,
  Search,
  Database,
  BarChart3
} from 'lucide-react';
import { DataRow, ProcessedData } from './types';
import { harmonizeData } from './utils/dataProcessor';
import { DataTable } from './components/DataTable';
import { PivotView } from './components/PivotView';
import { generateDataSummary } from './services/gemini';

const App: React.FC = () => {
  const [rawData, setRawData] = useState<DataRow[]>([]);
  const [processedData, setProcessedData] = useState<ProcessedData | null>(null);
  const [activeTab, setActiveTab] = useState<'preview' | 'pivot' | 'ai'>('preview');
  const [isProcessing, setIsProcessing] = useState(false);
  const [aiSummary, setAiSummary] = useState<string>('');
  const [searchTerm, setSearchTerm] = useState('');
  const [isGeneratingAi, setIsGeneratingAi] = useState(false);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const data = XLSX.utils.sheet_to_json(ws) as DataRow[];

        setRawData(data);
        const harmonized = harmonizeData(data);
        setProcessedData(harmonized);
      } catch (err) {
        console.error("Error reading file", err);
        alert("Failed to read file. Please ensure it is a valid Excel or CSV.");
      } finally {
        setIsProcessing(false);
      }
    };
    reader.readAsBinaryString(file);
  };

  const filteredRows = useMemo(() => {
    if (!processedData) return [];
    if (!searchTerm) return processedData.rows;
    const lowerSearch = searchTerm.toLowerCase();
    return processedData.rows.filter(row => 
      Object.values(row).some(val => String(val).toLowerCase().includes(lowerSearch))
    );
  }, [processedData, searchTerm]);

  const handleExport = () => {
    if (!processedData) return;
    const worksheet = XLSX.utils.json_to_sheet(processedData.rows);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "HarmonizedData");
    XLSX.writeFile(workbook, "DataHarmonizer_Export.xlsx");
  };

  const generateAiWriteup = async () => {
    if (!processedData) return;
    setIsGeneratingAi(true);
    const summary = await generateDataSummary(processedData.rows);
    setAiSummary(summary);
    setIsGeneratingAi(false);
  };

  return (
    <div className="min-h-screen flex flex-col font-sans">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 px-8 py-4 flex items-center justify-between sticky top-0 z-50">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-2 rounded-lg text-white">
            <Database size={24} />
          </div>
          <div>
            <h1 className="text-xl font-bold text-slate-800 tracking-tight">DataHarmonizer Pro</h1>
            <p className="text-xs text-slate-500 font-medium uppercase">Intelligent Data Separation Engine</p>
          </div>
        </div>

        {processedData && (
          <div className="flex items-center gap-3">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
              <input 
                type="text" 
                placeholder="Quick Filter..." 
                className="pl-9 pr-4 py-2 border border-slate-200 rounded-full text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all w-64"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
            <button 
              onClick={handleExport}
              className="flex items-center gap-2 bg-slate-800 hover:bg-black text-white px-4 py-2 rounded-full text-sm font-semibold transition-all shadow-lg active:scale-95"
            >
              <Download size={16} /> Export Excel
            </button>
          </div>
        )}
      </header>

      <main className="flex-1 flex overflow-hidden">
        {/* Sidebar */}
        <aside className="w-64 bg-slate-50 border-r border-slate-200 p-6 space-y-8 hidden md:block">
          <div className="space-y-4">
            <label className="block p-4 border-2 border-dashed border-slate-300 rounded-2xl hover:border-indigo-500 hover:bg-indigo-50 cursor-pointer transition-all text-center group">
              <input type="file" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleFileUpload} />
              <FileUp className="mx-auto mb-2 text-slate-400 group-hover:text-indigo-600" size={32} />
              <span className="text-sm font-bold text-slate-600 group-hover:text-indigo-700 block">Upload Data</span>
              <span className="text-[10px] text-slate-400 block mt-1">Excel or CSV</span>
            </label>
          </div>

          {processedData && (
            <nav className="space-y-1">
              <button 
                onClick={() => setActiveTab('preview')}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-medium transition-colors ${activeTab === 'preview' ? 'bg-indigo-600 text-white shadow-md shadow-indigo-200' : 'text-slate-600 hover:bg-slate-100'}`}
              >
                <Table size={18} /> Data Grid
              </button>
              <button 
                onClick={() => setActiveTab('pivot')}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-medium transition-colors ${activeTab === 'pivot' ? 'bg-indigo-600 text-white shadow-md shadow-indigo-200' : 'text-slate-600 hover:bg-slate-100'}`}
              >
                <LayoutGrid size={18} /> Pivot Engine
              </button>
              <button 
                onClick={() => setActiveTab('ai')}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-medium transition-colors ${activeTab === 'ai' ? 'bg-indigo-600 text-white shadow-md shadow-indigo-200' : 'text-slate-600 hover:bg-slate-100'}`}
              >
                <Sparkles size={18} /> AI Summary
              </button>
            </nav>
          )}

          {processedData && (
            <div className="pt-8 border-t border-slate-200">
              <div className="text-[10px] uppercase font-bold text-slate-400 mb-4 tracking-widest">Stats</div>
              <div className="space-y-3">
                <div className="bg-white p-3 rounded-lg border border-slate-200 shadow-sm">
                  <div className="text-xl font-bold text-slate-800">{processedData.rows.length.toLocaleString()}</div>
                  <div className="text-[10px] text-slate-400 uppercase font-semibold">Total Records</div>
                </div>
                <div className="bg-white p-3 rounded-lg border border-slate-200 shadow-sm">
                  <div className="text-xl font-bold text-slate-800">{processedData.headers.length}</div>
                  <div className="text-[10px] text-slate-400 uppercase font-semibold">Active Fields</div>
                </div>
              </div>
            </div>
          )}
        </aside>

        {/* Content Area */}
        <section className="flex-1 overflow-auto bg-slate-50 p-8 custom-scrollbar">
          {!processedData && !isProcessing && (
            <div className="h-full flex flex-col items-center justify-center text-center max-w-md mx-auto">
              <div className="bg-white p-8 rounded-3xl shadow-xl border border-slate-100 mb-6">
                <BarChart3 size={64} className="text-indigo-600 mx-auto mb-6 opacity-80" />
                <h2 className="text-2xl font-bold text-slate-800 mb-2">Welcome to Pro Analyzer</h2>
                <p className="text-slate-500 mb-8 leading-relaxed">
                  Upload your messy datasets. We'll automatically identify mixed columns and separate numbers, dates, and English text into clean, horizontal fields.
                </p>
                <label className="inline-flex items-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white px-8 py-3 rounded-full font-bold transition-all cursor-pointer shadow-lg shadow-indigo-100 active:scale-95">
                  <FileUp size={20} /> Select File to Begin
                  <input type="file" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleFileUpload} />
                </label>
              </div>
              <p className="text-[10px] text-slate-400 uppercase tracking-widest font-bold">Secure Client-Side Processing</p>
            </div>
          )}

          {isProcessing && (
            <div className="h-full flex flex-col items-center justify-center space-y-4">
              <RefreshCw className="animate-spin text-indigo-600" size={48} />
              <div className="text-center">
                <h3 className="text-lg font-bold text-slate-800">Processing Data Structure</h3>
                <p className="text-slate-500 text-sm">Identifying mixed types and re-organizing columns...</p>
              </div>
            </div>
          )}

          {processedData && !isProcessing && (
            <div className="max-w-7xl mx-auto space-y-6">
              <div className="flex items-center justify-between mb-4">
                <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
                  {activeTab === 'preview' && <><Table className="text-indigo-600" /> Data Preview</>}
                  {activeTab === 'pivot' && <><LayoutGrid className="text-indigo-600" /> Aggregation Engine</>}
                  {activeTab === 'ai' && <><Sparkles className="text-indigo-600" /> AI Insights</>}
                </h2>
                <div className="text-xs text-slate-400 font-bold uppercase tracking-wider bg-slate-200 px-3 py-1 rounded-full">
                  Step 2: Analysis & Refinement
                </div>
              </div>

              {activeTab === 'preview' && (
                <div className="animate-in fade-in duration-500">
                  <div className="flex items-center gap-2 mb-4">
                    <Filter size={16} className="text-slate-400" />
                    <span className="text-sm font-semibold text-slate-600">Active Harmonization:</span>
                    <span className="text-xs bg-indigo-100 text-indigo-700 px-2 py-0.5 rounded-full font-bold">Column Splitting Enabled</span>
                    <span className="text-xs bg-emerald-100 text-emerald-700 px-2 py-0.5 rounded-full font-bold ml-auto">{filteredRows.length} rows visible</span>
                  </div>
                  <DataTable headers={processedData.headers} rows={filteredRows} />
                </div>
              )}

              {activeTab === 'pivot' && (
                <div className="animate-in slide-in-from-bottom-4 duration-500">
                  <PivotView rows={processedData.rows} headers={processedData.headers} />
                </div>
              )}

              {activeTab === 'ai' && (
                <div className="animate-in zoom-in-95 duration-500">
                  <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-8">
                    <div className="flex items-center justify-between mb-8">
                      <div>
                        <h3 className="text-xl font-bold text-slate-800">Intelligent Narrative</h3>
                        <p className="text-sm text-slate-500">Auto-generated summary based on data distributions</p>
                      </div>
                      <button 
                        onClick={generateAiWriteup}
                        disabled={isGeneratingAi}
                        className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-700 disabled:bg-slate-300 text-white px-6 py-2.5 rounded-xl font-bold transition-all"
                      >
                        {isGeneratingAi ? <RefreshCw className="animate-spin" size={18} /> : <Sparkles size={18} />}
                        {aiSummary ? 'Regenerate Analysis' : 'Generate Summary'}
                      </button>
                    </div>

                    {!aiSummary && !isGeneratingAi && (
                      <div className="text-center py-12 border-2 border-dashed border-slate-100 rounded-xl">
                        <Sparkles size={48} className="text-slate-100 mx-auto mb-4" />
                        <p className="text-slate-400 font-medium">Click generate to start AI analysis of the dataset</p>
                      </div>
                    )}

                    {isGeneratingAi && (
                      <div className="space-y-4 py-8">
                        <div className="h-4 bg-slate-100 rounded w-3/4 animate-pulse"></div>
                        <div className="h-4 bg-slate-100 rounded w-1/2 animate-pulse"></div>
                        <div className="h-4 bg-slate-100 rounded w-5/6 animate-pulse"></div>
                        <div className="h-4 bg-slate-100 rounded w-2/3 animate-pulse"></div>
                      </div>
                    )}

                    {aiSummary && (
                      <div className="prose prose-slate max-w-none text-slate-700 leading-relaxed whitespace-pre-wrap">
                        {aiSummary}
                      </div>
                    )}
                  </div>
                </div>
              )}
            </div>
          )}
        </section>
      </main>

      {/* Footer / Status Bar */}
      <footer className="bg-white border-t border-slate-200 px-8 py-2 flex items-center justify-between text-[10px] text-slate-400 font-bold uppercase tracking-tighter">
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-1"><div className="w-1.5 h-1.5 rounded-full bg-emerald-500"></div> System Ready</div>
          {processedData && <div className="flex items-center gap-1 border-l pl-4 border-slate-200">Processing: Local Engine</div>}
        </div>
        <div>V2.0 PRO ENTERPRISE EDITION</div>
      </footer>
    </div>
  );
};

