/**
 * Standardizes cell splitting by common delimiters (newline, comma, semicolon, pipe)
 */
function splitCellContent(val: any): string[] {
  if (val === null || val === undefined) return [];
  const str = String(val);
  // Remove Arabic characters immediately
  const cleaned = str.replace(ARABIC_REGEX, '').trim();
  // Split by common separators
  return cleaned.split(/\r?\n|,|;|\|/).map(p => p.trim()).filter(p => p !== '');
}

/**
 * Removes Arabic characters from a string.
 */
function stripArabic(val: string): string {
  return val.replace(ARABIC_REGEX, '').trim();
}

function inferType(str: string): DataType {
  if (str === '') return DataType.UNKNOWN;

  // Try Number - ensure it's not a date-like number (e.g. 2024) if it's strictly a number
  if (!isNaN(Number(str)) && str !== '' && !DATE_REGEX.test(str)) return DataType.NUMBER;

  // Try Date
  if (DATE_REGEX.test(str)) return DataType.DATE;

  // Try English Text
  if (ENGLISH_TEXT_REGEX.test(str)) return DataType.TEXT_ENGLISH;

  return DataType.UNKNOWN;
}

export function harmonizeData(rawRows: DataRow[]): ProcessedData {
  if (rawRows.length === 0) return { headers: [], rows: [], originalHeaders: [] };

  const originalHeaders = Object.keys(rawRows[0]);
  const splitMap: Record<string, Set<DataType>> = {};

  // Step 1: Deep scan all records (handling 1500+) to find column type distributions
  originalHeaders.forEach(header => {
    const types = new Set<DataType>();
    rawRows.forEach(row => {
      const parts = splitCellContent(row[header]);
      parts.forEach(p => {
        const t = inferType(p);
        if (t !== DataType.UNKNOWN) types.add(t);
      });
    });
    splitMap[header] = types;
  });

  // Step 2: Transform rows into the harmonized horizontal structure
  const finalHeadersList: string[] = [];
  const columnMapping: Record<string, string[]> = {};

  originalHeaders.forEach(header => {
    const typesInCol = splitMap[header];

    // If column has 0 or 1 types across all 1500+ records, keep as is
    if (typesInCol.size <= 1) {
      finalHeadersList.push(header);
      columnMapping[header] = [header];
    } else {
      // Mixed column detected: create horizontal sub-headers for each detected type
      const subHeaders: string[] = [];
      // Sort types to maintain consistent column order
      Array.from(typesInCol).sort().forEach(t => {
        const subHeader = `${header} (${t})`;
        subHeaders.push(subHeader);
        finalHeadersList.push(subHeader);
      });
      columnMapping[header] = subHeaders;
    }
  });

  const harmonizedRows = rawRows.map(row => {
    const newRow: DataRow = {};

    originalHeaders.forEach(header => {
      const subHeaders = columnMapping[header];
      const typesInCol = splitMap[header];

      if (typesInCol.size <= 1) {
        // Single type column: just clean Arabic
        newRow[header] = stripArabic(String(row[header] || ''));
      } else {
        // Multi-type column: initialize sub-columns as empty
        subHeaders.forEach(sh => newRow[sh] = "");

        // Distribute parts horizontally into their respective type columns
        const parts = splitCellContent(row[header]);
        parts.forEach(p => {
          const type = inferType(p);
          if (type !== DataType.UNKNOWN) {
            const targetHeader = `${header} (${type})`;
            // Append with separator if multiple items of same type exist in one cell
            newRow[targetHeader] = newRow[targetHeader] 
              ? `${newRow[targetHeader]}; ${p}` 
              : p;
          }
        });
      }
    });
    return newRow;
  });

  return {
    headers: finalHeadersList,
    rows: harmonizedRows,
    originalHeaders
  };
}

