    mergedRows.forEach(row => {
      const parts = splitCellContent(row[header]);
      parts.forEach(p => {
        const t = inferType(p);
        if (t !== DataType.UNKNOWN) types.add(t);
      });
    });
    splitMap[header] = types;
  });

  // 3. Construct the final horizontal column structure
  const finalHeadersList: string[] = [];
  const columnMapping: Record<string, string[]> = {};

  originalHeaders.forEach(header => {
    const typesInCol = splitMap[header];

    if (typesInCol.size <= 1) {
      // Single type column remains unified
      finalHeadersList.push(header);
      columnMapping[header] = [header];
    } else {
      // Multi-type column is split horizontally
      const subHeaders: string[] = [];
      // Logical UI Order: Names/Text first, then IDs/Numbers, then Dates
      const preferredOrder = [DataType.TEXT_ENGLISH, DataType.NUMBER, DataType.DATE];

      preferredOrder.forEach(t => {
        if (typesInCol.has(t)) {
          const subHeader = `${header} (${t})`;
          subHeaders.push(subHeader);
          finalHeadersList.push(subHeader);
        }
      });
      columnMapping[header] = subHeaders;
    }
  });

  // 4. Transform data: Distribute cell parts into their respective type-specific columns
  const harmonizedRows = mergedRows.map(row => {
    const newRow: DataRow = {};

    originalHeaders.forEach(header => {
      const subHeaders = columnMapping[header];
      const typesInCol = splitMap[header];

      if (typesInCol.size <= 1) {
        // Maintain original value but strip Arabic
        newRow[header] = stripArabic(String(row[header] || ''));
      } else {
        // Initialize sub-columns as empty
        subHeaders.forEach(sh => newRow[sh] = "");

        const parts = splitCellContent(row[header]);
        parts.forEach(p => {
          let type = inferType(p);
          let value = p;

          // Excel Date Serial logic conversion
          if (type === DataType.NUMBER && !isNaN(Number(p))) {
            const num = Number(p);
            // If the column has Dates and this number fits the serial range
            if (typesInCol.has(DataType.DATE) && num > 40000 && num < 60000) {
              value = excelSerialToDate(num);
              type = DataType.DATE;
            }
          }

          const targetHeader = `${header} (${type})`;
          if (columnMapping[header].includes(targetHeader)) {
            newRow[targetHeader] = newRow[targetHeader] 
              ? `${newRow[targetHeader]}; ${value}` 
              : value;
          }
        });
      }
    });
    return newRow;
  });

  return {
    headers: finalHeadersList,
    rows: harmonizedRows,
    originalHeaders
  };
}

export function generatePivotData(rows: DataRow[], rowField: string, colField: string, valField: string, aggType: string) {
  const pivot: Record<string, Record<string, number>> = {};
  const allCols = new Set<string>();

  rows.forEach(row => {
    const rVal = String(row[rowField] || '(Blank)');
    const cVal = String(row[colField] || '(Blank)');
    // Robust number parsing removing any non-numeric chars except decimal/minus
    const vVal = parseFloat(String(row[valField]).replace(/[^0-9.-]+/g, '')) || 0;

    allCols.add(cVal);
    if (!pivot[rVal]) pivot[rVal] = {};

    if (aggType === 'sum') {
      pivot[rVal][cVal] = (pivot[rVal][cVal] || 0) + vVal;
    } else if (aggType === 'count') {
      pivot[rVal][cVal] = (pivot[rVal][cVal] || 0) + 1;
    }
  });

  return {
    rows: Object.keys(pivot).map(key => ({ row: key, ...pivot[key] })),
    columns: Array.from(allCols).sort()
  };
}

