/**
 * Enhanced regex patterns for better classification
 */
const DATE_REGEX = /^(?:\d{1,2}[\/\-]\d{1,2}[\/\-]\d{2,4})|(?:\d{4}[\/\-]\d{1,2}[\/\-]\d{1,2})|(?:\w{3,9}\s\d{1,2},?\s\d{4})$/;
const ARABIC_REGEX = /[\u0600-\u06FF]/g;

/**
 * Aggressive splitting logic that handles both delimiters and inline type changes.
 */
function splitCellContent(val: any): string[] {
  if (val === null || val === undefined) return [];
  const str = String(val).replace(ARABIC_REGEX, '').trim();

  // 1. Initial split by standard delimiters
  const initialParts = str.split(/\r?\n|,|;|\|/).map(p => p.trim()).filter(p => p !== '');

  const finalParts: string[] = [];

  initialParts.forEach(part => {
    // 2. Scan part for distinct chunks of text and long numbers (IDs)
    // This handles cases where Name and ID are on the same line without a clear separator
    const tokens = part.split(/(\d{8,})/).map(t => t.trim()).filter(t => t !== '');

    tokens.forEach(token => {
      // If the token is a long number, it's definitely an ID/Number
      if (/^\d+$/.test(token)) {
        finalParts.push(token);
      } else {
        finalParts.push(token);
      }
    });
  });

  return finalParts.map(p => p.trim()).filter(p => p !== '');
}

/**
 * Removes Arabic characters from a string.
 */
function stripArabic(val: string): string {
  return val.replace(ARABIC_REGEX, '').trim();
}

/**
 * Helper to convert Excel serial dates (like 46053) to readable date strings
 */
function excelSerialToDate(serial: number): string {
  const date = new Date(Math.round((serial - 25569) * 86400 * 1000));
  return date.toLocaleDateString();
}

/**
 * Robust type inference
 */
function inferType(str: string): DataType {
  if (str === '') return DataType.UNKNOWN;

  // Try Date (Standard formats)
  if (DATE_REGEX.test(str)) return DataType.DATE;

  // Try Numeric (Long IDs or standard numbers)
  if (/^\d+$/.test(str)) {
    const num = Number(str);
    // Excel date range check
    if (num > 40000 && num < 60000) return DataType.DATE;
    return DataType.NUMBER;
  }

  // Try English Text (If it contains letters)
  if (/[a-zA-Z]/.test(str)) return DataType.TEXT_ENGLISH;

  return DataType.UNKNOWN;
}

