import { DataRow, DataType, ProcessedData } from '../types';

/**
 * Robust regex for various date formats: DD/MM/YYYY, YYYY-MM-DD, DD-MM-YYYY, etc.
 */
const DATE_REGEX_PATTERN = /\b(?:\d{1,2}[\/\-]\d{1,2}[\/\-]\d{2,4}|\d{4}[\/\-]\d{1,2}[\/\-]\d{1,2})\b/g;
const LONG_ID_PATTERN = /\b\d{8,}\b/g;
const ARABIC_REGEX = /[\u0600-\u06FF]/g;

/**
 * Intelligent splitting that extracts Dates, Long IDs, and Text parts from a single cell.
 */
function splitCellContent(val: any): string[] {
  if (val === null || val === undefined) return [];
  let str = String(val).replace(ARABIC_REGEX, '').trim();

  const results: string[] = [];

  // 1. Initial split by common line/cell delimiters
  const initialParts = str.split(/\r?\n|,|;|\|/).map(p => p.trim()).filter(p => p !== '');

  initialParts.forEach(part => {
    let tempPart = part;

    // 2. Extract specific date patterns first
    const dateMatches = tempPart.match(DATE_REGEX_PATTERN);
    if (dateMatches) {
      dateMatches.forEach(m => {
        results.push(m);
        tempPart = tempPart.replace(m, ' '); // Remove extracted date to avoid double-processing
      });
    }

    // 3. Extract long numeric IDs (8+ digits)
    const idMatches = tempPart.match(LONG_ID_PATTERN);
    if (idMatches) {
      idMatches.forEach(m => {
        results.push(m);
        tempPart = tempPart.replace(m, ' ');
      });
    }

    // 4. Treat remaining non-empty, primarily alphabetic strings as text
    const remaining = tempPart.trim().split(/\s{2,}/); // Split by multiple spaces
    remaining.forEach(r => {
      const clean = r.trim();
      if (clean && clean.length > 1) {
        results.push(clean);
      }
    });
  });

  return results;
}

/**
 * Standardizes date values to a clean DD/MM/YYYY format for professional alignment.
 */
function formatDateValue(val: any): string {
  let date: Date;

  if (typeof val === 'number') {
    // Handle Excel Serial Dates
    date = new Date(Math.round((val - 25569) * 86400 * 1000));
  } else {
    // Handle Date Strings - sanitize slashes/dashes
    const normalized = String(val).replace(/[\/\-]/g, '-');
    date = new Date(normalized);

    // Try fallback if primary constructor fails (e.g. DD-MM-YYYY)
    if (isNaN(date.getTime())) {
      const parts = normalized.split('-');
      if (parts.length === 3) {
        if (parts[0].length === 4) { // YYYY-MM-DD
          date = new Date(parseInt(parts[0]), parseInt(parts[1]) - 1, parseInt(parts[2]));
        } else { // DD-MM-YYYY
          date = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
        }
      }
    }
  }

  if (isNaN(date.getTime())) return String(val);

  const day = String(date.getDate()).padStart(2, '0');
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const year = date.getFullYear();

  return `${day}/${month}/${year}`;
}

/**
 * Infers data type for a specific string token.
 */
function inferType(str: string): DataType {
  if (str === '') return DataType.UNKNOWN;

  // Standard date pattern check
  if (/\b(?:\d{1,2}[\/\-]\d{1,2}[\/\-]\d{2,4}|\d{4}[\/\-]\d{1,2}[\/\-]\d{1,2})\b/.test(str)) {
    return DataType.DATE;
  }

  // Pure numeric check
  if (/^\d+$/.test(str)) {
    const num = Number(str);
    // Excel date range check
    if (num > 40000 && num < 60000) return DataType.DATE;
    return DataType.NUMBER;
  }

  // Text check
  if (/[a-zA-Z]/.test(str)) return DataType.TEXT_ENGLISH;

  return DataType.UNKNOWN;
}

/**
 * Aggregates fragmented spreadsheet rows into logical records.
 */
function preProcessMergeRows(rawRows: DataRow[]): DataRow[] {
  if (rawRows.length === 0) return [];

  const merged: DataRow[] = [];
  const headers = Object.keys(rawRows[0]);
  let currentRecord: DataRow | null = null;

  rawRows.forEach((row) => {
    const firstColVal = String(row[headers[0]] || '').trim();

    if (firstColVal !== "") {
      currentRecord = { ...row };
      merged.push(currentRecord);
    } else if (currentRecord) {
      headers.forEach(h => {
        const val = String(row[h] || '').trim();
        if (val !== "") {
          const existingVal = String(currentRecord![h] || '').trim();
          currentRecord![h] = existingVal ? `${existingVal}\n${val}` : val;
        }
      });
    } else {
      currentRecord = { ...row };
      merged.push(currentRecord);
    }
  });

  return merged;
}

export function harmonizeData(rawRows: DataRow[]): ProcessedData {
  if (rawRows.length === 0) return { headers: [], rows: [], originalHeaders: [] };

  const mergedRows = preProcessMergeRows(rawRows);
  const originalHeaders = Object.keys(mergedRows[0]);
  const splitMap: Record<string, Set<DataType>> = {};

  // 1. Identify all data types in each column for schema planning
  originalHeaders.forEach((header, index) => {
    const types = new Set<DataType>();
    if (index === 0) {
      types.add(DataType.TEXT_ENGLISH);
    } else {
      mergedRows.forEach(row => {
        const parts = splitCellContent(row[header]);
        parts.forEach(p => {
          const t = inferType(p);
          if (t !== DataType.UNKNOWN) types.add(t);
        });
      });
    }
    splitMap[header] = types;
  });

  // 2. Build the new horizontal column header list
  const finalHeadersList: string[] = [];
  const columnMapping: Record<string, string[]> = {};

  originalHeaders.forEach((header, index) => {
    const typesInCol = splitMap[header];

    if (index === 0 || typesInCol.size <= 1) {
      finalHeadersList.push(header);
      columnMapping[header] = [header];
    } else {
      const subHeaders: string[] = [];
      const preferredOrder = [DataType.TEXT_ENGLISH, DataType.NUMBER, DataType.DATE];

      preferredOrder.forEach(t => {
        if (typesInCol.has(t)) {
          const subHeader = `${header} (${t})`;
          subHeaders.push(subHeader);
          finalHeadersList.push(subHeader);
        }
      });
      columnMapping[header] = subHeaders;
    }
  });

  // 3. Map values to the newly structured columns
  const harmonizedRows = mergedRows.map(row => {
    const newRow: DataRow = {};

    originalHeaders.forEach((header, index) => {
      const subHeaders = columnMapping[header];
      const typesInCol = splitMap[header];

      if (index === 0 || typesInCol.size <= 1) {
        newRow[header] = String(row[header] || '').replace(ARABIC_REGEX, '').replace(/\n/g, ' ').trim();
      } else {
        subHeaders.forEach(sh => newRow[sh] = "");

        const parts = splitCellContent(row[header]);
        parts.forEach(p => {
          let type = inferType(p);
          let value = p;

          // Standardize date representation
          const isSerial = type === DataType.NUMBER && !isNaN(Number(p)) && typesInCol.has(DataType.DATE) && Number(p) > 40000 && Number(p) < 60000;
          if (type === DataType.DATE || isSerial) {
            value = formatDateValue(isSerial ? Number(p) : p);
            type = DataType.DATE;
          }

          const targetHeader = `${header} (${type})`;
          if (columnMapping[header].includes(targetHeader)) {
            newRow[targetHeader] = newRow[targetHeader] 
              ? `${newRow[targetHeader]}; ${value}` 
              : value;
          }
        });
      }
    });
    return newRow;
  });

  return {
    headers: finalHeadersList,
    rows: harmonizedRows,
    originalHeaders
  };
}

export function generatePivotData(rows: DataRow[], rowField: string, colField: string, valField: string, aggType: string) {
  const pivot: Record<string, Record<string, number>> = {};
  const allCols = new Set<string>();

  rows.forEach(row => {
    const rVal = String(row[rowField] || '(Blank)');
    const cVal = String(row[colField] || '(Blank)');
    const vVal = parseFloat(String(row[valField]).replace(/[^0-9.-]+/g, '')) || 0;

    allCols.add(cVal);
    if (!pivot[rVal]) pivot[rVal] = {};

    if (aggType === 'sum') {
      pivot[rVal][cVal] = (pivot[rVal][cVal] || 0) + vVal;
    } else if (aggType === 'count') {
      pivot[rVal][cVal] = (pivot[rVal][cVal] || 0) + 1;
    }
  });

  return {
    rows: Object.keys(pivot).map(key => ({ row: key, ...pivot[key] })),
    columns: Array.from(allCols).sort()
  };
}

import { DataRow, DataType, ProcessedData } from '../types';

/**
 * Regex to identify date-like strings precisely within tokens.
 */
const DATE_PATTERN = /^(?:\d{1,2}[\/\-]\d{1,2}[\/\-]\d{2,4})|(?:\d{4}[\/\-]\d{1,2}[\/\-]\d{1,2})$/;
const ARABIC_REGEX = /[\u0600-\u06FF]/g;

/**
 * Tokenizes cell content and classifies each piece.
 * This ensures we extract exactly what's there without "smearing" data across rows.
 */
function getTokens(val: any): string[] {
  if (val === null || val === undefined) return [];
  // Clean Arabic and normalize whitespace/delimiters
  const str = String(val).replace(ARABIC_REGEX, '').trim();
  if (!str) return [];

  // Split by newlines, commas, semicolons, or multiple spaces
  return str.split(/[\n,;]|\s{2,}/).map(t => t.trim()).filter(t => t !== '');
}

/**
 * Attempts to parse a string or number into a standardized DD/MM/YYYY date.
 * Returns null if the value is not a valid date.
 */
function parseToStandardDate(val: string): string | null {
  // 1. Try direct pattern match
  if (DATE_PATTERN.test(val)) {
    const parts = val.split(/[\/\-]/);
    let d, m, y;
    if (parts[0].length === 4) { // YYYY-MM-DD
      [y, m, d] = parts;
    } else { // DD-MM-YYYY
      [d, m, y] = parts;
    }
    const date = new Date(parseInt(y), parseInt(m) - 1, parseInt(d));
    if (!isNaN(date.getTime())) {
      return `${String(date.getDate()).padStart(2, '0')}/${String(date.getMonth() + 1).padStart(2, '0')}/${date.getFullYear()}`;
    }
  }

  // 2. Try Excel Serial Number (40000 to 60000 range: ~2009 to ~2064)
  const num = Number(val);
  if (!isNaN(num) && num > 40000 && num < 60000) {
    const date = new Date(Math.round((num - 25569) * 86400 * 1000));
    return `${String(date.getDate()).padStart(2, '0')}/${String(date.getMonth() + 1).padStart(2, '0')}/${date.getFullYear()}`;
  }

  return null;
}

/**
 * Determines the specific data type of a token.
 */
function getTokenType(token: string): DataType {
  if (parseToStandardDate(token)) return DataType.DATE;
  if (/^\d{8,}$/.test(token)) return DataType.NUMBER; // Long IDs
  if (/[a-zA-Z]/.test(token)) return DataType.TEXT_ENGLISH;
  if (/^\d+(\.\d+)?$/.test(token)) return DataType.NUMBER; // Regular numbers
  return DataType.UNKNOWN;
}

/**
 * Merges fragmented rows based on the existence of a primary key in the first column.
 */
function mergeRecords(rawRows: DataRow[]): DataRow[] {
  if (rawRows.length === 0) return [];
  const merged: DataRow[] = [];
  const headers = Object.keys(rawRows[0]);
  let current: DataRow | null = null;

  rawRows.forEach((row) => {
    const idVal = String(row[headers[0]] || '').trim();
    if (idVal !== "") {
      // New record starts
      current = { ...row };
      merged.push(current);
    } else if (current) {
      // Continuation of previous record
      headers.forEach(h => {
        const val = String(row[h] || '').trim();
        if (val) {
          const existing = String(current![h] || '').trim();
          current![h] = existing ? `${existing}\n${val}` : val;
        }
      });
    } else {
      // Edge case: first rows are empty IDs
      current = { ...row };
      merged.push(current);
    }
  });
  return merged;
}

export function harmonizeData(rawRows: DataRow[]): ProcessedData {
  if (rawRows.length === 0) return { headers: [], rows: [], originalHeaders: [] };

  const mergedRows = mergeRecords(rawRows);
  const originalHeaders = Object.keys(mergedRows[0]);

  // 1. Schema Mapping: Determine which columns need splitting
  const columnTypeMap: Record<string, Set<DataType>> = {};
  originalHeaders.forEach((header, index) => {
    const types = new Set<DataType>();
    if (index === 0) {
      types.add(DataType.TEXT_ENGLISH); // Passport always combined
    } else {
      mergedRows.forEach(row => {
        const tokens = getTokens(row[header]);
        tokens.forEach(t => types.add(getTokenType(t)));
      });
    }
    columnTypeMap[header] = types;
  });

  // 2. Build Header Structure
  const finalHeaders: string[] = [];
  const expansionMap: Record<string, string[]> = {};

  originalHeaders.forEach((header, index) => {
    const types = columnTypeMap[header];
    if (index === 0 || types.size <= 1) {
      finalHeaders.push(header);
      expansionMap[header] = [header];
    } else {
      const subs: string[] = [];
      // Logical order for columns: Text -> ID -> Date
      if (types.has(DataType.TEXT_ENGLISH)) subs.push(`${header} (Text)`);
      if (types.has(DataType.NUMBER)) subs.push(`${header} (Number)`);
      if (types.has(DataType.DATE)) subs.push(`${header} (Date)`);

      finalHeaders.push(...subs);
      expansionMap[header] = subs;
    }
  });

  // 3. Process and Map Rows
  const finalRows = mergedRows.map(row => {
    const newRow: DataRow = {};
    originalHeaders.forEach((header, index) => {
      const tokens = getTokens(row[header]);
      const targets = expansionMap[header];

      if (index === 0 || targets.length === 1) {
        // Direct map for unified columns (Passport, etc.)
        newRow[targets[0]] = tokens.join(' ');
      } else {
        // Distributed map for split columns
        targets.forEach(t => newRow[t] = ""); // Init

        tokens.forEach(token => {
          const type = getTokenType(token);
          let val = token;
          let subSuffix = "";

          if (type === DataType.DATE) {
            val = parseToStandardDate(token) || token;
            subSuffix = " (Date)";
          } else if (type === DataType.NUMBER) {
            subSuffix = " (Number)";
          } else if (type === DataType.TEXT_ENGLISH) {
            subSuffix = " (Text)";
          }

          const targetHeader = `${header}${subSuffix}`;
          if (targets.includes(targetHeader)) {
            const existing = String(newRow[targetHeader] || '');
            newRow[targetHeader] = existing ? `${existing}; ${val}` : val;
          }
        });
      }
    });
    return newRow;
  });

  return {
    headers: finalHeaders,
    rows: finalRows,
    originalHeaders
  };
}

export function generatePivotData(rows: DataRow[], rowField: string, colField: string, valField: string, aggType: string) {
  const pivot: Record<string, Record<string, number>> = {};
  const allCols = new Set<string>();

  rows.forEach(row => {
    const rVal = String(row[rowField] || '(Blank)');
    const cVal = String(row[colField] || '(Blank)');
    const vRaw = String(row[valField] || '0').replace(/[^0-9.-]+/g, '');
    const vVal = parseFloat(vRaw) || 0;

    allCols.add(cVal);
    if (!pivot[rVal]) pivot[rVal] = {};

    if (aggType === 'sum') {
      pivot[rVal][cVal] = (pivot[rVal][cVal] || 0) + vVal;
    } else {
      pivot[rVal][cVal] = (pivot[rVal][cVal] || 0) + 1;
    }
  });

  return {
    rows: Object.keys(pivot).map(key => ({ row: key, ...pivot[key] })),
    columns: Array.from(allCols).sort()
  };
}

