interface MetricCardProps {
  icon: React.ReactNode;
  title: string;
  value: number | string;
  color: string;
  sub: string;
  urgent?: boolean;
}

const MetricCard: React.FC<MetricCardProps> = ({ icon, title, value, color, sub, urgent }) => {
  const colorMap: Record<string, string> = {
    blue: 'bg-blue-50 border-blue-100',
    emerald: 'bg-emerald-50 border-emerald-100',
    rose: 'bg-rose-50 border-rose-100',
    amber: 'bg-amber-50 border-amber-100',
  };

  return (
    <div className={`p-6 rounded-[32px] border shadow-sm transition-all hover:shadow-md ${colorMap[color] || 'bg-slate-50 border-slate-100'} ${urgent ? 'ring-2 ring-rose-500/20' : ''}`}>
      <div className="flex items-center justify-between mb-4">
        <div className="bg-white p-3 rounded-2xl shadow-sm">
          {icon}
        </div>
        {urgent && <div className="w-2 h-2 rounded-full bg-rose-500 animate-ping"></div>}
      </div>
      <div>
        <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">{title}</h4>
        <div className="text-3xl font-black text-slate-800 tracking-tight">{value}</div>
        <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase">{sub}</p>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import * as XLSX from 'xlsx';
import { 
  FileUp, 
  Table, 
  LayoutGrid, 
  Sparkles, 
  Download, 
  Filter, 
  RefreshCw,
  Search,
  Database,
  BarChart3,
  FileText,
  PieChart,
  X
} from 'lucide-react';
import { DataRow, ProcessedData } from './types';
import { harmonizeData } from './utils/dataProcessor';
import { DataTable } from './components/DataTable';
import { PivotView } from './components/PivotView';
import { Dashboard } from './components/Dashboard';
import { generateDataSummary } from './services/gemini';

const App: React.FC = () => {
  const [processedData, setProcessedData] = useState<ProcessedData | null>(null);
  const [activeTab, setActiveTab] = useState<'preview' | 'pivot' | 'dashboard' | 'ai'>('preview');
  const [isProcessing, setIsProcessing] = useState(false);
  const [aiSummary, setAiSummary] = useState<string>('');
  const [searchTerm, setSearchTerm] = useState('');
  const [isGeneratingAi, setIsGeneratingAi] = useState(false);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const data = XLSX.utils.sheet_to_json(ws) as DataRow[];
        const harmonized = harmonizeData(data);
        setProcessedData(harmonized);
        setActiveTab('dashboard'); // Default to dashboard on load for impact
      } catch (err) {
        console.error("Error reading file", err);
        alert("Failed to read file. Please ensure it is a valid Excel or CSV.");
      } finally {
        setIsProcessing(false);
      }
    };
    reader.readAsBinaryString(file);
  };

  const filteredRows = useMemo(() => {
    if (!processedData) return [];
    if (!searchTerm) return processedData.rows;
    const lowerSearch = searchTerm.toLowerCase();
    return processedData.rows.filter(row => 
      Object.values(row).some(val => String(val).toLowerCase().includes(lowerSearch))
    );
  }, [processedData, searchTerm]);

  const handleExport = () => {
    if (!processedData) return;
    const worksheet = XLSX.utils.json_to_sheet(processedData.rows);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "HarmonizedData");
    XLSX.writeFile(workbook, `Harmonized_Data_${new Date().getTime()}.xlsx`);
  };

  const generateAiWriteup = async () => {
    if (!processedData) return;
    setIsGeneratingAi(true);
    const summary = await generateDataSummary(processedData.rows);
    setAiSummary(summary);
    setIsGeneratingAi(false);
  };

  return (
    <div className="min-h-screen flex flex-col font-sans bg-slate-50/50">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 px-8 py-4 flex items-center justify-between sticky top-0 z-50 shadow-sm">
        <div className="flex items-center gap-3">
          <div className="bg-gradient-to-br from-indigo-600 to-indigo-800 p-2.5 rounded-xl text-white shadow-lg shadow-indigo-200">
            <Database size={24} />
          </div>
          <div>
            <h1 className="text-xl font-extrabold text-slate-800 tracking-tight leading-none">DataHarmonizer Pro</h1>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Advanced Pattern Orchestrator</p>
          </div>
        </div>

        {processedData && (
          <div className="flex items-center gap-4">
            <div className="relative group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-indigo-500 transition-colors" size={16} />
              <input 
                type="text" 
                placeholder="Deep query records..." 
                className="pl-10 pr-10 py-2.5 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all w-72 bg-slate-50 shadow-inner"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
              {searchTerm && (
                <button 
                  onClick={() => setSearchTerm('')}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600 p-1"
                >
                  <X size={14} />
                </button>
              )}
            </div>
            <button 
              onClick={handleExport}
              className="flex items-center gap-2 bg-slate-900 hover:bg-black text-white px-6 py-2.5 rounded-xl text-sm font-bold transition-all shadow-lg active:scale-95"
            >
              <Download size={18} /> Export Master
            </button>
