interface MetricCardProps {
  icon: React.ReactNode;
  title: string;
  value: number | string;
  color: string;
  sub: string;
  urgent?: boolean;
  onClick?: () => void;
}

const MetricCard: React.FC<MetricCardProps> = ({ icon, title, value, color, sub, urgent, onClick }) => {
  const colorMap: Record<string, string> = {
    blue: 'bg-blue-50 border-blue-100 hover:border-blue-300',
    emerald: 'bg-emerald-50 border-emerald-100 hover:border-emerald-300',
    rose: 'bg-rose-50 border-rose-100 hover:border-rose-300',
    amber: 'bg-amber-50 border-amber-100 hover:border-amber-300',
  };

  return (
    <div 
      onClick={onClick}
      className={`p-6 rounded-[32px] border shadow-sm transition-all hover:shadow-xl hover:-translate-y-1 cursor-pointer group ${colorMap[color] || 'bg-slate-50 border-slate-100'} ${urgent ? 'ring-2 ring-rose-500/20' : ''}`}
    >
      <div className="flex items-center justify-between mb-4">
        <div className="bg-white p-3 rounded-2xl shadow-sm group-hover:scale-110 transition-transform">
          {icon}
        </div>
        {urgent && <div className="w-2 h-2 rounded-full bg-rose-500 animate-ping"></div>}
      </div>
      <div>
        <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1 group-hover:text-slate-800">{title}</h4>
        <div className="text-3xl font-black text-slate-800 tracking-tight">{value}</div>
        <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase">{sub}</p>
      </div>
    </div>
  );
};

import React, { useMemo, useState } from 'react';
import { 
  Users, 
  CreditCard, 
  AlertCircle, 
  Calendar, 
  Globe, 
  TrendingUp, 
  ChevronRight,
  ShieldAlert,
  ArrowRight,
  SortAsc,
  SortDesc,
  ExternalLink
} from 'lucide-react';
import { DataRow } from '../types';
import { extractDashboardMetrics } from '../utils/dataProcessor';

interface DashboardProps {
  rows: DataRow[];
  onDrillDown: (title: string, filteredRows: DataRow[]) => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ rows, onDrillDown }) => {
  const metrics = useMemo(() => extractDashboardMetrics(rows), [rows]);
  const [escapeSortDesc, setEscapeSortDesc] = useState(true);

  // Helper to parse DD/MM/YYYY into a sortable number
  const getSortableDate = (row: DataRow) => {
    const dateKey = Object.keys(row).find(k => k.includes('(Date)'));
    if (!dateKey) return 0;
    const dateStr = String(row[dateKey]).split(';')[0].trim();
    const parts = dateStr.split('/');
    if (parts.length !== 3) return 0;
    return new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0])).getTime();
  };

  const sortedEscapeRecords = useMemo(() => {
    return [...metrics.escapeRecords].sort((a, b) => {
      const timeA = getSortableDate(a);
      const timeB = getSortableDate(b);
      return escapeSortDesc ? timeB - timeA : timeA - timeB;
    });
  }, [metrics.escapeRecords, escapeSortDesc]);

  const handleMetricClick = (title: string, type: 'total' | 'active' | 'expired' | 'upcoming') => {
    let filtered = rows;
    if (type === 'active') {
      filtered = rows.filter(r => {
        const dateKey = Object.keys(r).find(k => k.includes('(Date)'));
        if (!dateKey) return true;
        const parts = String(r[dateKey]).split(';')[0].trim().split('/');
        const d = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
        return !isNaN(d.getTime()) && d >= new Date();
      });
    } else if (type === 'expired') {
      filtered = sortedEscapeRecords;
    } else if (type === 'upcoming') {
      const today = new Date();
      filtered = rows.filter(r => {
        const dateKey = Object.keys(r).find(k => k.includes('(Date)'));
        if (!dateKey) return false;
        const parts = String(r[dateKey]).split(';')[0].trim().split('/');
        const d = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
        const diff = Math.ceil((d.getTime() - today.getTime()) / (1000 * 3600 * 24));
        return diff > 0 && diff <= 30;
      });
    }
    onDrillDown(title, filtered);
  };

  const handleNationalityClick = (nat: string) => {
    const natKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase().includes('nationality'));
    const filtered = rows.filter(r => natKey && String(r[natKey]).trim() === nat);
    onDrillDown(`Nationality: ${nat}`, filtered);
  };

  const handleStatusClick = (status: string) => {
    const statusKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase().includes('status') || k.toLowerCase().includes('card type'));
    const filtered = rows.filter(r => statusKey && String(r[statusKey]).trim() === status);
    onDrillDown(`Status: ${status}`, filtered);
  };

  const handleMonthClick = (monthLabel: string) => {
    const monthNames = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
    const filtered = rows.filter(r => {
      const dateKey = Object.keys(r).find(k => k.includes('(Date)'));
      if (!dateKey) return false;
      const parts = String(r[dateKey]).split(';')[0].trim().split('/');
      const d = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
      if (isNaN(d.getTime())) return false;
      const label = monthNames[d.getMonth()] + ' ' + d.getFullYear();
      return label === monthLabel;
    });
    onDrillDown(`Renewals: ${monthLabel}`, filtered);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Top Level Metric Cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <MetricCard 
          icon={<Users className="text-blue-600" />} 
          title="Total Workforce" 
          value={metrics.total} 
          color="blue" 
          sub="Synchronized records"
          onClick={() => handleMetricClick("Full Workforce List", 'total')}
        />
        <MetricCard 
          icon={<CreditCard className="text-emerald-600" />} 
          title="Active Cards" 
          value={metrics.activeCount} 
          color="emerald" 
          sub="Valid status tokens"
          onClick={() => handleMetricClick("Active Records", 'active')}
        />
        <MetricCard 
          icon={<ShieldAlert className="text-rose-600" />} 
          title="Expired/Escape" 
          value={metrics.expiredCount} 
          color="rose" 
          sub="Immediate action required"
          urgent={metrics.expiredCount > 0}
          onClick={() => handleMetricClick("Escape Report Detail", 'expired')}
        />
        <MetricCard 
          icon={<Calendar className="text-amber-600" />} 
          title="30-Day Renewals" 
          value={metrics.upcomingRenewals} 
          color="amber" 
          sub="Expiring this month"
          onClick={() => handleMetricClick("Upcoming Renewals List", 'upcoming')}
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Nationality Distribution */}
        <div className="bg-white p-6 rounded-[32px] border border-slate-200 shadow-sm col-span-1">
          <div className="flex items-center justify-between mb-6">
            <h3 className="font-black text-slate-800 flex items-center gap-2">
              <Globe size={20} className="text-indigo-600" />
              Nationality Vector
            </h3>
          </div>
          <div className="space-y-4">
            {Object.entries(metrics.nationalityData)
              .sort((a, b) => (b[1] as number) - (a[1] as number))
              .slice(0, 5)
              .map(([nat, count]) => (
                <div 
                  key={nat} 
                  className="space-y-1.5 cursor-pointer group"
                  onClick={() => handleNationalityClick(nat)}
                >
                  <div className="flex justify-between text-xs font-bold uppercase">
                    <span className="text-slate-500 group-hover:text-indigo-600 transition-colors">{nat}</span>
                    <span className="text-slate-800">{count}</span>
                  </div>
                  <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden">
                    <div 
                      className="h-full bg-indigo-500 group-hover:bg-indigo-600 rounded-full transition-all duration-1000" 
                      style={{ width: `${((count as number) / metrics.total) * 100}%` }}
                    ></div>
                  </div>
                </div>
              ))}
          </div>
        </div>

        {/* Card Status / Type Chart with Interactive Detail Tooltips */}
        <div className="bg-white p-6 rounded-[32px] border border-slate-200 shadow-sm col-span-1">
          <div className="flex items-center justify-between mb-6">
            <h3 className="font-black text-slate-800 flex items-center gap-2">
              <TrendingUp size={20} className="text-emerald-600" />
              Status Distribution
            </h3>
          </div>
          <div className="flex flex-col items-center justify-center h-48 relative">
            <div className="flex gap-4 items-end h-32 w-full px-4">
              {Object.entries(metrics.statusData).map(([status, count]) => (
                <div 
                  key={status} 
