                    <div className="bg-slate-900 text-white p-3.5 rounded-[20px] shadow-2xl border border-white/10 ring-4 ring-black/5">
                      <div className="text-[10px] font-black uppercase tracking-tighter text-emerald-400 mb-1 leading-tight break-words">
                        {status}
