                <th className="px-6 py-4 text-slate-300 font-black uppercase text-[10px] tracking-wider border-b border-white/10 text-center">Status Tag</th>
                <th className="px-6 py-4 text-slate-300 font-black uppercase text-[10px] tracking-wider border-b border-white/10">Action Required</th>
              </tr>
            </thead>
            <tbody>
              {sortedEscapeRecords.slice(0, 5).map((rec, i) => {
                const dateKey = Object.keys(rec).find(k => k.includes('(Date)'));
                const dateVal = dateKey ? String(rec[dateKey]).split(';')[0].trim() : 'N/A';
                return (
                  <tr key={i} className="hover:bg-white/10 transition-colors">
                    <td className="px-6 py-4 text-white font-bold border-b border-white/5">
                      {Object.values(rec)[0]}
                    </td>
                    <td className="px-6 py-4 text-slate-300 font-medium border-b border-white/5 text-center font-mono text-xs">
                      {dateVal}
                    </td>
                    <td className="px-6 py-4 border-b border-white/5 text-center">
                      <span className="bg-rose-500/20 text-rose-400 border border-rose-500/40 px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest">
                        CRITICAL EXPIRE
                      </span>
                    </td>
                    <td className="px-6 py-4 text-slate-400 text-xs border-b border-white/5">
                      Renew Document Immediately
                    </td>
                  </tr>
                );
              })}
              {metrics.escapeRecords.length === 0 && (
                <tr>
                  <td colSpan={4} className="px-6 py-12 text-center text-slate-500 italic font-medium">
                    Excellent compliance score. No escape records detected.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
          {metrics.escapeRecords.length > 0 && (
            <div className="p-4 text-center bg-white/5 border-t border-white/10">
              <button 
                onClick={() => handleMetricClick("Full Escape List", 'expired')}
                className="text-indigo-400 hover:text-white hover:bg-indigo-600 px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest flex items-center justify-center gap-2 mx-auto transition-all"
              >
                Inspect All {metrics.expiredCount} Exceptions <ChevronRight size={14} />
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

