import React, { useMemo, useState } from 'react';
import { 
  Users, 
  CreditCard, 
  AlertCircle, 
  Calendar, 
  Globe, 
  TrendingUp, 
  ChevronRight,
  ShieldAlert,
  ArrowRight,
  SortAsc,
  SortDesc,
  ExternalLink
} from 'lucide-react';
import { DataRow } from '../types';
import { extractDashboardMetrics } from '../utils/dataProcessor';

interface DashboardProps {
  rows: DataRow[];
  onDrillDown: (title: string, filteredRows: DataRow[]) => void;
}

const RAINBOW_COLORS = [
  '#FF595E', // Red
  '#FF924C', // Orange
  '#FFCA3A', // Yellow
  '#C5CA30', // Lime
  '#8AC926', // Green
  '#36949D', // Teal
  '#1982C4', // Blue
  '#4267AC', // Indigo
  '#6A4C93', // Purple
  '#B5179E', // Magenta
];

export const Dashboard: React.FC<DashboardProps> = ({ rows, onDrillDown }) => {
  const metrics = useMemo(() => extractDashboardMetrics(rows), [rows]);
  const [escapeSortDesc, setEscapeSortDesc] = useState(true);

  // Helper to parse DD/MM/YYYY into a sortable number
  const getSortableDate = (row: DataRow) => {
    const dateKey = Object.keys(row).find(k => k.includes('(Date)'));
    if (!dateKey) return 0;
    const dateStr = String(row[dateKey]).split(';')[0].trim();
    const parts = dateStr.split('/');
    if (parts.length !== 3) return 0;
    return new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0])).getTime();
  };

  const sortedEscapeRecords = useMemo(() => {
    return [...metrics.escapeRecords].sort((a, b) => {
      const timeA = getSortableDate(a);
      const timeB = getSortableDate(b);
      return escapeSortDesc ? timeB - timeA : timeA - timeB;
    });
  }, [metrics.escapeRecords, escapeSortDesc]);

  const handleMetricClick = (title: string, type: 'total' | 'active' | 'expired' | 'upcoming') => {
    let filtered = rows;
    if (type === 'active') {
      filtered = rows.filter(r => {
        const dateKey = Object.keys(r).find(k => k.includes('(Date)'));
        if (!dateKey) return true;
        const parts = String(r[dateKey]).split(';')[0].trim().split('/');
        const d = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
        return !isNaN(d.getTime()) && d >= new Date();
      });
    } else if (type === 'expired') {
      filtered = sortedEscapeRecords;
    } else if (type === 'upcoming') {
      const today = new Date();
      filtered = rows.filter(r => {
        const dateKey = Object.keys(r).find(k => k.includes('(Date)'));
        if (!dateKey) return false;
        const parts = String(r[dateKey]).split(';')[0].trim().split('/');
        const d = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
        const diff = Math.ceil((d.getTime() - today.getTime()) / (1000 * 3600 * 24));
        return diff > 0 && diff <= 30;
      });
    }
    onDrillDown(title, filtered);
  };

  const handleNationalityClick = (nat: string) => {
    const natKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase().includes('nationality'));
    const filtered = rows.filter(r => natKey && String(r[natKey]).trim() === nat);
    onDrillDown(`Nationality: ${nat}`, filtered);
  };

  const handleStatusClick = (status: string) => {
    const statusKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase().includes('status') || k.toLowerCase().includes('card type'));
    const filtered = rows.filter(r => statusKey && String(r[statusKey]).trim() === status);
    onDrillDown(`Status: ${status}`, filtered);
  };

  const handleMonthClick = (monthLabel: string) => {
    const monthNames = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
    const filtered = rows.filter(r => {
      const dateKey = Object.keys(r).find(k => k.includes('(Date)'));
      if (!dateKey) return false;
      const parts = String(r[dateKey]).split(';')[0].trim().split('/');
      const d = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
      if (isNaN(d.getTime())) return false;
      const label = monthNames[d.getMonth()] + ' ' + d.getFullYear();
      return label === monthLabel;
    });
    onDrillDown(`Renewals: ${monthLabel}`, filtered);
  };

  // Pie Chart Logic
  const pieSlices = useMemo(() => {
    const entries = Object.entries(metrics.statusData);
    const total = entries.reduce((acc, [_, count]) => acc + (count as number), 0);
    let cumulativePercent = 0;

    return entries.map(([status, count], index) => {
      const percent = (count as number) / total;
      const startX = Math.cos(2 * Math.PI * cumulativePercent);
      const startY = Math.sin(2 * Math.PI * cumulativePercent);
      cumulativePercent += percent;
      const endX = Math.cos(2 * Math.PI * cumulativePercent);
      const endY = Math.sin(2 * Math.PI * cumulativePercent);

      const largeArcFlag = percent > 0.5 ? 1 : 0;
      const pathData = [
        `M ${startX} ${startY}`,
        `A 1 1 0 ${largeArcFlag} 1 ${endX} ${endY}`,
        `L 0 0`,
      ].join(' ');

      // Calculate label position (center of the slice)
      const midAngle = 2 * Math.PI * (cumulativePercent - percent / 2);
      const labelX = Math.cos(midAngle) * 0.7;
      const labelY = Math.sin(midAngle) * 0.7;

      return {
        status,
        count: count as number,
        pathData,
        color: RAINBOW_COLORS[index % RAINBOW_COLORS.length],
        labelX,
        labelY,
        percent: (percent * 100).toFixed(1)
      };
    });
  }, [metrics.statusData]);

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Top Level Metric Cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <MetricCard 
          icon={<Users className="text-blue-600" />} 
          title="Total Workforce" 
          value={metrics.total} 
          color="blue" 
          sub="Synchronized records"
          onClick={() => handleMetricClick("Full Workforce List", 'total')}
        />
        <MetricCard 
          icon={<CreditCard className="text-emerald-600" />} 
          title="Active Cards" 
          value={metrics.activeCount} 
          color="emerald" 
          sub="Valid status tokens"
          onClick={() => handleMetricClick("Active Records", 'active')}
        />
        <MetricCard 
          icon={<ShieldAlert className="text-rose-600" />} 
          title="Expired/Escape" 
          value={metrics.expiredCount} 
          color="rose" 
          sub="Immediate action required"
          urgent={metrics.expiredCount > 0}
          onClick={() => handleMetricClick("Escape Report Detail", 'expired')}
        />
        <MetricCard 
          icon={<Calendar className="text-amber-600" />} 
          title="30-Day Renewals" 
          value={metrics.upcomingRenewals} 
          color="amber" 
          sub="Expiring this month"
          onClick={() => handleMetricClick("Upcoming Renewals List", 'upcoming')}
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Nationality Distribution */}
        <div className="bg-white p-6 rounded-[32px] border border-slate-200 shadow-sm col-span-1">
          <div className="flex items-center justify-between mb-6">
            <h3 className="font-black text-slate-800 flex items-center gap-2">
              <Globe size={20} className="text-indigo-600" />
              Nationality Vector
            </h3>
          </div>
          <div className="space-y-4">
            {Object.entries(metrics.nationalityData)
              .sort((a, b) => (b[1] as number) - (a[1] as number))
              .slice(0, 5)
              .map(([nat, count]) => (
                <div 
                  key={nat} 
                  className="space-y-1.5 cursor-pointer group"
                  onClick={() => handleNationalityClick(nat)}
                >
                  <div className="flex justify-between text-xs font-bold uppercase">
                    <span className="text-slate-500 group-hover:text-indigo-600 transition-colors">{nat}</span>
                    <span className="text-slate-800">{count}</span>
                  </div>
                  <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden">
                    <div 
                      className="h-full bg-indigo-500 group-hover:bg-indigo-600 rounded-full transition-all duration-1000" 
                      style={{ width: `${((count as number) / metrics.total) * 100}%` }}
                    ></div>
                  </div>
                </div>
              ))}
          </div>
        </div>

        {/* Status Distribution - Pie Diagram with Rainbow Colors */}
        <div className="bg-white p-6 rounded-[32px] border border-slate-200 shadow-sm col-span-1 flex flex-col">
          <div className="flex items-center justify-between mb-2">
            <h3 className="font-black text-slate-800 flex items-center gap-2">
              <TrendingUp size={20} className="text-emerald-600" />
              Status Distribution
            </h3>
          </div>

          <div className="flex-1 flex flex-col items-center justify-center min-h-[220px] relative">
            {pieSlices.length > 0 ? (
              <div className="w-full h-full max-w-[200px] aspect-square relative group">
                <svg viewBox="-1.1 -1.1 2.2 2.2" className="w-full h-full -rotate-90">
                  {pieSlices.map((slice, i) => (
                    <g key={slice.status} className="group/slice cursor-pointer" onClick={() => handleStatusClick(slice.status)}>
                      {/* Slice Path */}
                      <path
                        d={slice.pathData}
                        fill={slice.color}
                        className="transition-all duration-300 hover:scale-[1.05] origin-center hover:brightness-110"
                      />

                      {/* Number Overlay on Slice */}
                      {slice.percent > 5 && (
                        <text
                          x={slice.labelX}
                          y={slice.labelY}
                          textAnchor="middle"
                          dominantBaseline="middle"
                          fill="white"
                          className="text-[0.12px] font-black pointer-events-none drop-shadow-sm rotate-90"
                        >
                          {slice.count}
                        </text>
                      )}

                      {/* Tooltip implementation for individual slices */}
                      <foreignObject x="-1.1" y="-1.1" width="2.2" height="2.2" className="pointer-events-none opacity-0 group-hover/slice:opacity-100 transition-opacity duration-200">
                         <div className="flex items-center justify-center h-full w-full">
                            <div className="bg-slate-900 text-white p-3 rounded-2xl shadow-2xl border border-white/10 w-40 pointer-events-auto scale-[0.3]">
                               <div className="text-[14px] font-black uppercase tracking-tighter text-emerald-400 mb-1 leading-tight break-words">
                                  {slice.status}
                               </div>
                               <div className="flex justify-between items-center pt-2 border-t border-white/10 mt-2">
                                  <span className="text-[12px] font-bold text-slate-400 uppercase">Count</span>
                                  <span className="text-[14px] font-black text-white">{slice.count}</span>
                               </div>
                               <div className="flex items-center gap-2 mt-3 text-[10px] font-black text-indigo-300 uppercase animate-pulse">
                                  <ExternalLink size={14} /> Click to Inspect Group
                               </div>
                            </div>
                         </div>
                      </foreignObject>
                    </g>
                  ))}
                  {/* Center Hole for Donut Style (Optional, but looks cleaner) */}
                  <circle cx="0" cy="0" r="0.4" fill="white" />
                </svg>

                {/* Short Legend Below */}
                <div className="absolute -bottom-6 left-0 right-0 flex flex-wrap justify-center gap-2">
                   {pieSlices.slice(0, 4).map(s => (
                     <div key={s.status} className="flex items-center gap-1">
                        <div className="w-2 h-2 rounded-full" style={{ backgroundColor: s.color }}></div>
                        <span className="text-[9px] font-black text-slate-400 uppercase truncate max-w-[50px]">
                          {s.status.length > 6 ? s.status.substring(0, 5) + '..' : s.status}
                        </span>
                     </div>
                   ))}
                </div>
              </div>
            ) : (
              <p className="text-[10px] text-slate-400 font-bold uppercase">No status data detected</p>
            )}
          </div>
        </div>

        {/* Monthly Renewal Basis */}
        <div className="bg-white p-6 rounded-[32px] border border-slate-200 shadow-sm col-span-1">
          <div className="flex items-center justify-between mb-6">
            <h3 className="font-black text-slate-800 flex items-center gap-2">
              <Calendar size={20} className="text-amber-600" />
              Renewal Pipeline
            </h3>
          </div>
          <div className="space-y-3 max-h-52 overflow-auto custom-scrollbar pr-2">
            {Object.entries(metrics.monthlyRenewals)
              .sort((a, b) => {
                const dateA = new Date(a[0]);
                const dateB = new Date(b[0]);
                return dateA.getTime() - dateB.getTime();
              })
              .map(([month, count]) => (
                <div 
                  key={month} 
                  onClick={() => handleMonthClick(month)}
                  className="flex items-center gap-3 p-3 bg-slate-50 rounded-2xl hover:bg-indigo-50 hover:border-indigo-200 border border-transparent transition-all cursor-pointer group"
                >
                  <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center text-indigo-600 shadow-sm group-hover:scale-110 transition-transform">
                    <Calendar size={18} />
                  </div>
                  <div className="flex-1">
                    <div className="text-xs font-black text-slate-800 uppercase group-hover:text-indigo-600">{month}</div>
                    <div className="text-[10px] font-bold text-slate-400">{count} Renewals</div>
                  </div>
                  <ArrowRight size={14} className="text-slate-300 group-hover:text-indigo-400 group-hover:translate-x-1 transition-all" />
                </div>
              ))}
          </div>
        </div>
      </div>

      {/* The Escape Report Section */}
      <div className="bg-slate-900 rounded-[40px] p-8 shadow-2xl relative overflow-hidden group">
        <div className="absolute top-0 right-0 w-96 h-96 bg-indigo-500/10 rounded-full blur-3xl -mr-48 -mt-48 pointer-events-none"></div>
        <div className="flex items-center justify-between mb-8 relative">
          <div>
            <h3 className="text-2xl font-black text-white flex items-center gap-3">
              <AlertCircle size={28} className="text-rose-500 animate-pulse" />
              The Escape Report
            </h3>
            <p className="text-slate-400 font-bold uppercase tracking-widest text-[10px] mt-1">
              Critical Exceptions Tracking List
            </p>
          </div>
          <div className="flex flex-col items-end gap-2">
            <div className="bg-rose-500 text-white px-5 py-2 rounded-2xl text-sm font-black border border-rose-400 shadow-lg shadow-rose-900/40">
              {metrics.expiredCount} PERSONS ESCAPED
            </div>
            <p className="text-[10px] text-slate-500 font-bold uppercase">Total Non-Compliance Count</p>
          </div>
        </div>

        <div className="bg-white/5 rounded-2xl overflow-hidden border border-white/10">
          <table className="w-full text-sm text-left border-collapse">
            <thead className="bg-white/5">
              <tr>
                <th className="px-6 py-4 text-slate-300 font-black uppercase text-[10px] tracking-wider border-b border-white/10">Employee Primary Identity</th>
                <th className="px-6 py-4 text-slate-300 font-black uppercase text-[10px] tracking-wider border-b border-white/10 text-center">
                  <div className="flex items-center justify-center gap-2">
                    Expiry Date
                    <button 
                      onClick={() => setEscapeSortDesc(!escapeSortDesc)}
                      className="p-1 hover:bg-white/10 rounded-md transition-colors text-indigo-400"
                      title="Toggle Sort by Expiry Date"
                    >
                      {escapeSortDesc ? <SortDesc size={14} /> : <SortAsc size={14} />}
                    </button>
                  </div>
                </th>
                <th className="px-6 py-4 text-slate-300 font-black uppercase text-[10px] tracking-wider border-b border-white/10 text-center">Status Tag</th>
                <th className="px-6 py-4 text-slate-300 font-black uppercase text-[10px] tracking-wider border-b border-white/10">Action Required</th>
              </tr>
            </thead>
            <tbody>
              {sortedEscapeRecords.slice(0, 5).map((rec, i) => {
                const dateKey = Object.keys(rec).find(k => k.includes('(Date)'));
                const dateVal = dateKey ? String(rec[dateKey]).split(';')[0].trim() : 'N/A';
                return (
                  <tr key={i} className="hover:bg-white/10 transition-colors">
                    <td className="px-6 py-4 text-white font-bold border-b border-white/5">
                      {Object.values(rec)[0]}
                    </td>
                    <td className="px-6 py-4 text-slate-300 font-medium border-b border-white/5 text-center font-mono text-xs">
                      {dateVal}
                    </td>
                    <td className="px-6 py-4 border-b border-white/5 text-center">
                      <span className="bg-rose-500/20 text-rose-400 border border-rose-500/40 px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest">
                        CRITICAL EXPIRE
                      </span>
                    </td>
                    <td className="px-6 py-4 text-slate-400 text-xs border-b border-white/5">
                      Renew Document Immediately
                    </td>
                  </tr>
                );
              })}
              {metrics.escapeRecords.length === 0 && (
                <tr>
                  <td colSpan={4} className="px-6 py-12 text-center text-slate-500 italic font-medium">
                    Excellent compliance score. No escape records detected.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
          {metrics.escapeRecords.length > 0 && (
            <div className="p-4 text-center bg-white/5 border-t border-white/10">
              <button 
                onClick={() => handleMetricClick("Full Escape List", 'expired')}
                className="text-indigo-400 hover:text-white hover:bg-indigo-600 px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest flex items-center justify-center gap-2 mx-auto transition-all"
              >
                Inspect All {metrics.expiredCount} Exceptions <ChevronRight size={14} />
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

