export type DataRow = Record<string, any>;

export interface ProcessedData {
  headers: string[];
  rows: DataRow[];
  originalHeaders: string[];
}

export enum DataType {
  NUMBER = 'Number',
  TEXT_ENGLISH = 'Text (English)',
  DATE = 'Date',
  UNKNOWN = 'Unknown'
}

export interface PivotConfig {
  rowField: string;
  columnField: string;
  valueField: string;
  aggType: 'sum' | 'count' | 'avg';
}

export interface DashboardMetrics {
  total: number;
  expiredCount: number;
  activeCount: number;
  upcomingRenewals: number;
  nationalityData: Record<string, number>;
  nationalityEscapeData: Record<string, number>; // New tracking field
  statusData: Record<string, number>;
  monthlyRenewals: Record<string, number>;
  escapeRecords: DataRow[];
}

export interface FilterConfig {
  column: string;
  value: string;
  operator: 'equals' | 'contains' | 'greaterThan' | 'lessThan';
}

import { DataRow, DataType, ProcessedData, DashboardMetrics } from '../types';

/**
 * Regex to identify date-like strings precisely within tokens.
 */
const DATE_PATTERN = /^(?:\d{1,2}[\/\-]\d{1,2}[\/\-]\d{2,4})|(?:\d{4}[\/\-]\d{1,2}[\/\-]\d{1,2})$/;
const ARABIC_REGEX = /[\u0600-\u06FF]/g;

function getTokens(val: any): string[] {
  if (val === null || val === undefined) return [];
  const str = String(val).replace(ARABIC_REGEX, '').trim();
  if (!str) return [];
  return str.split(/[\n,;]|\s{2,}/).map(t => t.trim()).filter(t => t !== '');
}

function parseToStandardDate(val: string): string | null {
  if (DATE_PATTERN.test(val)) {
    const parts = val.split(/[\/\-]/);
    let d, m, y;
    if (parts[0].length === 4) { [y, m, d] = parts; } 
    else { [d, m, y] = parts; }
    const date = new Date(parseInt(y), parseInt(m) - 1, parseInt(d));
    if (!isNaN(date.getTime())) {
      return `${String(date.getDate()).padStart(2, '0')}/${String(date.getMonth() + 1).padStart(2, '0')}/${date.getFullYear()}`;
    }
  }
  const num = Number(val);
  if (!isNaN(num) && num > 40000 && num < 60000) {
    const date = new Date(Math.round((num - 25569) * 86400 * 1000));
    return `${String(date.getDate()).padStart(2, '0')}/${String(date.getMonth() + 1).padStart(2, '0')}/${date.getFullYear()}`;
  }
  return null;
}

function getTokenType(token: string): DataType {
  if (parseToStandardDate(token)) return DataType.DATE;
  if (/^\d{8,}$/.test(token)) return DataType.NUMBER;
  if (/[a-zA-Z]/.test(token)) return DataType.TEXT_ENGLISH;
  if (/^\d+(\.\d+)?$/.test(token)) return DataType.NUMBER;
  return DataType.UNKNOWN;
}

function mergeRecords(rawRows: DataRow[]): DataRow[] {
  if (rawRows.length === 0) return [];
  const merged: DataRow[] = [];
  const headers = Object.keys(rawRows[0]);
  let current: DataRow | null = null;
  rawRows.forEach((row) => {
    const idVal = String(row[headers[0]] || '').trim();
    if (idVal !== "") {
      current = { ...row };
      merged.push(current);
    } else if (current) {
      headers.forEach(h => {
        const val = String(row[h] || '').trim();
        if (val) {
          const existing = String(current![h] || '').trim();
          current![h] = existing ? `${existing}\n${val}` : val;
        }
      });
    } else {
      current = { ...row };
      merged.push(current);
    }
  });
  return merged;
}

export function harmonizeData(rawRows: DataRow[]): ProcessedData {
  if (rawRows.length === 0) return { headers: [], rows: [], originalHeaders: [] };
  const mergedRows = mergeRecords(rawRows);
  const originalHeaders = Object.keys(mergedRows[0]);
  const columnTypeMap: Record<string, Set<DataType>> = {};
  originalHeaders.forEach((header, index) => {
    const types = new Set<DataType>();
    if (index === 0) { types.add(DataType.TEXT_ENGLISH); } 
    else {
      mergedRows.forEach(row => {
        const tokens = getTokens(row[header]);
        tokens.forEach(t => types.add(getTokenType(t)));
      });
    }
    columnTypeMap[header] = types;
  });
  const finalHeaders: string[] = [];
  const expansionMap: Record<string, string[]> = {};
  originalHeaders.forEach((header, index) => {
    const types = columnTypeMap[header];
    if (index === 0 || types.size <= 1) {
      finalHeaders.push(header);
      expansionMap[header] = [header];
    } else {
      const subs: string[] = [];
      if (types.has(DataType.TEXT_ENGLISH)) subs.push(`${header} (Text)`);
      if (types.has(DataType.NUMBER)) subs.push(`${header} (Number)`);
      if (types.has(DataType.DATE)) subs.push(`${header} (Date)`);
      finalHeaders.push(...subs);
      expansionMap[header] = subs;
    }
  });
  const finalRows = mergedRows.map(row => {
    const newRow: DataRow = {};
    originalHeaders.forEach((header, index) => {
      const tokens = getTokens(row[header]);
      const targets = expansionMap[header];
      if (index === 0 || targets.length === 1) { newRow[targets[0]] = tokens.join(' '); } 
      else {
        targets.forEach(t => newRow[t] = "");
        tokens.forEach(token => {
          const type = getTokenType(token);
          let val = token;
          let subSuffix = "";
          if (type === DataType.DATE) {
            val = parseToStandardDate(token) || token;
            subSuffix = " (Date)";
          } else if (type === DataType.NUMBER) { subSuffix = " (Number)"; } 
          else if (type === DataType.TEXT_ENGLISH) { subSuffix = " (Text)"; }
          const targetHeader = `${header}${subSuffix}`;
          if (targets.includes(targetHeader)) {
            const existing = String(newRow[targetHeader] || '');
            newRow[targetHeader] = existing ? `${existing}; ${val}` : val;
          }
        });
      }
    });
    return newRow;
  });
  return { headers: finalHeaders, rows: finalRows, originalHeaders };
}

export function extractDashboardMetrics(data: DataRow[]): DashboardMetrics {
  const today = new Date();
  const metrics: DashboardMetrics = {
    total: data.length,
    expiredCount: 0,
    activeCount: 0,
    upcomingRenewals: 0,
    nationalityData: {},
    nationalityEscapeData: {},
    statusData: {},
    monthlyRenewals: {},
    escapeRecords: []
  };

  const monthNames = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];

  data.forEach(row => {
    // 1. Nationality Logic
    const natKey = Object.keys(row).find(k => k.toLowerCase().includes('nationality'));
    const nat = natKey ? (String(row[natKey]).trim() || 'Unspecified') : 'Unspecified';
    metrics.nationalityData[nat] = (metrics.nationalityData[nat] || 0) + 1;

    // 2. Card Status Logic
    const statusKey = Object.keys(row).find(k => k.toLowerCase().includes('status') || k.toLowerCase().includes('card type'));
    if (statusKey) {
      const status = String(row[statusKey]).trim() || 'Unknown';
      metrics.statusData[status] = (metrics.statusData[status] || 0) + 1;
    }

    // 3. Expiry & Renewals Logic
    const dateKey = Object.keys(row).find(k => k.includes('(Date)'));
    if (dateKey) {
      const dateStr = String(row[dateKey]).split(';')[0].trim();
      const parts = dateStr.split('/');
      if (parts.length === 3) {
        const dObj = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
        if (!isNaN(dObj.getTime())) {
          const monthLabel = monthNames[dObj.getMonth()] + ' ' + dObj.getFullYear();
          metrics.monthlyRenewals[monthLabel] = (metrics.monthlyRenewals[monthLabel] || 0) + 1;

          if (dObj < today) {
            metrics.expiredCount++;
            metrics.escapeRecords.push(row);
            // Track escape count by nationality
            metrics.nationalityEscapeData[nat] = (metrics.nationalityEscapeData[nat] || 0) + 1;
          } else {
            metrics.activeCount++;
            const diffDays = Math.ceil((dObj.getTime() - today.getTime()) / (1000 * 3600 * 24));
            if (diffDays <= 30) metrics.upcomingRenewals++;
          }
        }
      }
    }
  });

  return metrics;
}

export function generatePivotData(rows: DataRow[], rowField: string, colField: string, valField: string, aggType: string) {
  const pivot: Record<string, Record<string, number>> = {};
  const allCols = new Set<string>();
  rows.forEach(row => {
    const rVal = String(row[rowField] || '(Blank)');
    const cVal = String(row[colField] || '(Blank)');
    const vRaw = String(row[valField] || '0').replace(/[^0-9.-]+/g, '');
    const vVal = parseFloat(vRaw) || 0;
    allCols.add(cVal);
    if (!pivot[rVal]) pivot[rVal] = {};
    if (aggType === 'sum') { pivot[rVal][cVal] = (pivot[rVal][cVal] || 0) + vVal; } 
    else { pivot[rVal][cVal] = (pivot[rVal][cVal] || 0) + 1; }
  });
  return { rows: Object.keys(pivot).map(key => ({ row: key, ...pivot[key] })), columns: Array.from(allCols).sort() };
}

import React, { useMemo, useState } from 'react';
import { 
  Users, 
  CreditCard, 
  AlertCircle, 
  Calendar, 
  Globe, 
  TrendingUp, 
  ChevronRight,
  ShieldAlert,
  ArrowRight,
  SortAsc,
  SortDesc,
  ExternalLink,
  ListFilter
} from 'lucide-react';
import { DataRow } from '../types';
import { extractDashboardMetrics } from '../utils/dataProcessor';

interface DashboardProps {
  rows: DataRow[];
  onDrillDown: (title: string, filteredRows: DataRow[]) => void;
}

const RAINBOW_COLORS = [
  '#FF595E', // Red
  '#FF924C', // Orange
  '#FFCA3A', // Yellow
  '#C5CA30', // Lime
  '#8AC926', // Green
  '#36949D', // Teal
  '#1982C4', // Blue
  '#4267AC', // Indigo
  '#6A4C93', // Purple
  '#B5179E', // Magenta
];

export const Dashboard: React.FC<DashboardProps> = ({ rows, onDrillDown }) => {
  const metrics = useMemo(() => extractDashboardMetrics(rows), [rows]);
  const [escapeSortDesc, setEscapeSortDesc] = useState(true);

  // Helper to parse DD/MM/YYYY into a sortable number
  const getSortableDate = (row: DataRow) => {
    const dateKey = Object.keys(row).find(k => k.includes('(Date)'));
    if (!dateKey) return 0;
    const dateStr = String(row[dateKey]).split(';')[0].trim();
    const parts = dateStr.split('/');
    if (parts.length !== 3) return 0;
    return new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0])).getTime();
  };

  const sortedEscapeRecords = useMemo(() => {
    return [...metrics.escapeRecords].sort((a, b) => {
      const timeA = getSortableDate(a);
      const timeB = getSortableDate(b);
      return escapeSortDesc ? timeB - timeA : timeA - timeB;
    });
  }, [metrics.escapeRecords, escapeSortDesc]);

  const handleMetricClick = (title: string, type: 'total' | 'active' | 'expired' | 'upcoming') => {
    let filtered = rows;
    if (type === 'active') {
      filtered = rows.filter(r => {
        const dateKey = Object.keys(r).find(k => k.includes('(Date)'));
        if (!dateKey) return true;
        const parts = String(r[dateKey]).split(';')[0].trim().split('/');
        const d = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
        return !isNaN(d.getTime()) && d >= new Date();
      });
    } else if (type === 'expired') {
      filtered = sortedEscapeRecords;
    } else if (type === 'upcoming') {
      const today = new Date();
      filtered = rows.filter(r => {
        const dateKey = Object.keys(r).find(k => k.includes('(Date)'));
        if (!dateKey) return false;
        const parts = String(r[dateKey]).split(';')[0].trim().split('/');
        const d = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
        const diff = Math.ceil((d.getTime() - today.getTime()) / (1000 * 3600 * 24));
        return diff > 0 && diff <= 30;
      });
    }
    onDrillDown(title, filtered);
  };

  const handleNationalityClick = (nat: string, onlyEscaped: boolean = false) => {
    const natKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase().includes('nationality'));
    let filtered = rows.filter(r => natKey && String(r[natKey]).trim() === nat);

    if (onlyEscaped) {
      filtered = filtered.filter(r => {
        const dateKey = Object.keys(r).find(k => k.includes('(Date)'));
        if (!dateKey) return false;
        const parts = String(r[dateKey]).split(';')[0].trim().split('/');
        const d = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
        return !isNaN(d.getTime()) && d < new Date();
      });
      onDrillDown(`Nationality: ${nat} (Escaped Only)`, filtered);
    } else {
      onDrillDown(`Nationality: ${nat} (Full List)`, filtered);
    }
  };

  const handleStatusClick = (status: string) => {
    const statusKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase().includes('status') || k.toLowerCase().includes('card type'));
    const filtered = rows.filter(r => statusKey && String(r[statusKey]).trim() === status);
    onDrillDown(`Status: ${status}`, filtered);
  };

  const handleMonthClick = (monthLabel: string) => {
    const monthNames = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
    const filtered = rows.filter(r => {
      const dateKey = Object.keys(r).find(k => k.includes('(Date)'));
      if (!dateKey) return false;
      const parts = String(r[dateKey]).split(';')[0].trim().split('/');
      const d = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
      if (isNaN(d.getTime())) return false;
      const label = monthNames[d.getMonth()] + ' ' + d.getFullYear();
      return label === monthLabel;
    });
    onDrillDown(`Renewals: ${monthLabel}`, filtered);
  };

  // Pie Chart Logic
  const pieSlices = useMemo(() => {
    const entries = Object.entries(metrics.statusData);
    const total = entries.reduce((acc, [_, count]) => acc + (count as number), 0);
    let cumulativePercent = 0;

    return entries.map(([status, count], index) => {
      const percent = (count as number) / total;
      const startX = Math.cos(2 * Math.PI * cumulativePercent);
      const startY = Math.sin(2 * Math.PI * cumulativePercent);
      cumulativePercent += percent;
      const endX = Math.cos(2 * Math.PI * cumulativePercent);
      const endY = Math.sin(2 * Math.PI * cumulativePercent);

      const largeArcFlag = percent > 0.5 ? 1 : 0;
      const pathData = [
        `M ${startX} ${startY}`,
        `A 1 1 0 ${largeArcFlag} 1 ${endX} ${endY}`,
        `L 0 0`,
      ].join(' ');

      const midAngle = 2 * Math.PI * (cumulativePercent - percent / 2);
      const labelX = Math.cos(midAngle) * 0.7;
      const labelY = Math.sin(midAngle) * 0.7;

      return {
        status,
        count: count as number,
        pathData,
        color: RAINBOW_COLORS[index % RAINBOW_COLORS.length],
        labelX,
        labelY,
        percent: (percent * 100).toFixed(1)
      };
    });
  }, [metrics.statusData]);

  const maxNatCount = Math.max(...Object.values(metrics.nationalityData), 1);

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Top Level Metric Cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <MetricCard 
          icon={<Users className="text-blue-600" />} 
          title="Total Workforce" 
          value={metrics.total} 
          color="blue" 
          sub="Synchronized records"
          onClick={() => handleMetricClick("Full Workforce List", 'total')}
        />
        <MetricCard 
          icon={<CreditCard className="text-emerald-600" />} 
          title="Active Cards" 
          value={metrics.activeCount} 
          color="emerald" 
          sub="Valid status tokens"
          onClick={() => handleMetricClick("Active Records", 'active')}
        />
        <MetricCard 
          icon={<ShieldAlert className="text-rose-600" />} 
          title="Expired/Escape" 
          value={metrics.expiredCount} 
          color="rose" 
          sub="Immediate action required"
          urgent={metrics.expiredCount > 0}
          onClick={() => handleMetricClick("Escape Report Detail", 'expired')}
        />
        <MetricCard 
          icon={<Calendar className="text-amber-600" />} 
          title="30-Day Renewals" 
          value={metrics.upcomingRenewals} 
          color="amber" 
          sub="Expiring this month"
          onClick={() => handleMetricClick("Upcoming Renewals List", 'upcoming')}
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Nationality Vector with Escape Breakdown */}
        <div className="bg-white p-6 rounded-[32px] border border-slate-200 shadow-sm col-span-1">
          <div className="flex items-center justify-between mb-4">
            <h3 className="font-black text-slate-800 flex items-center gap-2 text-sm uppercase">
              <Globe size={18} className="text-indigo-600" />
              Nationality Breakdown
            </h3>
            <button 
              onClick={() => handleMetricClick("Full Workforce List", "total")}
              className="text-[9px] font-black text-indigo-600 hover:text-indigo-800 uppercase flex items-center gap-1 bg-indigo-50 px-2 py-1 rounded-md transition-all"
            >
              View All <ChevronRight size={10} />
            </button>
          </div>

          <div className="flex items-center gap-4 mb-6 border-b border-slate-50 pb-3">
             <div className="flex items-center gap-1.5">
                <div className="w-2.5 h-2.5 rounded-sm bg-indigo-500"></div>
                <span className="text-[9px] font-bold text-slate-400 uppercase">Total</span>
             </div>
             <div className="flex items-center gap-1.5">
                <div className="w-2.5 h-2.5 rounded-sm bg-rose-500"></div>
                <span className="text-[9px] font-bold text-slate-400 uppercase">Escaped</span>
             </div>
          </div>

          <div className="space-y-5">
            {Object.entries(metrics.nationalityData)
              .sort((a, b) => (b[1] as number) - (a[1] as number))
              .slice(0, 5)
              .map(([nat, count]) => {
                const escapeCount = metrics.nationalityEscapeData[nat] || 0;
                const totalPercent = (count / maxNatCount) * 100;
                const escapePercent = (escapeCount / count) * 100;

                return (
                  <div key={nat} className="group relative">
                    <div className="flex justify-between items-center mb-1.5">
                       <span className="text-[10px] font-black text-slate-700 uppercase">{nat}</span>
                       <div className="flex gap-2">
                          <span className="text-[10px] font-bold text-indigo-600">{count} Total</span>
                          {escapeCount > 0 && (
                            <span className="text-[10px] font-black text-rose-500">{escapeCount} Escaped</span>
                          )}
                       </div>
                    </div>

                    <div className="relative h-3 w-full bg-slate-100 rounded-full overflow-hidden flex cursor-pointer group/bar">
                       {/* Total Population Bar Segment */}
                       <div 
                         onClick={(e) => { e.stopPropagation(); handleNationalityClick(nat, false); }}
                         title={`View all ${count} ${nat} riders`}
                         className="h-full bg-indigo-500/30 hover:bg-indigo-500 transition-all relative z-10"
                         style={{ width: `${totalPercent}%` }}
                       >
                          {/* Inner Escaped Indicator */}
                          <div 
                            onClick={(e) => { e.stopPropagation(); handleNationalityClick(nat, true); }}
                            title={`View ${escapeCount} escaped ${nat} riders`}
                            className="h-full bg-rose-500 hover:brightness-125 transition-all"
                            style={{ width: `${escapePercent}%` }}
                          ></div>
                       </div>
                    </div>

                    {/* Tiny Action Links on Hover */}
                    <div className="opacity-0 group-hover:opacity-100 flex items-center gap-3 mt-1.5 transition-opacity">
                       <button 
                         onClick={() => handleNationalityClick(nat, false)}
                         className="text-[8px] font-black text-indigo-400 hover:text-indigo-600 uppercase underline underline-offset-2 flex items-center gap-0.5"
                       >
                          Full List <ExternalLink size={8} />
                       </button>
                       {escapeCount > 0 && (
                         <button 
                           onClick={() => handleNationalityClick(nat, true)}
                           className="text-[8px] font-black text-rose-400 hover:text-rose-600 uppercase underline underline-offset-2 flex items-center gap-0.5"
                         >
                            Escaped <ExternalLink size={8} />
                         </button>
                       )}
                    </div>
                  </div>
                );
              })}
          </div>
        </div>

        {/* Status Distribution - Pie Diagram with Rainbow Colors & Hover Detail */}
        <div className="bg-white p-6 rounded-[32px] border border-slate-200 shadow-sm col-span-1 flex flex-col">
          <div className="flex items-center justify-between mb-2">
            <h3 className="font-black text-slate-800 flex items-center gap-2 text-sm uppercase">
              <TrendingUp size={18} className="text-emerald-600" />
              Status Clusters
            </h3>
          </div>

          <div className="flex-1 flex flex-col items-center justify-center min-h-[220px] relative">
            {pieSlices.length > 0 ? (
              <div className="w-full h-full max-w-[200px] aspect-square relative group">
                <svg viewBox="-1.1 -1.1 2.2 2.2" className="w-full h-full -rotate-90">
                  {pieSlices.map((slice, i) => (
                    <g 
                      key={slice.status} 
                      className="group/slice cursor-pointer" 
                      onClick={() => handleStatusClick(slice.status)}
                    >
                      <title>{slice.status}: {slice.count} records</title>
                      <path
                        d={slice.pathData}
                        fill={slice.color}
                        className="transition-all duration-300 hover:scale-[1.05] origin-center hover:brightness-110"
                      />
                      {slice.percent > 5 && (
                        <text
                          x={slice.labelX}
                          y={slice.labelY}
                          textAnchor="middle"
                          dominantBaseline="middle"
                          fill="white"
                          className="text-[0.12px] font-black pointer-events-none drop-shadow-sm rotate-90"
                        >
                          {slice.count}
                        </text>
                      )}
                    </g>
                  ))}
                  <circle cx="0" cy="0" r="0.4" fill="white" />
                </svg>

                <div className="absolute -bottom-10 left-0 right-0 flex flex-wrap justify-center gap-2 px-2">
                   {pieSlices.slice(0, 6).map(s => (
                     <div 
                       key={s.status} 
                       className="flex items-center gap-1 cursor-help"
                       title={s.status}
                     >
                        <div className="w-2 h-2 rounded-full" style={{ backgroundColor: s.color }}></div>
                        <span className="text-[8px] font-black text-slate-400 uppercase truncate max-w-[40px]">
                          {s.status.length > 5 ? s.status.substring(0, 4) + '..' : s.status}
                        </span>
                     </div>
                   ))}
                </div>
              </div>
            ) : (
              <p className="text-[10px] text-slate-400 font-bold uppercase">No status data detected</p>
            )}
          </div>
        </div>

        {/* Monthly Renewal Basis */}
        <div className="bg-white p-6 rounded-[32px] border border-slate-200 shadow-sm col-span-1">
          <div className="flex items-center justify-between mb-6">
            <h3 className="font-black text-slate-800 flex items-center gap-2 text-sm uppercase">
              <Calendar size={18} className="text-amber-600" />
              Renewal Pipeline
            </h3>
          </div>
          <div className="space-y-3 max-h-52 overflow-auto custom-scrollbar pr-2">
            {Object.entries(metrics.monthlyRenewals)
              .sort((a, b) => {
                const dateA = new Date(a[0]);
                const dateB = new Date(b[0]);
                return dateA.getTime() - dateB.getTime();
              })
              .map(([month, count]) => (
                <div 
                  key={month} 
                  onClick={() => handleMonthClick(month)}
                  className="flex items-center gap-3 p-3 bg-slate-50 rounded-2xl hover:bg-indigo-50 hover:border-indigo-200 border border-transparent transition-all cursor-pointer group"
                >
                  <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center text-indigo-600 shadow-sm group-hover:scale-110 transition-transform">
                    <Calendar size={18} />
                  </div>
                  <div className="flex-1">
                    <div className="text-xs font-black text-slate-800 uppercase group-hover:text-indigo-600">{month}</div>
                    <div className="text-[10px] font-bold text-slate-400">{count} Renewals</div>
                  </div>
                  <ArrowRight size={14} className="text-slate-300 group-hover:text-indigo-400 group-hover:translate-x-1 transition-all" />
                </div>
              ))}
          </div>
        </div>
      </div>

      {/* The Escape Report Section */}
      <div className="bg-slate-900 rounded-[40px] p-8 shadow-2xl relative overflow-hidden group">
        <div className="absolute top-0 right-0 w-96 h-96 bg-indigo-500/10 rounded-full blur-3xl -mr-48 -mt-48 pointer-events-none"></div>
        <div className="flex items-center justify-between mb-8 relative">
          <div>
