            <div className="bg-rose-500 text-white px-5 py-2 rounded-2xl text-sm font-black border border-rose-400 shadow-lg shadow-rose-900/40">
              {metrics.expiredCount} PERSONS ESCAPED
            </div>
            <p className="text-[10px] text-slate-500 font-bold uppercase">Total Non-Compliance Count</p>
          </div>
        </div>

        <div className="bg-white/5 rounded-2xl overflow-hidden border border-white/10">
          <table className="w-full text-sm text-left border-collapse">
            <thead className="bg-white/5">
              <tr>
                <th className="px-6 py-4 text-slate-300 font-black uppercase text-[10px] tracking-wider border-b border-white/10">Employee Primary Identity</th>
                <th className="px-6 py-4 text-slate-300 font-black uppercase text-[10px] tracking-wider border-b border-white/10 text-center">
                  <div className="flex items-center justify-center gap-2">
                    Expiry Date
                    <button 
                      onClick={() => setEscapeSortDesc(!escapeSortDesc)}
                      className="p-1 hover:bg-white/10 rounded-md transition-colors text-indigo-400"
                      title="Toggle Sort by Expiry Date"
                    >
                      {escapeSortDesc ? <SortDesc size={14} /> : <SortAsc size={14} />}
                    </button>
                  </div>
                </th>
                <th className="px-6 py-4 text-slate-300 font-black uppercase text-[10px] tracking-wider border-b border-white/10 text-center">Status Tag</th>
                <th className="px-6 py-4 text-slate-300 font-black uppercase text-[10px] tracking-wider border-b border-white/10">Action Required</th>
              </tr>
            </thead>
            <tbody>
              {sortedEscapeRecords.slice(0, 5).map((rec, i) => {
                const dateKey = Object.keys(rec).find(k => k.includes('(Date)'));
                const dateVal = dateKey ? String(rec[dateKey]).split(';')[0].trim() : 'N/A';
                return (
                  <tr key={i} className="hover:bg-white/10 transition-colors">
                    <td className="px-6 py-4 text-white font-bold border-b border-white/5">
                      {Object.values(rec)[0]}
                    </td>
                    <td className="px-6 py-4 text-slate-300 font-medium border-b border-white/5 text-center font-mono text-xs">
                      {dateVal}
                    </td>
                    <td className="px-6 py-4 border-b border-white/5 text-center">
                      <span className="bg-rose-500/20 text-rose-400 border border-rose-500/40 px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest">
                        CRITICAL EXPIRE
                      </span>
                    </td>
                    <td className="px-6 py-4 text-slate-400 text-xs border-b border-white/5">
                      Renew Document Immediately
                    </td>
                  </tr>
                );
              })}
              {metrics.escapeRecords.length === 0 && (
                <tr>
                  <td colSpan={4} className="px-6 py-12 text-center text-slate-500 italic font-medium">
                    Excellent compliance score. No escape records detected.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
          {metrics.escapeRecords.length > 0 && (
            <div className="p-4 flex items-center justify-center gap-4 bg-white/5 border-t border-white/10">
              <button 
                onClick={() => handleMetricClick("Full Escape List", 'expired')}
                className="text-rose-400 hover:text-white hover:bg-rose-600 px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest flex items-center justify-center gap-2 transition-all shadow-lg shadow-rose-900/20 border border-rose-500/30"
              >
                <ListFilter size={14} /> Full Escape Report <ChevronRight size={14} />
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

interface MetricCardProps {
  icon: React.ReactNode;
  title: string;
  value: number | string;
  color: string;
  sub: string;
  urgent?: boolean;
  onClick?: () => void;
}

const MetricCard: React.FC<MetricCardProps> = ({ icon, title, value, color, sub, urgent, onClick }) => {
  const colorMap: Record<string, string> = {
    blue: 'bg-blue-50 border-blue-100 hover:border-blue-300',
    emerald: 'bg-emerald-50 border-emerald-100 hover:border-emerald-300',
    rose: 'bg-rose-50 border-rose-100 hover:border-rose-300',
    amber: 'bg-amber-50 border-amber-100 hover:border-amber-300',
  };

  return (
    <div 
      onClick={onClick}
      className={`p-6 rounded-[32px] border shadow-sm transition-all hover:shadow-xl hover:-translate-y-1 cursor-pointer group ${colorMap[color] || 'bg-slate-50 border-slate-100'} ${urgent ? 'ring-2 ring-rose-500/20' : ''}`}
    >
      <div className="flex items-center justify-between mb-4">
        <div className="bg-white p-3 rounded-2xl shadow-sm group-hover:scale-110 transition-transform">
          {icon}
        </div>
        {urgent && <div className="w-2 h-2 rounded-full bg-rose-500 animate-ping"></div>}
      </div>
      <div>
        <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1 group-hover:text-slate-800">{title}</h4>
        <div className="text-3xl font-black text-slate-800 tracking-tight">{value}</div>
        <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase">{sub}</p>
      </div>
    </div>
  );
};

import React, { useMemo, useState } from 'react';
import { 
  Users, 
  CreditCard, 
  AlertCircle, 
  Calendar, 
  Globe, 
  TrendingUp, 
  ChevronRight,
  ShieldAlert,
  ArrowRight,
  SortAsc,
  SortDesc,
  ExternalLink,
  ListFilter
} from 'lucide-react';
import { DataRow } from '../types';
import { extractDashboardMetrics } from '../utils/dataProcessor';

interface DashboardProps {
  rows: DataRow[];
  onDrillDown: (title: string, filteredRows: DataRow[]) => void;
}

const RAINBOW_COLORS = [
  '#FF595E', // Red
  '#FF924C', // Orange
  '#FFCA3A', // Yellow
  '#C5CA30', // Lime
  '#8AC926', // Green
  '#36949D', // Teal
  '#1982C4', // Blue
  '#4267AC', // Indigo
  '#6A4C93', // Purple
  '#B5179E', // Magenta
];

export const Dashboard: React.FC<DashboardProps> = ({ rows, onDrillDown }) => {
  const metrics = useMemo(() => extractDashboardMetrics(rows), [rows]);
  const [escapeSortDesc, setEscapeSortDesc] = useState(true);

  // Helper to parse DD/MM/YYYY into a sortable number
  const getSortableDate = (row: DataRow) => {
    const dateKey = Object.keys(row).find(k => k.includes('(Date)'));
    if (!dateKey) return 0;
    const dateStr = String(row[dateKey]).split(';')[0].trim();
    const parts = dateStr.split('/');
    if (parts.length !== 3) return 0;
    return new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0])).getTime();
  };

  const sortedEscapeRecords = useMemo(() => {
    return [...metrics.escapeRecords].sort((a, b) => {
      const timeA = getSortableDate(a);
      const timeB = getSortableDate(b);
      return escapeSortDesc ? timeB - timeA : timeA - timeB;
    });
  }, [metrics.escapeRecords, escapeSortDesc]);

  const handleMetricClick = (title: string, type: 'total' | 'active' | 'expired' | 'upcoming') => {
    let filtered = rows;
    if (type === 'active') {
      filtered = rows.filter(r => {
        const dateKey = Object.keys(r).find(k => k.includes('(Date)'));
        if (!dateKey) return true;
        const parts = String(r[dateKey]).split(';')[0].trim().split('/');
        const d = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
        return !isNaN(d.getTime()) && d >= new Date();
      });
    } else if (type === 'expired') {
      filtered = sortedEscapeRecords;
    } else if (type === 'upcoming') {
      const today = new Date();
      filtered = rows.filter(r => {
        const dateKey = Object.keys(r).find(k => k.includes('(Date)'));
        if (!dateKey) return false;
        const parts = String(r[dateKey]).split(';')[0].trim().split('/');
        const d = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
        const diff = Math.ceil((d.getTime() - today.getTime()) / (1000 * 3600 * 24));
        return diff > 0 && diff <= 30;
      });
    }
    onDrillDown(title, filtered);
  };

  const handleNationalityClick = (nat: string, onlyEscaped: boolean = false) => {
    const natKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase().includes('nationality'));
    let filtered = rows.filter(r => natKey && String(r[natKey]).trim() === nat);

    if (onlyEscaped) {
      filtered = filtered.filter(r => {
        const dateKey = Object.keys(r).find(k => k.includes('(Date)'));
        if (!dateKey) return false;
        const parts = String(r[dateKey]).split(';')[0].trim().split('/');
        const d = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
        return !isNaN(d.getTime()) && d < new Date();
      });
      onDrillDown(`Nationality: ${nat} (Escaped Only)`, filtered);
    } else {
      onDrillDown(`Nationality: ${nat} (Full List)`, filtered);
    }
  };

  const handleStatusClick = (status: string) => {
    const statusKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase().includes('status') || k.toLowerCase().includes('card type'));
    const filtered = rows.filter(r => statusKey && String(r[statusKey]).trim() === status);
    onDrillDown(`Status: ${status}`, filtered);
  };

  const handleMonthClick = (monthLabel: string) => {
    const monthNames = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
    const filtered = rows.filter(r => {
      const dateKey = Object.keys(r).find(k => k.includes('(Date)'));
      if (!dateKey) return false;
      const parts = String(r[dateKey]).split(';')[0].trim().split('/');
      const d = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
      if (isNaN(d.getTime())) return false;
      const label = monthNames[d.getMonth()] + ' ' + d.getFullYear();
      return label === monthLabel;
    });
    onDrillDown(`Renewals: ${monthLabel}`, filtered);
  };

  // Pie Chart Logic
  const pieSlices = useMemo(() => {
    const entries = Object.entries(metrics.statusData) as [string, number][];
    // Fix: Provide explicit type for accumulator and use Number() for robust conversion from unknown if needed.
    const total = entries.reduce((acc: number, [_, count]) => acc + Number(count), 0);
    let cumulativePercent = 0;

    return entries.map(([status, count], index) => {
      const percent = Number(count) / total;
      const startX = Math.cos(2 * Math.PI * cumulativePercent);
      const startY = Math.sin(2 * Math.PI * cumulativePercent);
      cumulativePercent += percent;
      const endX = Math.cos(2 * Math.PI * cumulativePercent);
      const endY = Math.sin(2 * Math.PI * cumulativePercent);

      const largeArcFlag = percent > 0.5 ? 1 : 0;
      const pathData = [
        `M ${startX} ${startY}`,
        `A 1 1 0 ${largeArcFlag} 1 ${endX} ${endY}`,
        `L 0 0`,
      ].join(' ');

      const midAngle = 2 * Math.PI * (cumulativePercent - percent / 2);
      const labelX = Math.cos(midAngle) * 0.7;
      const labelY = Math.sin(midAngle) * 0.7;

      return {
        status,
        count: count as number,
        pathData,
        color: RAINBOW_COLORS[index % RAINBOW_COLORS.length],
        labelX,
        labelY,
        percent: (percent * 100).toFixed(1)
