          </div>

          <div className="space-y-5">
            {/* Fix: Explicitly cast entries to [string, number][] to solve arithmetic operation errors on unknown types */}
            {(Object.entries(metrics.nationalityData) as [string, number][])
              .sort((a, b) => Number(b[1]) - Number(a[1]))
              .slice(0, 5)
              .map(([nat, count]) => {
                const escapeCount = metrics.nationalityEscapeData[nat] || 0;
