import { extractDashboardMetrics } from '../utils/dataProcessor';

interface DashboardProps {
  rows: DataRow[];
  onDrillDown: (title: string, filteredRows: DataRow[]) => void;
}

const RAINBOW_COLORS = [
  '#FF595E', // Red
  '#FF924C', // Orange
  '#FFCA3A', // Yellow
  '#C5CA30', // Lime
  '#8AC926', // Green
  '#36949D', // Teal
  '#1982C4', // Blue
  '#4267AC', // Indigo
  '#6A4C93', // Purple
  '#B5179E', // Magenta
];

export const Dashboard: React.FC<DashboardProps> = ({ rows, onDrillDown }) => {
  const metrics = useMemo(() => extractDashboardMetrics(rows), [rows]);
  const [escapeSortDesc, setEscapeSortDesc] = useState(true);

  const getSortableDate = (row: DataRow) => {
    const dateKey = Object.keys(row).find(k => k.includes('(Date)'));
    if (!dateKey) return 0;
    const dateStr = String(row[dateKey]).split(';')[0].trim();
    const parts = dateStr.split('/');
    if (parts.length !== 3) return 0;
    return new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0])).getTime();
  };

  const sortedEscapeRecords = useMemo(() => {
    return [...metrics.escapeRecords].sort((a, b) => {
      const timeA = getSortableDate(a);
      const timeB = getSortableDate(b);
      return escapeSortDesc ? timeB - timeA : timeA - timeB;
    });
  }, [metrics.escapeRecords, escapeSortDesc]);

  const handleMetricClick = (title: string, type: 'total' | 'active' | 'expired' | 'upcoming') => {
    let filtered = rows;
    if (type === 'active') {
      filtered = rows.filter(r => !metrics.escapeRecords.includes(r));
    } else if (type === 'expired') {
      filtered = metrics.escapeRecords;
    } else if (type === 'upcoming') {
      const today = new Date();
      filtered = rows.filter(r => {
        const dateKey = Object.keys(r).find(k => k.includes('(Date)'));
        if (!dateKey) return false;
        const parts = String(r[dateKey]).split(';')[0].trim().split('/');
        const d = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
        const diff = Math.ceil((d.getTime() - today.getTime()) / (1000 * 3600 * 24));
        return diff > 0 && diff <= 30;
      });
    }
    onDrillDown(title, filtered);
  };

  const handleNationalityClick = (nat: string, onlyEscaped: boolean = false) => {
    const natKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase().includes('nationality'));
    let filtered = rows.filter(r => natKey && String(r[natKey]).trim() === (nat === 'Unspecified' ? '' : nat) || (nat === 'Unspecified' && !r[natKey]));

    if (onlyEscaped) {
      filtered = filtered.filter(r => metrics.escapeRecords.includes(r));
      onDrillDown(`Escaped Riders: ${nat}`, filtered);
    } else {
      onDrillDown(`Total Riders: ${nat}`, filtered);
    }
  };

  const handleStatusClick = (status: string) => {
    const statusKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase().includes('status') || k.toLowerCase().includes('card type'));
    const filtered = rows.filter(r => statusKey && String(r[statusKey]).trim() === status);
    onDrillDown(`Status: ${status}`, filtered);
  };

  // Pie Chart Logic
  const pieSlices = useMemo(() => {
    const entries = Object.entries(metrics.statusData);
    const total = entries.reduce((acc, [_, count]) => acc + (count as number), 0);
    let cumulativePercent = 0;

    return entries.map(([status, count], index) => {
      const percent = (count as number) / total;
      const startX = Math.cos(2 * Math.PI * cumulativePercent);
      const startY = Math.sin(2 * Math.PI * cumulativePercent);
      cumulativePercent += percent;
      const endX = Math.cos(2 * Math.PI * cumulativePercent);
      const endY = Math.sin(2 * Math.PI * cumulativePercent);

      const largeArcFlag = percent > 0.5 ? 1 : 0;
      const pathData = [
        `M ${startX} ${startY}`,
        `A 1 1 0 ${largeArcFlag} 1 ${endX} ${endY}`,
        `L 0 0`,
      ].join(' ');

      const midAngle = 2 * Math.PI * (cumulativePercent - percent / 2);
      const labelX = Math.cos(midAngle) * 0.7;
      const labelY = Math.sin(midAngle) * 0.7;

      return {
        status,
        count: count as number,
        pathData,
        color: RAINBOW_COLORS[index % RAINBOW_COLORS.length],
        labelX,
        labelY,
        percent: (percent * 100).toFixed(1)
