          value={metrics.escapeCount} 
          color="rose" 
          sub="Explicit Escape Status"
          onClick={() => handleMetricClick("He has an escape Report - List", metrics.escapeRecords)}
        />
        <MetricCard 
          icon={<ShieldX className="text-amber-600" />} 
