            <table className="w-full text-xs text-left">
              <thead className="bg-white/10 sticky top-0">
                <tr>
                  <th className="px-4 py-3 text-slate-400 font-black uppercase text-[9px]">Identity</th>
                  <th className="px-4 py-3 text-slate-400 font-black uppercase text-[9px]">Reason</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-white/5">
                {sortedEscapes.map((rec, i) => (
                  <tr key={i} className="hover:bg-white/5 transition-colors">
                    <td className="px-4 py-3 text-white font-bold">{Object.values(rec)[0]}</td>
                    <td className="px-4 py-3 text-rose-400 font-bold uppercase text-[9px]">Escape report labeled</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          <button onClick={() => handleMetricClick("Full Escape List", metrics.escapeRecords)} className="w-full mt-4 py-3 bg-rose-500/10 hover:bg-rose-500/20 text-rose-400 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all">Expand Escape Registry</button>
        </div>

        <div className="bg-slate-800 rounded-[32px] p-6 shadow-xl relative overflow-hidden group">
          <div className="flex items-center justify-between mb-6">
            <h3 className="text-lg font-black text-white flex items-center gap-3">
              <ShieldX size={22} className="text-amber-500" />
              Expired Card Registry
            </h3>
            <div className="flex items-center gap-2">
              <button onClick={() => setSortDesc(!sortDesc)} className="text-slate-400 hover:text-white transition-colors">{sortDesc ? <SortDesc size={14} /> : <SortAsc size={14} />}</button>
              <span className="bg-amber-500/20 text-amber-400 px-3 py-1 rounded-lg text-[10px] font-black border border-amber-500/30">{metrics.expiredCardCount} EXPIRED</span>
            </div>
