          <div className="bg-white/5 rounded-2xl overflow-hidden border border-white/10 max-h-[300px] overflow-y-auto custom-scrollbar">
            <table className="w-full text-xs text-left">
              <thead className="bg-white/10 sticky top-0">
                <tr>
                  <th className="px-4 py-3 text-slate-400 font-black uppercase text-[9px]">Identity</th>
                  <th className="px-4 py-3 text-slate-400 font-black uppercase text-[9px] text-center">Expiry</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-white/5">
                {sortedExpired.map((rec, i) => {
                  const dk = Object.keys(rec).find(k => k.includes('(Date)'));
                  return (
                    <tr key={i} className="hover:bg-white/5 transition-colors">
                      <td className="px-4 py-3 text-white font-bold">{Object.values(rec)[0]}</td>
                      <td className="px-4 py-3 text-amber-400 font-mono text-center">{dk ? String(rec[dk]).split(';')[0].trim() : 'N/A'}</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
          <button onClick={() => handleMetricClick("Expired Card List", metrics.expiredRecords)} className="w-full mt-4 py-3 bg-amber-500/10 hover:bg-amber-500/20 text-amber-400 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all">Expand Expired Registry</button>
        </div>
      </div>
    </div>
  );

  function handleStatusClick(status: string) {
    const statusKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase().includes('status') || k.toLowerCase().includes('card type'));
    const filtered = rows.filter(r => statusKey && String(r[statusKey]).trim() === status);
    onDrillDown(`Status: ${status}`, filtered);
  }

  function handleMonthClick(monthKey: string, label: string) {
    const filtered = rows.filter(r => {
      const dateKey = Object.keys(r).find(k => k.includes('(Date)'));
      if (!dateKey) return false;
      const parts = String(r[dateKey]).split(';')[0].trim().split('/');
      const d = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
      const k = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
      return k === monthKey;
    });
    onDrillDown(`Renewals for ${label}`, filtered);
  }
};

interface MetricCardProps {
  icon: React.ReactNode;
  title: string;
  value: number | string;
  color: 'rose' | 'amber' | 'emerald' | 'indigo';
  sub: string;
  onClick?: () => void;
}

const MetricCard: React.FC<MetricCardProps> = ({ icon, title, value, color, sub, onClick }) => {
  const colorMap = {
    rose: 'bg-rose-50 border-rose-100 hover:border-rose-300 text-rose-600',
    amber: 'bg-amber-50 border-amber-100 hover:border-amber-300 text-amber-600',
    emerald: 'bg-emerald-50 border-emerald-100 hover:border-emerald-300 text-emerald-600',
    indigo: 'bg-indigo-50 border-indigo-100 hover:border-indigo-300 text-indigo-600',
  };

  return (
    <div 
      onClick={onClick}
      className={`p-6 rounded-[32px] border shadow-sm transition-all hover:shadow-xl hover:-translate-y-1 cursor-pointer group bg-white ${colorMap[color].split(' text-')[0]}`}
    >
      <div className="flex items-center justify-between mb-4">
        <div className={`bg-white p-3 rounded-2xl shadow-sm group-hover:scale-110 transition-transform ${colorMap[color].split(' ')[1]}`}>
          {icon}
        </div>
        <ArrowRight size={14} className="text-slate-200 group-hover:text-slate-400 group-hover:translate-x-1 transition-all" />
      </div>
      <div>
        <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">{title}</h4>
        <div className="text-3xl font-black text-slate-800 tracking-tight">{value}</div>
        <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase">{sub}</p>
      </div>
    </div>
  );
};

import React, { useMemo, useState } from 'react';
import { 
  Users, 
  CreditCard, 
  AlertCircle, 
  Calendar, 
  Globe, 
  TrendingUp, 
  ChevronRight,
  ShieldAlert,
  ArrowRight,
  SortAsc,
  SortDesc,
  ExternalLink,
  ListFilter,
  ShieldX,
  UserX,
  Briefcase,
  BarChart
} from 'lucide-react';
import { DataRow } from '../types';
import { extractDashboardMetrics } from '../utils/dataProcessor';

interface DashboardProps {
  rows: DataRow[];
  onDrillDown: (title: string, filteredRows: DataRow[]) => void;
}

const RAINBOW_COLORS = [
  '#FF595E', // Red
  '#FF924C', // Orange
  '#FFCA3A', // Yellow
  '#C5CA30', // Lime
  '#8AC926', // Green
  '#36949D', // Teal
  '#1982C4', // Blue
  '#4267AC', // Indigo
  '#6A4C93', // Purple
  '#B5179E', // Magenta
];

export const Dashboard: React.FC<DashboardProps> = ({ rows, onDrillDown }) => {
  const metrics = useMemo(() => extractDashboardMetrics(rows), [rows]);
  const [sortDesc, setSortDesc] = useState(true);

  const getSortableDate = (row: DataRow) => {
    const dateKey = Object.keys(row).find(k => k.includes('(Date)'));
    if (!dateKey) return 0;
    const dateStr = String(row[dateKey]).split(';')[0].trim();
    const parts = dateStr.split('/');
    if (parts.length !== 3) return 0;
    return new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0])).getTime();
  };

  const sortedExpired = useMemo(() => {
    return [...metrics.expiredRecords].sort((a, b) => {
      const timeA = getSortableDate(a);
      const timeB = getSortableDate(b);
      return sortDesc ? timeB - timeA : timeA - timeB;
    });
  }, [metrics.expiredRecords, sortDesc]);

  const sortedEscapes = useMemo(() => {
    return [...metrics.escapeRecords];
  }, [metrics.escapeRecords]);

  // 6-Month Renewal Pipeline Calculation
  const renewalForecast = useMemo(() => {
    const today = new Date();
    const months = [];
    const monthNames = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];

    for (let i = 0; i < 6; i++) {
      const d = new Date(today.getFullYear(), today.getMonth() + i, 1);
      const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
      months.push({
        key,
        label: `${monthNames[d.getMonth()]} ${d.getFullYear()}`,
        count: metrics.monthlyRenewals[key] || 0
      });
    }
    return months;
  }, [metrics.monthlyRenewals]);

  const handleMetricClick = (title: string, data: DataRow[]) => {
    onDrillDown(title, data);
  };

  const handleJobClick = (job: string) => {
    const jobKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase().includes('job') || k.toLowerCase().includes('description') || k.toLowerCase().includes('designation') || k.toLowerCase().includes('title'));
    const filtered = rows.filter(r => jobKey && String(r[jobKey]).trim() === job);
    onDrillDown(`Job Role: ${job}`, filtered);
  };

  const handleStatusClick = (status: string) => {
    const statusKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase().includes('status') || k.toLowerCase().includes('card type'));
    const filtered = rows.filter(r => statusKey && String(r[statusKey]).trim() === status);
    onDrillDown(`Status Clusters: ${status}`, filtered);
  };

  // Status Column Chart Data
  const statusChartData = useMemo(() => {
    const entries = Object.entries(metrics.statusData) as [string, number][];
    const sorted = entries.sort((a, b) => b[1] - a[1]).slice(0, 10); // Show top 10
    const maxVal = Math.max(...sorted.map(e => e[1]), 1);

    return sorted.map(([status, count], index) => ({
      status,
      shortStatus: status.length > 12 ? status.substring(0, 10) + '..' : status,
      count,
      height: (count / maxVal) * 100,
      color: RAINBOW_COLORS[index % RAINBOW_COLORS.length],
      percent: ((count / metrics.total) * 100).toFixed(1)
    }));
  }, [metrics.statusData, metrics.total]);

  const maxProblemCount = Math.max(
    ...Object.values(metrics.nationalityEscapeData).map(v => Number(v)),
    ...Object.values(metrics.nationalityExpiredData).map(v => Number(v)),
    1
  );

  const maxJobCount = Math.max(...(Object.values(metrics.jobDescriptionData) as number[]), 1);

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-12">
      {/* Primary KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <MetricCard 
          icon={<UserX className="text-rose-600" />} 
          title="Escape Reports" 
          value={metrics.escapeCount} 
          color="rose" 
          sub="Explicit Escape Status"
          onClick={() => handleMetricClick("He has an escape Report - List", metrics.escapeRecords)}
        />
        <MetricCard 
          icon={<ShieldX className="text-amber-600" />} 
          title="Expired Cards" 
          value={metrics.expiredCardCount} 
          color="amber" 
          sub="Calculated Date Violations"
          onClick={() => handleMetricClick("Expired Card List", metrics.expiredRecords)}
        />
        <MetricCard 
          icon={<CreditCard className="text-emerald-600" />} 
          title="Active Cards" 
          value={metrics.activeCount} 
          color="emerald" 
          sub="Compliant Records"
          onClick={() => handleMetricClick("Active Records", rows.filter(r => !metrics.expiredRecords.includes(r)))}
        />
        <MetricCard 
          icon={<Users className="text-indigo-600" />} 
          title="Total Workforce" 
          value={metrics.total} 
          color="indigo" 
          sub="Synchronized Database"
          onClick={() => handleMetricClick("Full Master Workforce", rows)}
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

        {/* Workforce Distribution by Job (Horizontal Bar Chart) */}
        <div className="bg-white p-6 rounded-[32px] border border-slate-200 shadow-sm col-span-1 lg:col-span-2">
           <div className="flex items-center justify-between mb-8">
            <h3 className="font-black text-slate-800 flex items-center gap-2 uppercase text-xs tracking-widest">
              <Briefcase size={20} className="text-slate-600" />
              Workforce Distribution by Job
            </h3>
            <span className="text-[10px] font-bold text-slate-400 uppercase">Top roles by headcount</span>
          </div>

          <div className="space-y-5">
            {(Object.entries(metrics.jobDescriptionData) as [string, number][])
              .sort((a, b) => b[1] - a[1])
              .slice(0, 8)
              .map(([job, count]) => (
                <div key={job} className="group cursor-pointer" onClick={() => handleJobClick(job)}>
                  <div className="flex justify-between items-center mb-1.5">
                    <span className="text-[10px] font-black text-slate-700 uppercase group-hover:text-indigo-600 transition-colors">{job}</span>
                    <span className="text-[10px] font-bold text-slate-400">{count} Employees</span>
                  </div>
                  <div className="h-2.5 w-full bg-slate-50 rounded-full overflow-hidden shadow-inner">
                    <div 
                      className="h-full bg-gradient-to-r from-indigo-500 to-indigo-400 rounded-full group-hover:scale-x-[1.01] origin-left transition-transform shadow-sm"
                      style={{ width: `${(count / maxJobCount) * 100}%` }}
                    />
                  </div>
                </div>
              ))}
          </div>
        </div>

        {/* Status Clusters - High Clarity Column Graph */}
        <div className="bg-white p-6 rounded-[32px] border border-slate-200 shadow-sm col-span-1 flex flex-col">
          <div className="flex items-center justify-between mb-6">
            <h3 className="font-black text-slate-800 flex items-center gap-2 uppercase text-xs tracking-widest">
              <BarChart size={20} className="text-emerald-600" />
              Status Clusters
            </h3>
            <div className="bg-slate-50 px-3 py-1 rounded-full">
              <span className="text-[9px] font-black text-slate-400 uppercase tracking-tighter">Click bar to filter</span>
            </div>
          </div>

          <div className="flex-1 flex flex-col justify-end min-h-[300px] mb-4">
            <div className="flex items-end justify-around h-full gap-2 px-2">
