                  <div className="absolute bottom-full mb-4 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none z-30">
                    <div className="bg-slate-900 text-white p-3 rounded-2xl shadow-2xl text-[10px] font-bold whitespace-nowrap border border-white/10">
                      <div className="text-indigo-400 uppercase tracking-widest mb-1">Full Status</div>
                      <div className="mb-2 leading-tight">{item.status}</div>
                      <div className="flex justify-between items-center gap-4 pt-2 border-t border-white/10">
                        <span className="text-slate-400 uppercase">Frequency</span>
                        <span className="text-white">{item.count} ({item.percent}%)</span>
                      </div>
                    </div>
                    <div className="w-3 h-3 bg-slate-900 rotate-45 mx-auto -mt-1.5 border-r border-b border-white/10"></div>
                  </div>

                  {/* Count Label */}
                  <span className="text-[9px] font-black text-slate-400 mb-1 group-hover:text-slate-800 transition-colors">
                    {item.count}
                  </span>

                  {/* The Bar */}
                  <div 
                    className="w-full rounded-t-xl transition-all duration-500 ease-out group-hover:brightness-110 shadow-lg group-hover:-translate-y-1"
