                    >
                      {item.shortStatus}
                    </span>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="pt-4 border-t border-slate-50 flex justify-between items-center px-2">
            <div className="text-[9px] font-bold text-slate-400 uppercase">Distribution Benchmark</div>
            <div className="text-[9px] font-black text-slate-800 uppercase">{metrics.total} Active Records</div>
          </div>
        </div>

      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

        {/* Nationality Exceptions Comparative */}
