               <div className="flex items-center gap-1.5"><div className="w-2.5 h-2.5 rounded-full bg-amber-500"></div><span className="text-[9px] font-bold text-slate-400 uppercase">Expired</span></div>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-x-12 gap-y-6">
            {(Object.entries(metrics.nationalityData) as [string, number][])
              .filter(([nat]) => (metrics.nationalityEscapeData[nat] || 0) > 0 || (metrics.nationalityExpiredData[nat] || 0) > 0)
              .sort((a, b) => {
                 const sumA = (metrics.nationalityEscapeData[a[0]] || 0) + (metrics.nationalityExpiredData[a[0]] || 0);
                 const sumB = (metrics.nationalityEscapeData[b[0]] || 0) + (metrics.nationalityExpiredData[b[0]] || 0);
                 return sumB - sumA;
