                         <div 
                           className="h-full bg-rose-500 hover:brightness-110 cursor-pointer transition-all" 
                           style={{ width: `${(escapeCount / maxProblemCount) * 100}%` }}
                           onClick={() => onDrillDown(`Escapes: ${nat}`, metrics.escapeRecords.filter(r => String(r[Object.keys(r).find(k => k.toLowerCase().includes('nationality')) || '']).trim() === (nat === 'Unspecified' ? '' : nat)))}
                           title={`View ${escapeCount} Escape Reports for ${nat}`}
