                       )}
                       {expiredCount > 0 && (
                         <div 
                           className="h-full bg-amber-500 hover:brightness-110 cursor-pointer transition-all border-l border-white/20" 
                           style={{ width: `${(expiredCount / maxProblemCount) * 100}%` }}
                           onClick={() => onDrillDown(`Expired Cards: ${nat}`, metrics.expiredRecords.filter(r => String(r[Object.keys(r).find(k => k.toLowerCase().includes('nationality')) || '']).trim() === (nat === 'Unspecified' ? '' : nat)))}
