  );

  function handleMonthClick(monthKey: string, label: string) {
    const filtered = rows.filter(r => {
      const dateKey = Object.keys(r).find(k => k.includes('(Date)'));
      if (!dateKey) return false;
      const parts = String(r[dateKey]).split(';')[0].trim().split('/');
      const d = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
      const k = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
      return k === monthKey;
    });
    onDrillDown(`Renewals for ${label}`, filtered);
  }
};

interface MetricCardProps {
  icon: React.ReactNode;
  title: string;
  value: number | string;
  color: 'rose' | 'amber' | 'emerald' | 'indigo';
  sub: string;
  onClick?: () => void;
}

const MetricCard: React.FC<MetricCardProps> = ({ icon, title, value, color, sub, onClick }) => {
  const colorMap = {
    rose: 'bg-rose-50 border-rose-100 hover:border-rose-300 text-rose-600',
    amber: 'bg-amber-50 border-amber-100 hover:border-amber-300 text-amber-600',
    emerald: 'bg-emerald-50 border-emerald-100 hover:border-emerald-300 text-emerald-600',
    indigo: 'bg-indigo-50 border-indigo-100 hover:border-indigo-300 text-indigo-600',
  };

  return (
    <div 
      onClick={onClick}
      className={`p-6 rounded-[32px] border shadow-sm transition-all hover:shadow-xl hover:-translate-y-1 cursor-pointer group bg-white ${colorMap[color].split(' text-')[0]}`}
    >
      <div className="flex items-center justify-between mb-4">
        <div className={`bg-white p-3 rounded-2xl shadow-sm group-hover:scale-110 transition-transform ${colorMap[color].split(' ')[1]}`}>
          {icon}
        </div>
        <ArrowRight size={14} className="text-slate-200 group-hover:text-slate-400 group-hover:translate-x-1 transition-all" />
      </div>
      <div>
        <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">{title}</h4>
        <div className="text-3xl font-black text-slate-800 tracking-tight">{value}</div>
        <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase">{sub}</p>
      </div>
    </div>
  );
};

