            <div className="flex items-center gap-4">
              <button onClick={() => setSortDesc(!sortDesc)} className="text-slate-400 hover:text-slate-800 transition-colors p-2 bg-slate-50 rounded-xl">
                {sortDesc ? <SortDesc size={18} /> : <SortAsc size={18} />}
              </button>
              <span className="bg-amber-50 text-amber-600 px-4 py-1.5 rounded-xl text-xs font-black border border-amber-100">
                {metrics.expiredCardCount} EXPIRED
              </span>
            </div>
          </div>
          <div className="bg-slate-50/50 rounded-[32px] overflow-hidden border border-slate-100 max-h-[350px] overflow-y-auto custom-scrollbar">
            <table className="w-full text-sm text-left">
              <thead className="bg-slate-100 sticky top-0 backdrop-blur-md">
                <tr>
                  <th className="px-6 py-4 text-slate-500 font-black uppercase text-[10px] tracking-widest">Employee Identity</th>
                  <th className="px-6 py-4 text-slate-500 font-black uppercase text-[10px] tracking-widest text-center">Expiry Date</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {sortedExpired.map((rec, i) => {
                  const dk = Object.keys(rec).find(k => k.includes('(Date)'));
                  return (
                    <tr key={i} className="hover:bg-white transition-colors">
                      <td className="px-6 py-4 text-slate-800 font-bold">{Object.values(rec)[0]}</td>
                      <td className="px-6 py-4 text-rose-500 font-black text-center text-xs">
                        {dk ? String(rec[dk]).split(';')[0].trim() : 'N/A'}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
          <button onClick={() => handleMetricClick("Expired Card List", metrics.expiredRecords)} className="w-full mt-6 py-4 bg-slate-900 hover:bg-black text-white text-xs font-black uppercase tracking-widest rounded-2xl transition-all shadow-lg active:scale-[0.98]">Expand Full Registry</button>
        </div>
      </div>
    </div>
  );

  function handleMonthClick(monthKey: string, label: string) {
    const filtered = rows.filter(r => {
      const dateKey = Object.keys(r).find(k => k.includes('(Date)'));
      if (!dateKey) return false;
      const parts = String(r[dateKey]).split(';')[0].trim().split('/');
      const d = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
      const k = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
      return k === monthKey;
    });
    onDrillDown(`Renewals for ${label}`, filtered);
  }
};

interface MetricCardProps {
  icon: React.ReactNode;
  title: string;
  value: number | string;
  color: 'rose' | 'amber' | 'emerald' | 'indigo';
