  const colorMap = {
    rose: 'bg-rose-50 border-rose-100 hover:border-rose-300 text-rose-600 shadow-rose-100/50',
    amber: 'bg-amber-50 border-amber-100 hover:border-amber-300 text-amber-600 shadow-amber-100/50',
    emerald: 'bg-emerald-50 border-emerald-100 hover:border-emerald-300 text-emerald-600 shadow-emerald-100/50',
    indigo: 'bg-indigo-50 border-indigo-100 hover:border-indigo-300 text-indigo-600 shadow-indigo-100/50',
