  return (
    <div 
      onClick={onClick}
      className={`p-8 rounded-[36px] border shadow-sm transition-all hover:shadow-2xl hover:-translate-y-1.5 cursor-pointer group bg-white ${colorMap[color].split(' shadow-')[0]}`}
    >
