        <KpiCard icon={<ShieldX />} label="Expired Cards" value={metrics.expiredCardCount} sub="Immediate Compliance Risk" color="amber" onClick={() => onDrillDown("Expired Registry", metrics.expiredRecords)} />
        <KpiCard icon={<CreditCard />} label="Active Workforce" value={metrics.activeCount} sub="Fully Compliant Employees" color="emerald" onClick={() => onDrillDown("Active Registry", rows.filter(r => !metrics.expiredRecords.includes(r)))} />
