  Users, 
  CreditCard, 
  AlertCircle, 
  Calendar, 
  Globe, 
  TrendingUp, 
  ShieldX,
  UserX,
  Briefcase,
  Layers,
  Activity,
  ArrowUpRight,
  Target,
  ChevronRight,
  BarChart,
  LayoutDashboard,
  ShieldCheck,
  Zap
} from 'lucide-react';
import { DataRow } from '../types';
import { extractDashboardMetrics } from '../utils/dataProcessor';

interface DashboardProps {
  rows: DataRow[];
  onDrillDown: (title: string, filteredRows: DataRow[]) => void;
}

const ELITE_COLORS = [
  '#6366f1', // Indigo
  '#06b6d4', // Cyan
  '#10b981', // Emerald
  '#f59e0b', // Amber
  '#ef4444', // Red
  '#8b5cf6', // Violet
  '#ec4899', // Pink
  '#f97316', // Orange
  '#3b82f6', // Blue
  '#14b8a6', // Teal
];

export const Dashboard: React.FC<DashboardProps> = ({ rows, onDrillDown }) => {
  const metrics = useMemo(() => extractDashboardMetrics(rows), [rows]);

  // Derived Management Metrics
  const complianceRate = useMemo(() => {
    if (metrics.total === 0) return 0;
    return (((metrics.total - metrics.expiredCardCount - metrics.escapeCount) / metrics.total) * 100).toFixed(1);
  }, [metrics]);

  const riskExposure = useMemo(() => {
    return metrics.expiredCardCount + metrics.escapeCount;
  }, [metrics]);

  // Status Chart Data (Expert Column Styling)
  const statusChartData = useMemo(() => {
    const entries = Object.entries(metrics.statusData) as [string, number][];
    const sorted = entries.sort((a, b) => b[1] - a[1]);
    const maxVal = Math.max(...sorted.map(e => e[1]), 1);

    return sorted.slice(0, 10).map(([status, count], index) => ({
      status,
      shortStatus: status.length > 15 ? status.substring(0, 12) + '..' : status,
      count,
      percent: ((count / metrics.total) * 100).toFixed(1),
      height: (count / maxVal) * 100,
      color: ELITE_COLORS[index % ELITE_COLORS.length]
    }));
  }, [metrics.statusData, metrics.total]);

  // Workforce Job List (Split into 2 Columns)
  const workforceGrid = useMemo(() => {
    const entries = Object.entries(metrics.jobDescriptionData) as [string, number][];
    const sorted = entries.sort((a, b) => b[1] - a[1]).slice(0, 16);
    const maxCount = Math.max(...sorted.map(e => e[1]), 1);

    const mid = Math.ceil(sorted.length / 2);
    return {
      left: sorted.slice(0, mid).map(e => ({ job: e[0], count: e[1], width: (e[1] / maxCount) * 100 })),
      right: sorted.slice(mid).map(e => ({ job: e[0], count: e[1], width: (e[1] / maxCount) * 100 }))
    };
  }, [metrics.jobDescriptionData]);

  // Nationality Compliance Vector
  const nationalityVector = useMemo(() => {
    return (Object.entries(metrics.nationalityData) as [string, number][])
      .sort((a, b) => b[1] - a[1])
      .slice(0, 12)
      .map(([nat, total]) => ({
        nat,
        total,
        escape: metrics.nationalityEscapeData[nat] || 0,
        expired: metrics.nationalityExpiredData[nat] || 0,
        clean: total - (metrics.nationalityEscapeData[nat] || 0) - (metrics.nationalityExpiredData[nat] || 0)
      }));
  }, [metrics]);

  const renewalForecast = useMemo(() => {
    const today = new Date();
    const months = [];
    const monthNames = ["JAN", "FEB", "MAR", "APR", "MAY", "JUN"];
    for (let i = 0; i < 6; i++) {
      const d = new Date(today.getFullYear(), today.getMonth() + i, 1);
      const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
      months.push({
        key,
        month: monthNames[i],
        year: d.getFullYear(),
        count: metrics.monthlyRenewals[key] || 0
      });
    }
    return months;
  }, [metrics.monthlyRenewals]);

  return (
    <div className="space-y-12 animate-in fade-in duration-1000 pb-24 w-full max-w-[2560px] mx-auto px-4">

      {/* 01. THE VITALITY STRIP (ELITE HEADER) */}
      <div className="bg-slate-900 rounded-[60px] p-12 shadow-2xl relative overflow-hidden flex flex-col xl:flex-row items-center justify-between gap-12">
        <div className="absolute top-0 right-0 w-[800px] h-[800px] bg-indigo-500/10 blur-[150px] -mr-96 -mt-96 rounded-full pointer-events-none"></div>

        <div className="relative z-10 space-y-4">
          <div className="flex items-center gap-4 text-indigo-400 font-black text-xs uppercase tracking-[0.4em]">
            <Zap size={18} />
            System Status: Optimal
          </div>
          <h2 className="text-5xl font-black text-white tracking-tighter leading-tight">Command Intelligence</h2>
          <p className="text-slate-400 font-medium text-lg max-w-2xl">High-precision workforce orchestration. Analyzing compliance gradients across {metrics.total} synchronized records.</p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 relative z-10 w-full xl:w-auto min-w-[600px]">
          <VitalityBox label="Global Compliance" value={`${complianceRate}%`} sub="+1.2% this quarter" icon={<ShieldCheck className="text-emerald-400" />} />
          <VitalityBox label="Active Risk" value={riskExposure} sub="Requires Attention" icon={<AlertCircle className="text-rose-400" />} />
          <VitalityBox label="Total Population" value={metrics.total} sub="Live Database" icon={<Users className="text-indigo-400" />} />
        </div>
      </div>

      {/* 02. PRIMARY PERFORMANCE METRICS */}
      <div className="grid grid-cols-1 sm:grid-cols-2 2xl:grid-cols-4 gap-8">
        <ProKpi icon={<UserX />} label="Escape Reports" value={metrics.escapeCount} color="rose" onClick={() => onDrillDown("Escape Registry", metrics.escapeRecords)} />
        <ProKpi icon={<ShieldX />} label="Expired Cards" value={metrics.expiredCardCount} color="amber" onClick={() => onDrillDown("Expired Registry", metrics.expiredRecords)} />
        <ProKpi icon={<CreditCard />} label="Valid Credentials" value={metrics.activeCount} color="emerald" onClick={() => onDrillDown("Active Registry", rows.filter(r => !metrics.expiredRecords.includes(r)))} />
        <ProKpi icon={<Activity />} label="Upcoming Renewals" value={metrics.upcomingRenewals} color="indigo" onClick={() => onDrillDown("Upcoming Renewals", [])} />
      </div>

      {/* 03. CORE ANALYTICS BENTO: STATUS & WORKFORCE */}
      <div className="grid grid-cols-1 2xl:grid-cols-2 gap-10">

        {/* STATUS CLUSTERS: VERTICAL COLUMN GRAPH (ELITE DESIGN) */}
        <div className="bg-white p-12 rounded-[56px] border border-slate-200 shadow-2xl flex flex-col min-h-[550px]">
          <div className="flex items-center justify-between mb-12">
            <div>
              <h3 className="text-2xl font-black text-slate-900 tracking-tight flex items-center gap-4">
                <BarChart className="text-indigo-600" size={32} />
                Status Clusters
              </h3>
              <p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em] mt-1 ml-12">Vertical Volumetric Analysis</p>
            </div>
            <div className="bg-slate-50 px-5 py-2.5 rounded-full border border-slate-100 shadow-sm">
              <span className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">Live Categories</span>
            </div>
          </div>

          <div className="flex-1 flex items-end justify-between gap-4 px-4 pb-4">
            {statusChartData.map((item) => (
              <div 
                key={item.status} 
                className="group relative flex flex-col items-center flex-1 h-full justify-end cursor-pointer"
                onClick={() => onDrillDown(`Status: ${item.status}`, rows.filter(r => String(r[Object.keys(r).find(k => k.toLowerCase().includes('status')) || '']).trim() === item.status))}
              >
                {/* Floating Value Tooltip */}
                <div className="absolute bottom-full mb-6 opacity-0 group-hover:opacity-100 transition-all duration-300 translate-y-2 group-hover:translate-y-0 z-20">
                  <div className="bg-slate-900 text-white px-4 py-3 rounded-2xl shadow-2xl text-xs font-black whitespace-nowrap border border-white/10">
                    <div className="text-indigo-400 mb-1">{item.status}</div>
                    <div className="flex items-center justify-between gap-6">
                      <span className="text-slate-500 uppercase text-[9px]">Headcount</span>
                      <span>{item.count}</span>
                    </div>
                  </div>
                  <div className="w-4 h-4 bg-slate-900 rotate-45 mx-auto -mt-2 border-r border-b border-white/10"></div>
                </div>

                <div className="text-[11px] font-black text-slate-400 mb-3 group-hover:text-slate-900 transition-colors">{item.count}</div>

                <div 
                  className="w-full rounded-2xl transition-all duration-500 ease-out shadow-xl group-hover:brightness-110 group-hover:-translate-y-2 relative overflow-hidden"
                  style={{ 
                    height: `${item.height}%`, 
                    background: `linear-gradient(to top, ${item.color}, ${item.color}ee)`,
                    minHeight: '8px'
                  }}
                >
                  <div className="absolute inset-0 bg-white/10 opacity-0 group-hover:opacity-100 transition-opacity"></div>
                </div>

                <div className="mt-6 text-center w-full">
                  <span className="text-[10px] font-black text-slate-500 uppercase block truncate px-1 group-hover:text-indigo-600 transition-colors" title={item.status}>
                    {item.shortStatus}
                  </span>
                  <span className="text-[9px] font-bold text-slate-300 uppercase mt-1 block">{item.percent}%</span>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* WORKFORCE DISTRIBUTION: DUAL COLUMN MATRIX */}
        <div className="bg-slate-50 p-12 rounded-[56px] border border-slate-200 shadow-inner flex flex-col">
          <div className="flex items-center justify-between mb-12">
            <div>
              <h3 className="text-2xl font-black text-slate-900 tracking-tight flex items-center gap-4">
                <Briefcase className="text-indigo-600" size={32} />
                Workforce Concentration
              </h3>
              <p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em] mt-1 ml-12">Split-Column Role Analysis</p>
            </div>
            <div className="bg-white px-5 py-2.5 rounded-2xl shadow-sm border border-slate-200">
               <span className="text-[10px] font-black text-slate-800 uppercase tracking-widest">Top 16 Roles</span>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-x-16 gap-y-10 flex-1">
            <JobCol items={workforceGrid.left} onDrillDown={onDrillDown} rows={rows} />
            <JobCol items={workforceGrid.right} onDrillDown={onDrillDown} rows={rows} />
          </div>
        </div>
      </div>

      {/* 04. NATIONALITY COMPLIANCE VECTOR (TOTAL COUNT INTEGRATED) */}
      <div className="grid grid-cols-1 2xl:grid-cols-3 gap-10">

        <div className="2xl:col-span-2 bg-white p-12 rounded-[56px] border border-slate-200 shadow-2xl relative overflow-hidden">
          <div className="flex items-center justify-between mb-12">
            <div>
              <h3 className="text-2xl font-black text-slate-900 tracking-tight flex items-center gap-4">
                <Globe className="text-indigo-600" size={32} />
                Nationality Compliance Vector
              </h3>
              <p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em] mt-1 ml-12">Absolute Headcount vs Risk Ratios</p>
            </div>
            <div className="flex items-center gap-10">
              <LegendItem label="Compliant" color="#10b981" />
              <LegendItem label="Expired" color="#f59e0b" />
              <LegendItem label="Escape" color="#ef4444" />
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-x-16 gap-y-10">
            {nationalityVector.map((data) => (
              <div key={data.nat} className="group p-6 rounded-[36px] hover:bg-slate-50 transition-all border border-transparent hover:border-slate-100 flex flex-col gap-4">
                <div className="flex justify-between items-end">
                  <div className="space-y-1">
                    <span className="text-lg font-black text-slate-800 uppercase tracking-tight block">{data.nat}</span>
                    <span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-3 py-1 rounded-full uppercase tracking-widest">
                      {data.total} Total Employees
                    </span>
                  </div>
                  <div className="text-right">
                    <div className="flex gap-4 mb-1">
                      {data.escape > 0 && <span className="text-[11px] font-black text-rose-500">{data.escape} ESC</span>}
                      {data.expired > 0 && <span className="text-[11px] font-black text-amber-500">{data.expired} EXP</span>}
                    </div>
                  </div>
                </div>

                <div className="h-4 w-full bg-slate-100 rounded-full flex overflow-hidden border border-slate-200 shadow-inner">
                  <Segment width={(data.clean / data.total) * 100} color="#10b981" />
                  <Segment width={(data.expired / data.total) * 100} color="#f59e0b" />
                  <Segment width={(data.escape / data.total) * 100} color="#ef4444" />
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* 6-MONTH RENEWAL PIPELINE (OPERATIONAL) */}
        <div className="bg-slate-900 p-12 rounded-[56px] flex flex-col shadow-2xl relative overflow-hidden text-white">
          <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-500/20 blur-[60px] rounded-full -mr-16 -mt-16"></div>

          <div className="flex items-center justify-between mb-12 relative z-10">
            <h3 className="text-2xl font-black tracking-tight flex items-center gap-4">
              <Calendar className="text-indigo-400" size={32} />
              Renewal Pipeline
            </h3>
            <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Op-View</span>
          </div>

          <div className="space-y-4 flex-1 overflow-auto custom-scrollbar pr-2 relative z-10">
            {renewalForecast.map((item) => (
              <div 
                key={item.key} 
                className="flex items-center gap-6 p-6 bg-white/5 hover:bg-white/10 rounded-[32px] border border-white/5 transition-all cursor-pointer group"
                onClick={() => handleMonthClick(item.key, `${item.month} ${item.year}`, rows, onDrillDown)}
              >
                <div className="w-16 h-16 bg-white/10 rounded-2xl flex flex-col items-center justify-center group-hover:bg-indigo-600 transition-all shadow-lg">
                  <span className="text-[10px] font-black text-slate-500 group-hover:text-white mb-1 leading-none">{item.year}</span>
                  <span className="text-lg font-black text-white">{item.month}</span>
                </div>
                <div className="flex-1">
                  <div className="text-slate-500 text-[10px] font-black uppercase tracking-[0.2em] mb-1">Expected Volume</div>
                  <div className="text-white text-xl font-bold">{item.count} Expiries</div>
                </div>
                <div className={`w-12 h-12 rounded-full flex items-center justify-center text-sm font-black ${item.count > 0 ? 'bg-indigo-500 text-white shadow-xl shadow-indigo-500/20' : 'bg-white/5 text-slate-700'}`}>
                  {item.count}
                </div>
              </div>
            ))}
          </div>
        </div>

      </div>
    </div>
  );
};

// HELPERS
