  <div className="p-8 bg-white/5 rounded-[40px] border border-white/10 group hover:bg-white/10 transition-all">
    <div className="flex items-center gap-3 mb-4">
      <div className="p-2.5 bg-white/5 rounded-xl group-hover:scale-110 transition-transform">{icon}</div>
      <span className="text-slate-400 text-[10px] font-black uppercase tracking-[0.2em]">{label}</span>
    </div>
    <div className="text-4xl font-black text-white mb-2 tracking-tighter">{value}</div>
    <div className="text-[10px] font-bold text-slate-500 uppercase">{sub}</div>
  </div>
);

const ProKpi = ({ icon, label, value, color, onClick }: any) => {
  const themes: any = {
    rose: 'text-rose-600 bg-rose-50 border-rose-100 shadow-rose-100',
    amber: 'text-amber-600 bg-amber-50 border-amber-100 shadow-amber-100',
    emerald: 'text-emerald-600 bg-emerald-50 border-emerald-100 shadow-emerald-100',
    indigo: 'text-indigo-600 bg-indigo-50 border-indigo-100 shadow-indigo-100',
  };
  return (
    <div 
      onClick={onClick}
      className={`p-10 bg-white rounded-[56px] border border-slate-200 shadow-xl hover:-translate-y-2 hover:shadow-2xl transition-all cursor-pointer group`}
    >
      <div className="flex justify-between items-start mb-8">
        <div className={`p-6 rounded-3xl shadow-lg group-hover:scale-110 transition-all ${themes[color].split(' ')[1]} ${themes[color].split(' ')[0]}`}>
          {React.cloneElement(icon, { size: 32 })}
        </div>
        <div className="w-12 h-12 rounded-full bg-slate-50 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-all translate-x-4 group-hover:translate-x-0">
