        <div className="flex items-center gap-2">
           <div className={`w-2 h-2 rounded-full ${themes[color].split(' ')[1].replace('bg-', 'bg-')}`} />
           <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Active Metric</p>
        </div>
      </div>
    </div>
  );
};

const JobCol = ({ items, onDrillDown, rows }: any) => (
  <div className="space-y-8">
    {items.map((item: any) => (
      <div 
        key={item.job} 
        className="group cursor-pointer flex items-center justify-between"
        onClick={() => onDrillDown(`Job Role: ${item.job}`, rows.filter((r: any) => String(r[Object.keys(r).find(k => k.toLowerCase().includes('job')) || '']).trim() === item.job))}
      >
        <div className="flex-1 pr-8">
          <div className="flex justify-between items-end mb-2.5">
            <span className="text-xs font-black text-slate-700 uppercase truncate group-hover:text-indigo-600 transition-colors" title={item.job}>{item.job}</span>
            <span className="text-[11px] font-black text-slate-900">{item.count}</span>
          </div>
          <div className="h-1.5 w-full bg-white rounded-full overflow-hidden shadow-sm border border-slate-100">
            <div className="h-full bg-slate-300 group-hover:bg-indigo-500 transition-all duration-700 origin-left" style={{ width: `${item.width}%` }} />
          </div>
        </div>
        <ChevronRight size={18} className="text-slate-200 group-hover:text-indigo-600 group-hover:translate-x-1 transition-all" />
      </div>
    ))}
  </div>
);

const LegendItem = ({ label, color }: { label: string, color: string }) => (
  <div className="flex items-center gap-3">
    <div className="w-3.5 h-3.5 rounded-full shadow-lg shadow-black/5" style={{ backgroundColor: color }}></div>
    <span className="text-[11px] font-black text-slate-500 uppercase tracking-widest">{label}</span>
  </div>
);

const Segment = ({ width, color }: { width: number, color: string }) => (
  <div 
    className="h-full transition-all duration-1000 ease-out" 
    style={{ width: `${width}%`, backgroundColor: color, minWidth: width > 0 ? '6px' : '0' }}
  />
);

function handleMonthClick(monthKey: string, label: string, rows: DataRow[], onDrillDown: any) {
  const filtered = rows.filter(r => {
    const dateKey = Object.keys(r).find(k => k.includes('(Date)'));
    if (!dateKey) return false;
    const parts = String(r[dateKey]).split(';')[0].trim().split('/');
    const d = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
    const k = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
    return k === monthKey;
  });
  onDrillDown(`Forecast: ${label}`, filtered);
}

import React, { useMemo, useState } from 'react';
import { 
  Users, 
  CreditCard, 
  AlertCircle, 
  Calendar, 
  Globe, 
  TrendingUp, 
  ShieldX,
  UserX,
  Briefcase,
  Layers,
  Activity,
  ArrowUpRight,
  Target,
  ChevronRight,
  BarChart,
  LayoutDashboard,
  ShieldCheck,
  Zap,
  Bike,
  MoreHorizontal
} from 'lucide-react';
import { DataRow } from '../types';
import { extractDashboardMetrics } from '../utils/dataProcessor';

interface DashboardProps {
  rows: DataRow[];
  onDrillDown: (title: string, filteredRows: DataRow[]) => void;
}

const ELITE_COLORS = [
  '#6366f1', // Indigo
  '#06b6d4', // Cyan
  '#10b981', // Emerald
  '#f59e0b', // Amber
  '#ef4444', // Red
  '#8b5cf6', // Violet
  '#ec4899', // Pink
  '#f97316', // Orange
  '#3b82f6', // Blue
  '#14b8a6', // Teal
];

export const Dashboard: React.FC<DashboardProps> = ({ rows, onDrillDown }) => {
  const metrics = useMemo(() => extractDashboardMetrics(rows), [rows]);

  // Derived Management Metrics
  const complianceRate = useMemo(() => {
    if (metrics.total === 0) return 0;
    return (((metrics.total - metrics.expiredCardCount - metrics.escapeCount) / metrics.total) * 100).toFixed(1);
  }, [metrics]);

  const riskExposure = useMemo(() => {
    return metrics.expiredCardCount + metrics.escapeCount;
  }, [metrics]);

  // Specialized Workforce Logic: Motorcyclist vs Others
  const workforceSplit = useMemo(() => {
    const jobKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase().includes('job') || k.toLowerCase().includes('description') || k.toLowerCase().includes('designation') || k.toLowerCase().includes('title'));

    let motorcyclistCount = 0;
    let othersCount = 0;
    const motorcyclistRows: DataRow[] = [];
    const othersRows: DataRow[] = [];

    rows.forEach(row => {
      const job = String(row[jobKey || ''] || '').toLowerCase();
      if (job.includes('motorcyclist') || job.includes('motorcycle') || job.includes('biker')) {
        motorcyclistCount++;
        motorcyclistRows.push(row);
      } else {
        othersCount++;
        othersRows.push(row);
      }
    });

    return {
      motorcyclist: { count: motorcyclistCount, rows: motorcyclistRows, percent: ((motorcyclistCount / rows.length) * 100).toFixed(1) },
      others: { count: othersCount, rows: othersRows, percent: ((othersCount / rows.length) * 100).toFixed(1) }
    };
  }, [rows]);

  // Status Cluster Logic: 2 Column Distribution
  const statusGrid = useMemo(() => {
    const entries = Object.entries(metrics.statusData) as [string, number][];
    const sorted = entries.sort((a, b) => b[1] - a[1]);
    const maxVal = Math.max(...sorted.map(e => e[1]), 1);

    const mapped = sorted.map(([status, count], index) => ({
      status,
      count,
      percent: ((count / metrics.total) * 100).toFixed(1),
      color: ELITE_COLORS[index % ELITE_COLORS.length],
      relativeWidth: (count / maxVal) * 100
    }));

    const mid = Math.ceil(mapped.length / 2);
    return {
      left: mapped.slice(0, mid),
      right: mapped.slice(mid, 12) // Limit to top 12 for high density
    };
  }, [metrics.statusData, metrics.total]);

  // Nationality Compliance Vector: Column-based Risk
  const nationalityVector = useMemo(() => {
    return (Object.entries(metrics.nationalityData) as [string, number][])
      .sort((a, b) => b[1] - a[1])
      .slice(0, 10) // Focus on top 10 for column clarity
      .map(([nat, total]) => ({
        nat,
        total,
        escape: metrics.nationalityEscapeData[nat] || 0,
        expired: metrics.nationalityExpiredData[nat] || 0,
        clean: total - (metrics.nationalityEscapeData[nat] || 0) - (metrics.nationalityExpiredData[nat] || 0),
        maxH: Math.max(total, 1)
      }));
