function handleMonthClick(monthKey: string, label: string, rows: DataRow[], onDrillDown: any) {
  const filtered = rows.filter(r => {
    const dateKey = Object.keys(r).find(k => k.includes('(Date)'));
    if (!dateKey) return false;
    const parts = String(r[dateKey]).split(';')[0].trim().split('/');
    const d = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
    const k = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
    return k === monthKey;
  });
  onDrillDown(`Forecast: ${label}`, filtered);
}

import React, { useMemo, useState } from 'react';
import { 
  Users, 
  CreditCard, 
  AlertCircle, 
  Calendar, 
  Globe, 
  TrendingUp, 
  ShieldX,
  UserX,
  Briefcase,
  Layers,
  Activity,
  ArrowUpRight,
  Target,
  ChevronRight,
  BarChart,
  LayoutDashboard,
  ShieldCheck,
  Zap,
  Bike,
  MoreHorizontal
} from 'lucide-react';
import { DataRow } from '../types';
import { extractDashboardMetrics } from '../utils/dataProcessor';

interface DashboardProps {
  rows: DataRow[];
  onDrillDown: (title: string, filteredRows: DataRow[]) => void;
}

const ELITE_COLORS = [
  '#6366f1', // Indigo
  '#06b6d4', // Cyan
  '#10b981', // Emerald
  '#f59e0b', // Amber
  '#ef4444', // Red
  '#8b5cf6', // Violet
  '#ec4899', // Pink
  '#f97316', // Orange
  '#3b82f6', // Blue
  '#14b8a6', // Teal
];

export const Dashboard: React.FC<DashboardProps> = ({ rows, onDrillDown }) => {
  const metrics = useMemo(() => extractDashboardMetrics(rows), [rows]);

  // Derived Management Metrics
  const complianceRate = useMemo(() => {
    if (metrics.total === 0) return 0;
    return (((metrics.total - metrics.expiredCardCount - metrics.escapeCount) / metrics.total) * 100).toFixed(1);
  }, [metrics]);

  const riskExposure = useMemo(() => {
    return metrics.expiredCardCount + metrics.escapeCount;
  }, [metrics]);

  // Specialized Workforce Logic: Motorcyclist vs Others
  const workforceSplit = useMemo(() => {
    const jobKey = Object.keys(rows[0] || {}).find(k => 
      k.toLowerCase().includes('job') || 
      k.toLowerCase().includes('description') || 
      k.toLowerCase().includes('designation') || 
      k.toLowerCase().includes('title')
    );

    let motorcyclistCount = 0;
    let othersCount = 0;
    const motorcyclistRows: DataRow[] = [];
    const othersRows: DataRow[] = [];

    rows.forEach(row => {
      const job = String(row[jobKey || ''] || '').toLowerCase();
      if (job.includes('motorcyclist') || job.includes('motorcycle') || job.includes('biker') || job.includes('bike')) {
        motorcyclistCount++;
        motorcyclistRows.push(row);
      } else {
        othersCount++;
        othersRows.push(row);
      }
    });

    return {
      motorcyclist: { count: motorcyclistCount, rows: motorcyclistRows, percent: ((motorcyclistCount / Math.max(rows.length, 1)) * 100).toFixed(1) },
      others: { count: othersCount, rows: othersRows, percent: ((othersCount / Math.max(rows.length, 1)) * 100).toFixed(1) }
    };
  }, [rows]);

  // Status Cluster Logic: Professional 2-Column Grid
  const statusGridData = useMemo(() => {
    const entries = Object.entries(metrics.statusData) as [string, number][];
    const sorted = entries.sort((a, b) => b[1] - a[1]);
    const maxVal = Math.max(...sorted.map(e => e[1]), 1);

    const mapped = sorted.map(([status, count], index) => ({
      status,
      count,
      percent: ((count / metrics.total) * 100).toFixed(1),
      color: ELITE_COLORS[index % ELITE_COLORS.length],
      relativeWidth: (count / maxVal) * 100
    }));

    const mid = Math.ceil(mapped.length / 2);
    return {
      left: mapped.slice(0, mid),
      right: mapped.slice(mid, 14) // Limit to top 14 items for clarity
    };
  }, [metrics.statusData, metrics.total]);

  // Nationality Compliance Vector: High-Impact Vertical Columns
  const nationalityVector = useMemo(() => {
    return (Object.entries(metrics.nationalityData) as [string, number][])
      .sort((a, b) => b[1] - a[1])
      .slice(0, 12) // Top 12 nationalities for high-resolution displays
      .map(([nat, total]) => ({
        nat,
        total,
        escape: metrics.nationalityEscapeData[nat] || 0,
        expired: metrics.nationalityExpiredData[nat] || 0,
        clean: total - (metrics.nationalityEscapeData[nat] || 0) - (metrics.nationalityExpiredData[nat] || 0)
      }));
  }, [metrics]);

  const renewalForecast = useMemo(() => {
    const today = new Date();
    const months = [];
    const monthNames = ["JAN", "FEB", "MAR", "APR", "MAY", "JUN"];
    for (let i = 0; i < 6; i++) {
      const d = new Date(today.getFullYear(), today.getMonth() + i, 1);
      const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
      months.push({
        key,
        month: monthNames[i],
        year: d.getFullYear(),
        count: metrics.monthlyRenewals[key] || 0
      });
    }
    return months;
  }, [metrics.monthlyRenewals]);

  return (
    <div className="space-y-12 animate-in fade-in duration-1000 pb-24 w-full max-w-[2560px] mx-auto px-4">

      {/* 01. ELITE COMMAND HEADER (BIG SCREEN FIX) */}
      <div className="bg-slate-900 rounded-[60px] p-12 shadow-2xl relative overflow-hidden flex flex-col xl:flex-row items-center justify-between gap-12 border border-white/5">
        <div className="absolute top-0 right-0 w-[800px] h-[800px] bg-indigo-500/10 blur-[150px] -mr-96 -mt-96 rounded-full pointer-events-none"></div>

        <div className="relative z-10 space-y-4">
          <div className="flex items-center gap-4 text-indigo-400 font-black text-xs uppercase tracking-[0.4em]">
            <Zap size={18} />
            Executive Oversight Protocol
          </div>
          <h2 className="text-5xl font-black text-white tracking-tighter leading-tight">Management Command Center</h2>
          <p className="text-slate-400 font-medium text-lg max-w-2xl">High-precision organizational intelligence. Monitoring compliance vectors and workforce distribution across all synchronized records.</p>
        </div>

