function handleMonthClick(monthKey: string, label: string, rows: DataRow[], onDrillDown: any) {
  const filtered = rows.filter(r => {
    const dateKey = Object.keys(r).find(k => k.includes('(Date)'));
    if (!dateKey) return false;
    const parts = String(r[dateKey]).split(';')[0].trim().split('/');
    const d = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
    const k = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
    return k === monthKey;
  });
  onDrillDown(`Forecast: ${label}`, filtered);
}

import React, { useMemo } from 'react';
import { 
  Users, 
  CreditCard, 
  AlertCircle, 
