import React, { useMemo } from 'react';
import { 
  Users, 
  CreditCard, 
  AlertCircle, 
  Globe, 
  ShieldX,
  UserX,
  Layers,
  Activity,
  ArrowUpRight,
  Target,
  ChevronRight,
  Zap,
  Bike,
  ShieldCheck,
  MoreHorizontal,
  Download,
  Calendar
} from 'lucide-react';
import { DataRow } from '../types';
import { extractDashboardMetrics } from '../utils/dataProcessor';

interface DashboardProps {
  rows: DataRow[];
  onDrillDown: (title: string, filteredRows: DataRow[]) => void;
}

const BRAND_COLORS = [
  '#6366f1', // Indigo
  '#06b6d4', // Cyan
  '#10b981', // Emerald
  '#f59e0b', // Amber
  '#ef4444', // Red
  '#8b5cf6', // Violet
];

export const Dashboard: React.FC<DashboardProps> = ({ rows, onDrillDown }) => {
  const metrics = useMemo(() => extractDashboardMetrics(rows), [rows]);

  // Workforce Segmentation: Motorcyclist vs Staff & Support
  const workforceSplit = useMemo(() => {
    const jobKey = Object.keys(rows[0] || {}).find(k => 
      k.toLowerCase().includes('job') || 
      k.toLowerCase().includes('description') || 
      k.toLowerCase().includes('designation') || 
      k.toLowerCase().includes('title')
    );

    const motorcyclistRows: DataRow[] = [];
    const staffSupportRows: DataRow[] = [];

    rows.forEach(row => {
      const job = String(row[jobKey || ''] || '').toLowerCase();
      if (job.includes('motorcyclist') || job.includes('motorcycle') || job.includes('biker') || job.includes('bike')) {
        motorcyclistRows.push(row);
      } else {
        staffSupportRows.push(row);
      }
    });

    return {
      motorcyclist: { 
        count: motorcyclistRows.length, 
        rows: motorcyclistRows, 
        percent: ((motorcyclistRows.length / Math.max(rows.length, 1)) * 100).toFixed(1) 
      },
      staffSupport: { 
        count: staffSupportRows.length, 
        rows: staffSupportRows, 
        percent: ((staffSupportRows.length / Math.max(rows.length, 1)) * 100).toFixed(1) 
      }
    };
  }, [rows]);

  // 6-Month Renewal Forecast
  const renewalForecast = useMemo(() => {
    const today = new Date();
    const months = [];
    const monthNames = ["JAN", "FEB", "MAR", "APR", "MAY", "JUN", "JUL", "AUG", "SEP", "OCT", "NOV", "DEC"];

    for (let i = 0; i < 6; i++) {
      const d = new Date(today.getFullYear(), today.getMonth() + i, 1);
      const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
      months.push({
        key,
        month: monthNames[d.getMonth()],
        year: d.getFullYear(),
        count: metrics.monthlyRenewals[key] || 0
      });
    }
    return months;
  }, [metrics.monthlyRenewals]);

  // Status Cluster Layout
  const statusGridData = useMemo(() => {
    const entries = Object.entries(metrics.statusData) as [string, number][];
    const sorted = entries.sort((a, b) => b[1] - a[1]);
    const maxVal = Math.max(...sorted.map(e => e[1]), 1);

    const mapped = sorted.map(([status, count], index) => ({
      status,
      count,
      percent: ((count / metrics.total) * 100).toFixed(1),
      color: BRAND_COLORS[index % BRAND_COLORS.length],
      relativeWidth: (count / maxVal) * 100
    }));

    const mid = Math.ceil(mapped.length / 2);
    return { left: mapped.slice(0, mid), right: mapped.slice(mid, 14) };
  }, [metrics.statusData, metrics.total]);

  const complianceRate = useMemo(() => {
    if (metrics.total === 0) return 0;
    return (((metrics.total - metrics.expiredCardCount - metrics.escapeCount) / metrics.total) * 100).toFixed(1);
  }, [metrics]);

  return (
    <div className="space-y-12 animate-in fade-in duration-1000 pb-24 w-full max-w-[2560px] mx-auto px-4">

      {/* 01. MASTER COMMAND HEADER */}
      <div className="bg-slate-900 rounded-[60px] p-12 shadow-2xl relative overflow-hidden flex flex-col xl:flex-row items-center justify-between gap-12 border border-white/5">
        <div className="absolute top-0 right-0 w-[800px] h-[800px] bg-indigo-500/10 blur-[150px] -mr-96 -mt-96 rounded-full pointer-events-none"></div>
        <div className="relative z-10 space-y-4">
          <div className="flex items-center gap-4 text-indigo-400 font-black text-xs uppercase tracking-[0.4em]">
            <Zap size={18} />
            Corporate Intelligence Unit
          </div>
          <h2 className="text-5xl font-black text-white tracking-tighter leading-tight">Elite Workforce Command</h2>
          <p className="text-slate-400 font-medium text-lg max-w-2xl">Executive oversight across {metrics.total} professional profiles. Identifying operational risks and compliance vectors in real-time.</p>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 relative z-10 w-full xl:w-auto min-w-[650px]">
          <VitalityBox label="Health Index" value={`${complianceRate}%`} sub="Global Integrity" icon={<ShieldCheck className="text-emerald-400" />} />
          <VitalityBox label="Priority Risk" value={metrics.expiredCardCount + metrics.escapeCount} sub="Immediate Action" icon={<AlertCircle className="text-rose-400" />} />
          <VitalityBox label="Global Census" value={metrics.total} sub="Total Personnel" icon={<Users className="text-indigo-400" />} />
        </div>
      </div>

      {/* 02. PRIMARY STRATEGIC HEADERS (NOW WITH MOTORCYCLIST & STAFF) */}
      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8">
        <ProKpi icon={<UserX />} label="Escape Reports" value={metrics.escapeCount} color="rose" onClick={() => onDrillDown("Escape Registry", metrics.escapeRecords)} />
        <ProKpi icon={<ShieldX />} label="Expired Credentials" value={metrics.expiredCardCount} color="amber" onClick={() => onDrillDown("Expired Registry", metrics.expiredRecords)} />
        <ProKpi icon={<Bike />} label="Motorcyclists" value={workforceSplit.motorcyclist.count} color="indigo" showDownload onClick={() => onDrillDown("Motorcyclist Registry", workforceSplit.motorcyclist.rows)} />
        <ProKpi icon={<MoreHorizontal />} label="Staff & Support" value={workforceSplit.staffSupport.count} color="slate" showDownload onClick={() => onDrillDown("Staff & Support Registry", workforceSplit.staffSupport.rows)} />
        <ProKpi icon={<CreditCard />} label="Active Personnel" value={metrics.activeCount} color="emerald" onClick={() => onDrillDown("Compliant Active Records", rows.filter(r => !metrics.expiredRecords.includes(r)))} />
        <ProKpi icon={<Activity />} label="Upcoming Renewals" value={metrics.upcomingRenewals} color="indigo" onClick={() => onDrillDown("Upcoming (30 Days)", [])} />
      </div>

      {/* 03. ROLE CONCENTRATION HEROES */}
      <div className="grid grid-cols-1 2xl:grid-cols-2 gap-10">
        <div className="bg-white p-12 rounded-[56px] border border-slate-200 shadow-2xl flex flex-col">
          <div className="flex items-center justify-between mb-12">
            <div>
              <h3 className="text-2xl font-black text-slate-900 tracking-tight flex items-center gap-4">
                <Layers className="text-indigo-600" size={32} />
                Status Clusters
              </h3>
              <p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em] mt-1 ml-12">Categorical Compliance Weighting</p>
            </div>
          </div>
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-x-12 gap-y-6 flex-1">
            <div className="space-y-6">
              {statusGridData.left.map((item) => (
                <StatusRow key={item.status} item={item} onDrillDown={onDrillDown} rows={rows} />
              ))}
            </div>
            <div className="space-y-6 lg:border-l lg:border-slate-100 lg:pl-12">
              {statusGridData.right.map((item) => (
                <StatusRow key={item.status} item={item} onDrillDown={onDrillDown} rows={rows} />
              ))}
            </div>
          </div>
        </div>

        <div className="bg-slate-900 p-12 rounded-[56px] shadow-2xl flex flex-col relative overflow-hidden">
          <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-500/10 blur-[100px] rounded-full"></div>
          <div className="flex items-center justify-between mb-12">
            <h3 className="text-2xl font-black text-white tracking-tight flex items-center gap-4">
              <Target className="text-indigo-400" size={32} />
              Concentration Drilldown
            </h3>
            <div className="bg-white/5 px-5 py-2.5 rounded-2xl border border-white/10 text-[10px] font-black text-white uppercase tracking-widest">
              Core Segments
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-10 flex-1">
            <WorkforceHero 
              icon={<Bike size={44} />} 
              label="Motorcyclists" 
              count={workforceSplit.motorcyclist.count} 
              percent={workforceSplit.motorcyclist.percent} 
              color="#6366f1"
              onClick={() => onDrillDown("Motorcyclist Registry", workforceSplit.motorcyclist.rows)}
            />
            <WorkforceHero 
              icon={<Users size={44} />} 
              label="Staff & Support" 
              count={workforceSplit.staffSupport.count} 
              percent={workforceSplit.staffSupport.percent} 
              color="#94a3b8"
              onClick={() => onDrillDown("Staff & Support Registry", workforceSplit.staffSupport.rows)}
            />
          </div>
        </div>
      </div>

      {/* 04. 6-MONTH RENEWAL PIPELINE */}
      <div className="bg-white p-12 rounded-[60px] border border-slate-200 shadow-2xl relative overflow-hidden">
        <div className="flex items-center justify-between mb-12">
          <div>
            <h3 className="text-3xl font-black text-slate-900 tracking-tighter flex items-center gap-4">
              <Calendar className="text-indigo-600" size={40} />
              6-Month Operational Renewal Pipeline
            </h3>
            <p className="text-[11px] text-slate-400 font-black uppercase tracking-[0.4em] mt-2 ml-14">Projected Resource Requirements</p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8">
          {renewalForecast.map((item) => (
            <div 
              key={item.key} 
              className="group p-10 bg-slate-50 hover:bg-white rounded-[48px] border border-slate-100 hover:border-indigo-200 hover:shadow-2xl transition-all cursor-pointer flex items-center justify-between relative overflow-hidden"
              onClick={() => handleMonthClick(item.key, `${item.month} ${item.year}`, rows, onDrillDown)}
            >
              <div className="absolute top-0 right-0 w-24 h-24 bg-indigo-500/5 blur-2xl rounded-full group-hover:bg-indigo-500/10 transition-colors"></div>
              <div className="flex items-center gap-8">
                <div className="w-20 h-20 bg-white rounded-[24px] shadow-lg flex flex-col items-center justify-center group-hover:bg-indigo-600 transition-all border border-slate-100 group-hover:border-indigo-500">
                  <span className="text-[10px] font-black text-slate-400 group-hover:text-white/70 uppercase mb-0.5">{item.year}</span>
                  <span className="text-2xl font-black text-slate-900 group-hover:text-white">{item.month}</span>
                </div>
                <div>
                  <div className="text-slate-400 text-[11px] font-black uppercase tracking-[0.2em] mb-1">Expected Batch</div>
                  <div className="text-5xl font-black text-slate-900 tracking-tighter group-hover:text-indigo-600 transition-colors">{item.count}</div>
                </div>
              </div>
              <div className="w-14 h-14 rounded-full flex items-center justify-center text-slate-300 group-hover:bg-indigo-50 group-hover:text-indigo-600 transition-all">
                <Download size={24} />
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* 05. NATIONALITY COMPLIANCE */}
      <div className="bg-slate-900 p-12 rounded-[60px] shadow-2xl relative overflow-hidden">
        <div className="absolute top-0 right-0 w-96 h-96 bg-indigo-500/5 blur-[120px] rounded-full"></div>
        <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-8 mb-16 relative z-10">
          <div>
            <h3 className="text-3xl font-black text-white tracking-tighter flex items-center gap-4">
