          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-x-12 gap-y-10 relative z-10">
          {(Object.entries(metrics.nationalityData) as [string, number][])
            .sort((a, b) => b[1] - a[1])
            .slice(0, 15)
            .map(([nat, total]) => {
              const escape = metrics.nationalityEscapeData[nat] || 0;
              const expired = metrics.nationalityExpiredData[nat] || 0;
              const clean = total - escape - expired;
              return (
                <div key={nat} className="group p-8 bg-white/5 hover:bg-white/10 rounded-[40px] border border-white/5 hover:border-white/10 transition-all cursor-pointer" onClick={() => onDrillDown(`Nationality: ${nat}`, rows.filter(r => String(r[Object.keys(r).find(k => k.toLowerCase().includes('nationality')) || '']).trim() === nat))}>
                  <div className="flex justify-between items-start mb-6">
                    <div>
                      <span className="text-lg font-black text-white uppercase tracking-tight block">{nat}</span>
                      <span className="text-[10px] font-black text-indigo-400 uppercase tracking-widest bg-indigo-500/10 px-3 py-1 rounded-full mt-2 inline-block">
                        {total} Total Records
                      </span>
                    </div>
                    <div className="text-right flex gap-3">
                      {escape > 0 && <span className="text-[11px] font-black text-rose-400">{escape} ESC</span>}
                      {expired > 0 && <span className="text-[11px] font-black text-amber-400">{expired} EXP</span>}
                    </div>
                  </div>
                  <div className="h-3 w-full bg-white/5 rounded-full flex overflow-hidden shadow-inner border border-white/5">
                    <Segment width={(clean / total) * 100} color="#10b981" />
                    <Segment width={(expired / total) * 100} color="#f59e0b" />
                    <Segment width={(escape / total) * 100} color="#ef4444" />
                  </div>
                </div>
              );
            })}
        </div>
      </div>
    </div>
  );
};

