    const maxVal = Math.max(...sorted.map(e => e[1]), 1);

    const mapped = sorted.map(([status, count], index) => ({
      status,
      count,
      percent: ((count / metrics.total) * 100).toFixed(1),
      color: BRAND_COLORS[index % BRAND_COLORS.length],
      relativeWidth: (count / maxVal) * 100
    }));

    return {
      col1: mapped.slice(0, Math.ceil(mapped.length / 3)),
      col2: mapped.slice(Math.ceil(mapped.length / 3), Math.ceil(mapped.length / 3) * 2),
      col3: mapped.slice(Math.ceil(mapped.length / 3) * 2, 18)
