            <LegendItem label="Expired" color="#f59e0b" />
            <LegendItem label="Escape" color="#ef4444" />
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-x-12 gap-y-10 relative z-10">
          {(Object.entries(metrics.nationalityData) as [string, number][])
            .sort((a, b) => b[1] - a[1])
            .slice(0, 15)
            .map(([nat, total]) => {
              const escape = metrics.nationalityEscapeData[nat] || 0;
              const expired = metrics.nationalityExpiredData[nat] || 0;
              const clean = total - escape - expired;
              return (
                <div key={nat} className="group p-8 bg-slate-50/50 hover:bg-white rounded-[40px] border border-transparent hover:border-slate-200 hover:shadow-xl transition-all cursor-pointer" onClick={() => onDrillDown(`Nationality: ${nat}`, rows.filter(r => String(r[Object.keys(r).find(k => k.toLowerCase().includes('nationality')) || '']).trim() === nat))}>
                  <div className="flex justify-between items-start mb-6">
                    <div>
                      <span className="text-lg font-black text-slate-900 uppercase tracking-tight block">{nat}</span>
                      <span className="text-[10px] font-black text-indigo-500 uppercase tracking-widest bg-indigo-50 px-3 py-1 rounded-full mt-2 inline-block">
                        {total} Total Headcount
                      </span>
                    </div>
                    <div className="text-right flex gap-3">
                      {escape > 0 && <span className="text-[11px] font-black text-rose-500">{escape} ESC</span>}
                      {expired > 0 && <span className="text-[11px] font-black text-amber-500">{expired} EXP</span>}
                    </div>
                  </div>
                  <div className="h-4 w-full bg-slate-200 rounded-full flex overflow-hidden shadow-inner border border-white">
                    <Segment width={(clean / total) * 100} color="#10b981" />
                    <Segment width={(expired / total) * 100} color="#f59e0b" />
                    <Segment width={(escape / total) * 100} color="#ef4444" />
                  </div>
                </div>
              );
            })}
        </div>
      </div>
    </div>
  );
};

