        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-x-12 gap-y-10 relative z-10">
          {(Object.entries(metrics.nationalityData) as [string, number][])
            .sort((a, b) => b[1] - a[1])
            .slice(0, 15)
            .map(([nat, total]) => {
              const escape = metrics.nationalityEscapeData[nat] || 0;
              const expired = metrics.nationalityExpiredData[nat] || 0;
              const clean = total - escape - expired;
              return (
                <div key={nat} className="group p-8 bg-slate-50/50 hover:bg-white rounded-[40px] border border-transparent hover:border-slate-200 hover:shadow-xl transition-all cursor-pointer" onClick={() => onDrillDown(`Nationality: ${nat}`, rows.filter(r => String(r[Object.keys(r).find(k => k.toLowerCase().includes('nationality')) || '']).trim() === nat))}>
