            <Zap size={18} />
            Command Intelligence Hub
          </div>
          <h2 className="text-6xl font-black text-white tracking-tighter leading-tight">Workforce Master<br/>Synchronization</h2>
          <p className="text-slate-400 font-medium text-lg max-w-2xl leading-relaxed">System-wide auditing of {metrics.total} professional entities. Real-time vector analysis across multiple operational dimensions.</p>
