import React, { useState, useMemo } from 'react';
import * as XLSX from 'xlsx';
import { 
  FileUp, 
  Table, 
  LayoutGrid, 
  Sparkles, 
  Download, 
  RefreshCw,
  Search,
  Database,
  BarChart3,
  PieChart,
  X,
  FileSpreadsheet,
  Building2,
  ChevronDown,
  Plus
} from 'lucide-react';
import { DataRow, ProcessedData, CompanyDataset } from './types';
import { harmonizeData } from './utils/dataProcessor';
import { DataTable } from './components/DataTable';
import { PivotView } from './components/PivotView';
import { Dashboard } from './components/Dashboard';
import { generateDataSummary } from './services/gemini';

const App: React.FC = () => {
  const [companyDatasets, setCompanyDatasets] = useState<CompanyDataset[]>([]);
  const [selectedCompanyId, setSelectedCompanyId] = useState<string>('all');
  const [activeTab, setActiveTab] = useState<'preview' | 'pivot' | 'dashboard' | 'ai'>('dashboard');
  const [isProcessing, setIsProcessing] = useState(false);
  const [aiSummary, setAiSummary] = useState<string>('');
  const [searchTerm, setSearchTerm] = useState('');
  const [isGeneratingAi, setIsGeneratingAi] = useState(false);

  // Upload Modal State
  const [pendingUpload, setPendingUpload] = useState<ProcessedData | null>(null);
  const [newCompanyName, setNewCompanyName] = useState('');

  // Drill-down State
  const [drillDownData, setDrillDownData] = useState<{ title: string; rows: DataRow[] } | null>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const data = XLSX.utils.sheet_to_json(ws) as DataRow[];
        const harmonized = harmonizeData(data);
        setPendingUpload(harmonized);
        setNewCompanyName(file.name.split('.')[0]); // Default to filename
      } catch (err) {
        console.error("Error reading file", err);
        alert("Failed to read file. Please ensure it is a valid Excel or CSV.");
      } finally {
        setIsProcessing(false);
        // Reset file input
        e.target.value = '';
      }
    };
    reader.readAsBinaryString(file);
  };

  const confirmUpload = () => {
    if (!pendingUpload || !newCompanyName.trim()) return;
    const newEntry: CompanyDataset = {
      id: crypto.randomUUID(),
      name: newCompanyName.trim(),
      data: pendingUpload
    };
    setCompanyDatasets(prev => [...prev, newEntry]);
    setSelectedCompanyId(newEntry.id);
    setPendingUpload(null);
    setNewCompanyName('');
    setActiveTab('dashboard');
  };

  const activeDataRows = useMemo(() => {
    if (companyDatasets.length === 0) return [];
    if (selectedCompanyId === 'all') {
      return companyDatasets.flatMap(ds => ds.data.rows);
    }
    return companyDatasets.find(ds => ds.id === selectedCompanyId)?.data.rows || [];
  }, [companyDatasets, selectedCompanyId]);

  const activeHeaders = useMemo(() => {
    if (companyDatasets.length === 0) return [];
    if (selectedCompanyId === 'all') {
      // Return unique headers from all sets, prioritizing the first one
      const allHeaders = new Set<string>();
      companyDatasets.forEach(ds => ds.data.headers.forEach(h => allHeaders.add(h)));
      return Array.from(allHeaders);
    }
    return companyDatasets.find(ds => ds.id === selectedCompanyId)?.data.headers || [];
  }, [companyDatasets, selectedCompanyId]);

  const filteredRows = useMemo(() => {
    if (!searchTerm) return activeDataRows;
    const lowerSearch = searchTerm.toLowerCase();
    return activeDataRows.filter(row => 
      Object.values(row).some(val => String(val).toLowerCase().includes(lowerSearch))
    );
  }, [activeDataRows, searchTerm]);

  const handleExport = (dataToExport?: DataRow[], fileName?: string) => {
    const rowsToExport = dataToExport || activeDataRows;
    if (rowsToExport.length === 0) return;

    const worksheet = XLSX.utils.json_to_sheet(rowsToExport);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "Data");
    const name = fileName || `Master_Export_${new Date().getTime()}`;
    XLSX.writeFile(workbook, `${name}.xlsx`);
  };

  const handleDrillDown = (title: string, rows: DataRow[]) => {
    setDrillDownData({ title, rows });
  };

  const generateAiWriteup = async () => {
    if (activeDataRows.length === 0) return;
    setIsGeneratingAi(true);
    const summary = await generateDataSummary(activeDataRows);
    setAiSummary(summary);
    setIsGeneratingAi(false);
  };

  const removeCompany = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setCompanyDatasets(prev => prev.filter(ds => ds.id !== id));
    if (selectedCompanyId === id) setSelectedCompanyId('all');
  };

  return (
    <div className="min-h-screen flex flex-col font-sans bg-slate-50/50">
      {/* Upload Confirmation Modal */}
      {pendingUpload && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-md rounded-[40px] shadow-2xl p-10 space-y-8 animate-in zoom-in-95 duration-300">
            <div className="text-center space-y-2">
              <div className="bg-indigo-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4">
                <Building2 className="text-indigo-600" size={32} />
              </div>
              <h3 className="text-2xl font-black text-slate-800 tracking-tight">Set Company Identity</h3>
              <p className="text-slate-400 text-sm font-medium">Define the organization name for this dataset</p>
            </div>
            <div className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Company Name</label>
                <input 
                  autoFocus
                  type="text"
                  className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-lg font-bold focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 outline-none transition-all"
                  value={newCompanyName}
                  onChange={(e) => setNewCompanyName(e.target.value)}
                  placeholder="Enter Organization..."
                  onKeyDown={(e) => e.key === 'Enter' && confirmUpload()}
                />
              </div>
            </div>
            <div className="flex gap-4">
              <button 
                onClick={() => setPendingUpload(null)}
                className="flex-1 py-4 text-slate-500 font-black uppercase text-xs tracking-widest hover:bg-slate-50 rounded-2xl transition-all"
              >
                Discard
              </button>
              <button 
                onClick={confirmUpload}
