              <div className="grid grid-cols-2 gap-3">
                <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                  <div className="text-lg font-black text-slate-800">{activeDataRows.length}</div>
                  <div className="text-[9px] text-slate-400 uppercase font-bold">Rows</div>
