        </aside>

        {/* Content Area */}
        <section className="flex-1 overflow-auto p-10 custom-scrollbar relative">
          {companyDatasets.length === 0 && !isProcessing && (
            <div className="h-full flex flex-col items-center justify-center text-center max-w-lg mx-auto">
              <div className="bg-white p-12 rounded-[40px] shadow-2xl border border-slate-100 mb-8 relative overflow-hidden">
                <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-indigo-500 to-purple-500"></div>
                <div className="bg-indigo-50 w-24 h-24 rounded-full flex items-center justify-center mx-auto mb-8 shadow-inner">
                  <BarChart3 size={48} className="text-indigo-600" />
                </div>
                <h2 className="text-3xl font-black text-slate-800 mb-4">Multi-Company Registry</h2>
                <p className="text-slate-500 mb-10 leading-relaxed text-lg">
                  Professional multi-organization data engine. Your synchronized data is stored locally and will persist even after a system refresh.
                </p>
                <label className="inline-flex items-center gap-3 bg-indigo-600 hover:bg-indigo-700 text-white px-10 py-4 rounded-2xl font-black transition-all cursor-pointer shadow-2xl shadow-indigo-200 active:scale-95 group">
                  <FileUp size={24} className="group-hover:translate-y-[-2px] transition-transform" /> Upload First Company
                  <input type="file" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleFileUpload} />
