import React, { useState, useMemo, useEffect, useCallback } from 'react';
import * as XLSX from 'xlsx';
import { 
  FileUp, 
  Table, 
  LayoutGrid, 
  Sparkles, 
  Download, 
  RefreshCw,
  Search,
  Database,
  BarChart3,
  PieChart,
  X,
  FileSpreadsheet,
  Building2,
  ChevronDown,
  Plus,
  Trash2,
  AlertTriangle
} from 'lucide-react';
import { DataRow, ProcessedData, CompanyDataset } from './types';
import { harmonizeData } from './utils/dataProcessor';
import { DataTable } from './components/DataTable';
import { PivotView } from './components/PivotView';
import { Dashboard } from './components/Dashboard';
import { generateDataSummary } from './services/gemini';

const STORAGE_KEY = 'harmonizer_company_datasets_v2';

const App: React.FC = () => {
  // Persistence: Initialize from localStorage
  const [companyDatasets, setCompanyDatasets] = useState<CompanyDataset[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to parse stored datasets", e);
      return [];
    }
  });

  const [selectedCompanyId, setSelectedCompanyId] = useState<string>('all');
  const [activeTab, setActiveTab] = useState<'preview' | 'pivot' | 'dashboard' | 'ai'>('dashboard');
  const [isProcessing, setIsProcessing] = useState(false);
  const [aiSummary, setAiSummary] = useState<string>('');
  const [searchTerm, setSearchTerm] = useState('');
  const [isGeneratingAi, setIsGeneratingAi] = useState(false);

  // Upload Modal State
  const [pendingUpload, setPendingUpload] = useState<ProcessedData | null>(null);
  const [newCompanyName, setNewCompanyName] = useState('');

  // Drill-down State
  const [drillDownData, setDrillDownData] = useState<{ title: string; rows: DataRow[] } | null>(null);

  // Persistence: Save to localStorage whenever datasets change
  useEffect(() => {
    try {
      if (companyDatasets.length === 0) {
        localStorage.removeItem(STORAGE_KEY);
      } else {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(companyDatasets));
      }
    } catch (e) {
      console.warn('Persistence Error:', e);
      if (e instanceof Error && e.name === 'QuotaExceededError') {
        alert("Local storage is full. Some data might not be saved permanently.");
      }
    }
  }, [companyDatasets]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const data = XLSX.utils.sheet_to_json(ws) as DataRow[];
        const harmonized = harmonizeData(data);
        setPendingUpload(harmonized);
        setNewCompanyName(file.name.split('.')[0]); 
      } catch (err) {
        console.error("Error reading file", err);
        alert("Failed to read file. Please ensure it is a valid Excel or CSV.");
      } finally {
        setIsProcessing(false);
        e.target.value = '';
      }
    };
    reader.readAsBinaryString(file);
  };

  const confirmUpload = () => {
    if (!pendingUpload || !newCompanyName.trim()) return;
    const newEntry: CompanyDataset = {
      id: crypto.randomUUID(),
      name: newCompanyName.trim(),
      data: pendingUpload
    };
    setCompanyDatasets(prev => [...prev, newEntry]);
    setSelectedCompanyId(newEntry.id);
    setPendingUpload(null);
    setNewCompanyName('');
    setActiveTab('dashboard');
  };

  const activeDataRows = useMemo(() => {
    if (companyDatasets.length === 0) return [];
    if (selectedCompanyId === 'all') {
      return companyDatasets.flatMap(ds => ds.data.rows);
    }
    return companyDatasets.find(ds => ds.id === selectedCompanyId)?.data.rows || [];
  }, [companyDatasets, selectedCompanyId]);

  const activeHeaders = useMemo(() => {
    if (companyDatasets.length === 0) return [];
    if (selectedCompanyId === 'all') {
      const allHeaders = new Set<string>();
      companyDatasets.forEach(ds => ds.data.headers.forEach(h => allHeaders.add(h)));
      return Array.from(allHeaders);
    }
    return companyDatasets.find(ds => ds.id === selectedCompanyId)?.data.headers || [];
  }, [companyDatasets, selectedCompanyId]);

  const filteredRows = useMemo(() => {
    if (!searchTerm) return activeDataRows;
    const lowerSearch = searchTerm.toLowerCase();
    return activeDataRows.filter(row => 
      Object.values(row).some(val => String(val).toLowerCase().includes(lowerSearch))
    );
  }, [activeDataRows, searchTerm]);

  const handleExport = (dataToExport?: DataRow[], fileName?: string) => {
    const rowsToExport = dataToExport || activeDataRows;
    if (rowsToExport.length === 0) return;

    const worksheet = XLSX.utils.json_to_sheet(rowsToExport);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "Data");
    const name = fileName || `Master_Export_${new Date().getTime()}`;
    XLSX.writeFile(workbook, `${name}.xlsx`);
  };

  const handleDrillDown = (title: string, rows: DataRow[]) => {
    setDrillDownData({ title, rows });
  };

  const generateAiWriteup = async () => {
    if (activeDataRows.length === 0) return;
    setIsGeneratingAi(true);
    const summary = await generateDataSummary(activeDataRows);
    setAiSummary(summary);
    setIsGeneratingAi(false);
  };

  const removeCompany = useCallback((id: string, e?: React.MouseEvent) => {
    if (e) {
      e.preventDefault();
      e.stopPropagation();
    }

    const targetCompany = companyDatasets.find(ds => ds.id === id);
    const companyName = targetCompany ? targetCompany.name : 'this organization';

    if (window.confirm(`PERMANENT ACTION: Purge all records for "${companyName}"? This cannot be undone.`)) {
      setCompanyDatasets(prev => {
        const updated = prev.filter(ds => ds.id !== id);
        if (updated.length === 0) {
          localStorage.removeItem(STORAGE_KEY);
        }
        return updated;
      });

      if (selectedCompanyId === id) {
        setSelectedCompanyId('all');
      }

      // If we just deleted the last item, reset related UI state
      if (companyDatasets.length <= 1) {
        setAiSummary('');
        setSearchTerm('');
        setActiveTab('dashboard');
      }
    }
  }, [companyDatasets, selectedCompanyId]);

  const clearAllCompanies = useCallback((e?: React.MouseEvent) => {
    if (e) {
      e.preventDefault();
      e.stopPropagation();
    }

    if (window.confirm('CRITICAL ACTION: This will permanently DELETE ALL uploaded files, company profiles, and synchronized records from your local storage. Proceed with complete purge?')) {
      // 1. Force clear state
      setCompanyDatasets([]);
      setSelectedCompanyId('all');
      setAiSummary('');
      setSearchTerm('');
      setActiveTab('dashboard');
      setDrillDownData(null);

      // 2. Direct storage purge
      localStorage.removeItem(STORAGE_KEY);

      // 3. Optional: Reload to guarantee a clean runtime state
      // window.location.reload(); 
    }
  }, []);

  return (
    <div className="min-h-screen flex flex-col font-sans bg-slate-50/50">
      {/* Upload Confirmation Modal */}
      {pendingUpload && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-md rounded-[40px] shadow-2xl p-10 space-y-8 animate-in zoom-in-95 duration-300">
            <div className="text-center space-y-2">
              <div className="bg-indigo-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4">
                <Building2 className="text-indigo-600" size={32} />
              </div>
              <h3 className="text-2xl font-black text-slate-800 tracking-tight">Identify Dataset</h3>
              <p className="text-slate-400 text-sm font-medium">Assign an organization name to this file</p>
            </div>
            <div className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Company Profile Name</label>
                <input 
                  autoFocus
                  type="text"
                  className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-lg font-bold focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 outline-none transition-all"
                  value={newCompanyName}
                  onChange={(e) => setNewCompanyName(e.target.value)}
                  placeholder="e.g. Acme Corp..."
                  onKeyDown={(e) => e.key === 'Enter' && confirmUpload()}
                />
              </div>
            </div>
            <div className="flex gap-4">
              <button 
                onClick={() => setPendingUpload(null)}
                className="flex-1 py-4 text-slate-500 font-black uppercase text-xs tracking-widest hover:bg-slate-50 rounded-2xl transition-all"
              >
                Discard
              </button>
              <button 
                onClick={confirmUpload}
                disabled={!newCompanyName.trim()}
                className="flex-1 py-4 bg-indigo-600 hover:bg-indigo-700 disabled:bg-slate-300 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl shadow-indigo-100 transition-all active:scale-95"
              >
                Link Organization
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Detail Drill-down Modal */}
      {drillDownData && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-6xl h-[85vh] rounded-[40px] shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 duration-300">
            <div className="p-8 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
              <div className="flex items-center gap-4">
                <div className="bg-indigo-600 p-2.5 rounded-2xl text-white shadow-lg shadow-indigo-100">
                  <FileSpreadsheet size={24} />
                </div>
                <div>
                  <h3 className="text-xl font-black text-slate-800">{drillDownData.title}</h3>
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-0.5">
                    Analyzing {drillDownData.rows.length} Targeted Records
                  </p>
                </div>
              </div>
              <div className="flex items-center gap-3">
                <button 
                  onClick={() => handleExport(drillDownData.rows, drillDownData.title.replace(/\s+/g, '_'))}
                  className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-700 text-white px-5 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all shadow-md active:scale-95"
                >
                  <Download size={16} /> Export View
                </button>
                <button 
                  onClick={() => setDrillDownData(null)}
                  className="p-2 hover:bg-slate-200 rounded-full text-slate-400 hover:text-slate-600 transition-colors"
                >
                  <X size={24} />
                </button>
              </div>
            </div>
            <div className="flex-1 overflow-hidden p-8">
              <DataTable 
                headers={activeHeaders} 
                rows={drillDownData.rows} 
              />
            </div>
            <div className="p-4 bg-slate-50 text-center border-t border-slate-100">
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">
                Harmonization Engine v2.8 • Data Integrity Verified
              </p>
            </div>
          </div>
        </div>
      )}

      {/* Header */}
      <header className="bg-white border-b border-slate-200 px-8 py-4 flex items-center justify-between sticky top-0 z-50 shadow-sm">
        <div className="flex items-center gap-3">
          <div className="bg-gradient-to-br from-indigo-600 to-indigo-800 p-2.5 rounded-xl text-white shadow-lg shadow-indigo-200">
            <Database size={24} />
          </div>
          <div>
            <h1 className="text-xl font-extrabold text-slate-800 tracking-tight leading-none">DataHarmonizer Pro</h1>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Intelligence Portal</p>
          </div>
        </div>

        {companyDatasets.length > 0 && (
          <div className="flex items-center gap-6">
            {/* Multi-Company Dropdown */}
            <div className="relative group">
              <div className="flex items-center gap-3 px-6 py-2.5 bg-slate-50 border border-slate-200 rounded-2xl cursor-pointer hover:border-indigo-500 transition-all shadow-sm">
                <Building2 size={18} className="text-indigo-500" />
                <div className="text-left">
                  <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest leading-none mb-1">Company Filter</p>
                  <p className="text-sm font-black text-slate-800 leading-none">
                    {selectedCompanyId === 'all' ? 'Consolidated View' : companyDatasets.find(d => d.id === selectedCompanyId)?.name}
                  </p>
                </div>
                <ChevronDown size={16} className="text-slate-400 ml-2" />
              </div>

              {/* Dropdown Menu */}
              <div className="absolute right-0 mt-2 w-80 bg-white rounded-3xl shadow-2xl border border-slate-100 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all z-[120] p-4 space-y-2 overflow-hidden">
                <button 
                  onClick={() => setSelectedCompanyId('all')}
                  className={`w-full text-left px-4 py-3 rounded-xl flex items-center justify-between transition-all ${selectedCompanyId === 'all' ? 'bg-indigo-600 text-white' : 'hover:bg-slate-50 text-slate-600 font-bold'}`}
                >
                  <span className="text-sm font-black uppercase tracking-tight">Master Summary (All)</span>
                  {selectedCompanyId === 'all' && <div className="w-2 h-2 rounded-full bg-white animate-pulse" />}
                </button>
                <div className="h-px bg-slate-100 mx-2" />
                <div className="max-h-64 overflow-y-auto custom-scrollbar pr-1">
                  {companyDatasets.map(ds => (
                    <button 
                      key={ds.id}
                      onClick={() => setSelectedCompanyId(ds.id)}
                      className={`w-full text-left px-4 py-3 rounded-xl flex items-center justify-between transition-all group/item mb-1 ${selectedCompanyId === ds.id ? 'bg-indigo-50 text-indigo-700 font-black' : 'hover:bg-slate-50 text-slate-600 font-bold'}`}
                    >
                      <span className="text-sm truncate pr-4">{ds.name}</span>
                      <div className="flex items-center gap-2">
                        <span className="text-[10px] opacity-50">{ds.data.rows.length}</span>
                        <div 
                          className="p-1 hover:bg-rose-100 hover:text-rose-600 text-slate-300 rounded-md transition-all"
                          onClick={(e) => removeCompany(ds.id, e)}
                        >
                          <Trash2 size={14} />
                        </div>
                      </div>
                    </button>
                  ))}
                </div>
                <div className="h-px bg-slate-100 mx-2" />
                <button 
                  onClick={(e) => clearAllCompanies(e)}
                  className="w-full text-left px-4 py-3 rounded-xl flex items-center gap-3 text-rose-600 hover:bg-rose-600 hover:text-white transition-all font-black text-[10px] uppercase tracking-widest group"
                >
                  <AlertTriangle size={16} className="group-hover:animate-bounce" /> Wipe All Data
                </button>
              </div>
            </div>

            <div className="relative group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-indigo-500 transition-colors" size={16} />
              <input 
                type="text" 
                placeholder="Query records..." 
                className="pl-10 pr-10 py-2.5 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all w-64 bg-slate-50 shadow-inner"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
              {searchTerm && (
                <button 
                  onClick={() => setSearchTerm('')}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600 p-1"
                >
                  <X size={14} />
                </button>
              )}
            </div>
            <button 
              onClick={() => handleExport()}
              className="flex items-center gap-2 bg-slate-900 hover:bg-black text-white px-6 py-2.5 rounded-xl text-sm font-bold transition-all shadow-lg active:scale-95"
            >
              <Download size={18} /> Export
            </button>
          </div>
        )}
      </header>

      <main className="flex-1 flex overflow-hidden">
        {/* Sidebar */}
        <aside className="w-72 bg-white border-r border-slate-200 p-6 flex flex-col space-y-8 hidden md:flex overflow-y-auto custom-scrollbar">
          <div className="space-y-4 shrink-0">
            <label className="block p-6 border-2 border-dashed border-slate-200 rounded-3xl hover:border-indigo-500 hover:bg-indigo-50/50 cursor-pointer transition-all text-center group bg-slate-50/50">
              <input type="file" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleFileUpload} />
              <div className="bg-white p-3 rounded-full shadow-sm mx-auto w-fit mb-3 group-hover:scale-110 transition-transform">
                <Plus className="text-slate-400 group-hover:text-indigo-600" size={28} />
              </div>
              <span className="text-sm font-bold text-slate-700 block">Link New Sheet</span>
              <span className="text-[10px] text-slate-400 font-bold uppercase mt-1 block">XLSX, CSV Supported</span>
            </label>
          </div>

          {companyDatasets.length > 0 && (
            <nav className="space-y-2 flex-1">
              <div className="text-[10px] text-slate-400 font-bold uppercase tracking-widest px-4 mb-2">View Controls</div>
              <button 
                onClick={() => setActiveTab('dashboard')}
                className={`w-full flex items-center gap-3 px-5 py-3.5 rounded-2xl text-sm font-bold transition-all ${activeTab === 'dashboard' ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-100 translate-x-1' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}
              >
                <PieChart size={20} /> Operational Dashboard
              </button>
              <button 
                onClick={() => setActiveTab('preview')}
                className={`w-full flex items-center gap-3 px-5 py-3.5 rounded-2xl text-sm font-bold transition-all ${activeTab === 'preview' ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-100 translate-x-1' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}
              >
                <Table size={20} /> Master Data Grid
              </button>
              <button 
                onClick={() => setActiveTab('pivot')}
                className={`w-full flex items-center gap-3 px-5 py-3.5 rounded-2xl text-sm font-bold transition-all ${activeTab === 'pivot' ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-100 translate-x-1' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}
              >
                <LayoutGrid size={20} /> Pivot Synthesis
              </button>
              <button 
                onClick={() => setActiveTab('ai')}
                className={`w-full flex items-center gap-3 px-5 py-3.5 rounded-2xl text-sm font-bold transition-all ${activeTab === 'ai' ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-100 translate-x-1' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}
              >
                <Sparkles size={20} /> AI Narrative
              </button>
            </nav>
          )}

          {companyDatasets.length > 0 && (
            <div className="pt-6 border-t border-slate-100 space-y-6 shrink-0">
              <div>
                <div className="text-[10px] uppercase font-bold text-slate-400 mb-4 tracking-widest px-4">Workspace Summary</div>
                <div className="grid grid-cols-2 gap-3">
                  <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                    <div className="text-lg font-black text-slate-800">{activeDataRows.length}</div>
                    <div className="text-[9px] text-slate-400 uppercase font-bold">Rows Linked</div>
                  </div>
                  <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                    <div className="text-lg font-black text-slate-800">{activeHeaders.length}</div>
                    <div className="text-[9px] text-slate-400 uppercase font-bold">Headers</div>
                  </div>
                </div>
              </div>

              <button 
                onClick={(e) => clearAllCompanies(e)}
                className="w-full flex items-center justify-center gap-2 py-4 bg-rose-50 hover:bg-rose-600 hover:text-white text-rose-600 rounded-2xl text-[10px] font-black uppercase tracking-widest border border-rose-100 transition-all active:scale-95 group"
              >
                <Trash2 size={16} className="group-hover:animate-pulse" /> Purge Portal Storage
              </button>
            </div>
          )}
        </aside>

        {/* Content Area */}
        <section className="flex-1 overflow-auto p-10 custom-scrollbar relative">
          {companyDatasets.length === 0 && !isProcessing && (
            <div className="h-full flex flex-col items-center justify-center text-center max-w-lg mx-auto">
              <div className="bg-white p-12 rounded-[40px] shadow-2xl border border-slate-100 mb-8 relative overflow-hidden animate-in zoom-in-95 duration-500">
                <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-indigo-500 to-rose-500"></div>
                <div className="bg-indigo-50 w-24 h-24 rounded-full flex items-center justify-center mx-auto mb-8 shadow-inner">
                  <BarChart3 size={48} className="text-indigo-600" />
                </div>
                <h2 className="text-3xl font-black text-slate-800 mb-4 tracking-tight">Portal Empty</h2>
                <p className="text-slate-500 mb-10 leading-relaxed text-lg">
                  No data linked to this portal. Upload organization sheets to start harmonizing your workforce data. All linked data remains private in your local browser cache.
                </p>
                <label className="inline-flex items-center gap-3 bg-indigo-600 hover:bg-indigo-700 text-white px-10 py-4 rounded-2xl font-black transition-all cursor-pointer shadow-2xl shadow-indigo-200 active:scale-95 group">
                  <FileUp size={24} className="group-hover:translate-y-[-2px] transition-transform" /> Link First Sheet
                  <input type="file" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleFileUpload} />
                </label>
              </div>
            </div>
          )}

          {isProcessing && (
            <div className="h-full flex flex-col items-center justify-center space-y-6">
              <RefreshCw className="animate-spin text-indigo-600" size={64} />
              <div className="text-center">
                <h3 className="text-xl font-black text-slate-800 mb-2">Synchronizing Records</h3>
                <p className="text-slate-400 text-sm font-medium">Processing vectors and mapping headers...</p>
              </div>
            </div>
          )}

          {companyDatasets.length > 0 && !isProcessing && (
            <div key={companyDatasets.length + selectedCompanyId} className="max-w-7xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-700">
              <div className="flex items-center justify-between border-b border-slate-200 pb-6">
                <div>
                  <h2 className="text-3xl font-black text-slate-800 tracking-tight flex items-center gap-3">
                    {activeTab === 'dashboard' && <><PieChart className="text-indigo-600" size={32} /> Operational Dashboard</>}
                    {activeTab === 'preview' && <><Table className="text-indigo-600" size={32} /> Master Data Grid</>}
                    {activeTab === 'pivot' && <><LayoutGrid className="text-indigo-600" size={32} /> Pivot Synthesis</>}
                    {activeTab === 'ai' && <><Sparkles className="text-indigo-600" size={32} /> AI Narrative</>}
                  </h2>
                  <div className="flex items-center gap-4 mt-1">
                    <p className="text-slate-400 font-bold text-[10px] uppercase tracking-[0.2em]">
                      Context: {selectedCompanyId === 'all' ? `Consolidated Audit (${companyDatasets.length} Entities)` : `Organization Linked: ${companyDatasets.find(d => d.id === selectedCompanyId)?.name}`}
                    </p>
                    {selectedCompanyId !== 'all' && (
                      <button 
                        onClick={(e) => removeCompany(selectedCompanyId, e)}
                        className="flex items-center gap-1.5 text-rose-500 hover:text-white hover:bg-rose-500 font-black text-[10px] uppercase tracking-widest border border-rose-100 bg-rose-50/50 px-2 py-1 rounded-lg transition-all"
                      >
                        <Trash2 size={12} /> Unlink Entity
                      </button>
                    )}
                  </div>
                </div>
                <div className="flex items-center gap-2">
                  <span className="text-[10px] bg-indigo-50 text-indigo-600 px-3 py-1.5 rounded-full font-black border border-indigo-100 shadow-sm">
                    {activeDataRows.length} ACTIVE RECORDS
                  </span>
                </div>
              </div>

              {activeTab === 'dashboard' && (
                <Dashboard rows={activeDataRows} onDrillDown={handleDrillDown} />
              )}

              {activeTab === 'preview' && (
                <div className="space-y-4">
                  <DataTable 
                    headers={activeHeaders} 
                    rows={filteredRows} 
                    highlightTerm={searchTerm}
                  />
                </div>
              )}

              {activeTab === 'pivot' && (
                <PivotView rows={activeDataRows} headers={activeHeaders} />
              )}

              {activeTab === 'ai' && (
                <div className="bg-white rounded-[32px] shadow-2xl border border-slate-100 p-10 relative overflow-hidden">
                  <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-50 rounded-full blur-3xl -mr-32 -mt-32 opacity-50"></div>
                  <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-10 relative">
                    <div>
                      <h3 className="text-2xl font-black text-slate-800">Operational Narrative</h3>
                      <p className="text-slate-400 font-medium">Advanced LLM synthesis for {selectedCompanyId === 'all' ? 'consolidated organizations' : 'the selected entity'}</p>
                    </div>
                    <button 
                      onClick={generateAiWriteup}
                      disabled={isGeneratingAi || activeDataRows.length === 0}
                      className="flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-700 disabled:bg-slate-300 text-white px-8 py-4 rounded-2xl font-black transition-all shadow-xl shadow-indigo-100 active:scale-95 whitespace-nowrap"
                    >
                      {isGeneratingAi ? <RefreshCw className="animate-spin" size={20} /> : <Sparkles size={20} />}
                      {aiSummary ? 'Regenerate Analysis' : 'Synthesize Insights'}
                    </button>
                  </div>
                  {aiSummary && (
                    <div className="prose prose-indigo max-w-none relative">
                      <div className="text-slate-700 leading-relaxed text-lg whitespace-pre-wrap font-medium">
                        {aiSummary}
                      </div>
                    </div>
                  )}
                  {!aiSummary && !isGeneratingAi && (
                    <div className="py-20 text-center text-slate-300">
                      <Sparkles size={48} className="mx-auto mb-4 opacity-20" />
                      <p className="font-black uppercase tracking-[0.2em] text-xs">Awaiting Narrative Generation</p>
                    </div>
                  )}
                </div>
              )}
            </div>
          )}
        </section>
      </main>

      <footer className="bg-white border-t border-slate-200 px-8 py-3 flex items-center justify-between text-[10px] text-slate-400 font-bold uppercase tracking-widest">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-2">
            <div className={`w-2 h-2 rounded-full ${companyDatasets.length > 0 ? 'bg-emerald-500 animate-pulse' : 'bg-slate-300'}`}></div> 
            Core Database: {companyDatasets.length > 0 ? 'Synchronized' : 'Ready'}
          </div>
          <div className="border-l pl-6 border-slate-200">Local Persistence: Active</div>
        </div>
        <div className="flex items-center gap-2">
          <span>Enterprise Harmonizer Pro • Release 2.8.4</span>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useCallback } from 'react';
