import { 
  FileUp, 
  Table, 
  LayoutGrid, 
  Sparkles, 
  Download, 
  RefreshCw,
  Search,
  Database,
  BarChart3,
  PieChart,
  X,
  FileSpreadsheet,
  Building2,
  ChevronDown,
  Plus,
  Trash2,
  AlertTriangle,
  Share2,
  Copy,
  ExternalLink,
  ShieldCheck,
  Eye,
  Settings
} from 'lucide-react';
import { DataRow, ProcessedData, CompanyDataset } from './types';
import { harmonizeData } from './utils/dataProcessor';
import { DataTable } from './components/DataTable';
import { PivotView } from './components/PivotView';
import { Dashboard } from './components/Dashboard';
import { generateDataSummary } from './services/gemini';

const STORAGE_KEY = 'harmonizer_company_datasets_v2';

const App: React.FC = () => {
  // Persistence & Sharing State
  const [isReadOnly, setIsReadOnly] = useState(false);
  const [shareStatus, setShareStatus] = useState<'idle' | 'generating' | 'copied'>('idle');

  const [companyDatasets, setCompanyDatasets] = useState<CompanyDataset[]>(() => {
    // 1. Check URL for Shared Snapshot first
    const hash = window.location.hash;
    if (hash && hash.startsWith('#data=')) {
      try {
        const compressed = hash.replace('#data=', '');
        const decompressed = LZString.decompressFromEncodedURIComponent(compressed);
        if (decompressed) {
          const data = JSON.parse(decompressed);
          setIsReadOnly(true); // Flag as Read-Only mode for viewers
          return data;
        }
      } catch (e) {
        console.error("Shared link corrupted or too large", e);
      }
    }

    // 2. Fallback to Local Storage
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to parse stored datasets", e);
      return [];
    }
  });

  const [selectedCompanyId, setSelectedCompanyId] = useState<string>('all');
  const [activeTab, setActiveTab] = useState<'preview' | 'pivot' | 'dashboard' | 'ai'>('dashboard');
  const [isProcessing, setIsProcessing] = useState(false);
  const [aiSummary, setAiSummary] = useState<string>('');
  const [searchTerm, setSearchTerm] = useState('');
  const [isGeneratingAi, setIsGeneratingAi] = useState(false);

  const [pendingUpload, setPendingUpload] = useState<ProcessedData | null>(null);
  const [newCompanyName, setNewCompanyName] = useState('');
  const [drillDownData, setDrillDownData] = useState<{ title: string; rows: DataRow[] } | null>(null);

  // Persistence Sync
  useEffect(() => {
    if (isReadOnly) return; // Don't overwrite personal storage if viewing a shared link

    try {
      if (companyDatasets.length === 0) {
        localStorage.removeItem(STORAGE_KEY);
      } else {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(companyDatasets));
      }
    } catch (e) {
      console.warn('Persistence Error:', e);
    }
  }, [companyDatasets, isReadOnly]);

  const generateShareLink = useCallback(() => {
    setShareStatus('generating');
    try {
      const json = JSON.stringify(companyDatasets);
      const compressed = LZString.compressToEncodedURIComponent(json);
      const shareUrl = `${window.location.origin}${window.location.pathname}#data=${compressed}`;

      if (shareUrl.length > 10000) {
        alert("Warning: Dataset is too large for a standard URL link. Try reducing the number of companies.");
      }

      navigator.clipboard.writeText(shareUrl);
      setShareStatus('copied');
      setTimeout(() => setShareStatus('idle'), 3000);
    } catch (e) {
      console.error("Link generation failed", e);
      setShareStatus('idle');
    }
  }, [companyDatasets]);

  const exitReadOnly = () => {
    if (window.confirm("Switch to your personal workspace? This will remove the shared data from your current view.")) {
      window.location.hash = '';
      window.location.reload();
    }
  };

  const importSharedData = () => {
    if (window.confirm("Save this shared data to your personal workspace? This will overwrite your existing local files.")) {
      setIsReadOnly(false);
      localStorage.setItem(STORAGE_KEY, JSON.stringify(companyDatasets));
      window.location.hash = '';
      alert("Successfully imported to your local portal!");
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (isReadOnly) return;
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const data = XLSX.utils.sheet_to_json(ws) as DataRow[];
        const harmonized = harmonizeData(data);
        setPendingUpload(harmonized);
        setNewCompanyName(file.name.split('.')[0]); 
      } catch (err) {
        console.error("Error reading file", err);
      } finally {
        setIsProcessing(false);
        e.target.value = '';
      }
    };
    reader.readAsBinaryString(file);
  };

  const confirmUpload = () => {
    if (!pendingUpload || !newCompanyName.trim()) return;
    const newEntry: CompanyDataset = {
      id: crypto.randomUUID(),
      name: newCompanyName.trim(),
      data: pendingUpload
    };
    setCompanyDatasets(prev => [...prev, newEntry]);
    setSelectedCompanyId(newEntry.id);
    setPendingUpload(null);
    setNewCompanyName('');
    setActiveTab('dashboard');
  };

  const activeDataRows = useMemo(() => {
    if (companyDatasets.length === 0) return [];
    if (selectedCompanyId === 'all') {
      return companyDatasets.flatMap(ds => ds.data.rows);
    }
    return companyDatasets.find(ds => ds.id === selectedCompanyId)?.data.rows || [];
  }, [companyDatasets, selectedCompanyId]);

  const activeHeaders = useMemo(() => {
    if (companyDatasets.length === 0) return [];
    if (selectedCompanyId === 'all') {
      const allHeaders = new Set<string>();
      companyDatasets.forEach(ds => ds.data.headers.forEach(h => allHeaders.add(h)));
      return Array.from(allHeaders);
    }
    return companyDatasets.find(ds => ds.id === selectedCompanyId)?.data.headers || [];
  }, [companyDatasets, selectedCompanyId]);

  const filteredRows = useMemo(() => {
    if (!searchTerm) return activeDataRows;
    const lowerSearch = searchTerm.toLowerCase();
    return activeDataRows.filter(row => 
      Object.values(row).some(val => String(val).toLowerCase().includes(lowerSearch))
    );
  }, [activeDataRows, searchTerm]);

  const handleExport = (dataToExport?: DataRow[], fileName?: string) => {
    const rowsToExport = dataToExport || activeDataRows;
    if (rowsToExport.length === 0) return;
    const worksheet = XLSX.utils.json_to_sheet(rowsToExport);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "Data");
    XLSX.writeFile(workbook, `${fileName || 'Export'}.xlsx`);
  };

  const removeCompany = useCallback((id: string, e?: React.MouseEvent) => {
    if (isReadOnly) return;
    if (e) e.stopPropagation();
    if (window.confirm(`Purge this organization?`)) {
      setCompanyDatasets(prev => prev.filter(ds => ds.id !== id));
      if (selectedCompanyId === id) setSelectedCompanyId('all');
    }
  }, [isReadOnly, companyDatasets, selectedCompanyId]);

  const clearAllCompanies = useCallback(() => {
    if (isReadOnly) return;
    if (window.confirm('Wipe all data?')) {
      setCompanyDatasets([]);
      setSelectedCompanyId('all');
      localStorage.removeItem(STORAGE_KEY);
    }
  }, [isReadOnly]);

  return (
    <div className="min-h-screen flex flex-col font-sans bg-slate-50/50 overflow-hidden h-screen">
      {/* Shared View Warning Banner */}
      {isReadOnly && (
        <div className="bg-indigo-600 text-white px-8 py-2.5 flex items-center justify-between text-xs font-black uppercase tracking-widest z-[60] shadow-lg">
          <div className="flex items-center gap-3">
            <Eye size={16} className="animate-pulse" />
            Viewing Shared Portal Snapshot
          </div>
          <div className="flex items-center gap-4">
            <button onClick={importSharedData} className="bg-white/20 hover:bg-white/30 px-3 py-1 rounded-lg transition-all flex items-center gap-2">
              <Download size={14} /> Import to Local Portal
            </button>
            <button onClick={exitReadOnly} className="text-white/70 hover:text-white transition-all underline">
              Exit Viewer
            </button>
          </div>
        </div>
      )}

      {/* Upload Confirmation Modal */}
      {pendingUpload && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md">
          <div className="bg-white w-full max-w-md rounded-[40px] shadow-2xl p-10 space-y-8">
            <div className="text-center space-y-2">
              <div className="bg-indigo-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4">
                <Building2 className="text-indigo-600" size={32} />
              </div>
              <h3 className="text-2xl font-black text-slate-800 tracking-tight">Identify Dataset</h3>
            </div>
            <input 
              autoFocus
              type="text"
              className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-lg font-bold"
              value={newCompanyName}
              onChange={(e) => setNewCompanyName(e.target.value)}
              placeholder="e.g. Acme Corp..."
              onKeyDown={(e) => e.key === 'Enter' && confirmUpload()}
            />
            <div className="flex gap-4">
              <button onClick={() => setPendingUpload(null)} className="flex-1 py-4 text-slate-500 font-black uppercase text-xs">Discard</button>
              <button onClick={confirmUpload} className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs">Link Entity</button>
            </div>
          </div>
        </div>
      )}

      {/* Header */}
      <header className="bg-white border-b border-slate-200 px-8 py-4 flex items-center justify-between sticky top-0 z-50 shadow-sm shrink-0">
        <div className="flex items-center gap-3">
          <div className="bg-gradient-to-br from-indigo-600 to-indigo-800 p-2.5 rounded-xl text-white shadow-lg">
            <Database size={24} />
          </div>
          <div>
            <h1 className="text-xl font-extrabold text-slate-800 tracking-tight leading-none">DataHarmonizer Pro</h1>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">
              {isReadOnly ? 'Shared Session' : 'Workspace Admin'}
            </p>
          </div>
        </div>

        {companyDatasets.length > 0 && (
          <div className="flex items-center gap-6">
            <div className="relative group">
              <div className="flex items-center gap-3 px-6 py-2.5 bg-slate-50 border border-slate-200 rounded-2xl cursor-pointer">
                <Building2 size={18} className="text-indigo-500" />
                <div className="text-left">
                  <p className="text-[8px] font-black text-slate-400 uppercase leading-none mb-1">Company Filter</p>
                  <p className="text-sm font-black text-slate-800 leading-none truncate max-w-[120px]">
                    {selectedCompanyId === 'all' ? 'All Entities' : companyDatasets.find(d => d.id === selectedCompanyId)?.name}
                  </p>
                </div>
                <ChevronDown size={16} className="text-slate-400" />
              </div>
              <div className="absolute right-0 mt-2 w-80 bg-white rounded-3xl shadow-2xl border border-slate-100 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all z-[120] p-4">
                <button onClick={() => setSelectedCompanyId('all')} className="w-full text-left px-4 py-3 rounded-xl mb-2 hover:bg-slate-50 text-sm font-black uppercase tracking-tight">Master Summary (All)</button>
                <div className="max-h-64 overflow-y-auto custom-scrollbar">
                  {companyDatasets.map(ds => (
                    <button key={ds.id} onClick={() => setSelectedCompanyId(ds.id)} className={`w-full text-left px-4 py-3 rounded-xl flex items-center justify-between hover:bg-slate-50 mb-1 ${selectedCompanyId === ds.id ? 'bg-indigo-50 text-indigo-700' : 'text-slate-600'}`}>
                      <span className="text-sm font-bold truncate">{ds.name}</span>
                      {!isReadOnly && <Trash2 size={14} className="text-slate-300 hover:text-rose-500" onClick={(e) => removeCompany(ds.id, e)} />}
                    </button>
                  ))}
                </div>
              </div>
            </div>

            <div className="relative group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
              <input type="text" placeholder="Query records..." className="pl-10 pr-4 py-2.5 border border-slate-200 rounded-xl text-sm w-64 bg-slate-50 focus:ring-2 focus:ring-indigo-500/20" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
            </div>
            <button onClick={() => handleExport()} className="flex items-center gap-2 bg-slate-900 text-white px-6 py-2.5 rounded-xl text-sm font-bold shadow-lg">
              <Download size={18} /> Export
            </button>
          </div>
        )}
      </header>

      <main className="flex-1 flex overflow-hidden">
        {/* Sidebar */}
        <aside className="w-80 bg-white border-r border-slate-200 p-6 flex flex-col space-y-8 hidden md:flex overflow-y-auto custom-scrollbar shrink-0">

          {/* Creator Tools (Only if not read-only) */}
          {!isReadOnly && (
            <div className="space-y-4 shrink-0">
              <label className="block p-8 border-2 border-dashed border-slate-200 rounded-3xl hover:border-indigo-500 hover:bg-indigo-50/50 cursor-pointer transition-all text-center group bg-slate-50/50">
                <input type="file" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleFileUpload} />
                <div className="bg-white p-3 rounded-full shadow-sm mx-auto w-fit mb-4 group-hover:scale-110 transition-transform">
                  <Plus className="text-slate-400 group-hover:text-indigo-600" size={32} />
                </div>
                <span className="text-sm font-black text-slate-700 block uppercase tracking-wide">Upload & Link Data</span>
                <span className="text-[10px] text-slate-400 font-bold uppercase mt-2 block tracking-widest">Excel / CSV Portal Source</span>
              </label>
            </div>
          )}

          {/* Navigation */}
          {companyDatasets.length > 0 && (
            <nav className="space-y-2 flex-1">
              <div className="text-[10px] text-slate-400 font-black uppercase tracking-[0.3em] px-4 mb-3 flex items-center gap-2">
                <LayoutGrid size={12} /> Modules
              </div>
              {[
                { id: 'dashboard', label: 'Dashboard', icon: PieChart },
                { id: 'preview', label: 'Data Grid', icon: Table },
                { id: 'pivot', label: 'Pivot Synthesis', icon: LayoutGrid },
                { id: 'ai', label: 'AI Narrative', icon: Sparkles }
              ].map(item => (
                <button 
                  key={item.id}
                  onClick={() => setActiveTab(item.id as any)}
                  className={`w-full flex items-center gap-3 px-6 py-4 rounded-2xl text-sm font-black transition-all ${activeTab === item.id ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-100 translate-x-1' : 'text-slate-500 hover:bg-slate-50'}`}
                >
                  <item.icon size={20} /> {item.label}
                </button>
              ))}
            </nav>
          )}

          {/* Collaboration Module */}
          {companyDatasets.length > 0 && (
            <div className="pt-6 border-t border-slate-100 space-y-4 shrink-0">
              <div className="text-[10px] text-slate-400 font-black uppercase tracking-[0.3em] px-4">Collaboration</div>
              <div className="bg-slate-50 p-6 rounded-[32px] border border-slate-100 space-y-4">
                <div className="flex items-center gap-3">
                  <div className="bg-indigo-500 p-2 rounded-xl text-white shadow-lg">
                    <Share2 size={16} />
                  </div>
                  <span className="text-[11px] font-black text-slate-800 uppercase tracking-widest leading-none">Share Workspace</span>
                </div>
                <p className="text-[10px] text-slate-400 font-bold leading-relaxed">Encodes current data into a shareable URL snapshot for viewers.</p>
                <button 
                  onClick={generateShareLink}
                  className={`w-full py-3.5 rounded-xl font-black text-[10px] uppercase tracking-[0.2em] transition-all flex items-center justify-center gap-2 border shadow-sm ${
                    shareStatus === 'copied' ? 'bg-emerald-500 text-white border-emerald-400' : 'bg-white text-indigo-600 border-indigo-100 hover:bg-indigo-50'
                  }`}
                >
                  {shareStatus === 'copied' ? <ShieldCheck size={16} /> : <Copy size={16} />}
                  {shareStatus === 'copied' ? 'Link Copied' : 'Generate Link'}
                </button>
              </div>

              {!isReadOnly && (
                <button 
                  onClick={clearAllCompanies}
                  className="w-full flex items-center justify-center gap-2 py-4 bg-rose-50 text-rose-600 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-rose-600 hover:text-white transition-all border border-rose-100"
                >
                  <Trash2 size={16} /> Wipe Portal
                </button>
              )}
            </div>
          )}
        </aside>

        {/* Content Area */}
        <section className="flex-1 overflow-auto p-10 custom-scrollbar relative">
          {companyDatasets.length === 0 && !isProcessing && (
            <div className="h-full flex flex-col items-center justify-center text-center max-w-lg mx-auto">
              <div className="bg-white p-14 rounded-[50px] shadow-2xl border border-slate-100 mb-8 relative overflow-hidden">
                <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-indigo-500 to-rose-500"></div>
                <div className="bg-indigo-50 w-24 h-24 rounded-full flex items-center justify-center mx-auto mb-8">
                  <BarChart3 size={48} className="text-indigo-600" />
                </div>
                <h2 className="text-4xl font-black text-slate-800 mb-6 tracking-tight">System Ready</h2>
                <p className="text-slate-500 mb-10 leading-relaxed text-lg">Your synchronized data remains private in your local browser. Share the link with others to provide a read-only dashboard of your data.</p>
                <label className="inline-flex items-center gap-3 bg-indigo-600 hover:bg-indigo-700 text-white px-12 py-5 rounded-3xl font-black text-lg transition-all cursor-pointer shadow-2xl active:scale-95 group">
                  <FileUp size={28} /> Link Source Data
                  <input type="file" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleFileUpload} />
                </label>
              </div>
            </div>
          )}

          {isProcessing && (
            <div className="h-full flex flex-col items-center justify-center space-y-6">
              <RefreshCw className="animate-spin text-indigo-600" size={64} />
              <h3 className="text-2xl font-black text-slate-800 tracking-tight">Restructuring Context</h3>
            </div>
          )}

          {companyDatasets.length > 0 && !isProcessing && (
            <div key={companyDatasets.length + selectedCompanyId} className="max-w-7xl mx-auto space-y-10 animate-in fade-in duration-700">
              <div className="flex items-center justify-between border-b border-slate-200 pb-10">
                <div>
                  <h2 className="text-4xl font-black text-slate-900 tracking-tight flex items-center gap-4">
                    {activeTab === 'dashboard' && <PieChart size={40} />}
                    {activeTab === 'preview' && <Table size={40} />}
                    {activeTab === 'pivot' && <LayoutGrid size={40} />}
                    {activeTab === 'ai' && <Sparkles size={40} />}
                    <span className="capitalize">{activeTab} View</span>
                  </h2>
                  <div className="flex items-center gap-4 mt-3">
                    <span className="text-slate-400 font-black text-[10px] uppercase tracking-[0.3em]">
                      ACTIVE ENTITIES: {companyDatasets.length}
                    </span>
                    <span className="w-1.5 h-1.5 rounded-full bg-slate-300"></span>
                    <span className="text-slate-400 font-black text-[10px] uppercase tracking-[0.3em]">
                      CONTEXT: {selectedCompanyId === 'all' ? 'Consolidated Master' : companyDatasets.find(d => d.id === selectedCompanyId)?.name}
                    </span>
                  </div>
                </div>

                {isReadOnly && (
                  <div className="flex items-center gap-3 bg-indigo-50 border border-indigo-100 px-6 py-4 rounded-[32px]">
                    <div className="relative flex items-center justify-center h-4 w-4">
                       <span className="pulse-dot"></span>
                       <span className="relative inline-flex rounded-full h-3 w-3 bg-emerald-500"></span>
                    </div>
                    <p className="text-[11px] font-black text-indigo-700 uppercase tracking-widest">Live Shared Session</p>
                  </div>
                )}
              </div>

              {activeTab === 'dashboard' && (
                <Dashboard rows={activeDataRows} onDrillDown={(t, r) => setDrillDownData({ title: t, rows: r })} />
              )}

              {active Tab === 'preview' && (
                <DataTable headers={activeHeaders} rows={filteredRows} highlightTerm={searchTerm} />
              )}

              {activeTab === 'pivot' && (
                <PivotView rows={activeDataRows} headers={activeHeaders} />
              )}

              {activeTab === 'ai' && (
                <div className="bg-white rounded-[40px] shadow-3xl border border-slate-100 p-16 relative overflow-hidden">
                  <div className="flex flex-col md:flex-row md:items-center justify-between gap-8 mb-12 relative z-10">
                    <div>
                      <h3 className="text-4xl font-black text-slate-900 tracking-tighter">Operational Narrative</h3>
                      <p className="text-slate-400 text-lg mt-2">LLM-Synthesized context of current workforce vectors.</p>
                    </div>
                    <button 
                      onClick={generateAiWriteup}
                      disabled={isGeneratingAi}
                      className="flex items-center justify-center gap-3 bg-indigo-600 hover:bg-indigo-700 text-white px-10 py-5 rounded-3xl font-black text-lg transition-all shadow-2xl active:scale-95 whitespace-nowrap"
                    >
                      {isGeneratingAi ? <RefreshCw className="animate-spin" /> : <Sparkles />}
                      {aiSummary ? 'Regenerate Analysis' : 'Synthesize Insights'}
                    </button>
                  </div>
                  <div className="prose prose-slate max-w-none text-xl leading-relaxed text-slate-700 relative z-10 whitespace-pre-wrap">
                    {aiSummary || <p className="text-slate-300 italic">Initiate AI analysis to generate executive narrative...</p>}
                  </div>
                </div>
              )}
            </div>
          )}
        </section>
      </main>

      {/* Detail Drill-down Modal */}
      {drillDownData && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-6xl h-[85vh] rounded-[40px] shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 duration-300">
            <div className="p-10 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
              <div className="flex items-center gap-5">
                <div className="bg-indigo-600 p-3 rounded-2xl text-white shadow-xl shadow-indigo-100">
                  <FileSpreadsheet size={32} />
                </div>
                <div>
                  <h3 className="text-2xl font-black text-slate-900 tracking-tight">{drillDownData.title}</h3>
                  <p className="text-[11px] text-slate-400 font-black uppercase tracking-widest mt-1">Audit Trail: {drillDownData.rows.length} Records</p>
                </div>
              </div>
              <div className="flex items-center gap-4">
                <button onClick={() => handleExport(drillDownData.rows, drillDownData.title)} className="bg-emerald-600 text-white px-8 py-3 rounded-xl text-sm font-black uppercase tracking-widest transition-all shadow-md">Export View</button>
                <button onClick={() => setDrillDownData(null)} className="p-3 hover:bg-slate-200 rounded-full text-slate-400 transition-colors"><X size={32} /></button>
              </div>
            </div>
            <div className="flex-1 overflow-hidden p-10">
              <DataTable headers={activeHeaders} rows={drillDownData.rows} />
            </div>
          </div>
        </div>
      )}

      <footer className="bg-white border-t border-slate-200 px-8 py-3 flex items-center justify-between text-[10px] text-slate-400 font-bold uppercase tracking-[0.3em] shrink-0">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-2">
            <div className={`w-2 h-2 rounded-full ${companyDatasets.length > 0 ? 'bg-emerald-500 animate-pulse' : 'bg-slate-300'}`}></div> 
            {isReadOnly ? 'READ-ONLY SHARED SESSION' : 'MASTER PORTAL ADMIN'}
          </div>
          <div className="border-l pl-6 border-slate-200">SNAP-SYNC v3.0 ACTIVE</div>
        </div>
        <div className="flex items-center gap-2">
           <ShieldCheck size={14} className="text-indigo-400" />
           DATA PERSISTENCE: {isReadOnly ? 'TEMPORARY (URL)' : 'LOCAL STORAGE'}
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useCallback } from 'react';
import * as XLSX from 'xlsx';
import LZString from 'lz-string';
import { 
  FileUp, 
  Table, 
  LayoutGrid, 
  Sparkles, 
  Download, 
  RefreshCw,
  Search,
  Database,
  BarChart3,
  PieChart,
  X,
  FileSpreadsheet,
  Building2,
  ChevronDown,
  Plus,
  Trash2,
  AlertTriangle,
  Share2,
  Copy,
  ExternalLink,
  ShieldCheck,
  Eye,
  Settings
} from 'lucide-react';
import { DataRow, ProcessedData, CompanyDataset } from './types';
import { harmonizeData } from './utils/dataProcessor';
import { DataTable } from './components/DataTable';
import { PivotView } from './components/PivotView';
import { Dashboard } from './components/Dashboard';
import { generateDataSummary } from './services/gemini';

const STORAGE_KEY = 'harmonizer_company_datasets_v2';

const App: React.FC = () => {
  // Persistence & Sharing State
  const [isReadOnly, setIsReadOnly] = useState(false);
  const [shareStatus, setShareStatus] = useState<'idle' | 'generating' | 'copied'>('idle');

  const [companyDatasets, setCompanyDatasets] = useState<CompanyDataset[]>(() => {
    // 1. Check URL for Shared Snapshot first
    const hash = window.location.hash;
    if (hash && hash.startsWith('#data=')) {
      try {
        const compressed = hash.replace('#data=', '');
        const decompressed = LZString.decompressFromEncodedURIComponent(compressed);
        if (decompressed) {
          const data = JSON.parse(decompressed);
          setIsReadOnly(true); // Flag as Read-Only mode for viewers
          return data;
        }
      } catch (e) {
        console.error("Shared link corrupted or too large", e);
      }
    }

    // 2. Fallback to Local Storage
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to parse stored datasets", e);
      return [];
    }
  });

  const [selectedCompanyId, setSelectedCompanyId] = useState<string>('all');
  const [activeTab, setActiveTab] = useState<'preview' | 'pivot' | 'dashboard' | 'ai'>('dashboard');
  const [isProcessing, setIsProcessing] = useState(false);
  const [aiSummary, setAiSummary] = useState<string>('');
  const [searchTerm, setSearchTerm] = useState('');
  const [isGeneratingAi, setIsGeneratingAi] = useState(false);

  const [pendingUpload, setPendingUpload] = useState<ProcessedData | null>(null);
  const [newCompanyName, setNewCompanyName] = useState('');
  const [drillDownData, setDrillDownData] = useState<{ title: string; rows: DataRow[] } | null>(null);

  // Persistence Sync
  useEffect(() => {
    if (isReadOnly) return; // Don't overwrite personal storage if viewing a shared link

    try {
      if (companyDatasets.length === 0) {
        localStorage.removeItem(STORAGE_KEY);
      } else {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(companyDatasets));
      }
    } catch (e) {
      console.warn('Persistence Error:', e);
    }
  }, [companyDatasets, isReadOnly]);

  const generateShareLink = useCallback(() => {
    setShareStatus('generating');
    try {
      const json = JSON.stringify(companyDatasets);
      const compressed = LZString.compressToEncodedURIComponent(json);
      const shareUrl = `${window.location.origin}${window.location.pathname}#data=${compressed}`;

      if (shareUrl.length > 10000) {
        alert("Warning: Dataset is too large for a standard URL link. Try reducing the number of companies.");
      }

      navigator.clipboard.writeText(shareUrl);
      setShareStatus('copied');
      setTimeout(() => setShareStatus('idle'), 3000);
    } catch (e) {
      console.error("Link generation failed", e);
      setShareStatus('idle');
    }
  }, [companyDatasets]);

  const exitReadOnly = () => {
    if (window.confirm("Switch to your personal workspace? This will remove the shared data from your current view.")) {
      window.location.hash = '';
      window.location.reload();
    }
  };

  const importSharedData = () => {
    if (window.confirm("Save this shared data to your personal workspace? This will overwrite your existing local files.")) {
      setIsReadOnly(false);
      localStorage.setItem(STORAGE_KEY, JSON.stringify(companyDatasets));
      window.location.hash = '';
      alert("Successfully imported to your local portal!");
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (isReadOnly) return;
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const data = XLSX.utils.sheet_to_json(ws) as DataRow[];
        const harmonized = harmonizeData(data);
        setPendingUpload(harmonized);
        setNewCompanyName(file.name.split('.')[0]); 
      } catch (err) {
        console.error("Error reading file", err);
      } finally {
        setIsProcessing(false);
        e.target.value = '';
      }
    };
    reader.readAsBinaryString(file);
  };

  const confirmUpload = () => {
    if (!pendingUpload || !newCompanyName.trim()) return;
    const newEntry: CompanyDataset = {
      id: crypto.randomUUID(),
      name: newCompanyName.trim(),
      data: pendingUpload
    };
    setCompanyDatasets(prev => [...prev, newEntry]);
    setSelectedCompanyId(newEntry.id);
    setPendingUpload(null);
    setNewCompanyName('');
    setActiveTab('dashboard');
  };

  const activeDataRows = useMemo(() => {
    if (companyDatasets.length === 0) return [];
    if (selectedCompanyId === 'all') {
      return companyDatasets.flatMap(ds => ds.data.rows);
    }
    return companyDatasets.find(ds => ds.id === selectedCompanyId)?.data.rows || [];
  }, [companyDatasets, selectedCompanyId]);

  const activeHeaders = useMemo(() => {
    if (companyDatasets.length === 0) return [];
    if (selectedCompanyId === 'all') {
      const allHeaders = new Set<string>();
      companyDatasets.forEach(ds => ds.data.headers.forEach(h => allHeaders.add(h)));
      return Array.from(allHeaders);
    }
    return companyDatasets.find(ds => ds.id === selectedCompanyId)?.data.headers || [];
  }, [companyDatasets, selectedCompanyId]);

  const filteredRows = useMemo(() => {
    if (!searchTerm) return activeDataRows;
    const lowerSearch = searchTerm.toLowerCase();
    return activeDataRows.filter(row => 
      Object.values(row).some(val => String(val).toLowerCase().includes(lowerSearch))
    );
  }, [activeDataRows, searchTerm]);

  const handleExport = (dataToExport?: DataRow[], fileName?: string) => {
    const rowsToExport = dataToExport || activeDataRows;
    if (rowsToExport.length === 0) return;
    const worksheet = XLSX.utils.json_to_sheet(rowsToExport);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "Data");
    XLSX.writeFile(workbook, `${fileName || 'Export'}.xlsx`);
  };

  const removeCompany = useCallback((id: string, e?: React.MouseEvent) => {
    if (isReadOnly) return;
    if (e) e.stopPropagation();
    if (window.confirm(`Purge this organization?`)) {
      setCompanyDatasets(prev => prev.filter(ds => ds.id !== id));
      if (selectedCompanyId === id) setSelectedCompanyId('all');
    }
  }, [isReadOnly, companyDatasets, selectedCompanyId]);

  const clearAllCompanies = useCallback(() => {
    if (isReadOnly) return;
    if (window.confirm('Wipe all data?')) {
      setCompanyDatasets([]);
      setSelectedCompanyId('all');
      localStorage.removeItem(STORAGE_KEY);
    }
  }, [isReadOnly]);

  // Fix: Implemented generateAiWriteup function to synthesize workforce data using Gemini API
  const generateAiWriteup = useCallback(async () => {
    if (activeDataRows.length === 0) {
      setAiSummary("No data available to analyze. Please upload and link data sources.");
      return;
    }
    setIsGeneratingAi(true);
    try {
      const narrative = await generateDataSummary(activeDataRows);
      setAiSummary(narrative);
    } catch (error) {
      console.error("Failed to generate AI narrative:", error);
      setAiSummary("System was unable to synthesize an operational narrative at this time.");
    } finally {
      setIsGeneratingAi(false);
    }
  }, [activeDataRows]);

  return (
    <div className="min-h-screen flex flex-col font-sans bg-slate-50/50 overflow-hidden h-screen">
      {/* Shared View Warning Banner */}
      {isReadOnly && (
        <div className="bg-indigo-600 text-white px-8 py-2.5 flex items-center justify-between text-xs font-black uppercase tracking-widest z-[60] shadow-lg">
          <div className="flex items-center gap-3">
            <Eye size={16} className="animate-pulse" />
            Viewing Shared Portal Snapshot
          </div>
          <div className="flex items-center gap-4">
            <button onClick={importSharedData} className="bg-white/20 hover:bg-white/30 px-3 py-1 rounded-lg transition-all flex items-center gap-2">
              <Download size={14} /> Import to Local Portal
            </button>
            <button onClick={exitReadOnly} className="text-white/70 hover:text-white transition-all underline">
              Exit Viewer
            </button>
          </div>
        </div>
      )}

      {/* Upload Confirmation Modal */}
      {pendingUpload && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md">
          <div className="bg-white w-full max-w-md rounded-[40px] shadow-2xl p-10 space-y-8">
            <div className="text-center space-y-2">
              <div className="bg-indigo-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4">
                <Building2 className="text-indigo-600" size={32} />
              </div>
              <h3 className="text-2xl font-black text-slate-800 tracking-tight">Identify Dataset</h3>
            </div>
            <input 
              autoFocus
              type="text"
              className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-lg font-bold"
              value={newCompanyName}
              onChange={(e) => setNewCompanyName(e.target.value)}
              placeholder="e.g. Acme Corp..."
              onKeyDown={(e) => e.key === 'Enter' && confirmUpload()}
            />
            <div className="flex gap-4">
              <button onClick={() => setPendingUpload(null)} className="flex-1 py-4 text-slate-500 font-black uppercase text-xs">Discard</button>
              <button onClick={confirmUpload} className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs">Link Entity</button>
            </div>
          </div>
        </div>
      )}

      {/* Header */}
      <header className="bg-white border-b border-slate-200 px-8 py-4 flex items-center justify-between sticky top-0 z-50 shadow-sm shrink-0">
        <div className="flex items-center gap-3">
          <div className="bg-gradient-to-br from-indigo-600 to-indigo-800 p-2.5 rounded-xl text-white shadow-lg">
            <Database size={24} />
          </div>
          <div>
            <h1 className="text-xl font-extrabold text-slate-800 tracking-tight leading-none">DataHarmonizer Pro</h1>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">
              {isReadOnly ? 'Shared Session' : 'Workspace Admin'}
            </p>
          </div>
        </div>

        {companyDatasets.length > 0 && (
          <div className="flex items-center gap-6">
            <div className="relative group">
              <div className="flex items-center gap-3 px-6 py-2.5 bg-slate-50 border border-slate-200 rounded-2xl cursor-pointer">
                <Building2 size={18} className="text-indigo-500" />
                <div className="text-left">
                  <p className="text-[8px] font-black text-slate-400 uppercase leading-none mb-1">Company Filter</p>
                  <p className="text-sm font-black text-slate-800 leading-none truncate max-w-[120px]">
                    {selectedCompanyId === 'all' ? 'All Entities' : companyDatasets.find(d => d.id === selectedCompanyId)?.name}
                  </p>
                </div>
                <ChevronDown size={16} className="text-slate-400" />
              </div>
              <div className="absolute right-0 mt-2 w-80 bg-white rounded-3xl shadow-2xl border border-slate-100 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all z-[120] p-4">
                <button onClick={() => setSelectedCompanyId('all')} className="w-full text-left px-4 py-3 rounded-xl mb-2 hover:bg-slate-50 text-sm font-black uppercase tracking-tight">Master Summary (All)</button>
                <div className="max-h-64 overflow-y-auto custom-scrollbar">
                  {companyDatasets.map(ds => (
                    <button key={ds.id} onClick={() => setSelectedCompanyId(ds.id)} className={`w-full text-left px-4 py-3 rounded-xl flex items-center justify-between hover:bg-slate-50 mb-1 ${selectedCompanyId === ds.id ? 'bg-indigo-50 text-indigo-700' : 'text-slate-600'}`}>
                      <span className="text-sm font-bold truncate">{ds.name}</span>
                      {!isReadOnly && <Trash2 size={14} className="text-slate-300 hover:text-rose-500" onClick={(e) => removeCompany(ds.id, e)} />}
                    </button>
                  ))}
                </div>
              </div>
            </div>

            <div className="relative group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
              <input type="text" placeholder="Query records..." className="pl-10 pr-4 py-2.5 border border-slate-200 rounded-xl text-sm w-64 bg-slate-50 focus:ring-2 focus:ring-indigo-500/20" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
            </div>
            <button onClick={() => handleExport()} className="flex items-center gap-2 bg-slate-900 text-white px-6 py-2.5 rounded-xl text-sm font-bold shadow-lg">
              <Download size={18} /> Export
            </button>
          </div>
        )}
      </header>

      <main className="flex-1 flex overflow-hidden">
        {/* Sidebar */}
        <aside className="w-80 bg-white border-r border-slate-200 p-6 flex flex-col space-y-8 hidden md:flex overflow-y-auto custom-scrollbar shrink-0">

          {/* Creator Tools (Only if not read-only) */}
          {!isReadOnly && (
            <div className="space-y-4 shrink-0">
              <label className="block p-8 border-2 border-dashed border-slate-200 rounded-3xl hover:border-indigo-500 hover:bg-indigo-50/50 cursor-pointer transition-all text-center group bg-slate-50/50">
                <input type="file" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleFileUpload} />
                <div className="bg-white p-3 rounded-full shadow-sm mx-auto w-fit mb-4 group-hover:scale-110 transition-transform">
                  <Plus className="text-slate-400 group-hover:text-indigo-600" size={32} />
                </div>
                <span className="text-sm font-black text-slate-700 block uppercase tracking-wide">Upload & Link Data</span>
                <span className="text-[10px] text-slate-400 font-bold uppercase mt-2 block tracking-widest">Excel / CSV Portal Source</span>
              </label>
            </div>
          )}

          {/* Navigation */}
          {companyDatasets.length > 0 && (
            <nav className="space-y-2 flex-1">
              <div className="text-[10px] text-slate-400 font-black uppercase tracking-[0.3em] px-4 mb-3 flex items-center gap-2">
                <LayoutGrid size={12} /> Modules
              </div>
              {[
                { id: 'dashboard', label: 'Dashboard', icon: PieChart },
                { id: 'preview', label: 'Data Grid', icon: Table },
                { id: 'pivot', label: 'Pivot Synthesis', icon: LayoutGrid },
                { id: 'ai', label: 'AI Narrative', icon: Sparkles }
              ].map(item => (
                <button 
                  key={item.id}
                  onClick={() => setActiveTab(item.id as any)}
                  className={`w-full flex items-center gap-3 px-6 py-4 rounded-2xl text-sm font-black transition-all ${activeTab === item.id ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-100 translate-x-1' : 'text-slate-500 hover:bg-slate-50'}`}
                >
                  <item.icon size={20} /> {item.label}
                </button>
              ))}
            </nav>
          )}

          {/* Collaboration Module */}
          {companyDatasets.length > 0 && (
            <div className="pt-6 border-t border-slate-100 space-y-4 shrink-0">
              <div className="text-[10px] text-slate-400 font-black uppercase tracking-[0.3em] px-4">Collaboration</div>
              <div className="bg-slate-50 p-6 rounded-[32px] border border-slate-100 space-y-4">
                <div className="flex items-center gap-3">
                  <div className="bg-indigo-500 p-2 rounded-xl text-white shadow-lg">
                    <Share2 size={16} />
                  </div>
                  <span className="text-[11px] font-black text-slate-800 uppercase tracking-widest leading-none">Share Workspace</span>
                </div>
                <p className="text-[10px] text-slate-400 font-bold leading-relaxed">Encodes current data into a shareable URL snapshot for viewers.</p>
                <button 
                  onClick={generateShareLink}
                  className={`w-full py-3.5 rounded-xl font-black text-[10px] uppercase tracking-[0.2em] transition-all flex items-center justify-center gap-2 border shadow-sm ${
                    shareStatus === 'copied' ? 'bg-emerald-500 text-white border-emerald-400' : 'bg-white text-indigo-600 border-indigo-100 hover:bg-indigo-50'
                  }`}
                >
                  {shareStatus === 'copied' ? <ShieldCheck size={16} /> : <Copy size={16} />}
                  {shareStatus === 'copied' ? 'Link Copied' : 'Generate Link'}
                </button>
              </div>

              {!isReadOnly && (
                <button 
                  onClick={clearAllCompanies}
                  className="w-full flex items-center justify-center gap-2 py-4 bg-rose-50 text-rose-600 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-rose-600 hover:text-white transition-all border border-rose-100"
                >
                  <Trash2 size={16} /> Wipe Portal
                </button>
              )}
            </div>
          )}
        </aside>

        {/* Content Area */}
        <section className="flex-1 overflow-auto p-10 custom-scrollbar relative">
          {companyDatasets.length === 0 && !isProcessing && (
            <div className="h-full flex flex-col items-center justify-center text-center max-w-lg mx-auto">
              <div className="bg-white p-14 rounded-[50px] shadow-2xl border border-slate-100 mb-8 relative overflow-hidden">
                <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-indigo-500 to-rose-500"></div>
                <div className="bg-indigo-50 w-24 h-24 rounded-full flex items-center justify-center mx-auto mb-8">
                  <BarChart3 size={48} className="text-indigo-600" />
                </div>
                <h2 className="text-4xl font-black text-slate-800 mb-6 tracking-tight">System Ready</h2>
                <p className="text-slate-500 mb-10 leading-relaxed text-lg">Your synchronized data remains private in your local browser. Share the link with others to provide a read-only dashboard of your data.</p>
                <label className="inline-flex items-center gap-3 bg-indigo-600 hover:bg-indigo-700 text-white px-12 py-5 rounded-3xl font-black text-lg transition-all cursor-pointer shadow-2xl active:scale-95 group">
                  <FileUp size={28} /> Link Source Data
                  <input type="file" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleFileUpload} />
                </label>
              </div>
            </div>
          )}

          {isProcessing && (
            <div className="h-full flex flex-col items-center justify-center space-y-6">
              <RefreshCw className="animate-spin text-indigo-600" size={64} />
              <h3 className="text-2xl font-black text-slate-800 tracking-tight">Restructuring Context</h3>
            </div>
          )}

          {companyDatasets.length > 0 && !isProcessing && (
            <div key={companyDatasets.length + selectedCompanyId} className="max-w-7xl mx-auto space-y-10 animate-in fade-in duration-700">
              <div className="flex items-center justify-between border-b border-slate-200 pb-10">
                <div>
                  <h2 className="text-4xl font-black text-slate-900 tracking-tight flex items-center gap-4">
                    {activeTab === 'dashboard' && <PieChart size={40} />}
                    {activeTab === 'preview' && <Table size={40} />}
                    {activeTab === 'pivot' && <LayoutGrid size={40} />}
                    {activeTab === 'ai' && <Sparkles size={40} />}
                    <span className="capitalize">{activeTab} View</span>
                  </h2>
                  <div className="flex items-center gap-4 mt-3">
                    <span className="text-slate-400 font-black text-[10px] uppercase tracking-[0.3em]">
                      ACTIVE ENTITIES: {companyDatasets.length}
                    </span>
                    <span className="w-1.5 h-1.5 rounded-full bg-slate-300"></span>
                    <span className="text-slate-400 font-black text-[10px] uppercase tracking-[0.3em]">
                      CONTEXT: {selectedCompanyId === 'all' ? 'Consolidated Master' : companyDatasets.find(d => d.id === selectedCompanyId)?.name}
                    </span>
                  </div>
                </div>

                {isReadOnly && (
                  <div className="flex items-center gap-3 bg-indigo-50 border border-indigo-100 px-6 py-4 rounded-[32px]">
                    <div className="relative flex items-center justify-center h-4 w-4">
                       <span className="pulse-dot"></span>
                       <span className="relative inline-flex rounded-full h-3 w-3 bg-emerald-500"></span>
                    </div>
                    <p className="text-[11px] font-black text-indigo-700 uppercase tracking-widest">Live Shared Session</p>
                  </div>
                )}
              </div>

              {activeTab === 'dashboard' && (
                <Dashboard rows={activeDataRows} onDrillDown={(t, r) => setDrillDownData({ title: t, rows: r })} />
              )}

              {/* Fix: Fixed typo 'active Tab' to 'activeTab' */}
              {activeTab === 'preview' && (
                <DataTable headers={activeHeaders} rows={filteredRows} highlightTerm={searchTerm} />
              )}

              {activeTab === 'pivot' && (
                <PivotView rows={activeDataRows} headers={activeHeaders} />
              )}

              {activeTab === 'ai' && (
                <div className="bg-white rounded-[40px] shadow-3xl border border-slate-100 p-16 relative overflow-hidden">
                  <div className="flex flex-col md:flex-row md:items-center justify-between gap-8 mb-12 relative z-10">
                    <div>
                      <h3 className="text-4xl font-black text-slate-900 tracking-tighter">Operational Narrative</h3>
                      <p className="text-slate-400 text-lg mt-2">LLM-Synthesized context of current workforce vectors.</p>
                    </div>
                    <button 
                      onClick={generateAiWriteup}
                      disabled={isGeneratingAi}
                      className="flex items-center justify-center gap-3 bg-indigo-600 hover:bg-indigo-700 text-white px-10 py-5 rounded-3xl font-black text-lg transition-all shadow-2xl active:scale-95 whitespace-nowrap"
                    >
                      {isGeneratingAi ? <RefreshCw className="animate-spin" /> : <Sparkles />}
                      {aiSummary ? 'Regenerate Analysis' : 'Synthesize Insights'}
                    </button>
                  </div>
                  <div className="prose prose-slate max-w-none text-xl leading-relaxed text-slate-700 relative z-10 whitespace-pre-wrap">
                    {aiSummary || <p className="text-slate-300 italic">Initiate AI analysis to generate executive narrative...</p>}
                  </div>
                </div>
              )}
            </div>
          )}
        </section>
      </main>

      {/* Detail Drill-down Modal */}
      {drillDownData && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-6xl h-[85vh] rounded-[40px] shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 duration-300">
            <div className="p-10 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
              <div className="flex items-center gap-5">
                <div className="bg-indigo-600 p-3 rounded-2xl text-white shadow-xl shadow-indigo-100">
                  <FileSpreadsheet size={32} />
                </div>
                <div>
                  <h3 className="text-2xl font-black text-slate-900 tracking-tight">{drillDownData.title}</h3>
                  <p className="text-[11px] text-slate-400 font-black uppercase tracking-widest mt-1">Audit Trail: {drillDownData.rows.length} Records</p>
                </div>
              </div>
              <div className="flex items-center gap-4">
                <button onClick={() => handleExport(drillDownData.rows, drillDownData.title)} className="bg-emerald-600 text-white px-8 py-3 rounded-xl text-sm font-black uppercase tracking-widest transition-all shadow-md">Export View</button>
                <button onClick={() => setDrillDownData(null)} className="p-3 hover:bg-slate-200 rounded-full text-slate-400 transition-colors"><X size={32} /></button>
              </div>
            </div>
            <div className="flex-1 overflow-hidden p-10">
              <DataTable headers={activeHeaders} rows={drillDownData.rows} />
            </div>
          </div>
        </div>
      )}

      <footer className="bg-white border-t border-slate-200 px-8 py-3 flex items-center justify-between text-[10px] text-slate-400 font-bold uppercase tracking-[0.3em] shrink-0">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-2">
            <div className={`w-2 h-2 rounded-full ${companyDatasets.length > 0 ? 'bg-emerald-500 animate-pulse' : 'bg-slate-300'}`}></div> 
            {isReadOnly ? 'READ-ONLY SHARED SESSION' : 'MASTER PORTAL ADMIN'}
          </div>
          <div className="border-l pl-6 border-slate-200">SNAP-SYNC v3.0 ACTIVE</div>
        </div>
        <div className="flex items-center gap-2">
           <ShieldCheck size={14} className="text-indigo-400" />
           DATA PERSISTENCE: {isReadOnly ? 'TEMPORARY (URL)' : 'LOCAL STORAGE'}
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useCallback } from 'react';
import * as XLSX from 'xlsx';
import LZString from 'lz-string';
import { 
  FileUp, 
  Table, 
  LayoutGrid, 
  Sparkles, 
  Download, 
  RefreshCw,
  Search,
  Database,
  BarChart3,
  PieChart,
  X,
  FileSpreadsheet,
  Building2,
  ChevronDown,
  Plus,
  Trash2,
  AlertTriangle,
  Share2,
  Copy,
  ExternalLink,
  ShieldCheck,
  Eye,
  Settings,
  Link,
  Info
} from 'lucide-react';
import { DataRow, ProcessedData, CompanyDataset } from './types';
import { harmonizeData } from './utils/dataProcessor';
import { DataTable } from './components/DataTable';
import { PivotView } from './components/PivotView';
import { Dashboard } from './components/Dashboard';
import { generateDataSummary } from './services/gemini';

const STORAGE_KEY = 'harmonizer_company_datasets_v3';

const App: React.FC = () => {
  // Persistence & Sharing State
  const [isReadOnly, setIsReadOnly] = useState(false);
  const [shareStatus, setShareStatus] = useState<'idle' | 'generating' | 'copied' | 'error'>('idle');
  const [hydrationError, setHydrationError] = useState<string | null>(null);

  const [companyDatasets, setCompanyDatasets] = useState<CompanyDataset[]>(() => {
    // 1. Check URL for Shared Snapshot first
    const hash = window.location.hash;
    if (hash && hash.includes('data=')) {
      try {
        // Find the data parameter in the hash
        const match = hash.match(/data=([^&]*)/);
        if (match && match[1]) {
          const compressed = match[1];
          const decompressed = LZString.decompressFromEncodedURIComponent(compressed);
          if (decompressed) {
            const data = JSON.parse(decompressed);
            if (Array.isArray(data) && data.length > 0) {
              setIsReadOnly(true); 
              return data;
            }
          }
        }
      } catch (e) {
        console.error("Shared link hydration failed", e);
        // We set hydration error to show the user why it's empty
        return []; 
      }
    }

    // 2. Fallback to Local Storage
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to parse stored datasets", e);
      return [];
    }
  });

  const [selectedCompanyId, setSelectedCompanyId] = useState<string>('all');
  const [activeTab, setActiveTab] = useState<'preview' | 'pivot' | 'dashboard' | 'ai'>('dashboard');
  const [isProcessing, setIsProcessing] = useState(false);
  const [aiSummary, setAiSummary] = useState<string>('');
  const [searchTerm, setSearchTerm] = useState('');
  const [isGeneratingAi, setIsGeneratingAi] = useState(false);

  const [pendingUpload, setPendingUpload] = useState<ProcessedData | null>(null);
  const [newCompanyName, setNewCompanyName] = useState('');
  const [drillDownData, setDrillDownData] = useState<{ title: string; rows: DataRow[] } | null>(null);

  // Hydration Error Detection
  useEffect(() => {
    if (window.location.hash.includes('data=') && companyDatasets.length === 0) {
      setHydrationError("The shared link appears to be corrupted or the dataset is too large for your browser to process. Please ask the sender to share a smaller subset of data.");
    }
  }, [companyDatasets]);

  // Persistence Sync (Local Only)
  useEffect(() => {
    if (isReadOnly) return;
    try {
      if (companyDatasets.length === 0) {
        localStorage.removeItem(STORAGE_KEY);
      } else {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(companyDatasets));
      }
    } catch (e) {
      console.warn('Persistence Error:', e);
    }
  }, [companyDatasets, isReadOnly]);

  /**
   * Data Minimization Strategy:
   * Strips originalHeaders and other metadata to reduce payload size 
   * specifically for URL sharing.
   */
  const generateShareLink = useCallback(() => {
    if (companyDatasets.length === 0) return;
    setShareStatus('generating');

    try {
      // Minimize the dataset payload for sharing
      const minimized = companyDatasets.map(ds => ({
        id: ds.id,
        name: ds.name,
        data: {
          headers: ds.data.headers,
          rows: ds.data.rows
          // We intentionally skip originalHeaders for sharing to save space
        }
      }));

      const json = JSON.stringify(minimized);
      const compressed = LZString.compressToEncodedURIComponent(json);
      const shareUrl = `${window.location.origin}${window.location.pathname}#data=${compressed}`;

      // Verification
      if (shareUrl.length > 12000) {
        setShareStatus('error');
        alert("CRITICAL: Dataset too large for URL sharing. Your link exceeds 12,000 characters. Please unlink some companies or use a smaller file to share.");
        return;
      }

      navigator.clipboard.writeText(shareUrl).then(() => {
        setShareStatus('copied');
        // Update browser URL so the user can also manually copy from the address bar
        window.location.hash = `data=${compressed}`;
        setTimeout(() => setShareStatus('idle'), 4000);
      });
    } catch (e) {
      console.error("Link generation failed", e);
      setShareStatus('error');
    }
  }, [companyDatasets]);

  const exitReadOnly = () => {
    if (window.confirm("Switch to your personal workspace?")) {
      window.location.hash = '';
      window.location.reload();
    }
  };

  const importSharedData = () => {
    if (window.confirm("Save this shared data as your permanent personal workspace? This overwrites existing local data.")) {
      setIsReadOnly(false);
      localStorage.setItem(STORAGE_KEY, JSON.stringify(companyDatasets));
      window.location.hash = '';
      alert("Successfully imported!");
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (isReadOnly) return;
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const data = XLSX.utils.sheet_to_json(ws) as DataRow[];
        const harmonized = harmonizeData(data);
        setPendingUpload(harmonized);
        setNewCompanyName(file.name.split('.')[0]); 
      } catch (err) {
        console.error("Error reading file", err);
        alert("Corrupted file format. Please use standard XLSX or CSV.");
      } finally {
        setIsProcessing(false);
        e.target.value = '';
      }
    };
    reader.readAsBinaryString(file);
  };

  const confirmUpload = () => {
    if (!pendingUpload || !newCompanyName.trim()) return;
    const newEntry: CompanyDataset = {
      id: crypto.randomUUID(),
      name: newCompanyName.trim(),
      data: pendingUpload
    };
    setCompanyDatasets(prev => [...prev, newEntry]);
    setSelectedCompanyId(newEntry.id);
    setPendingUpload(null);
    setNewCompanyName('');
    setActiveTab('dashboard');
  };

  const activeDataRows = useMemo(() => {
    if (companyDatasets.length === 0) return [];
    if (selectedCompanyId === 'all') {
      return companyDatasets.flatMap(ds => ds.data.rows);
    }
    return companyDatasets.find(ds => ds.id === selectedCompanyId)?.data.rows || [];
  }, [companyDatasets, selectedCompanyId]);

  const activeHeaders = useMemo(() => {
    if (companyDatasets.length === 0) return [];
    if (selectedCompanyId === 'all') {
      const allHeaders = new Set<string>();
      companyDatasets.forEach(ds => ds.data.headers.forEach(h => allHeaders.add(h)));
      return Array.from(allHeaders);
    }
    return companyDatasets.find(ds => ds.id === selectedCompanyId)?.data.headers || [];
  }, [companyDatasets, selectedCompanyId]);

  const filteredRows = useMemo(() => {
    if (!searchTerm) return activeDataRows;
    const lowerSearch = searchTerm.toLowerCase();
    return activeDataRows.filter(row => 
      Object.values(row).some(val => String(val).toLowerCase().includes(lowerSearch))
    );
  }, [activeDataRows, searchTerm]);

  const handleExport = (dataToExport?: DataRow[], fileName?: string) => {
    const rowsToExport = dataToExport || activeDataRows;
    if (rowsToExport.length === 0) return;
    const worksheet = XLSX.utils.json_to_sheet(rowsToExport);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "Data");
    XLSX.writeFile(workbook, `${fileName || 'Export'}.xlsx`);
  };

  const removeCompany = useCallback((id: string, e?: React.MouseEvent) => {
    if (isReadOnly) return;
    if (e) e.stopPropagation();
    if (window.confirm(`Permanently remove this organization context?`)) {
      setCompanyDatasets(prev => prev.filter(ds => ds.id !== id));
      if (selectedCompanyId === id) setSelectedCompanyId('all');
    }
  }, [isReadOnly, companyDatasets, selectedCompanyId]);

  const clearAllCompanies = useCallback(() => {
    if (isReadOnly) return;
    if (window.confirm('PURGE ALL DATA: This will wipe your local storage portal. Proceed?')) {
      setCompanyDatasets([]);
      setSelectedCompanyId('all');
      localStorage.removeItem(STORAGE_KEY);
    }
  }, [isReadOnly]);

  const generateAiWriteup = useCallback(async () => {
    if (activeDataRows.length === 0) return;
    setIsGeneratingAi(true);
    try {
      const narrative = await generateDataSummary(activeDataRows);
      setAiSummary(narrative);
    } catch (error) {
      setAiSummary("AI synthesis unavailable for this dataset density.");
    } finally {
      setIsGeneratingAi(false);
    }
  }, [activeDataRows]);

  return (
    <div className="min-h-screen flex flex-col font-sans bg-slate-50/50 overflow-hidden h-screen">
      {/* Shared View Warning Banner */}
      {isReadOnly && (
        <div className="bg-slate-900 text-white px-8 py-3 flex items-center justify-between text-xs font-black uppercase tracking-widest z-[60] shadow-2xl border-b border-white/10">
          <div className="flex items-center gap-4">
            <div className="bg-emerald-500 w-2.5 h-2.5 rounded-full animate-pulse shadow-[0_0_10px_#10b981]"></div>
            <span className="flex items-center gap-2">
              <Eye size={16} /> Viewing Active Shared Data Link
            </span>
          </div>
          <div className="flex items-center gap-4">
            <button onClick={importSharedData} className="bg-indigo-600 hover:bg-indigo-500 px-4 py-2 rounded-xl transition-all flex items-center gap-2 text-[10px] shadow-lg">
              <Download size={14} /> Import to My Portal
            </button>
            <div className="w-px h-6 bg-white/10"></div>
            <button onClick={exitReadOnly} className="text-white/60 hover:text-white transition-all underline decoration-white/20">
              Return to Personal Workspace
            </button>
          </div>
        </div>
      )}

      {/* Upload Confirmation Modal */}
      {pendingUpload && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-md rounded-[40px] shadow-2xl p-10 space-y-8 animate-in zoom-in-95">
            <div className="text-center space-y-2">
              <div className="bg-indigo-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4">
                <Building2 className="text-indigo-600" size={32} />
              </div>
              <h3 className="text-2xl font-black text-slate-800 tracking-tight leading-none">Map Organization</h3>
              <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest mt-2">Define entity for this dataset</p>
            </div>
            <input 
              autoFocus
              type="text"
              className="w-full p-5 bg-slate-50 border border-slate-200 rounded-2xl text-lg font-bold outline-none focus:ring-2 focus:ring-indigo-500/20 transition-all"
              value={newCompanyName}
              onChange={(e) => setNewCompanyName(e.target.value)}
              placeholder="e.g. Acme Logistics..."
              onKeyDown={(e) => e.key === 'Enter' && confirmUpload()}
            />
            <div className="flex gap-4">
              <button onClick={() => setPendingUpload(null)} className="flex-1 py-4 text-slate-400 font-black uppercase text-[10px] tracking-widest hover:bg-slate-50 rounded-2xl transition-all">Discard</button>
              <button onClick={confirmUpload} className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl shadow-indigo-100 transition-all active:scale-95">Verify & Link</button>
            </div>
          </div>
        </div>
      )}

      {/* Header */}
      <header className="bg-white border-b border-slate-200 px-8 py-4 flex items-center justify-between sticky top-0 z-50 shadow-sm shrink-0">
        <div className="flex items-center gap-3">
          <div className="bg-gradient-to-br from-indigo-600 to-indigo-800 p-2.5 rounded-xl text-white shadow-lg">
            <Database size={24} />
          </div>
          <div>
            <h1 className="text-xl font-extrabold text-slate-800 tracking-tight leading-none">DataHarmonizer Pro</h1>
            <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mt-1">
              {isReadOnly ? 'Collaborative Instance' : 'Master Portal Admin'}
            </p>
          </div>
        </div>

        {companyDatasets.length > 0 && (
          <div className="flex items-center gap-6">
            <div className="relative group">
              <div className="flex items-center gap-3 px-6 py-2.5 bg-slate-50 border border-slate-200 rounded-2xl cursor-pointer hover:border-indigo-500 transition-colors">
                <Building2 size={18} className="text-indigo-500" />
                <div className="text-left">
                  <p className="text-[8px] font-black text-slate-400 uppercase leading-none mb-1">Active Context</p>
                  <p className="text-sm font-black text-slate-800 leading-none truncate max-w-[140px]">
                    {selectedCompanyId === 'all' ? 'Consolidated Master' : companyDatasets.find(d => d.id === selectedCompanyId)?.name}
                  </p>
                </div>
                <ChevronDown size={16} className="text-slate-400" />
              </div>
              <div className="absolute right-0 mt-2 w-80 bg-white rounded-3xl shadow-2xl border border-slate-100 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all z-[120] p-4 overflow-hidden">
                <button onClick={() => setSelectedCompanyId('all')} className="w-full text-left px-4 py-3 rounded-xl mb-2 hover:bg-slate-50 text-[10px] font-black uppercase tracking-widest text-indigo-600 border border-indigo-50">Master Summary (All)</button>
                <div className="max-h-64 overflow-y-auto custom-scrollbar">
                  {companyDatasets.map(ds => (
                    <button key={ds.id} onClick={() => setSelectedCompanyId(ds.id)} className={`w-full text-left px-4 py-3 rounded-xl flex items-center justify-between hover:bg-slate-50 mb-1 transition-colors ${selectedCompanyId === ds.id ? 'bg-indigo-50 text-indigo-700 font-black' : 'text-slate-600 font-bold'}`}>
                      <span className="text-sm truncate">{ds.name}</span>
                      {!isReadOnly && <Trash2 size={14} className="text-slate-300 hover:text-rose-500 transition-colors" onClick={(e) => removeCompany(ds.id, e)} />}
                    </button>
                  ))}
                </div>
              </div>
            </div>

            <div className="relative group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
              <input type="text" placeholder="Deep query..." className="pl-10 pr-4 py-2.5 border border-slate-200 rounded-xl text-sm w-64 bg-slate-50 focus:ring-2 focus:ring-indigo-500/20 outline-none transition-all" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
            </div>
            <button onClick={() => handleExport()} className="flex items-center gap-2 bg-slate-900 hover:bg-black text-white px-6 py-2.5 rounded-xl text-sm font-bold shadow-lg transition-all active:scale-95">
              <Download size={18} /> Export
            </button>
          </div>
        )}
      </header>

      <main className="flex-1 flex overflow-hidden">
        {/* Sidebar */}
        <aside className="w-80 bg-white border-r border-slate-200 p-6 flex flex-col space-y-8 hidden md:flex overflow-y-auto custom-scrollbar shrink-0">

          {/* Creator Tools */}
          {!isReadOnly && (
            <div className="space-y-4 shrink-0">
              <label className="block p-8 border-2 border-dashed border-slate-200 rounded-[40px] hover:border-indigo-500 hover:bg-indigo-50/50 cursor-pointer transition-all text-center group bg-slate-50/50">
                <input type="file" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleFileUpload} />
                <div className="bg-white p-4 rounded-full shadow-sm mx-auto w-fit mb-4 group-hover:scale-110 transition-transform">
                  <Plus className="text-slate-400 group-hover:text-indigo-600" size={32} />
                </div>
                <span className="text-[10px] font-black text-slate-700 block uppercase tracking-[0.2em]">Add Source Sheet</span>
                <span className="text-[9px] text-slate-400 font-bold uppercase mt-2 block tracking-widest">Excel / CSV Portal Data</span>
              </label>
            </div>
          )}

          {/* Navigation */}
          {companyDatasets.length > 0 && (
            <nav className="space-y-2 flex-1">
              <div className="text-[10px] text-slate-400 font-black uppercase tracking-[0.3em] px-4 mb-3 flex items-center gap-2">
                <LayoutGrid size={12} /> Portal Access
              </div>
              {[
                { id: 'dashboard', label: 'Intelligence Hub', icon: PieChart },
                { id: 'preview', label: 'Master Data Grid', icon: Table },
                { id: 'pivot', label: 'Pivot Engine', icon: LayoutGrid },
                { id: 'ai', label: 'AI Narrative', icon: Sparkles }
              ].map(item => (
                <button 
                  key={item.id}
                  onClick={() => setActiveTab(item.id as any)}
                  className={`w-full flex items-center gap-3 px-6 py-4 rounded-2xl text-sm font-black transition-all ${activeTab === item.id ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-100 translate-x-1' : 'text-slate-500 hover:bg-slate-50'}`}
                >
                  <item.icon size={20} /> {item.label}
                </button>
              ))}
            </nav>
          )}

          {/* Collaboration Module (Share Link Feature) */}
          {companyDatasets.length > 0 && (
            <div className="pt-6 border-t border-slate-100 space-y-4 shrink-0">
              <div className="text-[10px] text-slate-400 font-black uppercase tracking-[0.3em] px-4">Collaboration Console</div>
              <div className="bg-indigo-50/50 p-6 rounded-[32px] border border-indigo-100 space-y-4 shadow-inner">
                <div className="flex items-center gap-3">
                  <div className="bg-indigo-600 p-2.5 rounded-xl text-white shadow-lg">
                    <Share2 size={16} />
                  </div>
                  <span className="text-[11px] font-black text-indigo-700 uppercase tracking-widest leading-none">Share Workspace</span>
                </div>
                <p className="text-[10px] text-indigo-900/60 font-bold leading-relaxed">
                  Creates a unique, data-rich URL. Share this link for recipients to view your exact dashboard.
                </p>
                <div className="space-y-2">
                  <button 
                    onClick={generateShareLink}
                    disabled={shareStatus === 'generating'}
                    className={`w-full py-4 rounded-2xl font-black text-[10px] uppercase tracking-[0.2em] transition-all flex items-center justify-center gap-3 border ${
                      shareStatus === 'copied' ? 'bg-emerald-500 text-white border-emerald-400 shadow-emerald-100' : 
                      shareStatus === 'error' ? 'bg-rose-500 text-white border-rose-400' :
                      'bg-white text-indigo-600 border-indigo-200 hover:bg-indigo-50 shadow-sm'
                    }`}
                  >
                    {shareStatus === 'generating' ? <RefreshCw className="animate-spin" size={16} /> : 
                     shareStatus === 'copied' ? <ShieldCheck size={16} /> : <Link size={16} />}
                    {shareStatus === 'generating' ? 'Syncing...' : 
                     shareStatus === 'copied' ? 'Link Copied!' : 
                     shareStatus === 'error' ? 'Failed - Too Large' : 'Generate Link'}
                  </button>
                  {shareStatus === 'copied' && (
                    <div className="flex items-center gap-2 justify-center text-[9px] font-black text-emerald-600 animate-in fade-in">
                      <ShieldCheck size={10} /> LINK CONTAINS SNAPSHOT
                    </div>
                  )}
                </div>
              </div>

              {!isReadOnly && (
                <button 
                  onClick={clearAllCompanies}
                  className="w-full flex items-center justify-center gap-2 py-4 bg-rose-50 text-rose-600 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-rose-600 hover:text-white transition-all border border-rose-100"
                >
                  <Trash2 size={16} /> Purge Portal Storage
                </button>
              )}
            </div>
          )}
        </aside>

        {/* Content Area */}
        <section className="flex-1 overflow-auto p-10 custom-scrollbar relative">

          {/* Hydration Error State */}
          {hydrationError && companyDatasets.length === 0 && (
            <div className="h-full flex flex-col items-center justify-center text-center max-w-lg mx-auto">
               <div className="bg-rose-50 p-12 rounded-[40px] border border-rose-100 shadow-2xl space-y-6">
                 <div className="bg-white w-20 h-20 rounded-full flex items-center justify-center mx-auto text-rose-500 shadow-sm">
                   <AlertTriangle size={40} />
                 </div>
                 <h2 className="text-2xl font-black text-rose-900 tracking-tight">Sync Failure</h2>
                 <p className="text-rose-700/70 font-bold leading-relaxed">{hydrationError}</p>
                 <button onClick={() => {window.location.hash = ''; window.location.reload();}} className="bg-rose-600 text-white px-8 py-4 rounded-2xl font-black text-xs uppercase tracking-widest active:scale-95 shadow-lg">Reset Workspace</button>
               </div>
            </div>
          )}

          {/* Empty State */}
          {companyDatasets.length === 0 && !isProcessing && !hydrationError && (
            <div className="h-full flex flex-col items-center justify-center text-center max-w-lg mx-auto">
              <div className="bg-white p-14 rounded-[50px] shadow-2xl border border-slate-100 mb-8 relative overflow-hidden animate-in zoom-in-95 duration-500">
                <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-indigo-500 to-emerald-500"></div>
                <div className="bg-indigo-50 w-24 h-24 rounded-full flex items-center justify-center mx-auto mb-8">
                  <BarChart3 size={48} className="text-indigo-600" />
                </div>
                <h2 className="text-3xl font-black text-slate-800 mb-6 tracking-tight">Workforce Portal Empty</h2>
                <p className="text-slate-500 mb-10 leading-relaxed text-lg">No synchronized data found in this session. Upload a sheet or use a shared link to activate the intelligence portal.</p>
                <label className="inline-flex items-center gap-4 bg-indigo-600 hover:bg-indigo-700 text-white px-12 py-5 rounded-3xl font-black text-lg transition-all cursor-pointer shadow-2xl active:scale-95 group">
                  <FileUp size={28} className="group-hover:translate-y-[-2px] transition-transform" /> Link Source File
                  <input type="file" className="hidden" accept=".xlsx, .xls, .csv" onChange={handleFileUpload} />
                </label>
