            <div className="h-full flex flex-col items-center justify-center space-y-6">
              <RefreshCw className="animate-spin text-indigo-600" size={64} />
              <div className="text-center">
                <h3 className="text-2xl font-black text-slate-800 tracking-tight leading-none">Mapping Vectors</h3>
                <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.3em] mt-3">Harmonizing Data Types & Schema</p>
              </div>
