          {companyDatasets.length > 0 && !isProcessing && (
            <div key={companyDatasets.length + selectedCompanyId} className="max-w-7xl mx-auto space-y-10 animate-in fade-in slide-in-from-bottom-2 duration-700">
              <div className="flex items-center justify-between border-b border-slate-200 pb-10">
                <div>
                  <h2 className="text-4xl font-black text-slate-900 tracking-tight flex items-center gap-4">
                    {activeTab === 'dashboard' && <PieChart size={44} className="text-indigo-600" />}
                    {activeTab === 'preview' && <Table size={44} className="text-indigo-600" />}
                    {activeTab === 'pivot' && <LayoutGrid size={44} className="text-indigo-600" />}
                    {activeTab === 'ai' && <Sparkles size={44} className="text-indigo-600" />}
                    <span className="capitalize">{activeTab === 'preview' ? 'Data Grid' : activeTab === 'ai' ? 'AI Insights' : activeTab}</span>
                  </h2>
                  <div className="flex items-center gap-4 mt-3">
                    <span className="text-slate-400 font-black text-[10px] uppercase tracking-[0.3em] flex items-center gap-2">
                      <div className="w-2 h-2 rounded-full bg-emerald-500"></div>
                      Active Entities: {companyDatasets.length}
                    </span>
                    <span className="w-1.5 h-1.5 rounded-full bg-slate-300"></span>
                    <span className="text-slate-400 font-black text-[10px] uppercase tracking-[0.3em]">
                      Context: {selectedCompanyId === 'all' ? 'Consolidated Master' : companyDatasets.find(d => d.id === selectedCompanyId)?.name}
                    </span>
                  </div>
                </div>

                {isReadOnly ? (
                  <div className="flex items-center gap-4 bg-slate-900 border border-white/10 px-6 py-4 rounded-[32px] shadow-2xl">
                    <div className="relative flex items-center justify-center h-4 w-4">
                       <div className="absolute inset-0 bg-emerald-500/30 rounded-full animate-ping"></div>
                       <div className="relative inline-flex rounded-full h-3 w-3 bg-emerald-500"></div>
                    </div>
                    <p className="text-[11px] font-black text-white uppercase tracking-widest">LIVE SHARED DATASET</p>
                  </div>
                ) : (
                  <div className="flex items-center gap-4 bg-indigo-50 border border-indigo-100 px-6 py-4 rounded-[32px]">
                    <ShieldCheck size={18} className="text-indigo-600" />
                    <p className="text-[11px] font-black text-indigo-700 uppercase tracking-widest">PRIVATE ADMIN PORTAL</p>
                  </div>
                )}
              </div>

              {activeTab === 'dashboard' && (
                <Dashboard rows={activeDataRows} onDrillDown={(t, r) => setDrillDownData({ title: t, rows: r })} />
              )}

              {activeTab === 'preview' && (
                <DataTable headers={activeHeaders} rows={filteredRows} highlightTerm={searchTerm} />
              )}

              {activeTab === 'pivot' && (
                <PivotView rows={activeDataRows} headers={activeHeaders} />
              )}

              {activeTab === 'ai' && (
                <div className="bg-white rounded-[50px] shadow-3xl border border-slate-100 p-16 relative overflow-hidden">
                  <div className="absolute top-0 right-0 w-96 h-96 bg-indigo-50 rounded-full blur-[100px] -mr-48 -mt-48 opacity-40"></div>
                  <div className="flex flex-col md:flex-row md:items-center justify-between gap-10 mb-12 relative z-10">
                    <div>
                      <h3 className="text-4xl font-black text-slate-900 tracking-tighter">Operational Synthesis</h3>
                      <p className="text-slate-400 text-lg mt-3 font-medium">Executive AI narrative for {selectedCompanyId === 'all' ? 'the consolidated workforce' : companyDatasets.find(d => d.id === selectedCompanyId)?.name}.</p>
                    </div>
                    <button 
                      onClick={generateAiWriteup}
                      disabled={isGeneratingAi || activeDataRows.length === 0}
                      className="flex items-center justify-center gap-3 bg-indigo-600 hover:bg-indigo-700 text-white px-10 py-5 rounded-3xl font-black text-lg transition-all shadow-2xl active:scale-95 whitespace-nowrap disabled:bg-slate-200"
                    >
                      {isGeneratingAi ? <RefreshCw className="animate-spin" /> : <Sparkles />}
                      {aiSummary ? 'Regenerate Narrative' : 'Initiate Analysis'}
                    </button>
                  </div>
                  <div className="prose prose-slate max-w-none text-xl leading-relaxed text-slate-700 relative z-10 whitespace-pre-wrap font-medium">
                    {aiSummary || (
                      <div className="py-20 text-center space-y-4">
                        <Sparkles size={64} className="mx-auto text-slate-100" />
                        <p className="text-slate-300 italic tracking-wide">Ready for executive narrative synthesis...</p>
                      </div>
                    )}
                  </div>
                </div>
              )}
            </div>
          )}
        </section>
      </main>

      {/* Detail Drill-down Modal */}
      {drillDownData && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-6xl h-[85vh] rounded-[50px] shadow-3xl flex flex-col overflow-hidden animate-in zoom-in-95 duration-300">
            <div className="p-10 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
              <div className="flex items-center gap-6">
                <div className="bg-indigo-600 p-4 rounded-2xl text-white shadow-xl shadow-indigo-100">
                  <FileSpreadsheet size={32} />
                </div>
                <div>
                  <h3 className="text-2xl font-black text-slate-900 tracking-tight">{drillDownData.title}</h3>
                  <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mt-2 flex items-center gap-2">
                    <Info size={14} /> Audit Trace: {drillDownData.rows.length} Verified Records
                  </p>
                </div>
              </div>
              <div className="flex items-center gap-4">
                <button onClick={() => handleExport(drillDownData.rows, drillDownData.title)} className="bg-emerald-600 hover:bg-emerald-700 text-white px-8 py-3.5 rounded-2xl text-xs font-black uppercase tracking-widest transition-all shadow-lg active:scale-95">Export Subset</button>
                <button onClick={() => setDrillDownData(null)} className="p-4 hover:bg-slate-200 rounded-full text-slate-400 transition-colors"><X size={32} /></button>
              </div>
            </div>
            <div className="flex-1 overflow-hidden p-10 bg-white">
              <DataTable headers={activeHeaders} rows={drillDownData.rows} />
            </div>
          </div>
        </div>
      )}

      <footer className="bg-white border-t border-slate-200 px-8 py-4 flex items-center justify-between text-[10px] text-slate-400 font-black uppercase tracking-[0.3em] shrink-0">
        <div className="flex items-center gap-8">
          <div className="flex items-center gap-2">
            <div className={`w-2 h-2 rounded-full ${companyDatasets.length > 0 ? 'bg-emerald-500 animate-pulse' : 'bg-slate-300'}`}></div> 
            Portal Integrity: {isReadOnly ? 'READ-ONLY ACCESS' : 'FULL ADMIN ACTIVE'}
          </div>
          <div className="border-l pl-8 border-slate-200">Snap-Sync Protocol v3.1</div>
          <div className="border-l pl-8 border-slate-200">ISO Data Harmonization Verified</div>
        </div>
        <div className="flex items-center gap-3">
           <ShieldCheck size={16} className="text-indigo-400" />
           Storage Mode: {isReadOnly ? 'Volatile (Session URL)' : 'Persistent (Local Cache)'}
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useCallback } from 'react';
import * as XLSX from 'xlsx';
import LZString from 'lz-string';
import { 
  FileUp, 
  Table, 
  LayoutGrid, 
  Sparkles, 
  Download, 
  RefreshCw,
  Search,
  Database,
  BarChart3,
  PieChart,
  X,
  FileSpreadsheet,
  Building2,
  ChevronDown,
  Plus,
  Trash2,
  AlertTriangle,
  Share2,
  Copy,
  ShieldCheck,
  Eye,
  Settings,
  Link,
  Info,
  LogOut,
  UploadCloud,
  Layers,
  HardDrive
} from 'lucide-react';
import { DataRow, ProcessedData, CompanyDataset } from './types';
import { harmonizeData } from './utils/dataProcessor';
import { DataTable } from './components/DataTable';
import { PivotView } from './components/PivotView';
import { Dashboard } from './components/Dashboard';
import { generateDataSummary } from './services/gemini';

const STORAGE_KEY = 'harmonizer_pro_v5';

const App: React.FC = () => {
  // --- STATE MANAGEMENT ---
  const [isAdmin, setIsAdmin] = useState(true); // Default to true for the creator
  const [shareStatus, setShareStatus] = useState<'idle' | 'generating' | 'copied' | 'error'>('idle');
  const [activeTab, setActiveTab] = useState<'dashboard' | 'preview' | 'pivot' | 'ai'>('dashboard');
  const [isProcessing, setIsProcessing] = useState(false);
  const [aiSummary, setAiSummary] = useState<string>('');
  const [searchTerm, setSearchTerm] = useState('');
  const [isGeneratingAi, setIsGeneratingAi] = useState(false);
  const [pendingUpload, setPendingUpload] = useState<ProcessedData | null>(null);
  const [newCompanyName, setNewCompanyName] = useState('');
  const [drillDownData, setDrillDownData] = useState<{ title: string; rows: DataRow[] } | null>(null);

  // --- PERSISTENCE & HYDRATION ---
  const [companyDatasets, setCompanyDatasets] = useState<CompanyDataset[]>(() => {
    const hash = window.location.hash;
    if (hash && hash.includes('data=')) {
      try {
        const match = hash.match(/data=([^&]*)/);
        if (match && match[1]) {
          const decompressed = LZString.decompressFromEncodedURIComponent(match[1]);
          if (decompressed) {
            const data = JSON.parse(decompressed);
            if (Array.isArray(data)) {
              // If loaded via link, disable Admin tools for this session
              return data;
            }
          }
        }
      } catch (e) {
        console.error("Hydration Error:", e);
      }
    }
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  // Determine Role on Mount
  useEffect(() => {
    if (window.location.hash.includes('data=')) {
      setIsAdmin(false);
    }
  }, []);

  // Sync to LocalStorage (Admin Only)
  useEffect(() => {
    if (!isAdmin) return;
    if (companyDatasets.length === 0) {
      localStorage.removeItem(STORAGE_KEY);
    } else {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(companyDatasets));
    }
  }, [companyDatasets, isAdmin]);

  // --- CORE ACTIONS ---
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!isAdmin) return;
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws) as DataRow[];
        const harmonized = harmonizeData(data);
        setPendingUpload(harmonized);
        setNewCompanyName(file.name.split('.')[0]); 
      } catch (err) {
        alert("Upload failed. Unsupported file format.");
      } finally {
        setIsProcessing(false);
        e.target.value = '';
      }
    };
    reader.readAsBinaryString(file);
  };

  const confirmUpload = () => {
    const newEntry: CompanyDataset = {
      id: crypto.randomUUID(),
      name: newCompanyName.trim() || 'Untitled Entity',
      data: pendingUpload!
    };
    setCompanyDatasets(prev => [...prev, newEntry]);
    setPendingUpload(null);
  };

  const clearAllData = useCallback(() => {
    if (window.confirm("MASTER PURGE: This will permanently delete ALL uploaded sheets and resets your portal to empty. Proceed?")) {
      setCompanyDatasets([]);
      setAiSummary('');
      localStorage.removeItem(STORAGE_KEY);
      window.location.hash = '';
    }
  }, []);

  const generateShareLink = useCallback(() => {
    if (companyDatasets.length === 0) return;
    setShareStatus('generating');

    setTimeout(() => {
      try {
        // Optimization: Strip large metadata for URL length safety
        const sharedPayload = companyDatasets.map(ds => ({
          id: ds.id,
          name: ds.name,
          data: { headers: ds.data.headers, rows: ds.data.rows }
        }));

        const compressed = LZString.compressToEncodedURIComponent(JSON.stringify(sharedPayload));
        const url = `${window.location.origin}${window.location.pathname}#data=${compressed}`;

        if (url.length > 14000) {
          setShareStatus('error');
          alert("Error: Data too large for sharing via URL. Please reduce the number of sheets.");
          return;
        }

        navigator.clipboard.writeText(url);
        setShareStatus('copied');
        setTimeout(() => setShareStatus('idle'), 3000);
      } catch (e) {
        setShareStatus('error');
      }
    }, 800);
  }, [companyDatasets]);

  const generateAiWriteup = async () => {
    const rows = companyDatasets.flatMap(d => d.data.rows);
    if (rows.length === 0) return;
    setIsGeneratingAi(true);
    const summary = await generateDataSummary(rows);
    setAiSummary(summary);
    setIsGeneratingAi(false);
  };

  // --- RENDER LOGIC ---
  const activeRows = useMemo(() => companyDatasets.flatMap(d => d.data.rows), [companyDatasets]);
  const activeHeaders = useMemo(() => {
    const headers = new Set<string>();
    companyDatasets.forEach(d => d.data.headers.forEach(h => headers.add(h)));
    return Array.from(headers);
  }, [companyDatasets]);

  return (
    <div className="min-h-screen flex flex-col font-sans bg-[#0f172a] text-slate-200 overflow-hidden h-screen">

      {/* Role Banner */}
      {!isAdmin && (
        <div className="bg-indigo-600 text-white px-8 py-2 flex items-center justify-between text-[10px] font-black uppercase tracking-[0.3em] shadow-2xl z-[100]">
          <div className="flex items-center gap-3">
            <Eye size={14} className="animate-pulse" />
            Active Shared Session • View Only Access
          </div>
          <button onClick={() => {window.location.hash = ''; window.location.reload();}} className="hover:underline flex items-center gap-2">
            <LogOut size={12} /> Exit to My Workspace
          </button>
        </div>
      )}

      {/* Header */}
      <header className="bg-slate-900 border-b border-white/5 px-8 py-5 flex items-center justify-between shrink-0">
        <div className="flex items-center gap-4">
          <div className="bg-indigo-600 p-2.5 rounded-2xl text-white shadow-xl shadow-indigo-900/20">
            <Database size={24} />
          </div>
          <div>
            <h1 className="text-xl font-black text-white tracking-tight leading-none">DataHarmonizer Pro</h1>
            <p className="text-[9px] text-slate-500 font-black uppercase tracking-[0.4em] mt-1.5">
              {isAdmin ? 'Owner Console' : 'Intelligence Hub'}
            </p>
          </div>
        </div>

        <div className="flex items-center gap-6">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={16} />
            <input 
              type="text" 
              placeholder="Query portal..." 
              className="bg-slate-800 border-none rounded-xl pl-10 pr-4 py-2.5 text-sm focus:ring-2 focus:ring-indigo-500 transition-all w-64 text-white"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <button 
            onClick={() => {
              const worksheet = XLSX.utils.json_to_sheet(activeRows);
              const workbook = XLSX.utils.book_new();
              XLSX.utils.book_append_sheet(workbook, worksheet, "Data");
              XLSX.writeFile(workbook, "Portal_Export.xlsx");
            }}
            className="flex items-center gap-2 bg-white/5 hover:bg-white/10 text-white px-5 py-2.5 rounded-xl text-xs font-bold transition-all"
          >
            <Download size={16} /> Export
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden">

        {/* Sidebar */}
        <aside className="w-80 bg-slate-900/50 border-r border-white/5 p-6 flex flex-col space-y-8 hidden md:flex overflow-y-auto custom-scrollbar">

          {/* Admin Tools */}
          {isAdmin && (
            <div className="space-y-4">
              <div className="text-[10px] text-slate-500 font-black uppercase tracking-[0.3em] px-2 mb-3">Management</div>
              <label className="flex items-center gap-4 p-4 bg-indigo-600 hover:bg-indigo-500 rounded-2xl cursor-pointer transition-all shadow-xl shadow-indigo-900/20 group">
                <Plus size={20} className="text-white group-hover:rotate-90 transition-transform" />
                <span className="text-sm font-black text-white">Upload New Sheet</span>
                <input type="file" className="hidden" onChange={handleFileUpload} accept=".xlsx,.csv" />
              </label>

              <button 
                onClick={clearAllData}
                className="w-full flex items-center gap-4 p-4 bg-white/5 hover:bg-rose-500 text-slate-400 hover:text-white rounded-2xl transition-all border border-white/5"
              >
                <Trash2 size={20} />
                <span className="text-sm font-black">Purge All Sheets</span>
              </button>
            </div>
          )}

          {/* Navigation */}
          <nav className="space-y-2 flex-1 pt-4">
            <div className="text-[10px] text-slate-500 font-black uppercase tracking-[0.3em] px-2 mb-3">Workspace Modules</div>
            {[
              { id: 'dashboard', label: 'Intelligence Hub', icon: PieChart },
              { id: 'preview', label: 'Data Grid', icon: Table },
              { id: 'pivot', label: 'Pivot Synthesis', icon: LayoutGrid },
              { id: 'ai', label: 'AI Narrative', icon: Sparkles },
            ].map(item => (
              <button 
                key={item.id}
                onClick={() => setActiveTab(item.id as any)}
                className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-black transition-all ${activeTab === item.id ? 'bg-white/10 text-indigo-400 border border-white/5' : 'text-slate-500 hover:text-slate-200'}`}
              >
                <item.icon size={20} /> {item.label}
              </button>
            ))}
          </nav>

          {/* Share Section */}
          <div className="pt-6 border-t border-white/5">
            <div className="bg-slate-800/50 p-6 rounded-3xl border border-white/5 space-y-4">
              <div className="flex items-center gap-3">
                <Share2 size={16} className="text-indigo-400" />
                <span className="text-[11px] font-black uppercase tracking-widest">Collaboration</span>
              </div>
              <p className="text-[10px] text-slate-500 font-medium leading-relaxed">
                Generate a data-encoded URL for viewers to access this portal's current state.
              </p>
              <button 
                onClick={generateShareLink}
                disabled={shareStatus === 'generating' || companyDatasets.length === 0}
                className={`w-full py-4 rounded-xl text-[10px] font-black uppercase tracking-[0.2em] transition-all flex items-center justify-center gap-3 border shadow-2xl ${
                  shareStatus === 'copied' ? 'bg-emerald-500 text-white border-emerald-400' : 'bg-white/5 text-indigo-400 border-indigo-500/20 hover:bg-indigo-500/10'
                }`}
              >
                {shareStatus === 'generating' ? <RefreshCw className="animate-spin" size={14} /> : 
                 shareStatus === 'copied' ? <ShieldCheck size={14} /> : <Link size={14} />}
                {shareStatus === 'generating' ? 'Syncing...' : shareStatus === 'copied' ? 'Link Copied' : 'Generate Share Link'}
              </button>
            </div>
          </div>
        </aside>

        {/* Content Area */}
        <section className="flex-1 overflow-auto bg-slate-950 p-10 custom-scrollbar">

          {companyDatasets.length === 0 && !isProcessing && (
            <div className="h-full flex flex-col items-center justify-center text-center max-w-xl mx-auto space-y-8 animate-in fade-in zoom-in-95 duration-700">
              <div className="bg-indigo-600/10 w-32 h-32 rounded-full flex items-center justify-center shadow-2xl border border-indigo-500/20">
                <UploadCloud size={64} className="text-indigo-500 animate-bounce" />
              </div>
              <div className="space-y-4">
                <h2 className="text-4xl font-black text-white tracking-tighter">System Synchronized</h2>
                <p className="text-slate-400 text-lg font-medium leading-relaxed">
                  Your portal is active. Link your workforce spreadsheets to generate real-time operational narratives and compliance dashboards.
                </p>
              </div>
              {isAdmin && (
                <label className="bg-indigo-600 hover:bg-indigo-500 text-white px-10 py-5 rounded-[28px] font-black text-lg transition-all cursor-pointer shadow-2xl shadow-indigo-900/40 active:scale-95 flex items-center gap-4">
                  <FileUp size={28} /> Link Data Drive
                  <input type="file" className="hidden" onChange={handleFileUpload} accept=".xlsx,.csv" />
                </label>
              )}
            </div>
          )}

          {isProcessing && (
            <div className="h-full flex flex-col items-center justify-center space-y-6">
              <RefreshCw className="animate-spin text-indigo-500" size={64} />
              <p className="text-slate-500 font-black uppercase tracking-[0.5em] text-xs">Processing Workforce Vectors</p>
            </div>
          )}

          {companyDatasets.length > 0 && !isProcessing && (
            <div className="max-w-7xl mx-auto space-y-10 animate-in fade-in duration-1000">

              {/* Context Header */}
              <div className="flex items-center justify-between border-b border-white/5 pb-10">
                <div>
                   <h2 className="text-4xl font-black text-white tracking-tighter capitalize flex items-center gap-5">
                     <Layers className="text-indigo-500" /> {activeTab} Intelligence
                   </h2>
                   <div className="flex items-center gap-4 mt-3">
                     <span className="text-indigo-500 font-black text-[10px] uppercase tracking-[0.3em] bg-indigo-500/10 px-3 py-1 rounded-lg border border-indigo-500/20">
                       Active Sheets: {companyDatasets.length}
                     </span>
                     <span className="text-slate-500 font-black text-[10px] uppercase tracking-[0.3em]">
                       Dataset Volume: {activeRows.length} Records
                     </span>
                   </div>
                </div>
                {!isAdmin && (
                  <div className="flex items-center gap-4 bg-slate-900 px-6 py-4 rounded-3xl border border-white/5">
                    <div className="w-2.5 h-2.5 rounded-full bg-emerald-500 animate-pulse"></div>
                    <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">Read-Only Environment</span>
                  </div>
                )}
              </div>

              {/* Module Content */}
              {activeTab === 'dashboard' && (
                <Dashboard rows={activeRows} onDrillDown={(t, r) => setDrillDownData({ title: t, rows: r })} />
              )}

              {activeTab === 'preview' && (
                <DataTable headers={activeHeaders} rows={activeRows} highlightTerm={searchTerm} />
              )}

              {activeTab === 'pivot' && (
                <PivotView rows={activeRows} headers={activeHeaders} />
              )}

              {activeTab === 'ai' && (
                <div className="bg-slate-900 rounded-[50px] border border-white/5 p-16 relative overflow-hidden">
                  <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-10 mb-12 relative z-10">
                    <div className="space-y-2">
                      <h3 className="text-3xl font-black text-white tracking-tighter">AI Operational Narrative</h3>
                      <p className="text-slate-400 font-medium">Synthesized overview of total workforce compliance.</p>
                    </div>
                    <button 
                      onClick={generateAiWriteup}
                      disabled={isGeneratingAi}
                      className="bg-indigo-600 hover:bg-indigo-500 text-white px-10 py-5 rounded-3xl font-black text-lg transition-all shadow-2xl active:scale-95 flex items-center gap-3"
                    >
                      {isGeneratingAi ? <RefreshCw className="animate-spin" /> : <Sparkles />}
                      {aiSummary ? 'Regenerate Analysis' : 'Synthesize Insights'}
                    </button>
                  </div>
                  <div className="prose prose-invert max-w-none text-xl leading-relaxed text-slate-300 relative z-10 whitespace-pre-wrap font-medium">
                    {aiSummary || <p className="text-slate-600 italic">Initiate synthesis to generate executive summary...</p>}
                  </div>
                </div>
              )}
            </div>
          )}
        </section>
      </main>

      {/* Upload Confirmation Modal */}
      {pendingUpload && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm">
          <div className="bg-slate-900 w-full max-w-md rounded-[40px] border border-white/10 shadow-2xl p-10 space-y-8 animate-in zoom-in-95">
            <div className="text-center space-y-3">
              <div className="bg-indigo-600/20 w-20 h-20 rounded-full flex items-center justify-center mx-auto">
                <Building2 className="text-indigo-500" size={32} />
              </div>
              <h3 className="text-2xl font-black text-white tracking-tight">Identify Source</h3>
              <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">Assign organization profile</p>
            </div>
            <input 
              autoFocus
              type="text"
              className="w-full p-5 bg-slate-800 border-none rounded-2xl text-lg font-bold text-white outline-none ring-2 ring-white/5 focus:ring-indigo-500 transition-all"
              value={newCompanyName}
              onChange={(e) => setNewCompanyName(e.target.value)}
              placeholder="e.g. Regional Hub A..."
              onKeyDown={(e) => e.key === 'Enter' && confirmUpload()}
            />
            <div className="flex gap-4">
              <button onClick={() => setPendingUpload(null)} className="flex-1 py-4 text-slate-500 font-black uppercase text-[10px] tracking-widest">Discard</button>
              <button onClick={confirmUpload} className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl">Verify & Map</button>
            </div>
          </div>
        </div>
      )}

      {/* Detail Drill-down Modal */}
      {drillDownData && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-black/80 backdrop-blur-md">
          <div className="bg-slate-900 w-full max-w-6xl h-[85vh] rounded-[50px] border border-white/10 shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
            <div className="p-10 border-b border-white/5 flex items-center justify-between bg-slate-800/30">
              <div className="flex items-center gap-6">
                <div className="bg-indigo-600 p-4 rounded-2xl text-white">
                  <FileSpreadsheet size={32} />
                </div>
                <div>
                  <h3 className="text-3xl font-black text-white tracking-tighter">{drillDownData.title}</h3>
                  <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest mt-2">Subset: {drillDownData.rows.length} Verified Records</p>
                </div>
              </div>
              <div className="flex items-center gap-4">
                <button 
                  onClick={() => {
                    const ws = XLSX.utils.json_to_sheet(drillDownData.rows);
                    const wb = XLSX.utils.book_new();
                    XLSX.utils.book_append_sheet(workbook, worksheet, "Subset");
                    XLSX.writeFile(workbook, "Subset_Audit.xlsx");
                  }}
                  className="bg-emerald-600 text-white px-8 py-4 rounded-2xl text-xs font-black uppercase tracking-widest transition-all"
                >
                  Download Report
                </button>
                <button onClick={() => setDrillDownData(null)} className="p-4 hover:bg-white/5 rounded-full text-slate-500 transition-colors">
                  <X size={32} />
                </button>
              </div>
            </div>
            <div className="flex-1 overflow-hidden p-10 bg-slate-950">
              <DataTable headers={activeHeaders} rows={drillDownData.rows} />
            </div>
          </div>
        </div>
      )}

      <footer className="bg-slate-900 border-t border-white/5 px-8 py-4 flex items-center justify-between text-[9px] text-slate-500 font-black uppercase tracking-[0.4em] shrink-0">
        <div className="flex items-center gap-8">
          <div className="flex items-center gap-2">
            <div className={`w-2 h-2 rounded-full ${companyDatasets.length > 0 ? 'bg-indigo-500' : 'bg-slate-700'}`}></div> 
            Core Sync: {companyDatasets.length > 0 ? 'ACTIVE' : 'IDLE'}
          </div>
          <div className="border-l pl-8 border-white/10 flex items-center gap-2">
            <HardDrive size={12} /> Portal Integrity Verified
          </div>
        </div>
        <div className="flex items-center gap-3">
           <ShieldCheck size={14} className="text-indigo-500" />
           Local Data Encryption: AES-256 (Simulated)
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useCallback } from 'react';
import * as XLSX from 'xlsx';
import LZString from 'lz-string';
import { 
  FileUp, 
  Table, 
  LayoutGrid, 
  Sparkles, 
  Download, 
  RefreshCw,
  Search,
  Database,
  BarChart3,
  PieChart,
  X,
  FileSpreadsheet,
  Building2,
  ChevronDown,
  Plus,
  Trash2,
  AlertTriangle,
  Share2,
  Copy,
  ShieldCheck,
  Eye,
  Settings,
  Link,
  Info,
  LogOut,
  UploadCloud,
  Layers,
  HardDrive
} from 'lucide-react';
import { DataRow, ProcessedData, CompanyDataset } from './types';
import { harmonizeData } from './utils/dataProcessor';
import { DataTable } from './components/DataTable';
import { PivotView } from './components/PivotView';
import { Dashboard } from './components/Dashboard';
import { generateDataSummary } from './services/gemini';

const STORAGE_KEY = 'harmonizer_pro_v5';

const App: React.FC = () => {
  // --- STATE MANAGEMENT ---
  const [isAdmin, setIsAdmin] = useState(true); // Default to true for the creator
  const [shareStatus, setShareStatus] = useState<'idle' | 'generating' | 'copied' | 'error'>('idle');
  const [activeTab, setActiveTab] = useState<'dashboard' | 'preview' | 'pivot' | 'ai'>('dashboard');
  const [isProcessing, setIsProcessing] = useState(false);
  const [aiSummary, setAiSummary] = useState<string>('');
  const [searchTerm, setSearchTerm] = useState('');
  const [isGeneratingAi, setIsGeneratingAi] = useState(false);
  const [pendingUpload, setPendingUpload] = useState<ProcessedData | null>(null);
  const [newCompanyName, setNewCompanyName] = useState('');
  const [drillDownData, setDrillDownData] = useState<{ title: string; rows: DataRow[] } | null>(null);

  // --- PERSISTENCE & HYDRATION ---
  const [companyDatasets, setCompanyDatasets] = useState<CompanyDataset[]>(() => {
    const hash = window.location.hash;
    if (hash && hash.includes('data=')) {
      try {
        const match = hash.match(/data=([^&]*)/);
        if (match && match[1]) {
          const decompressed = LZString.decompressFromEncodedURIComponent(match[1]);
          if (decompressed) {
            const data = JSON.parse(decompressed);
            if (Array.isArray(data)) {
              // If loaded via link, disable Admin tools for this session
              return data;
            }
          }
        }
      } catch (e) {
        console.error("Hydration Error:", e);
      }
    }
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  // Determine Role on Mount
  useEffect(() => {
    if (window.location.hash.includes('data=')) {
      setIsAdmin(false);
    }
  }, []);

  // Sync to LocalStorage (Admin Only)
  useEffect(() => {
    if (!isAdmin) return;
    if (companyDatasets.length === 0) {
      localStorage.removeItem(STORAGE_KEY);
    } else {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(companyDatasets));
    }
  }, [companyDatasets, isAdmin]);

  // --- CORE ACTIONS ---
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!isAdmin) return;
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws) as DataRow[];
        const harmonized = harmonizeData(data);
        setPendingUpload(harmonized);
        setNewCompanyName(file.name.split('.')[0]); 
      } catch (err) {
        alert("Upload failed. Unsupported file format.");
      } finally {
        setIsProcessing(false);
        e.target.value = '';
      }
    };
    reader.readAsBinaryString(file);
  };

  const confirmUpload = () => {
    const newEntry: CompanyDataset = {
      id: crypto.randomUUID(),
      name: newCompanyName.trim() || 'Untitled Entity',
      data: pendingUpload!
    };
    setCompanyDatasets(prev => [...prev, newEntry]);
    setPendingUpload(null);
  };

  const clearAllData = useCallback(() => {
    if (window.confirm("MASTER PURGE: This will permanently delete ALL uploaded sheets and resets your portal to empty. Proceed?")) {
      setCompanyDatasets([]);
      setAiSummary('');
      localStorage.removeItem(STORAGE_KEY);
      window.location.hash = '';
    }
  }, []);

  const generateShareLink = useCallback(() => {
    if (companyDatasets.length === 0) return;
    setShareStatus('generating');

    setTimeout(() => {
      try {
        // Optimization: Strip large metadata for URL length safety
        const sharedPayload = companyDatasets.map(ds => ({
          id: ds.id,
          name: ds.name,
          data: { headers: ds.data.headers, rows: ds.data.rows }
        }));

        const compressed = LZString.compressToEncodedURIComponent(JSON.stringify(sharedPayload));
        const url = `${window.location.origin}${window.location.pathname}#data=${compressed}`;

        if (url.length > 14000) {
          setShareStatus('error');
          alert("Error: Data too large for sharing via URL. Please reduce the number of sheets.");
          return;
        }

        navigator.clipboard.writeText(url);
        setShareStatus('copied');
        setTimeout(() => setShareStatus('idle'), 3000);
      } catch (e) {
        setShareStatus('error');
      }
    }, 800);
  }, [companyDatasets]);

  const generateAiWriteup = async () => {
    const rows = companyDatasets.flatMap(d => d.data.rows);
    if (rows.length === 0) return;
    setIsGeneratingAi(true);
    const summary = await generateDataSummary(rows);
    setAiSummary(summary);
    setIsGeneratingAi(false);
  };

  // --- RENDER LOGIC ---
  const activeRows = useMemo(() => companyDatasets.flatMap(d => d.data.rows), [companyDatasets]);
  const activeHeaders = useMemo(() => {
    const headers = new Set<string>();
    companyDatasets.forEach(d => d.data.headers.forEach(h => headers.add(h)));
    return Array.from(headers);
  }, [companyDatasets]);

  return (
    <div className="min-h-screen flex flex-col font-sans bg-[#0f172a] text-slate-200 overflow-hidden h-screen">

      {/* Role Banner */}
      {!isAdmin && (
        <div className="bg-indigo-600 text-white px-8 py-2 flex items-center justify-between text-[10px] font-black uppercase tracking-[0.3em] shadow-2xl z-[100]">
          <div className="flex items-center gap-3">
            <Eye size={14} className="animate-pulse" />
            Active Shared Session • View Only Access
          </div>
          <button onClick={() => {window.location.hash = ''; window.location.reload();}} className="hover:underline flex items-center gap-2">
            <LogOut size={12} /> Exit to My Workspace
          </button>
        </div>
      )}

      {/* Header */}
      <header className="bg-slate-900 border-b border-white/5 px-8 py-5 flex items-center justify-between shrink-0">
        <div className="flex items-center gap-4">
          <div className="bg-indigo-600 p-2.5 rounded-2xl text-white shadow-xl shadow-indigo-900/20">
            <Database size={24} />
          </div>
          <div>
            <h1 className="text-xl font-black text-white tracking-tight leading-none">DataHarmonizer Pro</h1>
            <p className="text-[9px] text-slate-500 font-black uppercase tracking-[0.4em] mt-1.5">
              {isAdmin ? 'Owner Console' : 'Intelligence Hub'}
            </p>
          </div>
        </div>

        <div className="flex items-center gap-6">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={16} />
            <input 
              type="text" 
              placeholder="Query portal..." 
              className="bg-slate-800 border-none rounded-xl pl-10 pr-4 py-2.5 text-sm focus:ring-2 focus:ring-indigo-500 transition-all w-64 text-white"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <button 
            onClick={() => {
              const worksheet = XLSX.utils.json_to_sheet(activeRows);
              const workbook = XLSX.utils.book_new();
              XLSX.utils.book_append_sheet(workbook, worksheet, "Data");
              XLSX.writeFile(workbook, "Portal_Export.xlsx");
            }}
            className="flex items-center gap-2 bg-white/5 hover:bg-white/10 text-white px-5 py-2.5 rounded-xl text-xs font-bold transition-all"
          >
            <Download size={16} /> Export
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden">

        {/* Sidebar */}
        <aside className="w-80 bg-slate-900/50 border-r border-white/5 p-6 flex flex-col space-y-8 hidden md:flex overflow-y-auto custom-scrollbar">

          {/* Admin Tools */}
          {isAdmin && (
            <div className="space-y-4">
              <div className="text-[10px] text-slate-500 font-black uppercase tracking-[0.3em] px-2 mb-3">Management</div>
              <label className="flex items-center gap-4 p-4 bg-indigo-600 hover:bg-indigo-500 rounded-2xl cursor-pointer transition-all shadow-xl shadow-indigo-900/20 group">
                <Plus size={20} className="text-white group-hover:rotate-90 transition-transform" />
                <span className="text-sm font-black text-white">Upload New Sheet</span>
                <input type="file" className="hidden" onChange={handleFileUpload} accept=".xlsx,.csv" />
              </label>

              <button 
                onClick={clearAllData}
                className="w-full flex items-center gap-4 p-4 bg-white/5 hover:bg-rose-500 text-slate-400 hover:text-white rounded-2xl transition-all border border-white/5"
              >
                <Trash2 size={20} />
                <span className="text-sm font-black">Purge All Sheets</span>
              </button>
            </div>
          )}

          {/* Navigation */}
          <nav className="space-y-2 flex-1 pt-4">
            <div className="text-[10px] text-slate-500 font-black uppercase tracking-[0.3em] px-2 mb-3">Workspace Modules</div>
            {[
              { id: 'dashboard', label: 'Intelligence Hub', icon: PieChart },
              { id: 'preview', label: 'Data Grid', icon: Table },
              { id: 'pivot', label: 'Pivot Synthesis', icon: LayoutGrid },
              { id: 'ai', label: 'AI Narrative', icon: Sparkles },
            ].map(item => (
              <button 
                key={item.id}
                onClick={() => setActiveTab(item.id as any)}
                className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-black transition-all ${activeTab === item.id ? 'bg-white/10 text-indigo-400 border border-white/5' : 'text-slate-500 hover:text-slate-200'}`}
              >
                <item.icon size={20} /> {item.label}
              </button>
            ))}
          </nav>

          {/* Share Section */}
          <div className="pt-6 border-t border-white/5">
            <div className="bg-slate-800/50 p-6 rounded-3xl border border-white/5 space-y-4">
              <div className="flex items-center gap-3">
                <Share2 size={16} className="text-indigo-400" />
                <span className="text-[11px] font-black uppercase tracking-widest">Collaboration</span>
              </div>
              <p className="text-[10px] text-slate-500 font-medium leading-relaxed">
                Generate a data-encoded URL for viewers to access this portal's current state.
              </p>
              <button 
                onClick={generateShareLink}
                disabled={shareStatus === 'generating' || companyDatasets.length === 0}
                className={`w-full py-4 rounded-xl text-[10px] font-black uppercase tracking-[0.2em] transition-all flex items-center justify-center gap-3 border shadow-2xl ${
                  shareStatus === 'copied' ? 'bg-emerald-500 text-white border-emerald-400' : 'bg-white/5 text-indigo-400 border-indigo-500/20 hover:bg-indigo-500/10'
                }`}
              >
                {shareStatus === 'generating' ? <RefreshCw className="animate-spin" size={14} /> : 
                 shareStatus === 'copied' ? <ShieldCheck size={14} /> : <Link size={14} />}
                {shareStatus === 'generating' ? 'Syncing...' : shareStatus === 'copied' ? 'Link Copied' : 'Generate Share Link'}
              </button>
            </div>
          </div>
        </aside>

        {/* Content Area */}
        <section className="flex-1 overflow-auto bg-slate-950 p-10 custom-scrollbar">

          {companyDatasets.length === 0 && !isProcessing && (
            <div className="h-full flex flex-col items-center justify-center text-center max-w-xl mx-auto space-y-8 animate-in fade-in zoom-in-95 duration-700">
              <div className="bg-indigo-600/10 w-32 h-32 rounded-full flex items-center justify-center shadow-2xl border border-indigo-500/20">
                <UploadCloud size={64} className="text-indigo-500 animate-bounce" />
              </div>
              <div className="space-y-4">
                <h2 className="text-4xl font-black text-white tracking-tighter">System Synchronized</h2>
                <p className="text-slate-400 text-lg font-medium leading-relaxed">
                  Your portal is active. Link your workforce spreadsheets to generate real-time operational narratives and compliance dashboards.
                </p>
              </div>
              {isAdmin && (
                <label className="bg-indigo-600 hover:bg-indigo-500 text-white px-10 py-5 rounded-[28px] font-black text-lg transition-all cursor-pointer shadow-2xl shadow-indigo-900/40 active:scale-95 flex items-center gap-4">
                  <FileUp size={28} /> Link Data Drive
                  <input type="file" className="hidden" onChange={handleFileUpload} accept=".xlsx,.csv" />
                </label>
              )}
            </div>
          )}

          {isProcessing && (
            <div className="h-full flex flex-col items-center justify-center space-y-6">
              <RefreshCw className="animate-spin text-indigo-500" size={64} />
              <p className="text-slate-500 font-black uppercase tracking-[0.5em] text-xs">Processing Workforce Vectors</p>
            </div>
          )}

          {companyDatasets.length > 0 && !isProcessing && (
            <div className="max-w-7xl mx-auto space-y-10 animate-in fade-in duration-1000">

              {/* Context Header */}
              <div className="flex items-center justify-between border-b border-white/5 pb-10">
                <div>
                   <h2 className="text-4xl font-black text-white tracking-tighter capitalize flex items-center gap-5">
                     <Layers className="text-indigo-500" /> {activeTab} Intelligence
                   </h2>
                   <div className="flex items-center gap-4 mt-3">
                     <span className="text-indigo-500 font-black text-[10px] uppercase tracking-[0.3em] bg-indigo-500/10 px-3 py-1 rounded-lg border border-indigo-500/20">
                       Active Sheets: {companyDatasets.length}
                     </span>
                     <span className="text-slate-500 font-black text-[10px] uppercase tracking-[0.3em]">
                       Dataset Volume: {activeRows.length} Records
                     </span>
                   </div>
                </div>
                {!isAdmin && (
                  <div className="flex items-center gap-4 bg-slate-900 px-6 py-4 rounded-3xl border border-white/5">
                    <div className="w-2.5 h-2.5 rounded-full bg-emerald-500 animate-pulse"></div>
                    <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">Read-Only Environment</span>
                  </div>
                )}
              </div>

              {/* Module Content */}
              {activeTab === 'dashboard' && (
                <Dashboard rows={activeRows} onDrillDown={(t, r) => setDrillDownData({ title: t, rows: r })} />
              )}

              {activeTab === 'preview' && (
                <DataTable headers={activeHeaders} rows={activeRows} highlightTerm={searchTerm} />
              )}

              {activeTab === 'pivot' && (
                <PivotView rows={activeRows} headers={activeHeaders} />
              )}

              {activeTab === 'ai' && (
                <div className="bg-slate-900 rounded-[50px] border border-white/5 p-16 relative overflow-hidden">
                  <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-10 mb-12 relative z-10">
                    <div className="space-y-2">
                      <h3 className="text-3xl font-black text-white tracking-tighter">AI Operational Narrative</h3>
                      <p className="text-slate-400 font-medium">Synthesized overview of total workforce compliance.</p>
                    </div>
                    <button 
                      onClick={generateAiWriteup}
                      disabled={isGeneratingAi}
                      className="bg-indigo-600 hover:bg-indigo-500 text-white px-10 py-5 rounded-3xl font-black text-lg transition-all shadow-2xl active:scale-95 flex items-center gap-3"
                    >
                      {isGeneratingAi ? <RefreshCw className="animate-spin" /> : <Sparkles />}
                      {aiSummary ? 'Regenerate Analysis' : 'Synthesize Insights'}
                    </button>
                  </div>
                  <div className="prose prose-invert max-w-none text-xl leading-relaxed text-slate-300 relative z-10 whitespace-pre-wrap font-medium">
                    {aiSummary || <p className="text-slate-600 italic">Initiate synthesis to generate executive summary...</p>}
                  </div>
                </div>
              )}
            </div>
          )}
        </section>
      </main>

      {/* Upload Confirmation Modal */}
      {pendingUpload && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm">
          <div className="bg-slate-900 w-full max-w-md rounded-[40px] border border-white/10 shadow-2xl p-10 space-y-8 animate-in zoom-in-95">
            <div className="text-center space-y-3">
              <div className="bg-indigo-600/20 w-20 h-20 rounded-full flex items-center justify-center mx-auto">
                <Building2 className="text-indigo-500" size={32} />
              </div>
              <h3 className="text-2xl font-black text-white tracking-tight">Identify Source</h3>
              <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">Assign organization profile</p>
            </div>
            <input 
              autoFocus
              type="text"
              className="w-full p-5 bg-slate-800 border-none rounded-2xl text-lg font-bold text-white outline-none ring-2 ring-white/5 focus:ring-indigo-500 transition-all"
              value={newCompanyName}
              onChange={(e) => setNewCompanyName(e.target.value)}
              placeholder="e.g. Regional Hub A..."
              onKeyDown={(e) => e.key === 'Enter' && confirmUpload()}
            />
            <div className="flex gap-4">
              <button onClick={() => setPendingUpload(null)} className="flex-1 py-4 text-slate-500 font-black uppercase text-[10px] tracking-widest">Discard</button>
              <button onClick={confirmUpload} className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl">Verify & Map</button>
            </div>
          </div>
        </div>
      )}

      {/* Detail Drill-down Modal */}
      {drillDownData && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-black/80 backdrop-blur-md">
          <div className="bg-slate-900 w-full max-w-6xl h-[85vh] rounded-[50px] border border-white/10 shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
            <div className="p-10 border-b border-white/5 flex items-center justify-between bg-slate-800/30">
              <div className="flex items-center gap-6">
                <div className="bg-indigo-600 p-4 rounded-2xl text-white">
                  <FileSpreadsheet size={32} />
