                <div>
                  <h3 className="text-3xl font-black text-white tracking-tighter">{drillDownData.title}</h3>
                  <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest mt-2">Subset: {drillDownData.rows.length} Verified Records</p>
                </div>
              </div>
              <div className="flex items-center gap-4">
                <button 
                  onClick={() => {
                    const ws = XLSX.utils.json_to_sheet(drillDownData.rows);
                    const wb = XLSX.utils.book_new();
                    // Fix: Correct variable names 'wb' and 'ws' to avoid 'Cannot find name workbook/worksheet'
                    XLSX.utils.book_append_sheet(wb, ws, "Subset");
                    XLSX.writeFile(wb, "Subset_Audit.xlsx");
                  }}
                  className="bg-emerald-600 text-white px-8 py-4 rounded-2xl text-xs font-black uppercase tracking-widest transition-all"
                >
                  Download Report
                </button>
                <button onClick={() => setDrillDownData(null)} className="p-4 hover:bg-white/5 rounded-full text-slate-500 transition-colors">
                  <X size={32} />
                </button>
              </div>
            </div>
            <div className="flex-1 overflow-hidden p-10 bg-slate-950">
              <DataTable headers={activeHeaders} rows={drillDownData.rows} />
            </div>
          </div>
        </div>
      )}

      <footer className="bg-slate-900 border-t border-white/5 px-8 py-4 flex items-center justify-between text-[9px] text-slate-500 font-black uppercase tracking-[0.4em] shrink-0">
        <div className="flex items-center gap-8">
          <div className="flex items-center gap-2">
            <div className={`w-2 h-2 rounded-full ${companyDatasets.length > 0 ? 'bg-indigo-500' : 'bg-slate-700'}`}></div> 
            Core Sync: {companyDatasets.length > 0 ? 'ACTIVE' : 'IDLE'}
          </div>
          <div className="border-l pl-8 border-white/10 flex items-center gap-2">
            <HardDrive size={12} /> Portal Integrity Verified
          </div>
        </div>
        <div className="flex items-center gap-3">
           <ShieldCheck size={14} className="text-indigo-500" />
           Local Data Encryption: AES-256 (Simulated)
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useCallback } from 'react';
import * as XLSX from 'xlsx';
import LZString from 'lz-string';
import { 
  FileUp, 
  Table, 
  LayoutGrid, 
  Sparkles, 
  Download, 
  RefreshCw,
  Search,
  Database,
  BarChart3,
  PieChart,
  X,
  FileSpreadsheet,
  Building2,
  ChevronDown,
  Plus,
  Trash2,
  AlertTriangle,
  Share2,
  Copy,
  ShieldCheck,
  Eye,
  Settings,
  Link,
  Info,
  Layers,
  HardDrive,
  FileText,
  Monitor
} from 'lucide-react';
import { DataRow, ProcessedData, CompanyDataset } from './types';
import { harmonizeData } from './utils/dataProcessor';
import { DataTable } from './components/DataTable';
import { PivotView } from './components/PivotView';
import { Dashboard } from './components/Dashboard';
import { generateDataSummary } from './services/gemini';

const STORAGE_KEY = 'harmonizer_pro_v7_drive';

const App: React.FC = () => {
  // --- ROLE & PERSISTENCE STATE ---
  const [isAdmin, setIsAdmin] = useState(true);
  const [shareStatus, setShareStatus] = useState<'idle' | 'generating' | 'copied' | 'error'>('idle');
  const [activeTab, setActiveTab] = useState<'dashboard' | 'preview' | 'pivot' | 'ai'>('dashboard');
  const [selectedSheetId, setSelectedSheetId] = useState<string>('master'); // 'master' or sheet ID

  const [companyDatasets, setCompanyDatasets] = useState<CompanyDataset[]>(() => {
    // 1. Check for shared hash first
    const hash = window.location.hash;
    if (hash && hash.includes('data=')) {
      try {
        const match = hash.match(/data=([^&]*)/);
        if (match && match[1]) {
          const decompressed = LZString.decompressFromEncodedURIComponent(match[1]);
          if (decompressed) {
            const data = JSON.parse(decompressed);
            if (Array.isArray(data)) {
              return data; // Viewer loads data from URL
            }
          }
        }
      } catch (e) {
        console.error("Shared Link Corrupted");
      }
    }
    // 2. Load from Local Drive (LocalStorage)
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  // Determine Role on Mount
  useEffect(() => {
    if (window.location.hash.includes('data=')) {
      setIsAdmin(false);
    }
  }, []);

  // Save to Local Drive (Admin Only)
  useEffect(() => {
    if (!isAdmin) return;
    localStorage.setItem(STORAGE_KEY, JSON.stringify(companyDatasets));
  }, [companyDatasets, isAdmin]);

  // --- DATA PROCESSING ---
  const [isProcessing, setIsProcessing] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [aiSummary, setAiSummary] = useState<string>('');
  const [isGeneratingAi, setIsGeneratingAi] = useState(false);
  const [pendingUpload, setPendingUpload] = useState<ProcessedData | null>(null);
  const [newSheetName, setNewSheetName] = useState('');
  const [drillDownData, setDrillDownData] = useState<{ title: string; rows: DataRow[] } | null>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!isAdmin) return;
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws) as DataRow[];
        const harmonized = harmonizeData(data);
        setPendingUpload(harmonized);
        setNewSheetName(file.name.split('.')[0]); 
      } catch (err) {
        alert("Corrupted File Structure Detected.");
      } finally {
        setIsProcessing(false);
        e.target.value = '';
      }
    };
    reader.readAsBinaryString(file);
  };

  const confirmUpload = () => {
    const newEntry: CompanyDataset = {
      id: crypto.randomUUID(),
      name: newSheetName.trim() || 'Imported_Sheet',
      data: pendingUpload!
    };
    setCompanyDatasets(prev => [...prev, newEntry]);
    setSelectedSheetId(newEntry.id);
    setPendingUpload(null);
    setActiveTab('dashboard');
  };

  const deleteSheet = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!isAdmin) return;
    if (window.confirm("Permanently delete this source sheet from the drive?")) {
      setCompanyDatasets(prev => prev.filter(ds => ds.id !== id));
      if (selectedSheetId === id) setSelectedSheetId('master');
    }
  };

  const purgeDrive = () => {
    if (!isAdmin) return;
    if (window.confirm("CRITICAL: Wipe entire drive? This will permanently delete ALL uploaded sheets and resets the portal.")) {
      setCompanyDatasets([]);
      setSelectedSheetId('master');
      localStorage.removeItem(STORAGE_KEY);
      window.location.hash = '';
    }
  };

  const generateShareLink = useCallback(() => {
    if (companyDatasets.length === 0) return;
    setShareStatus('generating');

    // Pro-level payload minimization
    const payload = companyDatasets.map(ds => ({
      id: ds.id,
      name: ds.name,
      data: { headers: ds.data.headers, rows: ds.data.rows }
    }));

    const compressed = LZString.compressToEncodedURIComponent(JSON.stringify(payload));
    const url = `${window.location.origin}${window.location.pathname}#data=${compressed}`;

    if (url.length > 15000) {
      setShareStatus('error');
      alert("Payload too massive for URL sharing. Please delete some non-essential sheets.");
      return;
    }

    navigator.clipboard.writeText(url).then(() => {
      setShareStatus('copied');
      setTimeout(() => setShareStatus('idle'), 3000);
    });
  }, [companyDatasets]);

  // --- DERIVED VIEWS ---
  const displayedRows = useMemo(() => {
    if (selectedSheetId === 'master') {
      return companyDatasets.flatMap(d => d.data.rows);
    }
    return companyDatasets.find(d => d.id === selectedSheetId)?.data.rows || [];
  }, [companyDatasets, selectedSheetId]);

  const activeHeaders = useMemo(() => {
    if (selectedSheetId === 'master') {
      const allHeaders = new Set<string>();
      companyDatasets.forEach(d => d.data.headers.forEach(h => allHeaders.add(h)));
      return Array.from(allHeaders);
    }
    return companyDatasets.find(d => d.id === selectedSheetId)?.data.headers || [];
  }, [companyDatasets, selectedSheetId]);

  const filteredRows = useMemo(() => {
    if (!searchTerm) return displayedRows;
    const s = searchTerm.toLowerCase();
    return displayedRows.filter(r => Object.values(r).some(v => String(v).toLowerCase().includes(s)));
  }, [displayedRows, searchTerm]);

  return (
    <div className="min-h-screen flex flex-col font-sans bg-[#020617] text-slate-300 overflow-hidden h-screen">

      {/* Role Banner */}
      <div className={`px-8 py-2.5 flex items-center justify-between text-[10px] font-black uppercase tracking-[0.4em] z-[100] border-b border-white/5 ${isAdmin ? 'bg-indigo-600/10 text-indigo-400' : 'bg-emerald-600/10 text-emerald-400'}`}>
        <div className="flex items-center gap-3">
          {isAdmin ? <Settings size={14} /> : <Eye size={14} className="animate-pulse" />}
          {isAdmin ? 'Owner Management Console (Write Access)' : 'Shared Intelligence Portal (Read-Only)'}
        </div>
        {!isAdmin && (
          <button onClick={() => {window.location.hash = ''; window.location.reload();}} className="hover:text-white transition-colors flex items-center gap-2">
            Return to Master Drive <HardDrive size={12} />
          </button>
        )}
      </div>

      {/* Header */}
      <header className="bg-slate-950 border-b border-white/5 px-8 py-5 flex items-center justify-between shrink-0">
        <div className="flex items-center gap-4">
          <div className="bg-gradient-to-br from-indigo-600 to-indigo-800 p-2.5 rounded-2xl text-white shadow-2xl">
            <Database size={24} />
          </div>
          <div>
            <h1 className="text-xl font-black text-white tracking-tighter leading-none">DataHarmonizer <span className="text-indigo-500">Pro</span></h1>
            <p className="text-[9px] text-slate-500 font-black uppercase tracking-[0.4em] mt-1.5 flex items-center gap-2">
              <ShieldCheck size={10} className="text-emerald-500" /> ISO-9001 Data Sync Active
            </p>
          </div>
        </div>

        <div className="flex items-center gap-6">
          <div className="relative group">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 group-focus-within:text-indigo-500 transition-colors" size={16} />
            <input 
              type="text" 
              placeholder="Query Drive..." 
              className="bg-slate-900/50 border border-white/5 rounded-xl pl-10 pr-4 py-2.5 text-sm focus:ring-2 focus:ring-indigo-500 outline-none transition-all w-80 text-white font-medium"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <button 
            onClick={() => {
              const ws = XLSX.utils.json_to_sheet(displayedRows);
              const wb = XLSX.utils.book_new();
              XLSX.utils.book_append_sheet(wb, ws, "Drive_Export");
              XLSX.writeFile(wb, `Drive_Export_${selectedSheetId}.xlsx`);
            }}
            className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all shadow-xl shadow-indigo-900/20 active:scale-95"
          >
            <Download size={18} /> Export View
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden">

        {/* Sidebar */}
        <aside className="w-80 bg-slate-950/50 border-r border-white/5 p-6 flex flex-col space-y-8 hidden md:flex overflow-y-auto custom-scrollbar shrink-0">

          {/* Drive Management (Admin Only) */}
          {isAdmin && (
            <div className="space-y-4">
              <div className="text-[10px] text-slate-500 font-black uppercase tracking-[0.3em] px-2 mb-3">Management</div>
              <label className="flex items-center gap-4 p-4 bg-indigo-600 hover:bg-indigo-500 rounded-2xl cursor-pointer transition-all shadow-xl shadow-indigo-900/20 group">
                <FileUp size={20} className="text-white group-hover:translate-y-[-2px] transition-transform" />
                <span className="text-sm font-black text-white uppercase tracking-widest">Link Source</span>
                <input type="file" className="hidden" onChange={handleFileUpload} accept=".xlsx,.csv" />
              </label>

              <button 
                onClick={purgeDrive}
                className="w-full flex items-center gap-4 p-4 bg-white/5 hover:bg-rose-500/20 hover:text-rose-500 text-slate-500 rounded-2xl transition-all border border-white/5"
              >
                <Trash2 size={20} />
                <span className="text-sm font-black uppercase tracking-widest">Purge Drive</span>
              </button>
            </div>
          )}

          {/* Drive Contents (Sheet List) */}
          <div className="space-y-2">
            <div className="text-[10px] text-slate-500 font-black uppercase tracking-[0.3em] px-2 mb-3">Drive Inventory</div>
            <button 
              onClick={() => setSelectedSheetId('master')}
              className={`w-full flex items-center gap-4 p-4 rounded-2xl text-sm font-black transition-all border ${selectedSheetId === 'master' ? 'bg-indigo-600/10 text-indigo-400 border-indigo-500/30' : 'bg-transparent text-slate-500 border-transparent hover:bg-white/5'}`}
            >
              <Layers size={18} />
              <span className="uppercase tracking-widest">Consolidated</span>
            </button>
            <div className="space-y-1 pl-2 max-h-[300px] overflow-y-auto custom-scrollbar">
              {companyDatasets.map(ds => (
                <button 
                  key={ds.id}
                  onClick={() => setSelectedSheetId(ds.id)}
                  className={`w-full flex items-center justify-between p-3.5 rounded-xl text-xs font-bold transition-all group ${selectedSheetId === ds.id ? 'bg-white/5 text-white' : 'text-slate-500 hover:bg-white/5'}`}
                >
                  <div className="flex items-center gap-3 truncate">
                    <FileText size={14} className={selectedSheetId === ds.id ? 'text-indigo-400' : 'text-slate-600'} />
                    <span className="truncate uppercase tracking-wider">{ds.name}</span>
                  </div>
                  {isAdmin && (
                    <Trash2 
                      size={14} 
                      className="text-slate-700 hover:text-rose-500 transition-colors opacity-0 group-hover:opacity-100" 
                      onClick={(e) => deleteSheet(ds.id, e)} 
                    />
                  )}
                </button>
              ))}
            </div>
          </div>

          {/* Nav Modules */}
          <nav className="space-y-2 flex-1 pt-4 border-t border-white/5">
            <div className="text-[10px] text-slate-500 font-black uppercase tracking-[0.3em] px-2 mb-3">Intelligence</div>
            {[
              { id: 'dashboard', label: 'Analysis Hub', icon: PieChart },
              { id: 'preview', label: 'Drive Grid', icon: Table },
              { id: 'pivot', label: 'Pivot Engine', icon: LayoutGrid },
              { id: 'ai', label: 'AI Narrative', icon: Sparkles },
            ].map(item => (
              <button 
                key={item.id}
                onClick={() => setActiveTab(item.id as any)}
                className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-black transition-all ${activeTab === item.id ? 'bg-white/5 text-indigo-400 border border-white/5' : 'text-slate-500 hover:text-slate-200'}`}
              >
                <item.icon size={20} /> {item.label}
              </button>
            ))}
          </nav>

          {/* Shared Drive Generator */}
          <div className="pt-6 border-t border-white/5">
            <div className="bg-slate-900 p-6 rounded-[32px] border border-white/5 space-y-4 shadow-inner">
              <div className="flex items-center gap-3">
                <Share2 size={16} className="text-indigo-400" />
                <span className="text-[11px] font-black uppercase tracking-widest text-white">Share App link</span>
              </div>
              <p className="text-[10px] text-slate-500 font-medium leading-relaxed">
                Creates a persistent snapshot of this drive for external viewing.
              </p>
              <button 
                onClick={generateShareLink}
                disabled={shareStatus === 'generating' || companyDatasets.length === 0}
                className={`w-full py-4 rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] transition-all flex items-center justify-center gap-3 border shadow-2xl ${
                  shareStatus === 'copied' ? 'bg-emerald-600 text-white border-emerald-400' : 'bg-slate-800 text-indigo-400 border-indigo-500/20 hover:bg-slate-700'
                }`}
              >
                {shareStatus === 'generating' ? <RefreshCw className="animate-spin" size={14} /> : 
                 shareStatus === 'copied' ? <ShieldCheck size={14} /> : <Link size={14} />}
                {shareStatus === 'generating' ? 'Syncing...' : shareStatus === 'copied' ? 'Link Copied' : 'Generate Shared URL'}
              </button>
            </div>
          </div>
        </aside>

        {/* Workspace */}
        <section className="flex-1 overflow-auto bg-[#020617] p-12 custom-scrollbar relative">

          {/* Empty Drive State */}
          {companyDatasets.length === 0 && !isProcessing && (
            <div className="h-full flex flex-col items-center justify-center text-center max-w-xl mx-auto space-y-10 animate-in fade-in zoom-in-95 duration-700">
              <div className="relative">
                <div className="absolute inset-0 bg-indigo-500/20 blur-[60px] rounded-full"></div>
                <div className="bg-indigo-600/10 w-40 h-40 rounded-[50px] flex items-center justify-center shadow-2xl border border-indigo-500/20 relative z-10">
                  <HardDrive size={80} className="text-indigo-500 animate-pulse" />
                </div>
              </div>
              <div className="space-y-4">
                <h2 className="text-5xl font-black text-white tracking-tighter">Drive Offline</h2>
                <p className="text-slate-400 text-lg font-medium leading-relaxed">
                  The workforce drive is currently empty. Connect source sheets or use a shared link to activate intelligence modules.
                </p>
              </div>
              {isAdmin && (
                <label className="bg-indigo-600 hover:bg-indigo-500 text-white px-12 py-5 rounded-[32px] font-black text-lg transition-all cursor-pointer shadow-2xl shadow-indigo-900/40 active:scale-95 flex items-center gap-4">
                  <Plus size={32} /> Initialize Master Drive
                  <input type="file" className="hidden" onChange={handleFileUpload} accept=".xlsx,.csv" />
                </label>
              )}
            </div>
          )}

          {isProcessing && (
            <div className="h-full flex flex-col items-center justify-center space-y-8">
              <RefreshCw className="animate-spin text-indigo-500" size={80} />
              <div className="text-center space-y-2">
                <p className="text-slate-400 font-black uppercase tracking-[0.6em] text-xs">Vector Alignment in Progress</p>
                <p className="text-slate-600 text-[10px] font-bold uppercase tracking-widest">Mapping context to secure local storage</p>
              </div>
            </div>
          )}

          {companyDatasets.length > 0 && !isProcessing && (
            <div className="max-w-7xl mx-auto space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-1000">

              {/* Context Header */}
              <div className="flex items-center justify-between border-b border-white/5 pb-12">
                <div className="space-y-4">
                   <h2 className="text-5xl font-black text-white tracking-tighter capitalize flex items-center gap-6">
                     {activeTab === 'dashboard' && <PieChart size={56} className="text-indigo-500" />}
                     {activeTab === 'preview' && <Table size={56} className="text-indigo-500" />}
                     {activeTab === 'pivot' && <LayoutGrid size={56} className="text-indigo-500" />}
                     {activeTab === 'ai' && <Sparkles size={56} className="text-indigo-500" />}
                     {activeTab === 'preview' ? 'Drive Grid' : activeTab === 'ai' ? 'AI Insights' : activeTab}
                   </h2>
                   <div className="flex items-center gap-6">
                     <span className="flex items-center gap-2 text-indigo-400 font-black text-[10px] uppercase tracking-[0.4em] bg-indigo-500/10 px-4 py-2 rounded-xl border border-indigo-500/20 shadow-inner">
                       <HardDrive size={14} /> Drive Context: {selectedSheetId === 'master' ? 'Master Drive' : companyDatasets.find(d => d.id === selectedSheetId)?.name}
                     </span>
                     <span className="w-1.5 h-1.5 rounded-full bg-slate-700"></span>
                     <span className="text-slate-500 font-black text-[10px] uppercase tracking-[0.4em]">
                       Total Volume: {displayedRows.length} Verified Records
                     </span>
                   </div>
                </div>
                {!isAdmin && (
                  <div className="flex items-center gap-5 bg-slate-900/50 px-8 py-5 rounded-[32px] border border-white/5 shadow-2xl">
                    <div className="relative">
                      <div className="w-3 h-3 rounded-full bg-emerald-500 animate-pulse"></div>
                      <div className="absolute inset-0 bg-emerald-500/30 blur-sm rounded-full"></div>
                    </div>
                    <span className="text-[11px] font-black uppercase tracking-widest text-slate-300">Remote Session Active</span>
                  </div>
                )}
              </div>

              {/* Module Content */}
              {activeTab === 'dashboard' && (
                <Dashboard rows={displayedRows} onDrillDown={(t, r) => setDrillDownData({ title: t, rows: r })} />
              )}

              {activeTab === 'preview' && (
                <DataTable headers={activeHeaders} rows={filteredRows} highlightTerm={searchTerm} />
              )}

              {activeTab === 'pivot' && (
                <PivotView rows={displayedRows} headers={activeHeaders} />
              )}

              {activeTab === 'ai' && (
                <div className="bg-slate-900 rounded-[60px] border border-white/5 p-20 relative overflow-hidden shadow-2xl">
                  <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-indigo-600/10 blur-[120px] rounded-full -mr-64 -mt-64"></div>
                  <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-12 mb-16 relative z-10">
                    <div className="space-y-4">
                      <h3 className="text-4xl font-black text-white tracking-tighter">Operational Narrative Synthesis</h3>
                      <p className="text-slate-500 font-medium text-lg leading-relaxed max-w-2xl">AI-Synthesized auditing of {selectedSheetId === 'master' ? 'consolidated drive context' : `source: ${companyDatasets.find(d => d.id === selectedSheetId)?.name}`}.</p>
                    </div>
                    <button 
                      onClick={async () => {
                        setIsGeneratingAi(true);
                        const s = await generateDataSummary(displayedRows);
                        setAiSummary(s);
                        setIsGeneratingAi(false);
                      }}
                      disabled={isGeneratingAi}
                      className="bg-indigo-600 hover:bg-indigo-500 text-white px-12 py-6 rounded-[32px] font-black text-xl transition-all shadow-2xl active:scale-95 flex items-center gap-4 whitespace-nowrap"
                    >
                      {isGeneratingAi ? <RefreshCw className="animate-spin" /> : <Sparkles />}
                      {aiSummary ? 'Regenerate Narrative' : 'Initiate Analysis'}
                    </button>
                  </div>
                  <div className="prose prose-invert max-w-none text-xl leading-relaxed text-slate-400 relative z-10 whitespace-pre-wrap font-medium border-l-4 border-indigo-600/30 pl-10 italic">
                    {aiSummary || <p className="text-slate-600">Waiting for intelligence trigger...</p>}
                  </div>
                </div>
              )}
            </div>
          )}
        </section>
      </main>

      {/* Upload Confirmation Modal */}
      {pendingUpload && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-black/90 backdrop-blur-md animate-in fade-in">
          <div className="bg-slate-900 w-full max-w-md rounded-[50px] border border-white/10 shadow-[0_0_100px_rgba(0,0,0,0.5)] p-12 space-y-10 animate-in zoom-in-95">
            <div className="text-center space-y-4">
              <div className="bg-indigo-600/20 w-24 h-24 rounded-[32px] flex items-center justify-center mx-auto border border-indigo-500/20">
                <FileSpreadsheet className="text-indigo-500" size={48} />
              </div>
              <h3 className="text-3xl font-black text-white tracking-tighter">Link Source File</h3>
              <p className="text-slate-500 text-[10px] font-black uppercase tracking-[0.4em]">Assign profile identifier</p>
