const STORAGE_KEY = 'harmonizer_pro_v7_drive';

const App: React.FC = () => {
  // --- ROLE & PERSISTENCE STATE ---
  const [isAdmin, setIsAdmin] = useState(true);
  const [shareStatus, setShareStatus] = useState<'idle' | 'generating' | 'copied' | 'error'>('idle');
  const [activeTab, setActiveTab] = useState<'dashboard' | 'preview' | 'pivot' | 'ai'>('dashboard');
  const [selectedSheetId, setSelectedSheetId] = useState<string>('master'); 

  const [companyDatasets, setCompanyDatasets] = useState<CompanyDataset[]>(() => {
    const hash = window.location.hash;
    if (hash && hash.includes('data=')) {
      try {
        const match = hash.match(/data=([^&]*)/);
        if (match && match[1]) {
          const decompressed = LZString.decompressFromEncodedURIComponent(match[1]);
          if (decompressed) {
            const data = JSON.parse(decompressed);
            if (Array.isArray(data)) {
              return data; 
            }
          }
        }
      } catch (e) {
        console.error("Shared Link Corrupted");
      }
    }
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    if (window.location.hash.includes('data=')) {
      setIsAdmin(false);
    }
  }, []);

  useEffect(() => {
    if (!isAdmin) return;
    localStorage.setItem(STORAGE_KEY, JSON.stringify(companyDatasets));
  }, [companyDatasets, isAdmin]);

  // --- DATA PROCESSING ---
  const [isProcessing, setIsProcessing] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [aiSummary, setAiSummary] = useState<string>('');
  const [isGeneratingAi, setIsGeneratingAi] = useState(false);
  const [pendingUpload, setPendingUpload] = useState<ProcessedData | null>(null);
  const [newSheetName, setNewSheetName] = useState('');
  const [drillDownData, setDrillDownData] = useState<{ title: string; rows: DataRow[] } | null>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!isAdmin) return;
    const file = e.target.files?.[0]; // Strictly single file
    if (!file) return;

    if (file.type === 'application/pdf' || file.name.endsWith('.pdf')) {
      alert("PDF parsing is currently under development. Please use .xlsx or .csv for structured analysis.");
      e.target.value = '';
      return;
    }

    setIsProcessing(true);
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws) as DataRow[];
        const harmonized = harmonizeData(data);
        setPendingUpload(harmonized);
        setNewSheetName(file.name.split('.')[0]); 
      } catch (err) {
        alert("Corrupted File Structure Detected. Ensure it is a valid Excel or CSV file.");
      } finally {
        setIsProcessing(false);
        e.target.value = '';
      }
    };
    reader.readAsBinaryString(file);
  };

  const confirmUpload = () => {
    const newEntry: CompanyDataset = {
      id: crypto.randomUUID(),
      name: newSheetName.trim() || 'Imported_Sheet',
      data: pendingUpload!
    };
    // Replace current drive with single file or append?
    // Based on "Remove Multiple files uploads", we might want to only hold one active dataset or just handle one upload at a time.
    // Assuming the user wants to manage individual files but upload only one at a time.
    setCompanyDatasets(prev => [...prev, newEntry]);
    setSelectedSheetId(newEntry.id);
    setPendingUpload(null);
    setActiveTab('dashboard');
  };

  const deleteSheet = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!isAdmin) return;
    if (window.confirm("Permanently delete this source sheet from the drive?")) {
      setCompanyDatasets(prev => prev.filter(ds => ds.id !== id));
      if (selectedSheetId === id) setSelectedSheetId('master');
    }
  };

  const purgeDrive = () => {
    if (!isAdmin) return;
    if (window.confirm("CRITICAL: Wipe entire drive? This will permanently delete ALL uploaded sheets and resets the portal.")) {
      setCompanyDatasets([]);
      setSelectedSheetId('master');
      localStorage.removeItem(STORAGE_KEY);
      window.location.hash = '';
    }
  };

  const generateShareLink = useCallback(() => {
    if (companyDatasets.length === 0) return;
    setShareStatus('generating');

    const payload = companyDatasets.map(ds => ({
      id: ds.id,
      name: ds.name,
      data: { headers: ds.data.headers, rows: ds.data.rows }
    }));

    const compressed = LZString.compressToEncodedURIComponent(JSON.stringify(payload));
    const url = `${window.location.origin}${window.location.pathname}#data=${compressed}`;

    if (url.length > 15000) {
      setShareStatus('error');
      alert("Payload too massive for URL sharing. Please delete some non-essential sheets.");
      return;
    }

    navigator.clipboard.writeText(url).then(() => {
      setShareStatus('copied');
      setTimeout(() => setShareStatus('idle'), 3000);
    });
  }, [companyDatasets]);

  // --- DERIVED VIEWS ---
  const displayedRows = useMemo(() => {
    if (selectedSheetId === 'master') {
      return companyDatasets.flatMap(d => d.data.rows);
    }
    return companyDatasets.find(d => d.id === selectedSheetId)?.data.rows || [];
  }, [companyDatasets, selectedSheetId]);

  const activeHeaders = useMemo(() => {
    if (selectedSheetId === 'master') {
      const allHeaders = new Set<string>();
      companyDatasets.forEach(d => d.data.headers.forEach(h => allHeaders.add(h)));
      return Array.from(allHeaders);
    }
    return companyDatasets.find(d => d.id === selectedSheetId)?.data.headers || [];
  }, [companyDatasets, selectedSheetId]);

  const filteredRows = useMemo(() => {
    if (!searchTerm) return displayedRows;
    const s = searchTerm.toLowerCase();
    return displayedRows.filter(r => Object.values(r).some(v => String(v).toLowerCase().includes(s)));
  }, [displayedRows, searchTerm]);

  const metrics = useMemo(() => extractDashboardMetrics(displayedRows), [displayedRows]);

  const handleDrillDown = (title: string, data: DataRow[]) => {
    // If it's upcoming renewals, ensure we use the pre-filtered upcoming records
    if (title.toLowerCase().includes('upcoming')) {
      setDrillDownData({ title: "Current Month Renewals", rows: metrics.upcomingRecords });
    } else {
      setDrillDownData({ title, rows: data });
    }
  };

  return (
    <div className="min-h-screen flex flex-col font-sans bg-[#020617] text-slate-300 overflow-hidden h-screen">

      {/* Role Banner */}
      <div className={`px-8 py-2.5 flex items-center justify-between text-[10px] font-black uppercase tracking-[0.4em] z-[100] border-b border-white/5 ${isAdmin ? 'bg-indigo-600/10 text-indigo-400' : 'bg-emerald-600/10 text-emerald-400'}`}>
        <div className="flex items-center gap-3">
          {isAdmin ? <Settings size={14} /> : <Eye size={14} className="animate-pulse" />}
          {isAdmin ? 'Owner Management Console (Write Access)' : 'Shared Intelligence Portal (Read-Only)'}
        </div>
        {!isAdmin && (
          <button onClick={() => {window.location.hash = ''; window.location.reload();}} className="hover:text-white transition-colors flex items-center gap-2">
            Return to Master Drive <HardDrive size={12} />
          </button>
        )}
      </div>

      {/* Header */}
      <header className="bg-slate-950 border-b border-white/5 px-8 py-5 flex items-center justify-between shrink-0">
