import React, { useState, useMemo, useEffect, useCallback } from 'react';
import * as XLSX from 'xlsx';
import LZString from 'lz-string';
import { 
  FileUp, 
  Table, 
  LayoutGrid, 
  Sparkles, 
  Download, 
  RefreshCw,
  Search,
  Database,
  BarChart3,
  PieChart,
  X,
  FileSpreadsheet,
  Building2,
  ChevronDown,
  Plus,
  Trash2,
  AlertTriangle,
  Share2,
  Copy,
  ShieldCheck,
  Eye,
  Settings,
  Link,
  Info,
  Layers,
  HardDrive,
  FileText,
  Monitor,
  CalendarDays,
  Filter
} from 'lucide-react';
import { DataRow, ProcessedData, CompanyDataset } from './types';
import { harmonizeData, extractDashboardMetrics } from './utils/dataProcessor';
import { DataTable } from './components/DataTable';
import { PivotView } from './components/PivotView';
import { Dashboard } from './components/Dashboard';
import { generateDataSummary } from './services/gemini';

const STORAGE_KEY = 'harmonizer_pro_v7_drive';

const App: React.FC = () => {
  const [isAdmin, setIsAdmin] = useState(true);
  const [shareStatus, setShareStatus] = useState<'idle' | 'generating' | 'copied' | 'error'>('idle');
  const [activeTab, setActiveTab] = useState<'dashboard' | 'preview' | 'pivot' | 'ai'>('dashboard');
  const [selectedSheetId, setSelectedSheetId] = useState<string>('master'); 

  const [companyDatasets, setCompanyDatasets] = useState<CompanyDataset[]>(() => {
    const hash = window.location.hash;
    if (hash && hash.includes('data=')) {
      try {
        const match = hash.match(/data=([^&]*)/);
        if (match && match[1]) {
          const decompressed = LZString.decompressFromEncodedURIComponent(match[1]);
          if (decompressed) {
            const data = JSON.parse(decompressed);
            if (Array.isArray(data)) {
              return data; 
            }
          }
        }
      } catch (e) {
        console.error("Shared Link Corrupted");
      }
    }
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    if (window.location.hash.includes('data=')) {
      setIsAdmin(false);
    }
  }, []);

  useEffect(() => {
    if (!isAdmin) return;
    localStorage.setItem(STORAGE_KEY, JSON.stringify(companyDatasets));
  }, [companyDatasets, isAdmin]);

  const [isProcessing, setIsProcessing] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [aiSummary, setAiSummary] = useState<string>('');
  const [isGeneratingAi, setIsGeneratingAi] = useState(false);
  const [pendingUpload, setPendingUpload] = useState<ProcessedData | null>(null);
  const [newSheetName, setNewSheetName] = useState('');

  // Drilldown and Range Filter State
  const [drillDownData, setDrillDownData] = useState<{ title: string; rows: DataRow[] } | null>(null);
  const [dateRange, setDateRange] = useState<{ start: string; end: string }>({ start: '', end: '' });

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!isAdmin) return;
    const file = e.target.files?.[0]; 
    if (!file) return;

    if (file.type === 'application/pdf' || file.name.endsWith('.pdf')) {
      alert("PDF parsing is currently under development. Please use .xlsx or .csv for structured analysis.");
      e.target.value = '';
      return;
    }

    setIsProcessing(true);
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws) as DataRow[];
        const harmonized = harmonizeData(data);
        setPendingUpload(harmonized);
        setNewSheetName(file.name.split('.')[0]); 
      } catch (err) {
        alert("Corrupted File Structure Detected. Ensure it is a valid Excel or CSV file.");
      } finally {
        setIsProcessing(false);
        e.target.value = '';
      }
    };
    reader.readAsBinaryString(file);
  };

  const confirmUpload = () => {
    const newEntry: CompanyDataset = {
      id: crypto.randomUUID(),
      name: newSheetName.trim() || 'Imported_Sheet',
      data: pendingUpload!
    };
    setCompanyDatasets(prev => [...prev, newEntry]);
    setSelectedSheetId(newEntry.id);
    setPendingUpload(null);
    setActiveTab('dashboard');
  };

  const deleteSheet = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!isAdmin) return;
    if (window.confirm("Permanently delete this source sheet from the drive?")) {
      setCompanyDatasets(prev => prev.filter(ds => ds.id !== id));
      if (selectedSheetId === id) setSelectedSheetId('master');
    }
  };

  const purgeDrive = () => {
    if (!isAdmin) return;
    if (window.confirm("CRITICAL: Wipe entire drive? This will permanently delete ALL uploaded sheets and resets the portal.")) {
      setCompanyDatasets([]);
      setSelectedSheetId('master');
      localStorage.removeItem(STORAGE_KEY);
      window.location.hash = '';
    }
  };

  const generateShareLink = useCallback(() => {
    if (companyDatasets.length === 0) return;
    setShareStatus('generating');

    const payload = companyDatasets.map(ds => ({
      id: ds.id,
      name: ds.name,
      data: { headers: ds.data.headers, rows: ds.data.rows }
    }));

    const compressed = LZString.compressToEncodedURIComponent(JSON.stringify(payload));
    const url = `${window.location.origin}${window.location.pathname}#data=${compressed}`;

    if (url.length > 15000) {
      setShareStatus('error');
      alert("Payload too massive for URL sharing. Please delete some non-essential sheets.");
      return;
    }

    navigator.clipboard.writeText(url).then(() => {
      setShareStatus('copied');
      setTimeout(() => setShareStatus('idle'), 3000);
    });
  }, [companyDatasets]);

  const displayedRows = useMemo(() => {
    if (selectedSheetId === 'master') {
      return companyDatasets.flatMap(d => d.data.rows);
    }
    return companyDatasets.find(d => d.id === selectedSheetId)?.data.rows || [];
  }, [companyDatasets, selectedSheetId]);

  const activeHeaders = useMemo(() => {
    if (selectedSheetId === 'master') {
      const allHeaders = new Set<string>();
      companyDatasets.forEach(d => d.data.headers.forEach(h => allHeaders.add(h)));
      return Array.from(allHeaders);
    }
    return companyDatasets.find(d => d.id === selectedSheetId)?.data.headers || [];
  }, [companyDatasets, selectedSheetId]);

  const filteredRows = useMemo(() => {
    if (!searchTerm) return displayedRows;
    const s = searchTerm.toLowerCase();
    return displayedRows.filter(r => Object.values(r).some(v => String(v).toLowerCase().includes(s)));
  }, [displayedRows, searchTerm]);

  const handleDrillDown = (title: string, data: DataRow[]) => {
    setDateRange({ start: '', end: '' }); // Reset filters on new drill down
    setDrillDownData({ title, rows: data });
  };

  // Logic to apply date filter to drill down results
  const drillDownFiltered = useMemo(() => {
    if (!drillDownData) return [];
    if (!dateRange.start && !dateRange.end) return drillDownData.rows;

    return drillDownData.rows.filter(row => {
      const dateKey = Object.keys(row).find(k => k.includes('(Date)'));
      if (!dateKey) return true; // Keep rows without dates unless strictly filtering

      const dateStr = String(row[dateKey]).split(';')[0].trim();
      const parts = dateStr.split('/');
      if (parts.length === 3) {
        const rowDate = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
        if (dateRange.start) {
          const startDate = new Date(dateRange.start);
          if (rowDate < startDate) return false;
        }
        if (dateRange.end) {
          const endDate = new Date(dateRange.end);
          if (rowDate > endDate) return false;
        }
      }
      return true;
    });
  }, [drillDownData, dateRange]);

  const handleAuditDownload = () => {
    if (!drillDownData) return;

    const exportData = drillDownFiltered.map(row => {
      let isEscape = false;
      Object.values(row).forEach(val => {
        if (String(val).toLowerCase().includes('he has an escape report')) isEscape = true;
      });

      return {
        '!!! STATUS ALERT !!!': isEscape ? 'RED ALERT: ESCAPE REPORT' : 'VERIFIED',
        ...row
      };
    });

    const ws = XLSX.utils.json_to_sheet(exportData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Audit_Trace");
    XLSX.writeFile(wb, `Audit_Trace_${drillDownData.title.replace(/\s+/g, '_')}.xlsx`);
  };

  return (
    <div className="min-h-screen flex flex-col font-sans bg-[#020617] text-slate-300 overflow-hidden h-screen">

      <div className={`px-8 py-2.5 flex items-center justify-between text-[10px] font-black uppercase tracking-[0.4em] z-[100] border-b border-white/5 ${isAdmin ? 'bg-indigo-600/10 text-indigo-400' : 'bg-emerald-600/10 text-emerald-400'}`}>
        <div className="flex items-center gap-3">
          {isAdmin ? <Settings size={14} /> : <Eye size={14} className="animate-pulse" />}
          {isAdmin ? 'Owner Management Console (Write Access)' : 'Shared Intelligence Portal (Read-Only)'}
        </div>
        {!isAdmin && (
          <button onClick={() => {window.location.hash = ''; window.location.reload();}} className="hover:text-white transition-colors flex items-center gap-2">
            Return to Master Drive <HardDrive size={12} />
          </button>
        )}
      </div>

      <header className="bg-slate-950 border-b border-white/5 px-8 py-5 flex items-center justify-between shrink-0">
        <div className="flex items-center gap-4">
          <div className="bg-gradient-to-br from-indigo-600 to-indigo-800 p-2.5 rounded-2xl text-white shadow-2xl">
            <Database size={24} />
          </div>
          <div>
            <h1 className="text-xl font-black text-white tracking-tighter leading-none">DataHarmonizer <span className="text-indigo-500">Pro</span></h1>
            <p className="text-[9px] text-slate-500 font-black uppercase tracking-[0.4em] mt-1.5 flex items-center gap-2">
              <ShieldCheck size={10} className="text-emerald-500" /> ISO-9001 Data Sync Active
            </p>
          </div>
        </div>

        <div className="flex items-center gap-6">
          <div className="relative group">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 group-focus-within:text-indigo-500 transition-colors" size={16} />
            <input 
              type="text" 
              placeholder="Query Drive..." 
              className="bg-slate-900/50 border border-white/5 rounded-xl pl-10 pr-4 py-2.5 text-sm focus:ring-2 focus:ring-indigo-500 outline-none transition-all w-80 text-white font-medium"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <button 
            onClick={() => {
              const ws = XLSX.utils.json_to_sheet(displayedRows);
              const wb = XLSX.utils.book_new();
              XLSX.utils.book_append_sheet(wb, ws, "Drive_Export");
              XLSX.writeFile(wb, `Drive_Export_${selectedSheetId}.xlsx`);
            }}
            className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all shadow-xl shadow-indigo-900/20 active:scale-95"
          >
            <Download size={18} /> Export View
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden">
        <aside className="w-80 bg-slate-950/50 border-r border-white/5 p-6 flex flex-col space-y-8 hidden md:flex overflow-y-auto custom-scrollbar shrink-0">
          {isAdmin && (
            <div className="space-y-4">
              <div className="text-[10px] text-slate-500 font-black uppercase tracking-[0.3em] px-2 mb-3">Management</div>
              <label className="flex items-center gap-4 p-4 bg-indigo-600 hover:bg-indigo-500 rounded-2xl cursor-pointer transition-all shadow-xl shadow-indigo-900/20 group">
                <FileUp size={20} className="text-white group-hover:translate-y-[-2px] transition-transform" />
                <span className="text-sm font-black text-white uppercase tracking-widest">Link Source</span>
                <input type="file" className="hidden" onChange={handleFileUpload} accept=".xlsx,.csv,.pdf" />
              </label>
              <button 
