                  onClick={() => setSelectedSheetId(ds.id)}
                  className={`w-full flex items-center justify-between p-3.5 rounded-xl text-xs font-bold transition-all group ${selectedSheetId === ds.id ? 'bg-white/5 text-white' : 'text-slate-500 hover:bg-white/5'}`}
                >
                  <div className="flex items-center gap-3 truncate">
                    <FileText size={14} className={selectedSheetId === ds.id ? 'text-indigo-400' : 'text-slate-600'} />
                    <span className="truncate uppercase tracking-wider">{ds.name}</span>
                  </div>
                  {isAdmin && (
                    <Trash2 
