import React, { useMemo, useState } from 'react';
import { 
  Users, 
  CreditCard, 
  AlertCircle, 
  Globe, 
  ShieldX, 
  UserX, 
  Layers, 
  Activity, 
  ArrowUpRight, 
  Target, 
  ChevronRight, 
  Zap, 
  Bike, 
  ShieldCheck, 
  MoreHorizontal, 
  Download, 
  Calendar, 
  TrendingUp, 
  CheckCircle2, 
  ShieldAlert, 
  BarChart4,
  Layout
} from 'lucide-react';
import { DataRow } from '../types';
import { extractDashboardMetrics } from '../utils/dataProcessor';

interface DashboardProps {
  rows: DataRow[];
  onDrillDown: (title: string, filteredRows: DataRow[]) => void;
}

const BRAND_COLORS = [
  '#6366f1', // Indigo
  '#10b981', // Emerald
  '#f59e0b', // Amber
  '#ef4444', // Red
  '#06b6d4', // Cyan
  '#8b5cf6', // Violet
  '#f43f5e', // Rose
  '#3b82f6', // Blue
  '#ec4899', // Pink
  '#84cc16', // Lime
];

export const Dashboard: React.FC<DashboardProps> = ({ rows, onDrillDown }) => {
  const metrics = useMemo(() => extractDashboardMetrics(rows), [rows]);

  // Workforce Segmentation logic
  const workforceSplit = useMemo(() => {
    const jobKey = Object.keys(rows[0] || {}).find(k => 
      k.toLowerCase().includes('job') || 
      k.toLowerCase().includes('description') || 
      k.toLowerCase().includes('designation') || 
      k.toLowerCase().includes('title')
    );

    const motorcyclistRows: DataRow[] = [];
    const staffSupportRows: DataRow[] = [];

    rows.forEach(row => {
      const job = String(row[jobKey || ''] || '').toLowerCase();
      if (job.includes('motorcyclist') || job.includes('motorcycle') || job.includes('biker') || job.includes('bike')) {
        motorcyclistRows.push(row);
      } else {
        staffSupportRows.push(row);
      }
    });

    return {
      motorcyclist: { count: motorcyclistRows.length, rows: motorcyclistRows },
      staffSupport: { count: staffSupportRows.length, rows: staffSupportRows }
    };
  }, [rows]);

  // 6-Month Renewal Pipeline logic
  const renewalForecast = useMemo(() => {
    const today = new Date();
    const months = [];
    const monthNames = ["JAN", "FEB", "MAR", "APR", "MAY", "JUN", "JUL", "AUG", "SEP", "OCT", "NOV", "DEC"];

    let totalProjected = 0;
    for (let i = 0; i < 6; i++) {
      const d = new Date(today.getFullYear(), today.getMonth() + i, 1);
      const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
      const count = metrics.monthlyRenewals[key] || 0;
      const escapeCount = metrics.monthlyEscapes[key] || 0;
      totalProjected += count;
      months.push({
        key,
        month: monthNames[d.getMonth()],
        year: d.getFullYear(),
        count,
        escapeCount
      });
    }

    const maxMonthCount = Math.max(...months.map(m => m.count), 1);

    return months.map(m => ({
      ...m,
      intensity: (m.count / maxMonthCount) * 100,
      status: m.count > (totalProjected / 6) * 1.5 ? 'CRITICAL' : m.count > 0 ? 'ACTIVE' : 'STABLE'
    }));
  }, [metrics.monthlyRenewals, metrics.monthlyEscapes]);

  // COLUMN GRAPH DATA PREPARATION
  const statusGraphData = useMemo(() => {
    const entries = Object.entries(metrics.statusData) as [string, number][];
    const sorted = entries.sort((a, b) => b[1] - a[1]);
    const maxVal = Math.max(...sorted.map(e => e[1]), 1);

    return sorted.map(([status, count], index) => ({
      status,
      count,
      percent: ((count / (metrics.total || 1)) * 100).toFixed(1),
      color: BRAND_COLORS[index % BRAND_COLORS.length],
      height: (count / maxVal) * 100,
    })).slice(0, 12); 
  }, [metrics.statusData, metrics.total]);

  const complianceRate = useMemo(() => {
    if (metrics.total === 0) return 0;
    return (((metrics.total - metrics.expiredCardCount - metrics.escapeCount) / metrics.total) * 100).toFixed(1);
  }, [metrics]);

  return (
    <div className="space-y-16 animate-in fade-in duration-1000 pb-24 w-full max-w-[2560px] mx-auto px-4">

      {/* 01. EXECUTIVE COMMAND HEADER */}
      <div className="bg-slate-900 rounded-[60px] p-12 shadow-2xl relative overflow-hidden flex flex-col xl:flex-row items-center justify-between gap-12 border border-white/5">
        <div className="absolute top-0 right-0 w-[800px] h-[800px] bg-indigo-500/10 blur-[150px] -mr-96 -mt-96 rounded-full pointer-events-none"></div>
        <div className="relative z-10 space-y-5">
          <div className="flex items-center gap-4 text-indigo-400 font-black text-[10px] uppercase tracking-[0.5em]">
            <Zap size={18} />
            Command Intelligence Hub
          </div>
          <h2 className="text-6xl font-black text-white tracking-tighter leading-tight">Workforce Master<br/>Synchronization</h2>
          <p className="text-slate-400 font-medium text-lg max-w-2xl leading-relaxed">System-wide auditing of {metrics.total} professional entities. Real-time vector analysis across multiple operational dimensions.</p>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 relative z-10 w-full xl:w-auto min-w-[680px]">
          <VitalityBox label="Health Index" value={`${complianceRate}%`} sub="Global Integrity" icon={<ShieldCheck className="text-emerald-400" />} />
          <VitalityBox label="Risk Density" value={metrics.expiredCardCount + metrics.escapeCount} sub="Immediate Priority" icon={<ShieldAlert className="text-rose-400" />} />
          <VitalityBox label="Total Census" value={metrics.total} sub="Live Personnel" icon={<Users className="text-indigo-400" />} />
        </div>
      </div>

      {/* 02. CORE OPERATIONAL KPIS */}
      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-10">
        <ProKpi icon={<UserX />} label="Escape Reports" value={metrics.escapeCount} color="rose" onClick={() => onDrillDown("Escape Registry", metrics.escapeRecords)} />
        <ProKpi icon={<ShieldX />} label="Expired Credentials" value={metrics.expiredCardCount} color="amber" onClick={() => onDrillDown("Expired Registry", metrics.expiredRecords)} />
        <ProKpi icon={<Bike />} label="Motorcyclists" value={workforceSplit.motorcyclist.count} color="indigo" showDownload onClick={() => onDrillDown("Motorcyclist Registry", workforceSplit.motorcyclist.rows)} />
        <ProKpi icon={<MoreHorizontal />} label="Staff & Support" value={workforceSplit.staffSupport.count} color="slate" showDownload onClick={() => onDrillDown("Staff & Support Registry", workforceSplit.staffSupport.rows)} />
        <ProKpi icon={<CreditCard />} label="Active Personnel" value={metrics.activeCount} color="emerald" onClick={() => onDrillDown("Compliant Active Records", rows.filter(r => !metrics.expiredRecords.includes(r)))} />
        <ProKpi icon={<Activity />} label="Upcoming Renewals" value={metrics.upcomingRenewals} color="indigo" onClick={() => onDrillDown("Upcoming (Current Month)", metrics.upcomingRecords)} />
      </div>

      {/* 03. STATUS DISTRIBUTION */}
      <div className="bg-white rounded-[70px] border border-slate-200 shadow-3xl overflow-hidden relative">
        <div className="absolute top-0 right-0 w-[600px] h-[600px] bg-slate-50 rounded-full blur-[120px] -mr-96 -mt-96 opacity-60"></div>
        <div className="p-16 border-b border-slate-100 flex flex-col lg:flex-row items-start lg:items-center justify-between gap-8 bg-slate-50/30">
          <div className="space-y-4">
            <h3 className="text-5xl font-black text-slate-900 tracking-tighter flex items-center gap-6">
              <BarChart4 className="text-indigo-600" size={56} />
              Status Distribution Matrix
            </h3>
            <p className="text-[13px] text-slate-400 font-black uppercase tracking-[0.5em] ml-20 leading-none">High-Density Categorical Volume Analysis</p>
          </div>
        </div>
        <div className="p-16 relative">
          <div className="h-[500px] w-full flex items-end justify-between gap-4 md:gap-8 pb-12 border-b-2 border-slate-100">
            {statusGraphData.map((item) => (
              <div 
                key={item.status}
                className="group relative flex-1 flex flex-col items-center cursor-pointer h-full justify-end"
                onClick={() => onDrillDown(`Status: ${item.status}`, rows.filter(r => String(r[Object.keys(r).find(k => k.toLowerCase().includes('status')) || '']).trim() === item.status))}
              >
                <div className="absolute bottom-full mb-4 opacity-0 group-hover:opacity-100 transition-all duration-300 pointer-events-none z-30 translate-y-2 group-hover:translate-y-0">
                   <div className="bg-slate-900 text-white p-5 rounded-2xl shadow-2xl min-w-[160px] text-center">
                      <div className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-1">Total Volume</div>
                      <div className="text-3xl font-black mb-1">{item.count}</div>
                      <div className="text-[11px] font-bold text-indigo-400 uppercase tracking-widest">{item.percent}% of Total</div>
                   </div>
                   <div className="w-3 h-3 bg-slate-900 rotate-45 mx-auto -mt-1.5"></div>
                </div>
                <div 
                  className="w-full rounded-t-[24px] transition-all duration-1000 ease-out relative group-hover:brightness-110 group-hover:shadow-2xl overflow-hidden"
                  style={{ 
                    height: `${item.height}%`, 
                    backgroundColor: item.color,
                    boxShadow: `0 20px 40px -10px ${item.color}33`
                  }}
                >
                  <div className="absolute inset-0 bg-gradient-to-b from-white/20 to-transparent opacity-50"></div>
                </div>
                <div className="absolute top-full pt-4 w-full text-center">
                   <p className="text-[10px] md:text-[11px] font-black text-slate-500 uppercase tracking-widest truncate group-hover:text-slate-900 transition-colors" title={item.status}>
                     {item.status.length > 15 ? item.status.substring(0, 12) + '...' : item.status}
                   </p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* 04. DYNAMIC OPERATIONAL PIPELINE */}
      <div className="bg-slate-900 p-12 rounded-[70px] shadow-2xl relative overflow-hidden border border-white/5">
        <div className="absolute top-0 left-0 w-full h-full bg-[radial-gradient(circle_at_30%_20%,rgba(99,102,241,0.08),transparent)] pointer-events-none"></div>
        <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-8 mb-16 relative z-10">
          <div>
            <h3 className="text-4xl font-black text-white tracking-tighter flex items-center gap-5">
              <Calendar className="text-indigo-400" size={44} />
