// --- Types ---
export interface CompanyMeta {
  id: string;
  name: string;
  storagePath: string;
  uploadDate: string;
  uploadedBy: string;
}

// --- Mock State (In-Memory) ---
let mockUser: any = null;
const mockAuthListeners: ((user: any) => void)[] = [];
let mockCompanies: CompanyMeta[] = [
  { id: 'mock-1', name: 'Demo Corp (Mock)', storagePath: 'mock/path', uploadDate: new Date().toISOString(), uploadedBy: 'admin' }
];
// We'll store file data in memory for the mock session
const mockFileStorage: Record<string, ArrayBuffer> = {};

// --- Facade Methods ---

/**
 * Subscribes to auth state changes. 
 * Handles both Firebase Auth and Mock Auth.
 */
export const subscribeToAuth = (callback: (user: User | null) => void) => {
  if (hasFirebaseConfig && auth) {
    return onAuthStateChanged(auth, callback);
  } else {
    // Mock Subscription
    mockAuthListeners.push(callback);
    callback(mockUser);
    return () => {
      const idx = mockAuthListeners.indexOf(callback);
      if (idx > -1) mockAuthListeners.splice(idx, 1);
    };
  }
};

/**
 * Logs in the user.
 */
export const login = async (email: string, password: string): Promise<void> => {
  if (hasFirebaseConfig && auth) {
    await signInWithEmailAndPassword(auth, email, password);
  } else {
    // Mock Login
    if (!email || !password) throw new Error("Invalid credentials");

    // Simple mock validation for admin
    if (email === "admin@empmas.com" && password !== "admin123") {
        throw new Error("Invalid password for admin.");
    }

    // Simulate network delay
    await new Promise(r => setTimeout(r, 800));
    mockUser = { 
      uid: 'mock-user-123', 
      email: email, 
      displayName: email.split('@')[0] 
    };
    mockAuthListeners.forEach(cb => cb(mockUser));
  }
};

/**
 * Logs out the user.
 */
export const logout = async (): Promise<void> => {
  if (hasFirebaseConfig && auth) {
    await signOut(auth);
  } else {
    mockUser = null;
    mockAuthListeners.forEach(cb => cb(null));
  }
};

/**
 * Uploads company file and metadata.
 */
export const uploadCompanyData = async (file: File, companyName: string, userId: string): Promise<CompanyMeta> => {
  if (hasFirebaseConfig && storage && db) {
    const storagePath = `companies/${userId}/${Date.now()}_${file.name}`;
    const storageRef = ref(storage, storagePath);
    await uploadBytes(storageRef, file);

    const meta: Omit<CompanyMeta, 'id'> = {
      name: companyName,
      storagePath: storagePath,
      uploadDate: new Date().toISOString(),
      uploadedBy: userId
    };

    const docRef = await addDoc(collection(db, "companies"), meta);
    return { id: docRef.id, ...meta };
  } else {
    // Mock Upload
    await new Promise(r => setTimeout(r, 1000));
    const mockId = `mock-${Date.now()}`;
    const meta: CompanyMeta = {
      id: mockId,
      name: companyName + (hasFirebaseConfig ? "" : " (Mock)"),
      storagePath: `mock/${mockId}`,
      uploadDate: new Date().toISOString(),
      uploadedBy: userId
    };
    mockCompanies.unshift(meta);
    // Store file buffer
    mockFileStorage[meta.storagePath] = await file.arrayBuffer();
    return meta;
  }
};

/**
 * Fetches list of companies.
 */
export const fetchCompanies = async (): Promise<CompanyMeta[]> => {
  if (hasFirebaseConfig && db) {
    const q = query(collection(db, "companies"), orderBy("uploadDate", "desc"));
    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as CompanyMeta));
  } else {
    return [...mockCompanies];
  }
};

/**
 * Deletes company data.
 */
export const deleteCompanyData = async (id: string, storagePath: string) => {
  if (hasFirebaseConfig && db && storage) {
    const storageRef = ref(storage, storagePath);
    await deleteObject(storageRef);
    await deleteDoc(doc(db, "companies", id));
  } else {
    mockCompanies = mockCompanies.filter(c => c.id !== id);
    delete mockFileStorage[storagePath];
  }
};

/**
 * Downloads company file.
 */
export const downloadCompanyFile = async (storagePath: string): Promise<ArrayBuffer> => {
  if (hasFirebaseConfig && storage) {
    const pathReference = ref(storage, storagePath);
    const url = await getDownloadURL(pathReference);
    const response = await fetch(url);
    return await response.arrayBuffer();
  } else {
    const buffer = mockFileStorage[storagePath];
    if (buffer) return buffer;
    // Return empty buffer or dummy xlsx if not found in mock
    throw new Error("File not found in mock storage");
  }
};

