  const [searchTerm, setSearchTerm] = useState('');
  const [aiSummary, setAiSummary] = useState<string>('');
  const [isGeneratingAi, setIsGeneratingAi] = useState(false);
  const [drillDownData, setDrillDownData] = useState<{ title: string; rows: DataRow[] } | null>(null);
  const [dateRange, setDateRange] = useState<{ start: string; end: string }>({ start: '', end: '' });

  // Upload State
  const [isUploading, setIsUploading] = useState(false);
  const [uploadName, setUploadName] = useState('');
  const [uploadFile, setUploadFile] = useState<File | null>(null);

  // 1. Auth Listener
  useEffect(() => {
    const unsubscribe = subscribeToAuth((currentUser) => {
      setUser(currentUser);
      if (currentUser) {
        // Check if admin based on specific email
        const adminStatus = currentUser.email === ADMIN_EMAIL;
        setIsAdmin(adminStatus);

        // If user is not admin and was on a restricted tab, switch to dashboard
