          setActiveTab('dashboard');
        }

        loadCompanyList();
      } else {
        setIsAdmin(false);
        setCompanies([]);
        setCurrentData(null);
      }
      setLoadingAuth(false);
    });
    return () => unsubscribe();
  }, []);

  // 2. Load Company List
