      <header className="bg-slate-950 border-b border-white/5 px-8 py-5 flex items-center justify-between shrink-0">
        <div className="flex items-center gap-4">
          <div className="bg-gradient-to-br from-indigo-600 to-indigo-800 p-2.5 rounded-2xl text-white shadow-2xl"><Database size={24} /></div>
          <div>
            <h1 className="text-xl font-black text-white tracking-tighter leading-none">DataHarmonizer <span className="text-indigo-500">Pro</span></h1>
          </div>
        </div>

        {/* Company Selector Dropdown */}
        <div className="flex items-center gap-6">
          <div className="relative z-50">
            <div className="relative group">
              <Building2 className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={16} />
              <select 
                value={selectedCompanyId || ''}
                onChange={(e) => setSelectedCompanyId(e.target.value)}
                className="appearance-none bg-slate-900 border border-white/10 rounded-xl pl-12 pr-10 py-2.5 text-sm font-bold text-white outline-none focus:ring-2 focus:ring-indigo-500 w-64 cursor-pointer"
              >
                <option value="" disabled>Select Company Entity</option>
                {companies.map(c => (
                  <option key={c.id} value={c.id}>{c.name}</option>
                ))}
              </select>
              <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500 pointer-events-none" size={14} />
            </div>
          </div>

          <div className="relative group">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 group-focus-within:text-indigo-500 transition-colors" size={16} />
            <input type="text" placeholder="Global Filter..." className="bg-slate-900/50 border border-white/5 rounded-xl pl-10 pr-4 py-2.5 text-sm focus:ring-2 focus:ring-indigo-500 outline-none transition-all w-64 text-white font-medium" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
          </div>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden">
        <aside className="w-80 bg-slate-950/50 border-r border-white/5 p-6 flex flex-col space-y-8 hidden md:flex shrink-0">

          {/* Admin Upload Section */}
          {isAdmin && (
            <div className="space-y-4">
              <div className="text-[10px] text-slate-500 font-black uppercase tracking-[0.3em] px-2">Data Ingestion</div>
              <button 
                onClick={() => setUploadFile({} as File)} 
                className="w-full flex items-center gap-4 p-4 bg-indigo-600 hover:bg-indigo-500 rounded-2xl cursor-pointer transition-all shadow-xl shadow-indigo-900/20 group text-left"
              >
                <FileUp size={20} className="text-white" />
                <span className="text-sm font-black text-white uppercase tracking-widest">New Upload</span>
              </button>
            </div>
          )}

          {/* Company List (Sidebar) */}
          <div className="space-y-2 flex-1 overflow-y-auto custom-scrollbar">
            <div className="text-[10px] text-slate-500 font-black uppercase tracking-[0.3em] px-2 mb-3">Cloud Repository</div>
            {companies.map(c => (
              <div 
                key={c.id} 
                onClick={() => setSelectedCompanyId(c.id)}
                className={`w-full flex items-center justify-between p-3.5 rounded-xl text-xs font-bold transition-all cursor-pointer group ${selectedCompanyId === c.id ? 'bg-white/5 text-white border border-white/5' : 'text-slate-500 hover:bg-white/5 border border-transparent'}`}
              >
                <div className="flex items-center gap-3 truncate">
                  <FileText size={14} className={selectedCompanyId === c.id ? 'text-indigo-400' : 'text-slate-600'} />
                  <div className="flex flex-col truncate">
                    <span className="truncate">{c.name}</span>
                    <span className="text-[9px] font-medium opacity-50">{new Date(c.uploadDate).toLocaleDateString()}</span>
                  </div>
                </div>
                {isAdmin && (
                  <button onClick={(e) => handleDeleteCompany(c.id, c.storagePath, e)} className="p-1.5 hover:bg-rose-500/20 hover:text-rose-500 rounded-lg transition-colors opacity-0 group-hover:opacity-100">
                    <Trash2 size={12} />
                  </button>
                )}
              </div>
            ))}
            {companies.length === 0 && <div className="text-center text-[10px] text-slate-600 font-black uppercase tracking-widest py-10">Repository Empty</div>}
          </div>

          <nav className="space-y-2 pt-4 border-t border-white/5">
            {/* Standard Tabs */}
            {[
              { id: 'dashboard', label: 'Analysis Hub', icon: PieChart },
              { id: 'extract', label: 'Query Hub', icon: FileSearch },
              { id: 'pivot', label: 'Pivot Table', icon: LayoutGrid },
              { id: 'preview', label: 'Drive Grid', icon: Table },
              { id: 'ai', label: 'AI Narrative', icon: Sparkles },
            ].map(item => (
              <button 
                key={item.id} 
                onClick={() => setActiveTab(item.id as any)} 
                disabled={!currentData}
                className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-black transition-all ${activeTab === item.id ? 'bg-white/5 text-indigo-400 border border-white/5' : 'text-slate-500 hover:text-slate-200'} ${!currentData ? 'opacity-50 cursor-not-allowed' : ''}`}
              >
                <item.icon size={20} /> {item.label}
              </button>
            ))}

            {/* Admin Only Tab */}
            {isAdmin && (
               <button 
               onClick={() => setActiveTab('users')} 
               className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-black transition-all ${activeTab === 'users' ? 'bg-white/5 text-indigo-400 border border-white/5' : 'text-slate-500 hover:text-slate-200'}`}
             >
               <Users size={20} /> User Management
             </button>
            )}
          </nav>
        </aside>

        <section className="flex-1 overflow-auto bg-[#020617] p-12 custom-scrollbar relative">

          {/* Loading State */}
          {isLoadingData && (
            <div className="h-full flex flex-col items-center justify-center space-y-8 animate-in fade-in">
              <RefreshCw className="animate-spin text-indigo-500" size={60} />
              <p className="text-slate-500 font-black uppercase tracking-widest text-xs">Fetching Secure Data...</p>
            </div>
          )}

          {/* Special Case for User Management Tab which doesn't require currentData */}
          {!isLoadingData && activeTab === 'users' && isAdmin && (
             <div className="max-w-7xl mx-auto animate-in fade-in">
                <UserManagement />
             </div>
          )}

          {/* Empty State (Only if not in Users tab and no data) */}
          {!currentData && !isLoadingData && activeTab !== 'users' && (
            <div className="h-full flex flex-col items-center justify-center text-center space-y-6 max-w-lg mx-auto">
              <div className="w-24 h-24 bg-slate-900 rounded-full flex items-center justify-center border border-white/5">
                <Layers size={40} className="text-slate-600" />
              </div>
              <h2 className="text-3xl font-black text-white tracking-tighter">Select an Entity</h2>
              <p className="text-slate-500 text-sm font-medium leading-relaxed">
                Choose a company from the dropdown or sidebar to load its operational dashboard.
                {isAdmin && " As an administrator, you can also upload new datasets."}
              </p>
            </div>
          )}

          {/* Content for Data Tabs */}
          {currentData && !isLoadingData && activeTab !== 'users' && (
            <div className="max-w-7xl mx-auto space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-700">
              <div className="flex items-center gap-4 text-slate-500 font-bold text-xs uppercase tracking-widest mb-8">
                 <div className="w-2 h-2 rounded-full bg-emerald-500"></div> Live Stream: {companies.find(c => c.id === selectedCompanyId)?.name}
              </div>

              {activeTab === 'dashboard' && <Dashboard rows={currentData.rows} onDrillDown={handleDrillDown} />}
              {activeTab === 'extract' && <ReportExtractor rows={currentData.rows} headers={currentData.headers} />}
              {activeTab === 'pivot' && <PivotView rows={currentData.rows} headers={currentData.headers} />}
              {activeTab === 'preview' && <DataTable headers={currentData.headers} rows={filteredRows} highlightTerm={searchTerm} />}
              {activeTab === 'ai' && (
                <div className="bg-slate-900 rounded-[60px] border border-white/5 p-20 relative overflow-hidden shadow-2xl">
                  <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-12 mb-16 relative z-10">
                    <h3 className="text-4xl font-black text-white tracking-tighter">Narrative Synthesis</h3>
                    <button onClick={async () => { setIsGeneratingAi(true); const s = await generateDataSummary(currentData.rows); setAiSummary(s); setIsGeneratingAi(false); }} disabled={isGeneratingAi} className="bg-indigo-600 text-white px-12 py-6 rounded-[32px] font-black text-xl transition-all shadow-2xl">
                      {isGeneratingAi ? <RefreshCw className="animate-spin" /> : <Sparkles />} {aiSummary ? 'Regenerate' : 'Initiate'}
                    </button>
                  </div>
                  <div className="prose prose-invert max-w-none text-xl leading-relaxed text-slate-400 relative z-10 whitespace-pre-wrap italic">
                    {aiSummary || "Awaiting intelligence trigger..."}
                  </div>
                </div>
              )}
            </div>
          )}
        </section>
      </main>

      {/* Upload Modal (Admin Only) */}
      {uploadFile && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-black/90 backdrop-blur-md animate-in fade-in">
          <div className="bg-slate-900 w-full max-w-md rounded-[50px] border border-white/10 p-12 space-y-10 shadow-2xl">
            <div className="text-center space-y-4">
              <div className="w-16 h-16 bg-indigo-500/10 rounded-2xl flex items-center justify-center mx-auto text-indigo-500"><FileSpreadsheet size={32} /></div>
              <h3 className="text-3xl font-black text-white tracking-tighter">Ingest Data</h3>
              <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">Secure Cloud Upload</p>
            </div>

            <div className="space-y-4">
               <div>
                 <label className="text-xs font-bold text-slate-500 uppercase ml-2 mb-1 block">Entity Name</label>
                 <input autoFocus type="text" className="w-full p-4 bg-slate-950 border border-white/10 rounded-2xl text-lg font-bold text-white outline-none focus:ring-2 focus:ring-indigo-500" value={uploadName} onChange={(e) => setUploadName(e.target.value)} placeholder="Company Name" />
               </div>
               <div>
                 <label className="text-xs font-bold text-slate-500 uppercase ml-2 mb-1 block">Source File</label>
                 <input type="file" onChange={handleFileSelect} accept=".xlsx,.csv" className="w-full p-4 bg-slate-950 border border-white/10 rounded-2xl text-sm text-slate-400 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-xs file:font-semibold file:bg-indigo-500 file:text-white hover:file:bg-indigo-600" />
               </div>
            </div>

            <div className="flex gap-4 pt-4">
              <button onClick={() => { setUploadFile(null); setUploadName(''); }} className="flex-1 py-4 text-slate-500 font-black uppercase text-[11px] hover:text-white transition-colors">Cancel</button>
              <button onClick={handleUploadSubmit} disabled={isUploading || !uploadName} className="flex-1 py-4 bg-indigo-600 hover:bg-indigo-500 text-white rounded-2xl font-black uppercase text-[11px] shadow-lg shadow-indigo-500/20 flex items-center justify-center gap-2">
                 {isUploading ? <RefreshCw className="animate-spin" size={14} /> : "Upload to Cloud"}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Drill Down Modal */}
      {drillDownData && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-6 bg-black/90 backdrop-blur-xl animate-in fade-in">
          <div className="bg-slate-900 w-full max-w-7xl h-[90vh] rounded-[70px] border border-white/10 flex flex-col overflow-hidden shadow-2xl">
            <div className="p-12 border-b border-white/5 flex flex-col space-y-8 bg-white/5">
              <div className="flex items-center justify-between">
                <h3 className="text-4xl font-black text-white tracking-tighter">{drillDownData.title}</h3>
                <button onClick={() => setDrillDownData(null)} className="p-5 hover:bg-white/5 rounded-full text-slate-500"><X size={44} /></button>
              </div>
              <div className="flex flex-wrap items-center gap-8 bg-slate-950/50 p-6 rounded-[32px]">
                <div className="flex items-center gap-4"><CalendarDays className="text-indigo-400" size={14} /><input type="date" className="bg-slate-900 border border-white/10 rounded-xl px-4 py-2 text-xs font-bold text-white" value={dateRange.start} onChange={(e) => setDateRange(prev => ({ ...prev, start: e.target.value }))} /></div>
                <div className="flex items-center gap-4"><CalendarDays className="text-indigo-400" size={14} /><input type="date" className="bg-slate-900 border border-white/10 rounded-xl px-4 py-2 text-xs font-bold text-white" value={dateRange.end} onChange={(e) => setDateRange(prev => ({ ...prev, end: e.target.value }))} /></div>
              </div>
            </div>
            <div className="flex-1 overflow-hidden p-12 bg-slate-950"><DataTable headers={currentData?.headers || []} rows={drillDownFiltered} /></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useMemo, useState } from 'react';
import * as XLSX from 'xlsx';
import { 
  Users, 
  CreditCard, 
  Globe, 
  ShieldX, 
  UserX, 
  Activity, 
  ArrowUpRight, 
  Zap, 
  Bike, 
  ShieldCheck, 
  MoreHorizontal, 
  Download, 
  Calendar, 
  ShieldAlert, 
  BarChart4,
  Loader2,
  FileSpreadsheet
} from 'lucide-react';
import { DataRow, DashboardMetrics } from '../types';
import { extractDashboardMetrics } from '../utils/dataProcessor';

interface DashboardProps {
  rows: DataRow[];
  onDrillDown: (title: string, filteredRows: DataRow[]) => void;
}

const BRAND_COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ef4444', '#06b6d4', '#8b5cf6', '#f43f5e', '#3b82f6', '#ec4899', '#84cc16'];

export const Dashboard: React.FC<DashboardProps> = ({ rows, onDrillDown }) => {
  const [isExporting, setIsExporting] = useState(false);

  // Explicitly casting the result of extractDashboardMetrics to DashboardMetrics
  const metrics = useMemo(() => extractDashboardMetrics(rows), [rows]) as DashboardMetrics;

  const workforceSplit = useMemo(() => {
    const jobKey = Object.keys(rows[0] || {}).find(k => 
      k.toLowerCase().includes('job') || k.toLowerCase().includes('description') || k.toLowerCase().includes('designation')
    );
    const motorcyclistRows: DataRow[] = [];
    const staffSupportRows: DataRow[] = [];
    rows.forEach(row => {
      const job = String(row[jobKey || ''] || '').toLowerCase();
      if (job.includes('motorcycle') || job.includes('bike') || job.includes('motorcyclist')) motorcyclistRows.push(row);
      else staffSupportRows.push(row);
    });
    return { motorcyclist: motorcyclistRows, staffSupport: staffSupportRows };
  }, [rows]);

  const renewalForecast = useMemo(() => {
    const today = new Date();
    const months = [];
    const monthNames = ["JAN", "FEB", "MAR", "APR", "MAY", "JUN"];
    let totalProjected = 0;
    for (let i = 0; i < 6; i++) {
      const d = new Date(today.getFullYear(), today.getMonth() + i, 1);
      const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
      const count = (metrics.monthlyRenewals[key] || 0) as number;
      const escapeCount = (metrics.monthlyEscapes[key] || 0) as number;
      totalProjected += count;
      months.push({ key, month: monthNames[i % 6], year: d.getFullYear(), count, escapeCount });
    }
    const maxMonthCount = Math.max(...months.map(m => m.count as number), 1);
    return months.map(m => ({
      ...m,
      intensity: ((m.count as number) / maxMonthCount) * 100,
      status: (m.count as number) > (totalProjected / 6) * 1.5 ? 'CRITICAL' : (m.count as number) > 0 ? 'ACTIVE' : 'STABLE'
    }));
  }, [metrics]);

  const handleFullExport = async () => {
    setIsExporting(true);
    await new Promise(r => setTimeout(r, 500)); // UI Feedback

    const wb = XLSX.utils.book_new();

    // 1. Executive Summary Sheet
    const summaryData = [
      ["METRIC", "VALUE", "NOTES"],
      ["Total Personnel", metrics.total, "Full census count"],
      ["Active Credentials", metrics.activeCount, "Valid visas/labor cards"],
      ["Expired Credentials", metrics.expiredCardCount, "Requires immediate attention"],
      ["Escape Reports", metrics.escapeCount, "Absconding/Legal issues"],
      ["Upcoming Renewals", metrics.upcomingRenewals, "Due this month"],
      ["Motorcyclists", workforceSplit.motorcyclist.length, "Role-based count"],
      ["Support Staff", workforceSplit.staffSupport.length, "Role-based count"],
      [],
      ["NATIONALITY BREAKDOWN", "COUNT"],
      ...Object.entries(metrics.nationalityData),
      [],
      ["STATUS BREAKDOWN", "COUNT"],
      ...Object.entries(metrics.statusData)
    ];
    const wsSummary = XLSX.utils.aoa_to_sheet(summaryData);
    XLSX.utils.book_append_sheet(wb, wsSummary, "Executive Summary");

    // 2. Registries
    if (metrics.escapeRecords.length) {
      const ws = XLSX.utils.json_to_sheet(metrics.escapeRecords);
      XLSX.utils.book_append_sheet(wb, ws, "Escape Registry");
    }

    if (metrics.expiredRecords.length) {
      const ws = XLSX.utils.json_to_sheet(metrics.expiredRecords);
      XLSX.utils.book_append_sheet(wb, ws, "Expired Cards");
    }

    if (metrics.upcomingRecords.length) {
      const ws = XLSX.utils.json_to_sheet(metrics.upcomingRecords);
      XLSX.utils.book_append_sheet(wb, ws, "Renewals Due");
    }

    // 3. Workforce Split
    if (workforceSplit.motorcyclist.length) {
       const ws = XLSX.utils.json_to_sheet(workforceSplit.motorcyclist);
       XLSX.utils.book_append_sheet(wb, ws, "Motorcyclists");
    }

    if (workforceSplit.staffSupport.length) {
       const ws = XLSX.utils.json_to_sheet(workforceSplit.staffSupport);
       XLSX.utils.book_append_sheet(wb, ws, "Support Staff");
    }

    XLSX.writeFile(wb, `EMPMAS_Intelligence_Report_${new Date().toISOString().split('T')[0]}.xlsx`);
    setIsExporting(false);
  };

  return (
    <div className="space-y-16 animate-in fade-in duration-1000 pb-24 w-full">
      {/* EXECUTIVE COMMAND HEADER */}
      <div className="bg-slate-900 rounded-[60px] p-12 shadow-2xl relative overflow-hidden flex flex-col xl:flex-row items-center justify-between gap-12 border border-white/5">
        <div className="absolute top-0 right-0 w-[800px] h-[800px] bg-indigo-500/10 blur-[150px] -mr-96 -mt-96 rounded-full pointer-events-none"></div>
        <div className="relative z-10 space-y-5">
          <div className="flex items-center gap-4 text-indigo-400 font-black text-[10px] uppercase tracking-[0.5em]">
            <Zap size={18} /> Command Intelligence Hub
          </div>
          <h2 className="text-6xl font-black text-white tracking-tighter leading-tight">Master Sync</h2>
          <p className="text-slate-400 font-medium text-lg max-w-2xl">Auditing {metrics.total} professional entities across the master drive.</p>
        </div>

        <div className="flex flex-col md:flex-row gap-8 relative z-10 w-full xl:w-auto items-center">
          <div className="grid grid-cols-3 gap-6 w-full md:w-auto">
             {/* Vitality Stats */}
             <div className="flex flex-col items-center">
                <div className="text-emerald-400 font-black text-2xl">{metrics.total ? ((((metrics.total as number) - (metrics.expiredCardCount as number) - (metrics.escapeCount as number)) / (metrics.total as number)) * 100).toFixed(0) : 0}%</div>
                <div className="text-[9px] uppercase tracking-widest text-slate-500">Health</div>
             </div>
             <div className="flex flex-col items-center">
                <div className="text-rose-400 font-black text-2xl">{(metrics.expiredCardCount as number) + (metrics.escapeCount as number)}</div>
                <div className="text-[9px] uppercase tracking-widest text-slate-500">Risks</div>
             </div>
             <div className="flex flex-col items-center">
                <div className="text-indigo-400 font-black text-2xl">{metrics.total}</div>
                <div className="text-[9px] uppercase tracking-widest text-slate-500">Total</div>
             </div>
          </div>

          <button 
            onClick={handleFullExport}
            disabled={isExporting}
            className="bg-white text-slate-900 hover:bg-indigo-50 px-8 py-5 rounded-[24px] font-black text-xs uppercase tracking-widest transition-all shadow-xl hover:shadow-2xl hover:-translate-y-1 active:scale-95 flex items-center gap-3 whitespace-nowrap min-w-[200px] justify-center"
          >
            {isExporting ? <Loader2 className="animate-spin" size={18} /> : <FileSpreadsheet size={18} />}
            Export Intelligence Report
          </button>
        </div>
      </div>

      {/* CORE OPERATIONAL KPIS */}
      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-10">
        <ProKpi icon={<UserX />} label="Escape Reports" value={metrics.escapeCount} color="rose" onClick={() => onDrillDown("Escape Registry", metrics.escapeRecords)} />
        <ProKpi icon={<ShieldX />} label="Expired Credentials" value={metrics.expiredCardCount} color="amber" onClick={() => onDrillDown("Expired Registry", metrics.expiredRecords)} />
        <ProKpi icon={<Bike />} label="Motorcyclists" value={workforceSplit.motorcyclist.length} color="indigo" onClick={() => onDrillDown("Motorcyclists", workforceSplit.motorcyclist)} />
        <ProKpi icon={<MoreHorizontal />} label="Staff & Support" value={workforceSplit.staffSupport.length} color="slate" onClick={() => onDrillDown("Support Staff", workforceSplit.staffSupport)} />
        <ProKpi icon={<CreditCard />} label="Active Personnel" value={metrics.activeCount} color="emerald" onClick={() => onDrillDown("Active", rows.filter(r => !metrics.expiredRecords.includes(r)))} />
        <ProKpi icon={<Activity />} label="Upcoming Renewals" value={metrics.upcomingRenewals} color="indigo" onClick={() => onDrillDown("Upcoming (Current Month)", metrics.upcomingRecords)} />
      </div>

      {/* OPERATIONAL PIPELINE */}
      <div className="bg-slate-900 p-12 rounded-[70px] shadow-2xl relative overflow-hidden border border-white/5">
        <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-8 mb-16 relative z-10">
          <div>
            <h3 className="text-4xl font-black text-white tracking-tighter flex items-center gap-5">
              <Calendar className="text-indigo-400" size={44} /> Operational Expiry Pipeline
            </h3>
          </div>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-6 gap-6 relative z-10">
          {renewalForecast.map((item) => (
            <div key={item.key} className="group relative bg-white/5 hover:bg-white/10 rounded-[48px] p-8 border border-white/5 hover:border-indigo-500/30 transition-all cursor-pointer overflow-hidden flex flex-col justify-between min-h-[400px]" onClick={() => onDrillDown(`Forecast: ${item.month}`, rows)}>
              <div className="relative z-10">
                <div className="w-16 h-16 bg-white/10 rounded-2xl flex flex-col items-center justify-center mb-8">
                  <span className="text-[10px] font-black text-indigo-400 uppercase">{item.year}</span>
                  <span className="text-2xl font-black text-white">{item.month}</span>
                </div>
                <div>
                  <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest">Expected Batch</p>
                  <div className="text-6xl font-black text-white tracking-tighter">{item.count}</div>
                </div>
                {item.escapeCount > 0 && (
                  <div className="mt-4 bg-orange-600/20 border border-orange-500/30 px-5 py-3 rounded-2xl animate-pulse">
                    <p className="text-[9px] text-orange-400 font-black uppercase tracking-widest">Escape Reports</p>
                    <div className="text-2xl font-black text-orange-500">{item.escapeCount}</div>
                  </div>
                )}
              </div>
              <div className="relative z-10">
                <div className="h-1.5 w-full bg-white/5 rounded-full overflow-hidden">
                  <div className="h-full bg-indigo-500" style={{ width: `${item.intensity}%` }} />
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

