// --- Configuration & Environment ---

const getEnv = (key: string) => {
  const meta = import.meta as any;
  if (meta && meta.env && meta.env[key]) {
    return meta.env[key];
  }
  // Fallback for some environments where VITE_ vars might be directly on process.env
  try {
     // @ts-ignore
     if (typeof process !== 'undefined' && process.env && process.env[key]) {
        // @ts-ignore
        return process.env[key];
     }
  } catch (e) {}
  return undefined;
};

const apiKey = getEnv('VITE_FIREBASE_API_KEY');
const hasFirebaseConfig = !!apiKey && apiKey !== 'undefined';

// --- Firebase Instances ---
let app: any;
let auth: any;
let db: any;
let storage: any;

if (hasFirebaseConfig) {
  try {
    const firebaseConfig = {
      apiKey: apiKey,
      authDomain: getEnv('VITE_FIREBASE_AUTH_DOMAIN'),
      projectId: getEnv('VITE_FIREBASE_PROJECT_ID'),
      storageBucket: getEnv('VITE_FIREBASE_STORAGE_BUCKET'),
      messagingSenderId: getEnv('VITE_FIREBASE_MESSAGING_SENDER_ID'),
      appId: getEnv('VITE_FIREBASE_APP_ID')
    };
    app = initializeApp(firebaseConfig);
    auth = getAuth(app);
    db = getFirestore(app);
    storage = getStorage(app);
  } catch (e) {
    console.error("Firebase Initialization Failed:", e);
    // Fallback to mock if init fails
  }
}

// --- Types ---
export interface CompanyMeta {
  id: string;
  name: string;
  storagePath: string;
  uploadDate: string;
  uploadedBy: string;
}

export interface SystemUser {
  uid: string;
  email: string;
  role: 'admin' | 'user';
  password?: string; // Only used for mock auth verification
}

// --- Mock State (In-Memory & LocalStorage) ---
let mockUser: any = null;
const mockAuthListeners: ((user: any) => void)[] = [];

// Load users from localStorage or initialize with Admin
const loadMockUsers = (): SystemUser[] => {
  const stored = localStorage.getItem('mock_users_db');
  if (stored) {
    return JSON.parse(stored);
  }
  return [
    { uid: 'admin-123', email: 'admin@empmas.com', password: 'admin123', role: 'admin' }
  ];
};

let mockUsersDB: SystemUser[] = loadMockUsers();

const saveMockUsers = () => {
  localStorage.setItem('mock_users_db', JSON.stringify(mockUsersDB));
};

// Initialized as empty so the repository appears empty to the user
let mockCompanies: CompanyMeta[] = [];

// Mock storage initialized empty (files added via uploadCompanyData)
const mockFileStorage: Record<string, ArrayBuffer> = {};

// --- Facade Methods ---

/**
 * Subscribes to auth state changes. 
 * Handles both Firebase Auth and Mock Auth.
 */
export const subscribeToAuth = (callback: (user: User | null) => void) => {
  if (hasFirebaseConfig && auth) {
    return onAuthStateChanged(auth, callback);
  } else {
    // Mock Subscription
    mockAuthListeners.push(callback);
    callback(mockUser);
    return () => {
      const idx = mockAuthListeners.indexOf(callback);
      if (idx > -1) mockAuthListeners.splice(idx, 1);
    };
  }
};

/**
 * Logs in the user.
 */
export const login = async (email: string, password: string): Promise<void> => {
  if (hasFirebaseConfig && auth) {
    await signInWithEmailAndPassword(auth, email, password);
  } else {
    // Mock Login
    if (!email || !password) throw new Error("Invalid credentials");

    const user = mockUsersDB.find(u => u.email.toLowerCase() === email.toLowerCase() && u.password === password);

    if (!user) {
        throw new Error("Invalid email or password.");
    }

    // Simulate network delay
    await new Promise(r => setTimeout(r, 800));
    mockUser = { 
      uid: user.uid, 
      email: user.email, 
      displayName: user.email.split('@')[0] 
    };
    mockAuthListeners.forEach(cb => cb(mockUser));
  }
};

/**
 * Logs out the user.
 */
export const logout = async (): Promise<void> => {
  if (hasFirebaseConfig && auth) {
    await signOut(auth);
  } else {
    mockUser = null;
    mockAuthListeners.forEach(cb => cb(null));
  }
};

// --- User Management (Mock Only for now) ---

export const fetchSystemUsers = async (): Promise<SystemUser[]> => {
  // Return users without passwords for security display
  return mockUsersDB.map(u => ({ uid: u.uid, email: u.email, role: u.role }));
};

export const createSystemUser = async (email: string, password: string) => {
  if (mockUsersDB.some(u => u.email.toLowerCase() === email.toLowerCase())) {
    throw new Error("User with this email already exists.");
  }

  const newUser: SystemUser = {
    uid: `user-${Date.now()}`,
    email,
    password,
    role: 'user'
  };

  mockUsersDB.push(newUser);
  saveMockUsers();
  return newUser;
};

export const deleteSystemUser = async (uid: string) => {
  if (uid === 'admin-123') throw new Error("Cannot delete the root administrator.");
  mockUsersDB = mockUsersDB.filter(u => u.uid !== uid);
  saveMockUsers();
};

// --- Data Methods ---

/**
 * UPLOADS MASTER SHEET.
 * Parses a single Excel file, extracting EACH TAB as a separate Company Entity.
 */
export const uploadMasterSheet = async (file: File, userId: string): Promise<number> => {
  if (hasFirebaseConfig) {
     throw new Error("Master Sheet Split not implemented for Firebase Backend in this demo version.");
  }

  // 1. Read the Master File
  const arrayBuffer = await file.arrayBuffer();
  const wb = XLSX.read(arrayBuffer, { type: 'array' });

  let processedCount = 0;

  // 2. Clear existing mock data (Optional: based on requirement to 'update' daily)
  // For now, we append/overwrite based on simple logic, but to keep it clean as requested:
  // "Update on daily basis" -> We should probably clear old data or update it.
  // Given the limited user scope, let's clear old mock data to avoid duplicates on re-upload
  mockCompanies = []; 

  // 3. Iterate Sheets (Tabs)
  for (const sheetName of wb.SheetNames) {
    const ws = wb.Sheets[sheetName];

    // Skip empty sheets
    if (!ws['!ref']) continue;

    // Create a new Workbook for this specific sheet to isolate it
    const newWb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(newWb, ws, "Sheet1");
    const newBuffer = XLSX.write(newWb, { bookType: 'xlsx', type: 'array' });

    // Create Meta
    const mockId = `company-${Date.now()}-${processedCount}`;
    const meta: CompanyMeta = {
      id: mockId,
      name: sheetName, // The Tab Name becomes the Company Name
      storagePath: `mock/${mockId}`,
      uploadDate: new Date().toISOString(),
      uploadedBy: userId
    };

    mockCompanies.unshift(meta);
    mockFileStorage[meta.storagePath] = newBuffer;
    processedCount++;
  }

  return processedCount;
};

// Legacy single upload (kept for compatibility)
export const uploadCompanyData = async (file: File, companyName: string, userId: string): Promise<CompanyMeta> => {
   // Redirect to master sheet logic if needed, but for now specific single upload
   // ... existing implementation
   await new Promise(r => setTimeout(r, 1000));
    const mockId = `mock-${Date.now()}`;
    const meta: CompanyMeta = {
      id: mockId,
      name: companyName,
      storagePath: `mock/${mockId}`,
      uploadDate: new Date().toISOString(),
      uploadedBy: userId
    };
    mockCompanies.unshift(meta);
    mockFileStorage[meta.storagePath] = await file.arrayBuffer();
    return meta;
};

/**
 * Fetches list of companies.
 */
export const fetchCompanies = async (): Promise<CompanyMeta[]> => {
  if (hasFirebaseConfig && db) {
    const q = query(collection(db, "companies"), orderBy("uploadDate", "desc"));
    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as CompanyMeta));
  } else {
    return [...mockCompanies];
  }
};

/**
 * Deletes company data.
 */
export const deleteCompanyData = async (id: string, storagePath: string) => {
  if (hasFirebaseConfig && db && storage) {
    const storageRef = ref(storage, storagePath);
    await deleteObject(storageRef);
    await deleteDoc(doc(db, "companies", id));
  } else {
    mockCompanies = mockCompanies.filter(c => c.id !== id);
    delete mockFileStorage[storagePath];
  }
};

/**
 * Downloads company file.
 */
export const downloadCompanyFile = async (storagePath: string): Promise<ArrayBuffer> => {
  if (hasFirebaseConfig && storage) {
    const pathReference = ref(storage, storagePath);
    const url = await getDownloadURL(pathReference);
    const response = await fetch(url);
    return await response.arrayBuffer();
  } else {
    const buffer = mockFileStorage[storagePath];
    if (buffer) return buffer;
    throw new Error("File not found in mock storage");
  }
};

