      )}

      {/* Drill Down Modal */}
      {drillDownData && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-6 bg-black/90 backdrop-blur-xl animate-in fade-in">
          <div className="bg-slate-900 w-full max-w-7xl h-[90vh] rounded-[70px] border border-white/10 flex flex-col overflow-hidden shadow-2xl">
            <div className="p-12 border-b border-white/5 flex flex-col space-y-8 bg-white/5">
              <div className="flex items-center justify-between">
                <h3 className="text-4xl font-black text-white tracking-tighter">{drillDownData.title}</h3>
                <button onClick={() => setDrillDownData(null)} className="p-5 hover:bg-white/5 rounded-full text-slate-500"><X size={44} /></button>
              </div>
              <div className="flex flex-wrap items-center gap-8 bg-slate-950/50 p-6 rounded-[32px]">
                <div className="flex items-center gap-4"><CalendarDays className="text-indigo-400" size={14} /><input type="date" className="bg-slate-900 border border-white/10 rounded-xl px-4 py-2 text-xs font-bold text-white" value={dateRange.start} onChange={(e) => setDateRange(prev => ({ ...prev, start: e.target.value }))} /></div>
                <div className="flex items-center gap-4"><CalendarDays className="text-indigo-400" size={14} /><input type="date" className="bg-slate-900 border border-white/10 rounded-xl px-4 py-2 text-xs font-bold text-white" value={dateRange.end} onChange={(e) => setDateRange(prev => ({ ...prev, end: e.target.value }))} /></div>
              </div>
            </div>
            <div className="flex-1 overflow-hidden p-12 bg-slate-950"><DataTable headers={currentData?.headers || []} rows={drillDownFiltered} /></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

payload.text:
This is a complex application to port to Google Apps Script (GAS) because GAS does not have a native "Database" or "File Storage" like Firebase.

To make this work:
1.  **Database:** We will use a **Google Sheet** to store the list of companies (metadata).
2.  **Storage:** We will use **Google Drive** to store the actual `.xlsx` files.
3.  **Frontend:** We will bundle the React code into a single `index.html` file using CDN links (so you don't need a build step).
4.  **Backend:** The `Code.gs` file will handle the interaction with Drive, Sheets, and the Gemini API.

### Prerequisites
1.  Create a new Google Apps Script project (script.google.com).
2.  **Gemini API:** Go to **Project Settings > Script Properties** and add a property named `GEMINI_API_KEY` with your key.
3.  **Admin:** In `Code.gs`, update the `ADMIN_EMAIL` constant with your Google email address.

Here are the two files you need.

### 1. Code.gs
Copy this into the `Code.gs` file.

```javascript
// --- CONFIGURATION ---
const ADMIN_EMAILS = ["your-email@gmail.com", "admin@empmas.com"]; // Add your Google Email here
const DB_SHEET_NAME = "EMPMAS_DB";
const ROOT_FOLDER_NAME = "EMPMAS_Data_Repository";

// --- SERVE HTML ---
function doGet() {
  return HtmlService.createHtmlOutputFromFile('index')
    .setTitle('DataHarmonizer Pro')
    .setXFrameOptionsMode(HtmlService.XFrameOptionsMode.ALLOWALL)
    .addMetaTag('viewport', 'width=device-width, initial-scale=1');
}

// --- UTILS ---
function getDbSheet() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName(DB_SHEET_NAME);
  if (!sheet) {
    sheet = ss.insertSheet(DB_SHEET_NAME);
    sheet.appendRow(["ID", "Name", "FileId", "UploadDate", "UploadedBy", "HasData"]); // Headers
  }
  return sheet;
}

function getRootFolder() {
  const folders = DriveApp.getFoldersByName(ROOT_FOLDER_NAME);
  if (folders.hasNext()) return folders.next();
  return DriveApp.createFolder(ROOT_FOLDER_NAME);
}

// --- API METHODS ---

/**
 * Get current user and role
 */
function getUserSession() {
  const email = Session.getActiveUser().getEmail();
  const isAdmin = ADMIN_EMAILS.includes(email);
  return {
    email: email,
    isAdmin: isAdmin,
    uid: Utilities.base64Encode(email) // Simple UID
  };
}

/**
 * Fetch all companies
 */
function getCompanies() {
  const sheet = getDbSheet();
  const data = sheet.getDataRange().getValues();
  const headers = data.shift(); // Remove headers

  return data.map(row => ({
    id: row[0],
    name: row[1],
    storagePath: row[2], // In GAS, this is the Drive File ID
    uploadDate: row[3],
    uploadedBy: row[4],
    hasData: row[5] === true || row[5] === "true"
  }));
}

/**
 * Create a new Company Entity
 */
function createCompany(name) {
  const user = getUserSession();
  if (!user.isAdmin) throw new Error("Unauthorized");

  const id = 'comp-' + new Date().getTime();
  const sheet = getDbSheet();

  // ID, Name, FileId (null), Date, By, HasData
  sheet.appendRow([id, name, "", "", user.email, false]);

  return { id, name, hasData: false };
}

/**
 * Upload File (Overwrite logic)
 */
function uploadCompanyData(fileData, filename, companyId) {
  const user = getUserSession();
  if (!user.isAdmin) throw new Error("Unauthorized");

  const sheet = getDbSheet();
  const data = sheet.getDataRange().getValues();
  let rowIndex = -1;

  // Find Company Row (Start at 1 to skip header)
  for (let i = 1; i < data.length; i++) {
    if (data[i][0] == companyId) {
      rowIndex = i + 1; // 1-based index for Sheet operations
      break;
    }
  }

  if (rowIndex === -1) throw new Error("Company not found");

  // 1. Handle File in Drive
  const folder = getRootFolder();
  const contentType = "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet";
  const blob = Utilities.newBlob(Utilities.base64Decode(fileData), contentType, filename);

  // Delete old file if exists
  const oldFileId = data[rowIndex - 1][2];
  if (oldFileId) {
    try {
      DriveApp.getFileById(oldFileId).setTrashed(true);
    } catch (e) { console.log("Could not delete old file", e); }
  }

  const newFile = folder.createFile(blob);
  const newFileId = newFile.getId();
  const uploadDate = new Date().toISOString();

  // 2. Update Sheet
  // Columns: C=3 (FileId), D=4 (Date), E=5 (By), F=6 (HasData)
  sheet.getRange(rowIndex, 3).setValue(newFileId);
  sheet.getRange(rowIndex, 4).setValue(uploadDate);
  sheet.getRange(rowIndex, 5).setValue(user.email);
  sheet.getRange(rowIndex, 6).setValue(true);

  return "Success";
}

/**
 * Delete Company
 */
function deleteCompany(companyId, fileId) {
  const user = getUserSession();
  if (!user.isAdmin) throw new Error("Unauthorized");

  const sheet = getDbSheet();
  const data = sheet.getDataRange().getValues();

  // Delete file from Drive
  if (fileId) {
    try {
      DriveApp.getFileById(fileId).setTrashed(true);
    } catch(e) {}
  }

  // Delete row from Sheet
  for (let i = 1; i < data.length; i++) {
    if (data[i][0] == companyId) {
      sheet.deleteRow(i + 1);
      break;
    }
  }
}

/**
 * Download/Get File Data
 */
function getCompanyFile(fileId) {
  const file = DriveApp.getFileById(fileId);
  // Return Base64 string
  return Utilities.base64Encode(file.getBlob().getBytes());
}

/**
 * Gemini AI Proxy
 */
function callGemini(prompt) {
  const scriptProperties = PropertiesService.getScriptProperties();
  const apiKey = scriptProperties.getProperty('GEMINI_API_KEY');

  if (!apiKey) return "Error: GEMINI_API_KEY not set in Script Properties.";

  const url = `https://generativelanguage.googleapis.com/v1beta/models/gemini-pro:generateContent?key=${apiKey}`;

  const payload = {
    "contents": [{
      "parts": [{ "text": prompt }]
    }]
  };

  const options = {
    'method': 'post',
    'contentType': 'application/json',
    'payload': JSON.stringify(payload),
    'muteHttpExceptions': true
  };

  try {
    const response = UrlFetchApp.fetch(url, options);
    const json = JSON.parse(response.getContentText());

    if (json.error) return "AI Error: " + json.error.message;
    return json.candidates[0].content.parts[0].text;
  } catch (e) {
    return "Failed to call AI service: " + e.toString();
  }
}
```

### 2. index.html
Copy this into the `index.html` file. This is a monolithic file containing the React app, Styles, and Logic adapted for GAS.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>DataHarmonizer Pro</title>

    <!-- STYLES -->
    <script src="https://cdn.tailwindcss.com"></script>
    <style>
        body { background-color: #020617; color: #cbd5e1; }
        .custom-scrollbar::-webkit-scrollbar { width: 8px; height: 8px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: #0f172a; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #334155; border-radius: 4px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #475569; }
        .loader { border: 3px solid rgba(255,255,255,0.1); border-radius: 50%; border-top: 3px solid #6366f1; width: 20px; height: 20px; animation: spin 1s linear infinite; }
        @keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }
    </style>

    <!-- LIBRARIES -->
    <script crossorigin src="https://unpkg.com/react@18/umd/react.production.min.js"></script>
    <script crossorigin src="https://unpkg.com/react-dom@18/umd/react-dom.production.min.js"></script>
    <script src="https://unpkg.com/babel-standalone@6/babel.min.js"></script>
    <script src="https://cdn.sheetjs.com/xlsx-0.19.3/package/dist/xlsx.full.min.js"></script>
    <script src="https://unpkg.com/lucide@latest"></script>
</head>
<body>
    <div id="root"></div>

    <script type="text/babel">
        const { useState, useEffect, useMemo, useRef } = React;

        // --- ICONS WRAPPER (Since we can't import Lucide directly in browser) ---
        const Icon = ({ name, size = 24, className }) => {
            useEffect(() => {
                lucide.createIcons();
            }, [name]);
            return <i data-lucide={name} width={size} height={size} className={className}></i>;
        };

        // --- UTILS: DATA PROCESSING ---
        const DATE_PATTERN = /^(?:\d{1,2}[\/\-]\d{1,2}[\/\-]\d{2,4})|(?:\d{4}[\/\-]\d{1,2}[\/\-]\d{1,2})$/;

        function parseToStandardDate(val) {
            if (typeof val === 'number' && val > 40000 && val < 60000) {
                const date = new Date(Math.round((val - 25569) * 86400 * 1000));
                return `${String(date.getDate()).padStart(2, '0')}/${String(date.getMonth() + 1).padStart(2, '0')}/${date.getFullYear()}`;
            }
            if (typeof val === 'string' && DATE_PATTERN.test(val)) {
                // Simple parser, assuming DD/MM/YYYY or YYYY/MM/DD logic based on context or lib
                return val; 
            }
            return null;
        }

        function harmonizeData(rawRows) {
            if (!rawRows || rawRows.length === 0) return { headers: [], rows: [] };

            // 1. Merge Rows Logic (simplified for GAS version)
            // Assumes column 0 is the ID. If ID is present, new row. If ID empty, merge with prev.
            const merged = [];
            const headers = Object.keys(rawRows[0]);
            let current = null;

            rawRows.forEach(row => {
                const idVal = String(row[headers[0]] || '').trim();
                if (idVal !== "") {
                    current = { ...row };
                    merged.push(current);
                } else if (current) {
                    headers.forEach(h => {
                        const val = String(row[h] || '').trim();
                        if (val) {
                            const existing = String(current[h] || '').trim();
                            current[h] = existing ? `${existing}; ${val}` : val;
                        }
                    });
                }
            });

            // 2. Identify Types & Split Columns (Simplified)
            // For this demo, we will just use the headers and rows as is, 
            // but add date parsing for known date columns if needed.

            // Apply Date Parsing to merged rows
            const finalRows = merged.map(row => {
                const newRow = { ...row };
                Object.keys(newRow).forEach(k => {
                   if (k.toLowerCase().includes('date') || k.toLowerCase().includes('expiry')) {
                       const parsed = parseToStandardDate(newRow[k]);
                       if (parsed) newRow[k] = parsed;
                   }
                });
                return newRow;
            });

            return { headers, rows: finalRows };
        }

        function extractDashboardMetrics(rows) {
            const today = new Date();
            const metrics = {
                total: rows.length,
                escapeCount: 0,
                expiredCardCount: 0,
                activeCount: 0,
                upcomingRenewals: 0,
                monthlyRenewals: {},
                monthlyEscapes: {},
                escapeRecords: [],
                expiredRecords: [],
                upcomingRecords: [],
                nationalityData: {},
                statusData: {}
            };

            rows.forEach(row => {
                // Nationality
                const natKey = Object.keys(row).find(k => k.toLowerCase().includes('nationality'));
                const nat = natKey ? (String(row[natKey]).trim() || 'Unspecified') : 'Unspecified';
                metrics.nationalityData[nat] = (metrics.nationalityData[nat] || 0) + 1;

                // Status
                const statusKey = Object.keys(row).find(k => k.toLowerCase().includes('status') || k.toLowerCase().includes('card type'));
                if (statusKey) metrics.statusData[row[statusKey]] = (metrics.statusData[row[statusKey]] || 0) + 1;

                // Escape
                let hasEscape = false;
                Object.values(row).forEach(v => {
                    if (String(v).toLowerCase().includes('escape report')) hasEscape = true;
                });
                if (hasEscape) {
                    metrics.escapeCount++;
                    metrics.escapeRecords.push(row);
                }

                // Dates
                const dateKey = Object.keys(row).find(k => k.toLowerCase().includes('expiry') || k.toLowerCase().includes('(date)'));
                if (dateKey) {
                    const val = String(row[dateKey]).split(';')[0].trim(); // Take first date if merged
                    const parts = val.split(/[\/\-]/);
                    if (parts.length === 3) {
                         // Attempt parse DD/MM/YYYY
                         const dObj = new Date(parseInt(parts[2]), parseInt(parts[1])-1, parseInt(parts[0]));
                         if (!isNaN(dObj.getTime())) {
                             const monthKey = `${dObj.getFullYear()}-${String(dObj.getMonth()+1).padStart(2,'0')}`;
                             metrics.monthlyRenewals[monthKey] = (metrics.monthlyRenewals[monthKey] || 0) + 1;

                             if (hasEscape) metrics.monthlyEscapes[monthKey] = (metrics.monthlyEscapes[monthKey] || 0) + 1;

                             if (dObj < today) {
                                 metrics.expiredCardCount++;
                                 metrics.expiredRecords.push(row);
                             } else {
                                 metrics.activeCount++;
                                 if (dObj.getMonth() === today.getMonth() && dObj.getFullYear() === today.getFullYear()) {
                                     metrics.upcomingRenewals++;
                                     metrics.upcomingRecords.push(row);
                                 }
                             }
                         }
                    }
                }
            });

            return metrics;
        }

        // --- GAS BACKEND WRAPPER ---
        const GAS = {
            run: (fnName, ...args) => {
                return new Promise((resolve, reject) => {
                    google.script.run
                        .withSuccessHandler(resolve)
                        .withFailureHandler(reject)
                        [fnName](...args);
                });
            }
        };

        // --- COMPONENT: DASHBOARD ---
        const Dashboard = ({ rows, onDrillDown }) => {
            const metrics = useMemo(() => extractDashboardMetrics(rows), [rows]);

            // Forecast Logic
            const forecast = useMemo(() => {
                const today = new Date();
                const res = [];
                const monthNames = ["JAN","FEB","MAR","APR","MAY","JUN","JUL","AUG","SEP","OCT","NOV","DEC"];

                for(let i=0; i<6; i++) {
                    const d = new Date(today.getFullYear(), today.getMonth()+i, 1);
                    const key = `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}`;
                    res.push({
                        month: monthNames[d.getMonth()],
                        year: d.getFullYear(),
                        count: metrics.monthlyRenewals[key] || 0,
                        escapes: metrics.monthlyEscapes[key] || 0
                    });
                }
                return res;
            }, [metrics]);

            const downloadReport = (name, data) => {
                const ws = XLSX.utils.json_to_sheet(data);
                const wb = XLSX.utils.book_new();
                XLSX.utils.book_append_sheet(wb, ws, "Report");
                XLSX.writeFile(wb, `${name}.xlsx`);
            }

            const KPI = ({ label, val, color, icon, dataName, dataSet }) => (
                <div className="bg-white/5 border border-white/10 p-6 rounded-2xl cursor-pointer hover:bg-white/10 transition-all group relative overflow-hidden">
                    <div className="flex justify-between items-start">
