                    </div>}

                    {/* MODAL: UPLOAD */}
                    {showUpload && <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[100] flex items-center justify-center p-4">
                        <div className="bg-slate-900 p-8 rounded-[40px] border border-white/10 w-full max-w-md">
