                            <label className="text-[10px] text-slate-500 font-black uppercase mb-1 block ml-2">Target Entity</label>
                            <select value={uploadTargetId} onChange={e=>setUploadTargetId(e.target.value)} className="w-full bg-black/20 border border-white/10 rounded-xl p-4 text-white mb-4 outline-none">
