// --- CONFIGURATION ---
// REPLACE THIS WITH YOUR GOOGLE EMAIL
const ADMIN_EMAILS = ["admin@empmas.com", "your-email@gmail.com"]; 
const DB_SHEET_NAME = "EMPMAS_DB";
const ROOT_FOLDER_NAME = "EMPMAS_Data_Repository";

// --- SERVE HTML ---
function doGet() {
  return HtmlService.createHtmlOutputFromFile('index')
    .setTitle('DataHarmonizer Pro')
    .setXFrameOptionsMode(HtmlService.XFrameOptionsMode.ALLOWALL)
    .addMetaTag('viewport', 'width=device-width, initial-scale=1');
}

// --- UTILS ---
function getDbSheet() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName(DB_SHEET_NAME);
  if (!sheet) {
    sheet = ss.insertSheet(DB_SHEET_NAME);
    // Headers matching your data structure
    sheet.appendRow(["ID", "Name", "FileId", "UploadDate", "UploadedBy", "HasData"]); 
  }
  return sheet;
}

function getRootFolder() {
  const folders = DriveApp.getFoldersByName(ROOT_FOLDER_NAME);
  if (folders.hasNext()) return folders.next();
  return DriveApp.createFolder(ROOT_FOLDER_NAME);
}

// --- API METHODS (CALLED FROM REACT) ---

/**
 * Get current user session
 */
function getUserSession() {
  const email = Session.getActiveUser().getEmail();
  // Simple admin check based on hardcoded array
  const isAdmin = ADMIN_EMAILS.includes(email) || ADMIN_EMAILS.some(e => email.includes(e));
  return {
    uid: Utilities.base64Encode(email),
    email: email,
    role: isAdmin ? 'admin' : 'user'
  };
}

/**
 * Fetch all companies
 */
function getCompanies() {
  const sheet = getDbSheet();
  const data = sheet.getDataRange().getValues();
  const headers = data.shift(); // Remove headers

  return data.map(row => ({
    id: row[0],
    name: row[1],
    storagePath: row[2], // In GAS, this is the Drive File ID
    uploadDate: row[3],
    uploadedBy: row[4],
    hasData: row[5] === true || String(row[5]).toLowerCase() === "true"
  }));
}

/**
 * Create a new Company Entity
 */
function createCompany(name) {
  const user = getUserSession();
  if (user.role !== 'admin') throw new Error("Unauthorized");

  const id = 'comp-' + new Date().getTime();
  const sheet = getDbSheet();

  // ID, Name, FileId (null), Date, By, HasData
  sheet.appendRow([id, name, "", "", user.email, false]);

  return { id, name, hasData: false };
}

/**
 * Upload File (Overwrite logic)
 */
function uploadCompanyData(fileData, filename, companyId) {
  const user = getUserSession();
  if (user.role !== 'admin') throw new Error("Unauthorized");

  const sheet = getDbSheet();
  const data = sheet.getDataRange().getValues();
  let rowIndex = -1;

  // Find Company Row (Start at 1 to skip header)
  for (let i = 1; i < data.length; i++) {
    if (data[i][0] == companyId) {
      rowIndex = i + 1; // 1-based index for Sheet operations
      break;
    }
  }

  if (rowIndex === -1) throw new Error("Company not found");

  // 1. Handle File in Drive
  const folder = getRootFolder();
  // Create blob from base64
  const blob = Utilities.newBlob(Utilities.base64Decode(fileData), MimeType.MICROSOFT_EXCEL, filename);

  // Delete old file if exists
  const oldFileId = data[rowIndex - 1][2];
  if (oldFileId) {
    try {
      DriveApp.getFileById(oldFileId).setTrashed(true);
    } catch (e) { console.log("Could not delete old file", e); }
  }

  const newFile = folder.createFile(blob);
  const newFileId = newFile.getId();
  const uploadDate = new Date().toISOString();

  // 2. Update Sheet
  // Columns: C=3 (FileId), D=4 (Date), E=5 (By), F=6 (HasData)
  sheet.getRange(rowIndex, 3).setValue(newFileId);
  sheet.getRange(rowIndex, 4).setValue(uploadDate);
  sheet.getRange(rowIndex, 5).setValue(user.email);
  sheet.getRange(rowIndex, 6).setValue(true);

  return "Success";
}

/**
 * Delete Company
 */
function deleteCompany(companyId, fileId) {
  const user = getUserSession();
  if (user.role !== 'admin') throw new Error("Unauthorized");

  const sheet = getDbSheet();
  const data = sheet.getDataRange().getValues();

  // Delete file from Drive
  if (fileId) {
    try {
      DriveApp.getFileById(fileId).setTrashed(true);
    } catch(e) {}
  }

  // Delete row from Sheet
  for (let i = 1; i < data.length; i++) {
    if (data[i][0] == companyId) {
      sheet.deleteRow(i + 1);
      break;
    }
  }
}

/**
 * Download/Get File Data
 */
function getCompanyFile(fileId) {
  const file = DriveApp.getFileById(fileId);
  // Return Base64 string for client to parse
  return Utilities.base64Encode(file.getBlob().getBytes());
}

/**
 * Gemini AI Proxy (Since we can't use Node SDK)
 */
function callGemini(prompt) {
  const scriptProperties = PropertiesService.getScriptProperties();
  const apiKey = scriptProperties.getProperty('GEMINI_API_KEY');

  if (!apiKey) return "Error: GEMINI_API_KEY not set in Script Properties.";

  const url = `https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent?key=${apiKey}`;

  const payload = {
    "contents": [{
      "parts": [{ "text": prompt }]
    }]
  };

  const options = {
    'method': 'post',
    'contentType': 'application/json',
    'payload': JSON.stringify(payload),
    'muteHttpExceptions': true
  };

  try {
    const response = UrlFetchApp.fetch(url, options);
    const json = JSON.parse(response.getContentText());

    if (json.error) return "AI Error: " + json.error.message;
    if (!json.candidates || json.candidates.length === 0) return "No response from AI.";

    return json.candidates[0].content.parts[0].text;
  } catch (e) {
    return "Failed to call AI service: " + e.toString();
  }
}

import React, { useMemo, useState } from 'react';
import * as XLSX from 'xlsx';
import { 
  Users, CreditCard, Globe, ShieldX, UserX, Activity, ArrowUpRight, Zap, 
  Bike, ShieldCheck, MoreHorizontal, Download, Calendar, ShieldAlert, 
  BarChart4, Loader2, FileSpreadsheet, DownloadCloud
} from 'lucide-react';
import { DataRow, DashboardMetrics } from '../types';
import { extractDashboardMetrics } from '../utils/dataProcessor';

interface DashboardProps {
  rows: DataRow[];
  onDrillDown: (title: string, filteredRows: DataRow[]) => void;
}

const BRAND_COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ef4444', '#06b6d4', '#8b5cf6', '#f43f5e', '#3b82f6', '#ec4899', '#84cc16'];

export const Dashboard: React.FC<DashboardProps> = ({ rows, onDrillDown }) => {
  const [isExporting, setIsExporting] = useState(false);

  const metrics = useMemo(() => extractDashboardMetrics(rows), [rows]) as DashboardMetrics;

  // Helper to download specific subset immediately
  const directDownload = (filename: string, data: DataRow[], e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Report");
    XLSX.writeFile(wb, `${filename}_${new Date().getTime()}.xlsx`);
  };

  const workforceSplit = useMemo(() => {
    const jobKey = Object.keys(rows[0] || {}).find(k => 
      k.toLowerCase().includes('job') || k.toLowerCase().includes('description') || k.toLowerCase().includes('designation')
    );
    const motorcyclistRows: DataRow[] = [];
    const staffSupportRows: DataRow[] = [];
    rows.forEach(row => {
      const job = String(row[jobKey || ''] || '').toLowerCase();
      if (job.includes('motorcycle') || job.includes('bike') || job.includes('motorcyclist')) motorcyclistRows.push(row);
      else staffSupportRows.push(row);
    });
    return { motorcyclist: motorcyclistRows, staffSupport: staffSupportRows };
  }, [rows]);

  const renewalForecast = useMemo(() => {
    const today = new Date();
    const months = [];
    const monthNames = ["JAN", "FEB", "MAR", "APR", "MAY", "JUN"];
    let totalProjected = 0;

    // Helper to get rows for a specific month (Year, Month Index 0-11)
    const getMonthRows = (targetYear: number, targetMonth: number) => {
        return rows.filter(row => {
            const dateKey = Object.keys(row).find(k => k.includes('(Date)'));
            if (!dateKey) return false;
            const val = String(row[dateKey]).split(';')[0].trim();
            const parts = val.split('/');
            if (parts.length === 3) {
                 const d = parseInt(parts[0]);
                 const m = parseInt(parts[1]) - 1;
                 const y = parseInt(parts[2]);
                 return y === targetYear && m === targetMonth;
            }
            return false;
        });
    };

    for (let i = 0; i < 6; i++) {
      const d = new Date(today.getFullYear(), today.getMonth() + i, 1);
      const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
      const count = (metrics.monthlyRenewals[key] || 0) as number;
      const escapeCount = (metrics.monthlyEscapes[key] || 0) as number;

      const monthRows = getMonthRows(d.getFullYear(), d.getMonth());

      totalProjected += count;
      months.push({ 
          key, 
          month: monthNames[d.getMonth()], // Using d.getMonth() handles wrap around correctly (0-11)
          year: d.getFullYear(), 
          count, 
          escapeCount,
          rows: monthRows 
      });
    }

    // Calculate intensity for UI
    const maxMonthCount = Math.max(...months.map(m => m.count as number), 1);

    return months.map(m => ({
      ...m,
      intensity: ((m.count as number) / maxMonthCount) * 100
    }));
